-- Poems batch 114
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('11f50cbd-ef74-40ce-a662-0ff4162880ec','謁巫山廟兩廡碑版甚衆皆言神佐禹開峽之功而詆宋玉高唐賦之妄予亦賦詩一首','陸游','宋','宋诗','song-poetry','','[]','真人翳鳯駕蛟龍，一念何曾與世同。',64,'全唐诗/poet.song.127000.json','["真人翳鳯駕蛟龍，一念何曾與世同。", "不爲行雲求弭謗，那因治水欲論功。", "翺翔想見虚無裏，毁譽誰知溷濁中。", "讀盡舊碑成絕倒，書生惟慣諂王公。"]'),
('594fc930-a16f-4224-970b-3f60138e7266','聞猿','陸游','宋','宋诗','song-poetry','','[]','瘦盡腰圍不爲詩，良辰流落自成衰。',64,'全唐诗/poet.song.127000.json','["瘦盡腰圍不爲詩，良辰流落自成衰。", "也知客裏偏多感，誰料天涯有許悲。", "漢塞角殘人不寐，渭城歌罷客將離。", "故應未抵聞猿恨，況是巫山廟裏時。"]'),
('4c793d0c-6212-4870-a290-227f738d1ec1','瞿唐行','陸游','宋','宋诗','song-poetry','','[]','四月欲盡五月來，峽中水漲何雄哉。',99,'全唐诗/poet.song.127000.json','["四月欲盡五月來，峽中水漲何雄哉。", "浪花高飛暑路雪，灘石怒轉晴天雷。", "千艘萬舸不敢過，篙工柂師心膽破。", "人人陰拱待勢衰，誰敢輕行犯奇禍。", "一朝時去不自由，山腹空有沙痕留。", "君不見陸子歲暮來夔州，瞿唐峽水平如油。"]'),
('2ea0562e-356a-4b79-baae-78238f81db86','入瞿唐登白帝廟','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','曉入大谿口，是爲瞿唐門。',192,'全唐诗/poet.song.127000.json','["曉入大谿口，是爲瞿唐門。", "長江從蜀來，日夜東南奔。", "兩山對崔嵬，勢如塞乾坤。", "峭壁空仰視，欲上不可捫。", "禹功何巍巍，尚覩鐫鑿痕。", "天不生斯人，人皆化魚黿。", "於時仲冬月，水各歸其源。", "灩澦屹中流，百尺呈孤根。", "參差層顛屋，邦人祀公孫。", "力戰死社稷，宜享廟貎尊。", "丈夫貴不撓，成敗何足論。", "我欲伐巨石，作碑累千言。", "上陳躍馬壯，下斥乘騾昏。", "雖慚豪偉詞，尚慰雄傑魂。", "君王昔玉食，何至歆雞豚。", "願言采芳蘭，舞歌薦清尊。"]'),
('6341b1e6-18df-42b7-98d0-956436e9f259','登江樓','陸游','宋','宋诗','song-poetry','','[]','已過瞿唐更少留，小船聊繫古夔州。',64,'全唐诗/poet.song.127000.json','["已過瞿唐更少留，小船聊繫古夔州。", "簿書未破三年夢，杖履先尋百尺樓。", "日暮雪雲迷峽口，歲窮畬火照關頭。", "野人不解微官縛，尊酒應來此散愁。"]'),
('7eea5e94-cb95-4e3b-932b-38e7b8898f83','雪中臥病在吿戲作','陸游','宋','宋诗','song-poetry','','[]','面裂愁出門，指直但藏袖。',120,'全唐诗/poet.song.127000.json','["面裂愁出門，指直但藏袖。", "誰云三峽熱，有此凛冽候。", "殷勤愧雪片，飛舞爲我壽。", "方驚四山積，已見萬瓦覆。", "豈惟寒到骨，遂覺疾在腠。", "地爐熾薪炭，噤坐連昏晝。", "梅花真強項，不肯落春後。", "俗人愛桃李，苦道太疏瘦。", "清芬終見賞，此事非速售。", "已矣吾何言，高枕聽簷溜。"]'),
('785cd9ba-6f58-4112-83f5-09f8987ffe0e','雪晴','陸游','宋','宋诗','song-poetry','','[]','臘盡春生白帝城，俸錢雖薄勝躬耕。',64,'全唐诗/poet.song.127000.json','["臘盡春生白帝城，俸錢雖薄勝躬耕。", "眼前但恨親朋少，身外元知得喪輕。", "日映滿窗松竹影，雪消並舍鳥烏聲。", "老來莫道風情減，憶向烟蕪信馬行。"]'),
('e95b4015-3c22-4776-8b91-ffe33f9618c7','玉笈齋書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','莫笑新霜點鬢鬚，老來却得少工夫。',64,'全唐诗/poet.song.127000.json','["莫笑新霜點鬢鬚，老來却得少工夫。", "晨占上古連山易，夜對西真五嶽圖。", "叔夜曾聞高士嘯，孔賓豈待異人呼。", "眉間喜色誰知得，今日新添火四銖。"]'),
('6ce30d26-30f5-4353-82aa-b2000bf06301','玉笈齋書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','雪霽茆堂鐘磬清，晨齋枸杞一杯羮。',64,'全唐诗/poet.song.127000.json','["雪霽茆堂鐘磬清，晨齋枸杞一杯羮。", "隠書不厭千回讀，大藥何時九轉成。", "孤坐月魂寒徹骨，安眠龜息浩無聲。", "剩分松屑爲山信，明日青城有使行。"]'),
('6cea4c5b-7e2c-49ca-953d-436dc5653b08','記夢','陸游','宋','宋诗','song-poetry','','[]','夢裏都忘困晚途，縱横草疏論遷都。',32,'全唐诗/poet.song.127000.json','["夢裏都忘困晚途，縱横草疏論遷都。", "不知盡挽銀河水，洗得平生習氣無。"]'),
('6e9da08d-4de4-440c-b969-7c459f0c7d58','瀼西','陸游','宋','宋诗','song-poetry','','[]','千載瀼西路，今年著脚行。',48,'全唐诗/poet.song.127000.json','["千載瀼西路，今年著脚行。", "匆匆衰已具，渺渺恨難平。", "絕壁猿啼雨，深枝鵲報晴。", "亦知憂吏責，未忍廢詩情。"]'),
('017c7db6-cda1-4de2-a8e7-01be306981e3','山寺','陸游','宋','宋诗','song-poetry','','[]','籃輿送客過江村，小寺無人半掩門。',64,'全唐诗/poet.song.127000.json','["籃輿送客過江村，小寺無人半掩門。", "古佛負牆塵漠漠，孤燈照殿雨昏昏。", "喜投禪榻聊尋夢，懶爲啼猿更斷魂。", "要識人間盛衰理，岸沙君看去年痕。"]'),
('14a61562-3b02-4615-81eb-ce3f4119d322','蹋磧','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','鬼門關外逢人日，蹋磧千家萬家出。',96,'全唐诗/poet.song.127000.json','["鬼門關外逢人日，蹋磧千家萬家出。", "竹枝慘戚雲不動，劍氣聨翩日將夕。", "行人十有八九癭，見慣何曾羞顧影。", "江邊沽酒沙上臥，峽口月出風吹醒。", "人生未死信難知，憔悴夔州生鬢絲。", "何日畫船揺桂檝，西湖却賦探春詩。"]'),
('b96c91f3-41d6-4bb0-8a44-e9e525e08153','寒食','陸游','宋','宋诗','song-poetry','','[]','峽雲烘日欲成霞，瀼水生紋淺見沙。',64,'全唐诗/poet.song.127000.json','["峽雲烘日欲成霞，瀼水生紋淺見沙。", "又向蠻方作寒食，強持巵酒對梨花。", "身如巢燕年年客，心羨游僧處處家。", "賴有春風能領略，一生相伴遍天涯。"]'),
('30ca145b-5e36-4943-87e1-2c29376be291','晚晴書事呈同舍','陸游','宋','宋诗','song-poetry','','[]','魚復城邊夕照紅，物華偏解惱衰翁。',64,'全唐诗/poet.song.127000.json','["魚復城邊夕照紅，物華偏解惱衰翁。", "巴鶯有恨啼芳樹，野水無情入故宫。", "許國漸疏悲壯志，讀書多忘愧新功。", "因君共語增惆悵，京洛交遊欲半空。"]'),
('cc010d8f-5611-4e42-91da-46deba74e1b0','鄉中每以寒食立夏之間省墳客夔適逢此時悽然感懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','松陰繫馬啟朱扉，粔籹青紅正此時。',64,'全唐诗/poet.song.127000.json','["松陰繫馬啟朱扉，粔籹青紅正此時。", "守墓萬家猶有日，及親三釡永無期。", "詩成謾寫天涯感，泪盡何由地下知。", "富貴賤貧俱有恨，此生長廢蓼莪詩。"]'),
('3f66f54a-c0eb-4351-88da-a750771f8dfb','鄉中每以寒食立夏之間省墳客夔適逢此時悽然感懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','手持緑酒酹蒼苔，今歲何由疋馬來。',64,'全唐诗/poet.song.127000.json','["手持緑酒酹蒼苔，今歲何由疋馬來。", "清泪不隨春雨斷，孤吟欲和暮猿哀。", "皂貂破弊歸心切，白髮凄涼老境催。", "誓墓只思長不出，松門日日手親開。"]'),
('b8d3cb75-2507-466c-a7c1-6afe50e5720e','試院春晚','陸游','宋','宋诗','song-poetry','','[]','病思蕭條掩緑罇，閑坊寂歴鎖朱門。',64,'全唐诗/poet.song.127000.json','["病思蕭條掩緑罇，閑坊寂歴鎖朱門。", "故人别久難尋夢，遠客愁多易斷魂。", "漫漫晚花吹瀼岸，離離春草上宫垣。", "此生飄泊何時已，家在山陰水際村。"]'),
('cce6ee58-d8b7-4bf2-b749-6b11014e5b00','倚闌','陸游','宋','宋诗','song-poetry','','[]','故山未敢說歸期，十口相隨又别離。',32,'全唐诗/poet.song.127000.json','["故山未敢說歸期，十口相隨又别離。", "小雨初收殘照晚，闌干西角立多時。"]'),
('e310824b-4c5b-4d3e-b9fe-21fe0443d372','自詠','陸游','宋','宋诗','song-poetry','','[]','朝衣無色如霜葉，將奈雲安别駕何。',64,'全唐诗/poet.song.127000.json','["朝衣無色如霜葉，將奈雲安别駕何。", "鐘鼎山林俱不遂，聲名官職兩無多。", "低昻未免聞雞舞，慷慨猶能擊筑歌。", "頭白伴人書紙尾，只思歸去弄烟波。"]'),
('d8782634-d1cf-4977-826b-6bae20129d37','午興','陸游','宋','宋诗','song-poetry','','[]','漸轉廊腰日，徐來峽口風。',48,'全唐诗/poet.song.127000.json','["漸轉廊腰日，徐來峽口風。", "飱漿便北客，淖粥稱衰翁。", "槐晚纖纖緑，榴殘續續紅。", "責輕仍飽食，三嘆愧無功。"]'),
('53747d3e-6ac6-4aba-af2e-1fcbe89ae551','風雨中望峽口諸山奇甚戲作短歌','陸游','宋','宋诗','song-poetry','','[]','白鹽赤甲天下雄，拔地突兀摩蒼穹。',112,'全唐诗/poet.song.127000.json','["白鹽赤甲天下雄，拔地突兀摩蒼穹。", "凜然猛士舞長劍，空有豪健無雍容。", "不令氣象少渟滀，常恨天地無全功。", "今朝忽悟始嘆息，妙處元在烟雨中。", "太陰殺氣横慘澹，元化變態含空濛。", "正如奇材遇事見，平日乃與常人同。", "安得朱樓高百尺，看此疾雨吹横風。"]'),
('678a4d98-975a-4a77-97e6-2fed7c268d57','夜坐庭中','陸游','宋','宋诗','song-poetry','','[]','人靜風褰幔，更闌露泫衣。',48,'全唐诗/poet.song.127000.json','["人靜風褰幔，更闌露泫衣。", "暗窗饑鼠嚙，空廡冷螢飛。", "歲月背人去，鄉閭何日歸。", "脱巾還感嘆，殘髮不勝稀。"]'),
('8e791695-b597-4ca4-901d-b405d7b49eba','新蔬','陸游','宋','宋诗','song-poetry','','[]','黄瓜翠苣最相宜，上市登盤四月時。',32,'全唐诗/poet.song.127000.json','["黄瓜翠苣最相宜，上市登盤四月時。", "莫擬將軍春薺句，兩京名價有誰知。"]'),
('63a42a44-5421-428c-89b2-66aea375531e','初夏懷故山','陸游','宋','宋诗','song-poetry','','[]','鏡湖四月正清和，白塔紅橋小艇過。',64,'全唐诗/poet.song.127000.json','["鏡湖四月正清和，白塔紅橋小艇過。", "梅雨晴時插秧鼓，蘋風生處采菱歌。", "沉迷簿領吟哦少，淹泊蠻荒感慨多。", "誰謂吾廬六千里，眼中歴歴見漁蓑。"]'),
('9ce78a71-d146-4775-9bf5-b3c515a6a4da','初夏新晴','陸游','宋','宋诗','song-poetry','','[]','曲徑泥新晚照明，小軒纔受一床横。',64,'全唐诗/poet.song.127000.json','["曲徑泥新晚照明，小軒纔受一床横。", "翩翩乳燕穿簾影，蔌蔌新篁解籜聲。", "藥物屏除知病減，夢魂安穏覺心平。", "深居不恨無來客，時有山禽自贊名。"]'),
('4a29cf24-f315-404c-bc74-4a8622da988c','定拆號日喜而有作','陸游','宋','宋诗','song-poetry','','[]','小雨如絲落復收，悄無人語但鳴鳩。',64,'全唐诗/poet.song.127000.json','["小雨如絲落復收，悄無人語但鳴鳩。", "挽鬚預想諸兒喜，倒指猶爲五日留。", "滿案堆書惟引睡，侵天圍棘不遮愁。", "爲農父子長相守，誤計隨人學宦遊。"]'),
('a404e9d6-61fc-4208-8938-0588dea564be','睡起','陸游','宋','宋诗','song-poetry','','[]','深閉重門謝簿書，日長添得睡工夫。',64,'全唐诗/poet.song.127000.json','["深閉重門謝簿書，日長添得睡工夫。", "水紋笛簟涼如洗，雲碧紗幮薄欲無。", "半吐山榴看著子，新來梁燕見將雛。", "夢回茗椀聊須把，自掃桐陰置瓦爐。"]'),
('905afaf7-a5eb-4622-8192-33bea787f952','四月二十九日作','陸游','宋','宋诗','song-poetry','','[]','假館猶三日，還家甫四旬。',48,'全唐诗/poet.song.127000.json','["假館猶三日，還家甫四旬。", "昏眸雲霧隔，衰鬢雪霜新。", "尊酒雖慵近，囊詩却未貧。", "但愁門有客，流汗強冠巾。"]'),
('4d560ef5-eaff-46cf-b003-3983be7fa4b7','苦熱','陸游','宋','宋诗','song-poetry','','[]','萬瓦鱗鱗若火龍，日車不動汗珠融。',64,'全唐诗/poet.song.127000.json','["萬瓦鱗鱗若火龍，日車不動汗珠融。", "無因羽翮氛埃外，坐覺蒸炊釡甑中。", "石磵寒泉空有夢，冰壺團扇欲無功。", "餘威向晚猶堪畏，浴罷斜陽滿野紅。"]'),
('0869afe4-d10e-4c1e-bb3d-c8f49d92770b','拆號前一日作','陸游','宋','宋诗','song-poetry','','[]','飄零隨處是生涯，斷梗飛蓬但可嗟。',64,'全唐诗/poet.song.127000.json','["飄零隨處是生涯，斷梗飛蓬但可嗟。", "稚子歡迎先入夢，從兵結束待還家。", "食眠屢失身多病，憂愧相乘髮易華。", "隔日寄聲爲薄具，石榴應有未開花。"]'),
('f314db42-4497-40f1-9556-0ce9a4ed3423','暴雨','陸游','宋','宋诗','song-poetry','','[]','風怒欲掀屋，雨來如決隄。',48,'全唐诗/poet.song.127000.json','["風怒欲掀屋，雨來如決隄。", "孤燈映窗滅，羈鳥就簷棲。", "暑令方炎赫，秋聲忽慘凄。", "傳聞漲江水，已斷瀼東西。"]'),
('6a42ab6b-1df2-4ee4-8f45-b44e25b501db','西齋雨後','陸游','宋','宋诗','song-poetry','','[]','香碗灰深微炷火，茶鐺聲細緩煎湯。',64,'全唐诗/poet.song.127000.json','["香碗灰深微炷火，茶鐺聲細緩煎湯。", "百年浮世幾人樂，一雨虚齋三日涼。", "簾外微風斜燕影，池邊殘照斂萱房。", "紗幮石枕蕭然臥，付與今宵幽夢長。"]'),
('5721d5b5-6488-4b77-9494-c64c7a9d192f','急雨','陸游','宋','宋诗','song-poetry','','[]','陰雲屯硤口，急雨過城頭。',48,'全唐诗/poet.song.127000.json','["陰雲屯硤口，急雨過城頭。", "白舫投沙峽，青帘捲市樓。", "漂揺爭闔户，壅溢共疏溝。", "抽得驅蠅手，題詩慰旅愁。"]'),
('e0e45dd9-18f3-4e27-a866-b26510baf97b','晚晴聞角有感','陸游','宋','宋诗','song-poetry','','[]','暑雨初收白帝城，小荷新竹夕陽明。',64,'全唐诗/poet.song.127000.json','["暑雨初收白帝城，小荷新竹夕陽明。", "十年塵土青衫色，萬里江山畫角聲。", "零落親朋勞遠夢，凄涼鄉社負歸耕。", "議郎博士多新奏，誰致當時魯二生。"]'),
('4942001f-f1fb-492b-9e6c-35376fcb8112','夏夜起坐南亭達曉不復寐','陸游','宋','宋诗','song-poetry','','[]','風露青冥近九秋，脫巾扶杖冷颼飀。',64,'全唐诗/poet.song.127000.json','["風露青冥近九秋，脫巾扶杖冷颼飀。", "曲闌影外巴山月，畫角聲中楚塞愁。", "巢燕並棲高棟穩，潛魚時躍小池幽。", "悠然坐待江城曉，紅日將昇碧霧浮。"]'),
('931a9e83-3767-44ae-afc0-05fcd8627870','夜登白帝城樓懷少陵先生','陸游','宋','宋诗','song-poetry','','[]','拾遺白髮有誰憐，零落歌詩遍兩川。',64,'全唐诗/poet.song.127000.json','["拾遺白髮有誰憐，零落歌詩遍兩川。", "人立飛樓今已矣，浪翻孤月尚依然。", "升沉自古無窮事，愚智同歸有限年。", "此意凄涼誰共語，夜闌鷗鷺起沙邊。"]'),
('657dcf53-9f40-4984-b2c8-b3446aab907c','假日書事','陸游','宋','宋诗','song-poetry','','[]','萬里西來爲一饑，坐曹日日汗霑衣。',64,'全唐诗/poet.song.127000.json','["萬里西來爲一饑，坐曹日日汗霑衣。", "但嫌憂畏妨人樂，不恨疏慵與世違。", "雕檻迎陽花併發，畫梁避雨燕雙歸。", "放懷始得閑中趣，下馬何人又叩扉。"]'),
('7764a91a-957f-432b-9a78-91cdb67c455f','林亭書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','吏退林亭夏日長，烏紗白紵自生涼。',64,'全唐诗/poet.song.127000.json','["吏退林亭夏日長，烏紗白紵自生涼。", "遶簷密葉帷三面，覆水青萍錦一方。", "約束蠻僮收藥富，催呼稚子曬書忙。", "平生幽事還拈起，未覺巴山異故鄉。"]'),
('9d449511-ff18-4572-ad3f-b765b40db9e9','林亭書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','期會文書日日忙，偷門聊得臥方床。',64,'全唐诗/poet.song.127000.json','["期會文書日日忙，偷門聊得臥方床。", "花藏密葉多時在，風度疏簾特地涼。", "野艇空懷菱蔓滑，冰盆誰弄藕絲長。", "角聲喚起東歸夢，十里平湖一草堂。"]'),
('7a9b5801-bca3-4bfc-8cf5-3fe391af8c18','遊臥龍寺','陸游','宋','宋诗','song-poetry','','[]','曉發魚復走瞿唐，沙頭喚渡倚胡床。',117,'全唐诗/poet.song.127000.json','["曉發魚復走瞿唐，沙頭喚渡倚胡床。", "峒人爭趁五更市，我亦來追六月涼。", "殘星欲盡尚歴落，明河已淡餘蒼茫。", "翻翻林表鴉鵲語，渺渺烟邊鷗鷺行。", "過江走馬十五里，小寺殘僧真蕞爾。", "投鞭入門一爲笑，僻陋稱雄有如此。", "君不見天童徑山金碧浮虚空，千衲梵唄層雲中。"]'),
('2c4bc422-b046-44b6-af78-96fca13ef1eb','久病灼艾後獨臥有感','陸游','宋','宋诗','song-poetry','','[]','白帝城高暮柝傳，幽窗搔首意蕭然。',64,'全唐诗/poet.song.127000.json','["白帝城高暮柝傳，幽窗搔首意蕭然。", "江邊雲濕初横雁，牆下桐疏不庇蟬。", "計出火攻傷老病，臥聞鳶墮嘆蠻烟。", "諸賢好試籌戎策，斂退無心競著鞭。"]'),
('9c34f473-1731-41cf-a7a0-2e81fb64a68d','秋晚病起','陸游','宋','宋诗','song-poetry','','[]','心靜病良已，翛然巾屨輕。',48,'全唐诗/poet.song.127000.json','["心靜病良已，翛然巾屨輕。", "灰深地爐暖，日出紙窗明。", "宿雨全消瘴，新霜賸得晴。", "井梧殊可念，無葉送秋聲。"]'),
('095fb5bb-c053-4512-8435-77142b1bc57c','秋思','陸游','宋','宋诗','song-poetry','','[]','魚復城邊逢雁飛，白頭覊客恨依依。',64,'全唐诗/poet.song.127000.json','["魚復城邊逢雁飛，白頭覊客恨依依。", "遠遊眼底故交少，晚歲人間樂事稀。", "雲重古關傳夜柝，月斜深巷擣秋衣。", "官閑況是頻移疾，藥鼎熒熒臥掩扉。"]'),
('d46f3d5e-30a9-4ead-949f-d33dc4776127','一病四十日天氣遂寒感懷有賦','陸游','宋','宋诗','song-poetry','','[]','幽人病起鬢毛殘，硤口樓臺九月寒。',64,'全唐诗/poet.song.127000.json','["幽人病起鬢毛殘，硤口樓臺九月寒。", "暮角又催孤夢斷，早霜初染一林丹。", "鄉閭乖隔知誰健，懷抱凄涼用底寬。", "麴米春香雖可醉，瀼西新橘尚餘酸。"]'),
('639a4349-5454-40bd-bbd3-168fa77d1606','登城','陸游','宋','宋诗','song-poetry','','[]','簿領無時了，登臨亦快哉。',48,'全唐诗/poet.song.127000.json','["簿領無時了，登臨亦快哉。", "樓危壓城起，硤迮束江來。", "病瘴抛書帙，思鄉泥酒杯。", "天寒水盡落，灩澦已崔嵬。"]'),
('d217c958-1322-4817-bf1a-9396bcdd412f','夔州重陽','陸游','宋','宋诗','song-poetry','','[]','夔州鼓角晚凄悲，恰是幽窗睡起時。',64,'全唐诗/poet.song.127000.json','["夔州鼓角晚凄悲，恰是幽窗睡起時。", "但憶社醅挼菊蕋，敢希朝士賜茰枝。", "山川信美吾廬遠，天地無情客鬢衰。", "佳日掩門君莫笑，病來紗帽不禁吹。"]'),
('bc5542d9-b5ff-4ca6-b437-55e9a6f86053','追懷曾文清公呈趙教授趙近嘗示詩','陸游','宋','宋诗','song-poetry','','[]','憶在茶山聽說詩，親從夜半得玄機。',64,'全唐诗/poet.song.127000.json','["憶在茶山聽說詩，親從夜半得玄機。", "常憂老死無人付，不料窮荒見此奇。", "律令合時方帖妥，工夫深處却平夷。", "人間可恨知多少，不及同君叩老師。"]'),
('80988e29-39d7-40b0-b243-dd9b1b3a858c','謝張廷老司理録示山居詩二首  其一','陸游','宋','宋诗','song-poetry','','[]','憔悴經年客瘴鄉，把君詩卷意差強。',32,'全唐诗/poet.song.127000.json','["憔悴經年客瘴鄉，把君詩卷意差強。", "古人三語猶嗟賞，況是珠璣滿錦囊。"]'),
('6a004033-3689-4c00-ab27-25da463ed196','謝張廷老司理録示山居詩二首  其二','陸游','宋','宋诗','song-poetry','','[]','老覺人間萬事非，但思茆屋映疏籬。',32,'全唐诗/poet.song.127000.json','["老覺人間萬事非，但思茆屋映疏籬。", "秋衾已是饒歸夢，更讀山居二十詩。"]'),
('a5091640-085d-465e-9959-622552da0b58','秋晴欲出城以事不果','陸游','宋','宋诗','song-poetry','','[]','古人已云不可回，今人日夜歸泉臺。',160,'全唐诗/poet.song.127000.json','["古人已云不可回，今人日夜歸泉臺。", "浮生細看只此是，到死自苦何爲哉。", "矝名飾詐竟一世，忍寒觸熱忘其骸。", "不令金樽映翠杓，坐待白骨生蒼苔。", "清秋九月瘴如洗，白鹽千仞高崔嵬。", "荒庭落葉不可掃，惟有樷菊爭先開。", "瀼西黄柑霜落爪，溪口赤梨丹染腮。", "熊肪玉潔美香飯，鮓臠花糝宜新醅。", "南窗病起亦蕭散，甚欲往探城西梅。", "一官底處不敗意，正用此時持事來。"]'),
('fafe8e4a-5cf8-42d1-9820-2f1a37f6892e','南窗','陸游','宋','宋诗','song-poetry','','[]','流落逢知少，疏慵迕俗多。',48,'全唐诗/poet.song.127000.json','["流落逢知少，疏慵迕俗多。", "悶拈如意舞，狂叩唾壺歌。", "巴酒禁愁得，金丹奈老何。", "南窗好風月，聊復此婆娑。"]'),
('50c4c439-728f-4922-8348-74f762a527e5','遣興','陸游','宋','宋诗','song-poetry','','[]','酒量愁翻減，詩聲老轉低。',48,'全唐诗/poet.song.127000.json','["酒量愁翻減，詩聲老轉低。", "日高羮馬齒，霜冷駕雞栖。", "已判功名迕，寜論簿領迷。", "賴無權入手，軟弱實如泥。"]'),
('68424ffe-0cb6-4bca-b48f-2635f12e0ea8','九月三十日登城門東望悽然有感','陸游','宋','宋诗','song-poetry','','[]','減盡腰圍白盡頭，經年作客向夔州。',64,'全唐诗/poet.song.127000.json','["減盡腰圍白盡頭，經年作客向夔州。", "流離去國歸無日，瘴癘侵人病過秋。", "菊蕋殘時初把酒，雁行横處更登樓。", "蜀江朝暮東南注，我獨胡爲淹此留。"]'),
('1641e577-560d-4653-93cd-a7f46e0c21ed','初冬野興','陸游','宋','宋诗','song-poetry','','[]','關北關南霜露寒，瀼東瀼西山谷盤。',64,'全唐诗/poet.song.127000.json','["關北關南霜露寒，瀼東瀼西山谷盤。", "簟紋細細吹殘水，黿背時時出小灘。", "衰髮病來無復緑，寸心老去尚如丹。", "逆胡未滅時多事，却爲無才得少安。"]'),
('bd861905-2322-476b-b0a6-641d8794bd54','東屯呈同遊諸公','陸游','宋','宋诗','song-poetry','','[]','十月霜雕楓樹林，清溪白石稱幽尋。',64,'全唐诗/poet.song.127000.json','["十月霜雕楓樹林，清溪白石稱幽尋。", "按行老子誅茆地，惆悵孤臣許國心。", "走馬平沙嫌路近，傳杯小閣喜寒侵。", "也思試索梅花笑，凍蕊疏疏欲不禁。"]'),
('8dc4c37a-40db-4dcb-aa06-a9400fb62f2f','别王伯高','陸游','宋','宋诗','song-poetry','','[]','冷落何人肯見尋，斷弦塵匣愧知音。',64,'全唐诗/poet.song.127000.json','["冷落何人肯見尋，斷弦塵匣愧知音。", "傾家釀酒猶嫌少，入海求詩未厭深。", "薄宦簿書常衮衮，中年光景易駸駸。", "香匳贈别非無意，共約跏趺看此心。"]'),
('ca8251fe-19ac-42f2-bd41-69689290b30f','書驛壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','猿叫鋪前雪欲作，鬼門關頭路正惡。',64,'全唐诗/poet.song.127000.json','["猿叫鋪前雪欲作，鬼門關頭路正惡。", "泥深三尺馬蹄弱，霜厚一寸客衣薄。", "朝行過棧暮渡笮，夜投破驛火煜爚。", "人生但要無媿怍，萬里竄身元不錯。"]'),
('404ad5ad-1003-453a-914e-a17bac057984','書驛壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','峽中山多甲天下，萬嶂千峰通一罅。',64,'全唐诗/poet.song.127000.json','["峽中山多甲天下，萬嶂千峰通一罅。", "峒民無地習耕稼，射麋捕虎連晝夜。", "女兒薄命天不借，青燈獨宿江邊舍。", "黎明賣薪勿悲吒，女生豈有終不嫁。"]'),
('5ce214c1-7cb3-4b17-9e07-75b9bc0db218','醉中到白崖而歸','陸游','宋','宋诗','song-poetry','','[]','醉眼朦朧萬事空，今年痛飲瀼西東。',64,'全唐诗/poet.song.127000.json','["醉眼朦朧萬事空，今年痛飲瀼西東。", "偶呼快馬迎新月，却上輕輿御晚風。", "行路八千常是客，丈夫五十未稱翁。", "亂山缺處如横綫，遥指孤城翠靄中。"]'),
('0663756e-961f-480d-8d78-5b852249d812','十二月十九日晚巫山送客歸回望西寺小閣縹緲可愛遂與趙郭二教授同遊抵夜乃還楚鄉偶得長句呈二君','陸游','宋','宋诗','song-poetry','','[]','送客沙頭落日催，遥看重閣更同來。',64,'全唐诗/poet.song.127000.json','["送客沙頭落日催，遥看重閣更同來。", "清尊與悶都傾盡，倦馬和詩總勒回。", "憔悴遠遊悲騎省，豪華前事記章臺。", "歸時燈火參差晚，自脱征衣拂帽埃。"]'),
('5f85fafd-9922-4aa0-866b-885d8c3e1afa','飯三折鋪鋪在亂山中','陸游','宋','宋诗','song-poetry','','[]','平生愛山每自嘆，舉世但覺山可玩。',96,'全唐诗/poet.song.127000.json','["平生愛山每自嘆，舉世但覺山可玩。", "皇天憐之足其願，著在荒山更何怨。", "南窮閩粤西蜀漢，馬蹏幾歴天下半。", "山横水掩路欲斷，崔嵬可陟流可亂。", "春風桃李方漫漫，飛棧凌空又奇觀。", "但令身健能強飯，萬里只作遊山看。"]'),
('49aeb40a-8fa4-4dc2-8c7b-6cc411a76024','小市','陸游','宋','宋诗','song-poetry','','[]','小市門前沙作堤，杏花雖落不霑泥。',64,'全唐诗/poet.song.127000.json','["小市門前沙作堤，杏花雖落不霑泥。", "客心尚壯身先老，江水方東我獨西。", "蹔憩軒窗仍汛掃，遠遊書劍亦提攜。", "子規應笑飄零慣，故傍茆簷盡意啼。"]'),
('ad55c1e2-d95a-4180-bd9c-f27176797c43','酒無獨飲理','陸游','宋','宋诗','song-poetry','','[]','酒無獨飲理，常恨欠佳客。',96,'全唐诗/poet.song.127000.json','["酒無獨飲理，常恨欠佳客。", "忽得我輩人，豈計晨與夕。", "少年事虚名，歲月駒過隙。", "自從老大來，一日亦可惜。", "糟丘未易辦，小計且千石。", "頺然置萬事，天地爲幕帟。", "人生如刀礪，磨盡要有日。", "不須荷鍤隨，況問幾兩屐。"]'),
('87363b5f-7dca-4768-8d1e-f9af80a9ccaf','畏虎','陸游','宋','宋诗','song-poetry','','[]','滑路滑如苔，澀路澀若梯。',120,'全唐诗/poet.song.127000.json','["滑路滑如苔，澀路澀若梯。", "更堪都梁下，一雪三日泥。", "泥深尚云可，委身餓虎蹊。", "心寒道上迹，魄碎茆葉低。", "常恐不自免，一死均猪雞。", "老馬亦甚畏，愶愶不敢嘶。", "吾聞虎雖暴，未嘗窺汝棲。", "孤行暮不止，取禍非排擠。", "彼讒實有心，平地生溝谿。", "哀哉馬新息，薏苡成珠犀。"]'),
('8c12f15e-5550-460f-9dd5-38c4822b8c17','戲題','陸游','宋','宋诗','song-poetry','','[]','走馬平欺刺繡坡，放船横截亂絲渦。',32,'全唐诗/poet.song.127000.json','["走馬平欺刺繡坡，放船横截亂絲渦。", "從來倚箇心平穩，遇險方知得力多。"]'),
('967bbdb1-ca8e-4824-b409-d6992c974743','蟠龍瀑布','陸游','宋','宋诗','song-poetry','','[]','遠望紛珠纓，近觀轉雷霆。',96,'全唐诗/poet.song.127000.json','["遠望紛珠纓，近觀轉雷霆。", "人言水出奇，意使行人驚。", "人驚我何得，定非水之情。", "水亦有何情，因物以賦形。", "處高勢趨下，豈樂與石爭。", "退之亦隘人，強言不平鳴。", "古來賢達士，初亦願躬耕。", "意氣或感激，邂逅成功名。"]'),
('01171bc3-67fb-42c2-98fc-3760b754ddfe','題梁山軍瑞豐亭','陸游','宋','宋诗','song-poetry','','[]','我行都梁窘風雪，史君喜事能留客。',128,'全唐诗/poet.song.127000.json','["我行都梁窘風雪，史君喜事能留客。", "瑞豐亭上一尊酒，渺渺郊原水初白。", "峽中地褊常苦貧，政令愈簡民愈淳。", "本來無事只畏擾，擾者才吏非庸人。", "都梁之民獨無苦，須晴得晴雨得雨。", "史君心愛稼如雲，時上斯亭按歌舞。", "歌闌舞罷史君醉，父老羅拜豐年賜。", "聖朝尚實抑虚文，縱産芝房非上瑞。"]'),
('794ed05c-5dde-4f70-90ee-d6ac18af16e7','馬上','陸游','宋','宋诗','song-poetry','','[]','殘年流轉似萍根，馬上傷春易斷魂。',64,'全唐诗/poet.song.127000.json','["殘年流轉似萍根，馬上傷春易斷魂。", "烘暖花無經日蕊，漲深水過去年痕。", "迷行每問樵夫路，投宿時敲竹寺門。", "不信太平元有象，牛羊點點散烟村。"]'),
('14457bb5-fc3c-4b31-a1f2-573b11385008','鄰山縣道上作','陸游','宋','宋诗','song-poetry','','[]','微雨晴時出驛門，亂鶯啼處過江村。',64,'全唐诗/poet.song.127000.json','["微雨晴時出驛門，亂鶯啼處過江村。", "挽花醉袖霑餘馥，迎日征鞍借小温。", "客路一身真吊影，故園萬里欲招魂。", "鬢毛無色心猶壯，藉草悲歌對酒尊。"]'),
('8bfbaae2-6910-4b15-9de2-726b34851733','鄰水延福寺早行','陸游','宋','宋诗','song-poetry','','[]','化蝶方酣枕，聞雞又著鞭。',48,'全唐诗/poet.song.127000.json','["化蝶方酣枕，聞雞又著鞭。", "亂山徐吐日，積水遠生烟。", "淹泊真衰矣，登臨獨惘然。", "桃花應笑客，無酒到愁邊。"]'),
('9b2d2d78-c5d9-4633-a074-ce3f21ed75d2','岳池農家','陸游','宋','宋诗','song-poetry','','[]','春深農家耕未足，原頭叱叱兩黄犢。',128,'全唐诗/poet.song.127000.json','["春深農家耕未足，原頭叱叱兩黄犢。", "泥融無塊水初渾，雨細有痕秧正緑。", "緑秧分時風日美，時平未有差科起。", "買花西舍喜成婚，持酒東鄰賀生子。", "誰言農家不入時，小姑畫得城中眉。", "一雙素手無人識，空村相喚看繅絲。", "農家農家樂復樂，不比市朝爭奪惡。", "宦遊所得真幾何，我已三年廢東作。"]'),
('7f74edb4-c034-479d-a855-e0155bdaebec','過廣安吊張才叔諫議','陸游','宋','宋诗','song-poetry','','[]','春風疋馬過孤城，欲吊先賢涕已傾。',64,'全唐诗/poet.song.127000.json','["春風疋馬過孤城，欲吊先賢涕已傾。", "許國肺肝知激烈，照人眉宇尚崢嶸。", "中原成敗寜非數，後世忠邪自有評。", "嘆息知人真未易，流芳遺臭盡書生。"]'),
('bb11e8bd-c16f-41e7-b721-24ebd397b9f0','果州驛','陸游','宋','宋诗','song-poetry','','[]','驛前官路堠纍纍，嘆息何時送我歸。',64,'全唐诗/poet.song.127000.json','["驛前官路堠纍纍，嘆息何時送我歸。", "池館鶯花春漸老，窗扉燈火夜相依。", "孤鸞怯舞愁窺鏡，老馬貪行強受鞿。", "到處風塵常撲面，豈惟京洛化人衣。"]'),
('4c5e3dba-b839-4ba3-90fa-09bf7bd8e53d','留樊亭三日王覺民檢詳日攜酒來飲海棠下比去花亦衰矣二首  其一','陸游','宋','宋诗','song-poetry','','[]','留落猶能領物華，名園又作醉生涯。',32,'全唐诗/poet.song.127000.json','["留落猶能領物華，名園又作醉生涯。", "何妨海內功名士，共賞人間富貴花。"]'),
('42e41dbf-f4d4-42cc-aba4-b8214be3f1c4','留樊亭三日王覺民檢詳日攜酒來飲海棠下比去花亦衰矣二首  其二','陸游','宋','宋诗','song-poetry','','[]','石衛尉家錦步障，移在樊家園館中。',32,'全唐诗/poet.song.127000.json','["石衛尉家錦步障，移在樊家園館中。", "醉到花殘呼馬去，聊將俠氣壓春風。"]'),
('aa1f69ac-4ddc-4875-9c9c-92a1eb7f6372','柳林酒家小樓','陸游','宋','宋诗','song-poetry','','[]','桃花如燒酒如油，緩轡郊原當出遊。',64,'全唐诗/poet.song.127000.json','["桃花如燒酒如油，緩轡郊原當出遊。", "微倦放教成午夢，宿酲留得伴春愁。", "遠途始悟乾坤大，晚節偏驚歲月遒。", "記取晴明果州路，半天高柳小青樓。"]'),
('acdd1cc5-6bdc-4b2e-b9c1-08fe6dcb4b13','南池','陸游','宋','宋诗','song-poetry','','[]','二月鶯花滿閬中，城南搔首立衰翁。',64,'全唐诗/poet.song.127000.json','["二月鶯花滿閬中，城南搔首立衰翁。", "數莖白髮愁無那，萬頃蒼池事已空。", "陂復豈惟民食足，渠成終助霸圖雄。", "眼前碌碌誰知此，漫走樷祠乞歲豐。"]'),
('ea151b3a-676e-48d2-8c1d-87b0d8ef90bf','唐長慶中南池新亭碑在漢高帝廟側亭已失所在矣','陸游','宋','宋诗','song-poetry','','[]','池廢新亭亦已無，遺碑半滅臥春蕪。',32,'全唐诗/poet.song.127000.json','["池廢新亭亦已無，遺碑半滅臥春蕪。", "文章綺靡雖非古，今代詞人不辦渠。"]'),
('f2ba136f-a5a2-474c-8271-399e4cec2a1d','聞杜鵑戲作絕句','陸游','宋','宋诗','song-poetry','','[]','半世羈遊厭路岐，憑鞍日日數歸期。',32,'全唐诗/poet.song.127000.json','["半世羈遊厭路岐，憑鞍日日數歸期。", "勞君樹杪丁寜語，似勸饑人食肉糜。"]'),
('40582873-9ca0-4489-b89b-e93c054c2dea','鼓樓鋪醉歌','陸游','宋','宋诗','song-poetry','','[]','書生迫饑寒，一飽輕三巴。',132,'全唐诗/poet.song.127000.json','["書生迫饑寒，一飽輕三巴。", "三巴未云已，北首趨褒斜。", "匆匆出門去，裘馬不復華。", "短帽障赤日，烈風吹黄沙。", "俶裝先晨雞，投鞭後昏鴉。", "壯哉利閬間，崖谷何谽谺。", "地荒多牧卒，往往聞蘆笳。", "我行春未動，原野今無花。", "稚子入旅夢，挽鬚勸還家。", "起坐不能寐，愁腸如轉車。", "四方丈夫事，行矣勿咨嗟。"]'),
('e5ac6ee2-ed21-409c-94ae-5548f27dd2af','登慧照寺小閣','陸游','宋','宋诗','song-poetry','','[]','少年富貴已悠悠，老大功名定有不。',64,'全唐诗/poet.song.127000.json','["少年富貴已悠悠，老大功名定有不。", "歲月消磨閲亭傳，山川遼邈弊衣裘。", "殺身有地初非惜，報國無時未免愁。", "局促每思舒望眼，雖非吾土強登樓。"]'),
('67421347-93d9-4b0e-a664-b7119e7959fb','春雨','陸游','宋','宋诗','song-poetry','','[]','江頭一夜雨，曉路無新花。',48,'全唐诗/poet.song.127000.json','["江頭一夜雨，曉路無新花。", "我今爲陳人，感此重嘆嗟。", "羲和挾兩曜，疾走不可遮。", "古今俛仰間，那暇惜物華。"]'),
('8d20eb81-b5e8-494c-baf0-d27c0b88ff2d','風雨中過龍洞閣','陸游','宋','宋诗','song-poetry','','[]','飄然醉袖怒人扶，箇裏何曾有畏塗。',64,'全唐诗/poet.song.127000.json','["飄然醉袖怒人扶，箇裏何曾有畏塗。", "卷地黑風吹慘澹，半天朱閣插虚無。", "闌邊歸鶴如爭捷，雲表飛仙定可呼。", "莫怪衰翁心膽壯，此身元是一枯株。"]'),
('e6b6a979-4b51-43e4-ace7-6348c8abb5a8','驛舍海棠已過有感','陸游','宋','宋诗','song-poetry','','[]','凄涼古驛官道傍，朱門沈沈春日長。',96,'全唐诗/poet.song.127000.json','["凄涼古驛官道傍，朱門沈沈春日長。", "暄妍光景老海棠，顛風吹花滿空廊。", "物生榮顇固其常，惜哉無與持一觴。", "遊蜂戲蝶空自忙，豈知美人在西廂。", "我雖已老猶能狂，竚立爲爾悲容光。", "盛時不遇誠可傷，零落逢知更斷腸。"]'),
('731303fe-f4d9-4485-84eb-4b5a33656e8d','籌筆驛','陸游','宋','宋诗','song-poetry','','[]','運籌陳迹故依然，想見旌旗駐道邊。',32,'全唐诗/poet.song.127000.json','["運籌陳迹故依然，想見旌旗駐道邊。", "一等人間管城子，不堪譙叟作降牋。"]'),
('ee5875e0-1be3-4b64-9fed-85782cbd4305','嘉川鋪遇小雨景物尤奇','陸游','宋','宋诗','song-poetry','','[]','一春客路厭風埃，小雨山行亦樂哉。',64,'全唐诗/poet.song.127000.json','["一春客路厭風埃，小雨山行亦樂哉。", "危棧巧依青嶂出，飛花併下緑巖來。", "面前雲氣翔孤鳯，脚底江聲轉疾雷。", "堪笑書生輕性命，每逢險處更徘徊。"]'),
('8787a316-b1c6-4803-b37f-938ee4a481a4','老君洞','陸游','宋','宋诗','song-poetry','','[]','丹鳯樓頭語未終，崎嶇蜀道復相逢。',32,'全唐诗/poet.song.127000.json','["丹鳯樓頭語未終，崎嶇蜀道復相逢。", "太清宫闕俱煨燼，豈亦南來避賊鋒。"]'),
('d1bc056a-3fd0-41df-adb8-0cf4dd56136d','大安病酒留半日王守復來招不往送酒解酲因小飲江月館','陸游','宋','宋诗','song-poetry','','[]','江驛春酲半日留，更煩送酒爲扶頭。',32,'全唐诗/poet.song.127000.json','["江驛春酲半日留，更煩送酒爲扶頭。", "柳花漠漠嘉陵岸，别是天涯一段愁。"]'),
('94c4456d-9590-4464-9987-a175fc3ff6da','金牛道中遇寒食','陸游','宋','宋诗','song-poetry','','[]','乍换春衫一倍輕，況逢寒食十分晴。',64,'全唐诗/poet.song.127000.json','["乍换春衫一倍輕，況逢寒食十分晴。", "鶯穿驛樹惺愡語，馬過溪橋蹀躞行。", "畫柱綵繩喧笑樂，豔粧麗服角鮮明。", "誰知此日金牛道，非復當時鐵馬聲。"]'),
('05e0f070-5338-4542-8caa-def84fde7d13','曉發金牛','陸游','宋','宋诗','song-poetry','','[]','客枕何時穏，匆匆又束裝。',48,'全唐诗/poet.song.127000.json','["客枕何時穏，匆匆又束裝。", "快晴生馬影，新暖坼花房。", "沮水春流緑，嶓山曉色蒼。", "阿瞞狼狽地，千古有遺傷。"]'),
('a0bcd6e5-94f6-4b8b-af0a-bb555d69ea05','山南行','陸游','宋','宋诗','song-poetry','','[]','我行山南已三日，如繩大路東西出。',128,'全唐诗/poet.song.127000.json','["我行山南已三日，如繩大路東西出。", "平川沃野望不盡，麥隴青青桑鬱鬱。", "地近函秦氣俗豪，鞦韆蹴鞠分朋曹。", "苜蓿連雲馬蹄健，楊柳夾道車聲高。", "古來歴歴興亡處，舉目山川尚如故。", "將軍壇上冷雲低，丞相祠前春日暮。", "國家四紀失中原，師出江淮未易吞。", "會看金鼓從天下，却用關中作本根。"]'),
('8eed3f53-e210-4f53-b311-3de5b2448f0e','南鄭馬上作','陸游','宋','宋诗','song-poetry','','[]','南鄭春殘信馬行，通都氣象尚崢嶸。',64,'全唐诗/poet.song.127000.json','["南鄭春殘信馬行，通都氣象尚崢嶸。", "迷空遊絮憑陵去，曵綫飛鳶跋扈鳴。", "落日斷雲唐闕廢，淡烟芳草漢壇平。", "猶嫌未豁胸中氣，目斷南山天際横。"]'),
('4ab097ce-26cb-4f58-9391-cc32ac597305','和高子長參議道中二絕  其一','陸游','宋','宋诗','song-poetry','','[]','梁州四月晚鶯啼，共憶扁舟罨畫谿。',32,'全唐诗/poet.song.127000.json','["梁州四月晚鶯啼，共憶扁舟罨畫谿。", "莫作世間兒女態，明年萬里駐安西。"]'),
('0934e37c-ea77-43d5-898e-afb941e73c11','和高子長參議道中二絕  其二','陸游','宋','宋诗','song-poetry','','[]','豐年食少厭兒啼，覓得微官落五谿。',32,'全唐诗/poet.song.127000.json','["豐年食少厭兒啼，覓得微官落五谿。", "大似無家老禪衲，打包還度棧雲西。"]'),
('863a8ee3-1bc8-4798-aec8-164847935189','次韵張季長題龍洞','陸游','宋','宋诗','song-poetry','','[]','我昔謁紫皇，翳鳯驂虬龍。',120,'全唐诗/poet.song.127000.json','["我昔謁紫皇，翳鳯驂虬龍。", "俯不見塵世，浩浩萬里空。", "謫墮尚遠遊，忽到漢始封。", "西望接蜀道，北顧連秦中。", "壯哉形勝區，有此蜿蜒宫。", "雷霆自鞺鞳，環玦亦璁瓏。", "石屋如建章，萬户交相通。", "來者各有得，盡取知無從。", "憑高三嘆息，自古幾英雄。", "老我文字衰，揮毫看諸公。"]'),
('3ccfbf89-6d5e-475f-aaa3-4ca6873bad7b','次韵子長題吳太尉雲山亭','陸游','宋','宋诗','song-poetry','','[]','參謀健筆落縱横，太尉清罇賞快晴。',32,'全唐诗/poet.song.127000.json','["參謀健筆落縱横，太尉清罇賞快晴。", "文雅風流雖可愛，關中遺虜要人平。"]'),
('bd71c4e1-c739-42a5-b30e-e64a6a719670','送劉戒之東歸','陸游','宋','宋诗','song-poetry','','[]','去國三年恨未平，東城況復送君行。',64,'全唐诗/poet.song.127000.json','["去國三年恨未平，東城況復送君行。", "難憑魂夢尋言笑，空向除書見姓名。", "殘日半竿斜谷路，西風萬里玉關情。", "蘭臺粉署朝回晚，肻記麤官數寄聲。"]'),
('468ab110-c965-4c69-baff-964c3e9bed72','周元吉蟠室詩','陸游','宋','宋诗','song-poetry','','[]','天下有廣居，非阿房建章。',144,'全唐诗/poet.song.127000.json','["天下有廣居，非阿房建章。", "賔餞日及月，闔闢陰與陽。", "山川坦然平，何者爲藩牆。", "孔公暨瞿聃，同坐此道塲。", "哀哉世日隘，肝膽分界疆。", "蹙縮戰蝸角，崎嶇走羊腸。", "周先早得道，所證非復常。", "小室古城隅，宛如野僧房。", "能容人天衆，雜沓來燒香。", "三萬二千人，各據獅子床。", "實際正如此，切忌錯商量。", "須彌芥子話，今夕當舉揚。"]'),
('bae1260e-dea0-4af6-80e6-5acee16fc8c5','送范西叔赴召二首  其一','陸游','宋','宋诗','song-poetry','','[]','天涯流落過重陽，楓葉揺丹已著霜。',64,'全唐诗/poet.song.127000.json','["天涯流落過重陽，楓葉揺丹已著霜。", "衰病強陪蓮幕客，凄涼又送石渠郎。", "杜陵雁下悲徂歲，笠澤魚肥夢故鄉。", "便恐從今長隔濶，舊交新貴例相忘。"]'),
('731e1307-3b7f-402a-8faf-875133798483','送范西叔赴召二首  其二','陸游','宋','宋诗','song-poetry','','[]','欲駕征車勸小留，南山南畔更逢秋。',64,'全唐诗/poet.song.127000.json','["欲駕征車勸小留，南山南畔更逢秋。", "數聲過雁催行色，一醆昏燈話别愁。", "自昔文章關治道，即今臺閣要名流。", "白頭尚作書癡在，剩乞朱黄與校讐。"]'),
('b6dd1b0b-64ea-4b7b-8a23-e5551e29ba27','寄鄧公壽','陸游','宋','宋诗','song-poetry','','[]','高標瑶樹與瓊林，靈府清寒出苦吟。',64,'全唐诗/poet.song.127000.json','["高標瑶樹與瓊林，靈府清寒出苦吟。", "海內十年求識面，江邊一見即論心。", "紛紛俗子常成市，亹亹微言孰賞音。", "聞道南池梅最早，要君攜手試同尋。"]'),
('a29a71f8-a02f-4ea3-9341-4cbd36eb051e','簡章德茂','陸游','宋','宋诗','song-poetry','','[]','殊方邂逅豈無緣，世事多乖復悵然。',64,'全唐诗/poet.song.127000.json','["殊方邂逅豈無緣，世事多乖復悵然。", "造物無情吾輩老，古人不死此心傳。", "冷雲黯黯朝横棧，紅葉蕭蕭夜滿船。", "箇裏約君同著句，不應輸與灞橋邊。"]'),
('f24d08fe-48ff-44b8-a720-1980fb30b489','自三泉泛嘉陵至利州','陸游','宋','宋诗','song-poetry','','[]','日日邅途處處詩，書生活計絕堪悲。',32,'全唐诗/poet.song.127000.json','["日日邅途處處詩，書生活計絕堪悲。", "江雲垂地灘風急，一似前年上硤時。"]'),
('436733ee-e28c-4e50-b17b-fae8cbc58910','木瓜鋪短歌','陸游','宋','宋诗','song-poetry','','[]','鼓樓坡前木瓜鋪，歲晚悲辛利州路。',160,'全唐诗/poet.song.127000.json','["鼓樓坡前木瓜鋪，歲晚悲辛利州路。", "當車礧礧石如屋，百里夷途無十步。", "溪橋缺斷水齧沙，崖腹崩頺風拔樹。", "虎狼妥尾擇肉食，狐狸竪毛啼日莫。", "冢丘短草聲窸窣，往往精靈與人遇。", "我生胡爲忽在此，正坐一饑忘百慮。", "五更出門寒裂面，半夜燎衣泥滿袴。", "妻孥八月離夔州，寄書未到今何處。", "餘年有幾百憂集，日夜朱顔不如故。", "即今臺省盛諸賢，細思寜是儒冠誤。"]'),
('82b5eb2e-0433-40a5-ab98-f8e03870b28a','夜抵葭萌惠照寺寓榻小閣','陸游','宋','宋诗','song-poetry','','[]','亭驛驅馳髀肉消，故山歸夢愈迢迢。',64,'全唐诗/poet.song.127000.json','["亭驛驅馳髀肉消，故山歸夢愈迢迢。", "夜行觸尉那能避，旦過隨僧不待招。", "雨後風雲猶慘澹，霜前草木已蕭條。", "衰遲事事非平日，醉裏題詩亦復聊。"]'),
('fa10f71f-cfdc-4864-9709-d02905dfcade','太息二首  其一','陸游','宋','宋诗','song-poetry','','[]','太息重太息，吾行無終極。',108,'全唐诗/poet.song.127000.json','["太息重太息，吾行無終極。", "冰霜迫殘歲，鳥獸號落日。", "秋砧滿孤村，枯葉擁破驛。", "白頭鄉萬里，墮此虎豹宅。", "道邊新食人，膏血染草棘。", "平生鐵石心，忘家思報國。", "即今冒九死，家國兩無益。", "中原久喪亂，志士泪横臆。", "切勿輕書生，上馬能擊賊。"]'),
('a0a64cd9-65fa-4ea9-ba4c-f3c5bd94d017','太息二首  其二','陸游','宋','宋诗','song-poetry','','[]','凄凄復凄凄，山路窮攀躋。',108,'全唐诗/poet.song.127000.json','["凄凄復凄凄，山路窮攀躋。", "僕病臥草間，馬困聲酸嘶。", "脱兔截道奔，窮狖上樹啼。", "崩湍一何哀，下落萬仞谿。", "昏黑投孤戍，洗我衣上泥。", "下愚不可遷，大惑終身迷。", "仕宦十五年，曾不飽糠粞。", "客路少睡眠，月白聞號雞。", "欲行且復止，虎來茆葉低。"]'),
('181ff947-2fd6-46b5-bf41-260e333e0594','閬中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','殘年作客遍天涯，下馬長亭便似家。',64,'全唐诗/poet.song.127000.json','["殘年作客遍天涯，下馬長亭便似家。", "三疊凄涼渭城曲，數枝閑澹閬中花。", "襞牋授管相逢晚，理鬢熏衣一笑譁。", "俱是邯鄲枕中夢，墜鞭不用憶京華。"]'),
('c271038e-2232-4602-b527-10c7279983ac','閬中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','挽住征衣爲濯塵，閬州齋釀絕芳醇。',64,'全唐诗/poet.song.127000.json','["挽住征衣爲濯塵，閬州齋釀絕芳醇。", "鶯花舊識非生客，山水曾遊是故人。", "遨樂無時冠巴蜀，語音漸正带咸秦。", "平生賸有尋梅債，作意城南看小春。"]'),
('8b8c9ed6-d4e7-4429-88a0-d045e7e6dbad','遊錦屏山謁少陵祠堂','陸游','宋','宋诗','song-poetry','','[]','城中飛閣連危亭，處處軒窗臨錦屏。',128,'全唐诗/poet.song.127000.json','["城中飛閣連危亭，處處軒窗臨錦屏。", "涉江親到錦屏上，却望城郭如丹青。", "虚堂奉祠子杜子，眉宇高寒照江水。", "古來磨滅知幾人，此老至今元不死。", "山川寂寞客子迷，草木揺落壯士悲。", "文章垂世自一事，忠義凛凛令人思。", "夜歸沙頭雨如注，北風吹船横半渡。", "亦知此老憤未平，萬竅爭號泄悲怒。"]'),
('ac31ddd9-ef9a-4314-bca4-ec8569943555','仙魚鋪得仲高兄書','陸游','宋','宋诗','song-poetry','','[]','病酒今朝載臥輿，秋雲漠漠雨疏疏。',32,'全唐诗/poet.song.127000.json','["病酒今朝載臥輿，秋雲漠漠雨疏疏。", "閬州城北仙魚鋪，忽得山陰萬里書。"]'),
('ef75a087-7112-41f5-b921-4eb0e2e0f8fd','自閬復還漢中次益昌','陸游','宋','宋诗','song-poetry','','[]','北首褒斜又幾程，驕雲未放十分晴。',64,'全唐诗/poet.song.127000.json','["北首褒斜又幾程，驕雲未放十分晴。", "馬經斷棧危無路，風掠枯茆颯有聲。", "季子貂裘端已弊，吳中菰菜正堪烹。", "朱顔漸改功名晚，擊筑悲歌一再行。"]'),
('31513dc4-82bb-4562-9105-1309cb279743','驛亭小憩遣興','陸游','宋','宋诗','song-poetry','','[]','淡日微雲共陸離，曲闌危棧出參差。',64,'全唐诗/poet.song.127000.json','["淡日微雲共陸離，曲闌危棧出參差。", "老松臨道閲千載，杜宇號山連四時。", "漢水東流那有極，秦關北望不勝悲。", "郵亭下馬開孤劍，老大功名頗自期。"]'),
('f9259f31-5015-4fb7-b745-6eab09fa7a6f','再過龍洞閣','陸游','宋','宋诗','song-poetry','','[]','天險龍門道，霜清客子遊。',48,'全唐诗/poet.song.127000.json','["天險龍門道，霜清客子遊。", "一笻緣絕壁，萬仞俯洪流。", "著脚初疑夢，回頭始欲愁。", "危身無補國，忠孝兩堪羞。"]'),
('d7737476-a826-496f-bbfd-6e37fbbc3b9a','自笑','陸游','宋','宋诗','song-poetry','','[]','自笑謀生事事疏，年來錐與地俱無。',64,'全唐诗/poet.song.127000.json','["自笑謀生事事疏，年來錐與地俱無。", "平章春韭秋菘味，拆補天吳紫鳯圖。", "食肉定知無骨相，珥貂空自誑頭顱。", "惟餘數卷殘書在，破篋蕭然笑獠奴。"]'),
('93d1eaff-80c6-4574-881b-5f0e07dc9c16','三泉驛舍','陸游','宋','宋诗','song-poetry','','[]','殘鐘斷角度黄昏，小驛孤燈早閉門。',64,'全唐诗/poet.song.127000.json','["殘鐘斷角度黄昏，小驛孤燈早閉門。", "霜氣峭深摧草木，風聲浩蕩卷郊原。", "故山有約頻回首，末路無歸易斷魂。", "短鬢蕭蕭不禁白，強排幽恨近清罇。"]'),
('a650e9cd-d1d0-4c26-9c91-96acc3ed1872','嘉川鋪得檄遂行中夜次小柏','陸游','宋','宋诗','song-poetry','','[]','黄旗傳檄趣歸程，急服單裝破夜行。',64,'全唐诗/poet.song.127000.json','["黄旗傳檄趣歸程，急服單裝破夜行。", "肅肅霜飛當十月，離離斗轉欲三更。", "酒消頓覺衣裘薄，驛近先看炬火迎。", "渭水函關元不遠，著鞭無日涕空横。"]'),
('dc3b8e15-ceef-4cb1-8ebc-cfaab4a7e994','歸次漢中境上','陸游','宋','宋诗','song-poetry','','[]','雲棧屏山閲月遊，馬蹄初喜蹋梁州。',64,'全唐诗/poet.song.127000.json','["雲棧屏山閲月遊，馬蹄初喜蹋梁州。", "地連秦雍川原壯，水下荆楊日夜流。", "遺虜孱孱寜遠略，孤臣耿耿獨私憂。", "良時恐作他年恨，大散關頭又一秋。"]'),
('47f188a4-466a-48a2-9a9b-1042cae84fa2','沔陽夜行','陸游','宋','宋诗','song-poetry','','[]','夜發沔陽驛，坡陁岡阜重。',48,'全唐诗/poet.song.127000.json','["夜發沔陽驛，坡陁岡阜重。", "月斜欹帽影，霜重濕裘茸。", "野岸鳴枯葉，烟林度曉鐘。", "梁州明日到，一笑解衰容。"]'),
('a3ec8b1a-d3f9-4529-a38c-302969c72673','道中累日不肉食至西縣市中得羊因小酌','陸游','宋','宋诗','song-poetry','','[]','門外倚車轅，頺然就醉昏。',48,'全唐诗/poet.song.127000.json','["門外倚車轅，頺然就醉昏。", "棧餘羊絕美，壓近酒微渾。", "一洗窮邊恨，重招去國魂。", "客中無晤語，燈燼爲誰繁。"]'),
('342b17d7-c01f-4730-9140-e7295de5e97d','初離興元','陸游','宋','宋诗','song-poetry','','[]','夢裏何曾有去來，高城無奈角聲哀。',64,'全唐诗/poet.song.127000.json','["夢裏何曾有去來，高城無奈角聲哀。", "連林秋葉吹初盡，滿路寒泥蹋欲開。", "笠澤決歸猶小憩，錦城未到莫輕回。", "炊菰斫膾明年事，却憶斯遊亦壯哉。"]'),
('9a80ad81-6b8d-4847-8f30-52c997b5475a','自興元赴官成都','陸游','宋','宋诗','song-poetry','','[]','平生無遠謀，一飽百念已。',96,'全唐诗/poet.song.127000.json','["平生無遠謀，一飽百念已。", "造物戲饑之，聊遣行萬里。", "梁州在何處，飛蓬起孤壘。", "憑高望杜陵，烟樹略可指。", "今朝忽夢破，跋馬臨漾水。", "此生均是客，處處皆可死。", "劍南亦何好，小憩聊爾爾。", "舟車有通塗，吾行良未止。"]'),
('9d903238-60d8-471c-b1e4-51005e23a0a0','書事','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','生長江湖狎釣船，跨鞍塞上亦前緣。',64,'全唐诗/poet.song.127000.json','["生長江湖狎釣船，跨鞍塞上亦前緣。", "雲埋廢苑呼鷹處，雪暗荒郊射虎天。", "醪酒芳醇偏易醉，胡羊肥美了無羶。", "楊州雖有東歸日，閉置車中定悵然。"]'),
('b3c07fbf-4f2b-42a6-b5ad-2ab117298837','雨中過臨溪古堠','陸游','宋','宋诗','song-poetry','','[]','道邊相送驛邊迎，水隔山遮似有情。',32,'全唐诗/poet.song.127000.json','["道邊相送驛邊迎，水隔山遮似有情。", "歲晚無聊莫相笑，君方雨立我泥行。"]'),
('684d0c6c-323d-4c37-8a83-8a24e81c531f','南沮水道中','陸游','宋','宋诗','song-poetry','','[]','磑舍臨湍瀨，罾船聚小潭。',48,'全唐诗/poet.song.127000.json','["磑舍臨湍瀨，罾船聚小潭。", "山形寒漸瘦，雪意暮方酣。", "久客情懷惡，頻來道路諳。", "家山空悵望，無夢到江南。"]'),
('030663af-a0ea-42c6-be1d-da1e4875c974','長木晚興','陸游','宋','宋诗','song-poetry','','[]','沮水嶓山名古今，聊將行役當登臨。',64,'全唐诗/poet.song.127000.json','["沮水嶓山名古今，聊將行役當登臨。", "斷橋烟雨梅花瘦，絕磵風霜槲葉深。", "末路清愁常衮衮，殘冬急景易駸駸。", "故巢東望知何處，空羨歸鴉解滿林。"]'),
('a09243f3-3168-4dbf-b383-28d31b281bf0','遣興','陸游','宋','宋诗','song-poetry','','[]','貂裘破弊色凄涼，塞上歸來路更長。',64,'全唐诗/poet.song.127000.json','["貂裘破弊色凄涼，塞上歸來路更長。", "老驥嘶鳴常伏櫪，寒龜藏縮正支床。", "雕零客路新霜鬢，掃灑先師舊草堂。", "九折阪頭休絕嘆，世間何地不羊腸。"]'),
('585dc329-1d4e-48ed-b7e4-129b8eb47ccb','長木夜行抵金堆市','陸游','宋','宋诗','song-poetry','','[]','夜行長木村，重霧雜零雨。',96,'全唐诗/poet.song.127000.json','["夜行長木村，重霧雜零雨。", "濕螢粘野蔓，寒犬吠雲塢。", "道壞交細泉，亭廢立遺堵。", "時時過農家，燈火照鳴杼。", "嗟予獨何事，無歲得安處。", "即今窮谷中，性命寄豺虎。", "三更投小市，買酒慰羈旅。", "高詠東山詩，悵望懷往古。"]'),
('7c83d069-a0fc-4e5b-a3d2-d45207a25520','赴成都泛舟自三泉至益昌謀以明年下三峽','陸游','宋','宋诗','song-poetry','','[]','詩酒清狂二十年，又摩病眼看西川。',64,'全唐诗/poet.song.127000.json','["詩酒清狂二十年，又摩病眼看西川。", "心如老驥常千里，身似春蠶已再眠。", "暮雪烏奴停醉帽，秋風白帝放歸船。", "飄零自是關天命，錯被人呼作地仙。"]'),
('4f3f5a96-c067-4064-ad66-6def966985df','壬辰十月十三日自閬中還興元遊三泉龍門十一月二日自興元適成都復攜兒曹往遊賦詩','陸游','宋','宋诗','song-poetry','','[]','勝地惜輕别，短笻成後遊。',96,'全唐诗/poet.song.127000.json','["勝地惜輕别，短笻成後遊。", "門呀一境異，木落四山秋。", "野鴿翔深竇，蟠蛟擅古湫。", "棧危縈峭壁，橋逈跨奔流。", "白雨穿林至，腥風卷地浮。", "真成起衰病，不但洗孤愁。", "登陟知難再，吟哦爲小留。", "回頭即萬里，雪滿戴谿舟。"]'),
('4e4229da-dd7f-41d3-9180-c99e45316f28','予行蜀漢間道出潭毒關下每憩羅漢院山光軒今復過之悵然有感','陸游','宋','宋诗','song-poetry','','[]','山光軒上幾閑遊，潭毒關前又小留。',64,'全唐诗/poet.song.127000.json','["山光軒上幾閑遊，潭毒關前又小留。", "麥隴雪苗寒剡剡，柘林風葉莫颼颼。", "馬行劍閣從今始，門泊吳船亦已謀。", "醉眼每嫌天地迮，盡將萬里著吾愁。"]'),
('f7b0a8a3-8151-4e71-902b-160bc640c296','棧路書事','陸游','宋','宋诗','song-poetry','','[]','危閣聞鈴馱，湍流見磑船。',48,'全唐诗/poet.song.127000.json','["危閣聞鈴馱，湍流見磑船。", "汲江人負盎，騎馬客蒙氊。", "梨美來秦地，橙香接楚天。", "癡頑殊耐事，隨處一欣然。"]'),
('db916d33-a925-4a57-9072-1239b0cef17a','雪晴行益昌道中頗有春意','陸游','宋','宋诗','song-poetry','','[]','杜陵雁下歲將殘，疋馬西遊雪擁關。',64,'全唐诗/poet.song.127000.json','["杜陵雁下歲將殘，疋馬西遊雪擁關。", "憔悴敢忘雙闕路，淹遲遍看兩川山。", "春回柳眼梅鬚裏，愁在鞭絲帽影間。", "安得黄金成大藥，爲人千載駐頺顔。"]'),
('f5864887-00d2-42fd-aa3c-2e1615ec37f9','思歸引','陸游','宋','宋诗','song-poetry','','[]','善泅不如穩乘舟，善騎不如謹持轡。',146,'全唐诗/poet.song.127000.json','["善泅不如穩乘舟，善騎不如謹持轡。", "妙於服食不如寡欲，工於揣摩不如省事。", "在天有命誰得逃，在我無求直差易。", "散人家風脫糾纏，烟蓑雨笠全其天。", "蒓絲老盡歸不得，但坐長饑須俸錢。", "此身不堪阿堵役，寜待秋風始投檄。", "山林聊復取熊掌，仕宦真當棄雞肋。", "錦城小憩不淹遲，即是輕舠下硤時。", "那用更爲麟閣夢，從今正有鹿門期。"]'),
('15daae3f-0e71-40f0-8af5-7711f8635b77','誌公院在劍門東五里院東石壁間有若僧負杖者杖端髣髴有刀尺拂子之狀','陸游','宋','宋诗','song-poetry','','[]','江東爭奪纏妖祲，哀哉斯民亂方甚。',96,'全唐诗/poet.song.127000.json','["江東爭奪纏妖祲，哀哉斯民亂方甚。", "錦幪老人蓋古佛，現身爲作大慈蔭。", "蕭翁八十尚兒癡，旛蓋鍾螺閙中禁。", "當時此老黙笑渠，大法棟梁身獨任。", "杖頭示人三轉語，開口喪身如飲鴆。", "紛紛放弑但可憐，何曾爲汝陳符讖。"]'),
('e3968594-3315-41a9-9c79-bc08107019a0','劍門道中遇微雨','陸游','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u6292\u6000", "\u96e8", "\u5b8b\u8bd7"]','衣上征塵雜酒痕，遠遊無處不消魂。',32,'全唐诗/poet.song.127000.json','["衣上征塵雜酒痕，遠遊無處不消魂。", "此身合是詩人未，細雨騎驢入劍門。"]'),
('d69f04e4-4a56-4fb1-b81c-da3f7c9c7f3e','劍門關','陸游','宋','宋诗','song-poetry','','[]','劍門天設險，北鄉控函秦。',48,'全唐诗/poet.song.127000.json','["劍門天設險，北鄉控函秦。", "客主固殊勢，存亡終在人。", "棧雲寒欲雨，關柳暗知春。", "羈客垂垂老，憑高一愴神。"]'),
('bb9c5616-6ea5-4f40-8419-a2787ebd8965','劍門城北回望劍關諸峰青入雲漢感蜀亡事慨然有賦','陸游','宋','宋诗','song-poetry','','[]','自昔英雄有屈信，危機變化亦逡巡。',32,'全唐诗/poet.song.127000.json','["自昔英雄有屈信，危機變化亦逡巡。", "陰平窮宼非難禦，如此江山坐付人。"]'),
('fd2b306d-56ff-4267-a42f-9cb85d9a73a4','丹芝行','陸游','宋','宋诗','song-poetry','','[]','劍山峨峨插穹蒼，千林萬谷蟠其陽。',64,'全唐诗/poet.song.127000.json','["劍山峨峨插穹蒼，千林萬谷蟠其陽。", "大丹九轉古所藏，靈芝三秀夜吐光。", "如火非火森有芒，朝陽欲升尚煌煌。", "何由劚取换肝腸，往駕素虬朝紫皇。"]'),
('787ac2a8-f7e8-4836-bb0f-58ea85924aaf','過武連縣北柳池安國院煮泉試日鑄顧渚茶院有二泉皆甘寒傳云唐僖宗幸蜀在道不豫至此飲泉而愈賜名報國靈泉云三首  其一','陸游','宋','宋诗','song-poetry','','[]','滴瀝珠璣翠壁間，遭時曾得奉龍顔。',32,'全唐诗/poet.song.127000.json','["滴瀝珠璣翠壁間，遭時曾得奉龍顔。", "欄傾甃缺無人管，滿院松風晝掩關。"]'),
('78335ed7-4169-44e8-8f4b-9efb73348e52','過武連縣北柳池安國院煮泉試日鑄顧渚茶院有二泉皆甘寒傳云唐僖宗幸蜀在道不豫至此飲泉而愈賜名報國靈泉云三首  其二','陸游','宋','宋诗','song-poetry','','[]','行殿凄涼迹已陳，至今父老記南巡。',32,'全唐诗/poet.song.127000.json','["行殿凄涼迹已陳，至今父老記南巡。", "一泓寒碧無今古，付與閑人作主人。"]'),
('642a3815-50a1-4b8d-b22f-5b0c63b8a049','過武連縣北柳池安國院煮泉試日鑄顧渚茶院有二泉皆甘寒傳云唐僖宗幸蜀在道不豫至此飲泉而愈賜名報國靈泉云三首  其三','陸游','宋','宋诗','song-poetry','','[]','我是江南桑苧家，汲泉閑品故園茶。',32,'全唐诗/poet.song.127000.json','["我是江南桑苧家，汲泉閑品故園茶。", "只應碧缶蒼鷹爪，可壓紅囊白雪芽。"]'),
('087a8c0f-3936-4e5e-96ef-76a1dcd007b4','宿武連縣驛','陸游','宋','宋诗','song-poetry','','[]','平日功名浪自期，頭顱到此不難知。',64,'全唐诗/poet.song.127000.json','["平日功名浪自期，頭顱到此不難知。", "宦情薄似秋蟬翼，鄉思多於春繭絲。", "野店風霜俶裝早，縣橋燈火下程遲。", "鞭寒熨手戎衣窄，忽憶南山射虎時。"]'),
('8d7243d5-6ee2-4d40-9b03-1df7ed88f6b6','初入西州境述懷','陸游','宋','宋诗','song-poetry','','[]','我無飛仙術，御氣周八極。',192,'全唐诗/poet.song.127000.json','["我無飛仙術，御氣周八極。", "寸步常依人，艱哉萬里役。", "自行劍關南，大道平如席。", "日高徐駕車，薄暮亦兩驛。", "及兹山愈遠，原野若加闢。", "茂樹冬不凋，寒花晚猶拆。", "昔我卜遠遊，至蜀龜輒食。", "弛裝有定處，嗚呼豈人力。", "頗傳岷山下，清淑無癘疫。", "士風尚豪舉，意氣喜遠客。", "薪米家可求，借書亦易得。", "思吳雖不忘，所願少休息。", "吾聞右達人，雅志在山澤。", "豈無及物心，但恨俗褊迫。", "攬德雖成留，引去常勇決。", "駭機滿人間，著脚無上策。"]'),
('236196a4-4901-4d0d-abdf-b33b1b47c752','綿州魏成縣驛有羅江東詩云芳草有情皆礙馬好雲無處不遮樓戲用其韵','陸游','宋','宋诗','song-poetry','','[]','老夫乘興忽西遊，遠跨秦吳萬里秋。',64,'全唐诗/poet.song.127000.json','["老夫乘興忽西遊，遠跨秦吳萬里秋。", "尊酒登臨遍山寺，歌辭散落滿江樓。", "孤城木葉蕭蕭下，古驛灘聲㶁㶁流。", "未許詩人誇此地，茂林修竹憶吾州。"]'),
('44d6d927-bf11-408a-8e2e-bae48d6abc12','即事','陸游','宋','宋诗','song-poetry','','[]','渭水岐山不出兵，却攜琴劍錦官城。',64,'全唐诗/poet.song.127000.json','["渭水岐山不出兵，却攜琴劍錦官城。", "醉來身外窮通小，老去人間毁譽輕。", "捫蝨雄豪空自許，屠龍工巧竟何成。", "雅聞岷下多區芋，聊試寒爐玉糝羮。"]'),
('2d82e679-00ad-4122-b056-78db3e2a2da1','青村寺','陸游','宋','宋诗','song-poetry','','[]','十年淹泊望修門，臨水登山幾斷魂。',32,'全唐诗/poet.song.127000.json','["十年淹泊望修門，臨水登山幾斷魂。", "短鬢星星身欲老，小樓微月宿青村。"]'),
('fd26c5ba-6276-4b61-8752-e364801747b6','行綿州道中','陸游','宋','宋诗','song-poetry','','[]','三年客江硤，萬死脱魚黿。',48,'全唐诗/poet.song.127000.json','["三年客江硤，萬死脱魚黿。", "平地從今始，窮塗敢復論。", "園畦棋局整，坡壟海濤翻。", "瘦犢應多恨，泥塗伏短轅。"]'),
('51fbcd86-e066-40a4-873d-cc986ff9e14f','越王樓二首  其一','陸游','宋','宋诗','song-poetry','','[]','上盡江邊百尺樓，倚欄極目莫江秋。',32,'全唐诗/poet.song.127000.json','["上盡江邊百尺樓，倚欄極目莫江秋。", "未甘便作衰翁在，兩脚猶堪蹋九州。"]'),
('c3370065-fd2f-4590-b708-4b9bb74c7cd6','越王樓二首  其二','陸游','宋','宋诗','song-poetry','','[]','蒲萄酒緑似江流，夜燕唐家帝子樓。',32,'全唐诗/poet.song.127000.json','["蒲萄酒緑似江流，夜燕唐家帝子樓。", "約住筦絃呼羯鼓，要渠打散醉中愁。"]'),
('fae7b26a-bc48-47fb-baf5-97245593e00e','東津','陸游','宋','宋诗','song-poetry','','[]','歲暮涪江水歸壑，白沙渺然石犖确。',96,'全唐诗/poet.song.127000.json','["歲暮涪江水歸壑，白沙渺然石犖确。", "蜀天常燠少雪霜，緑樹青林不揺落。", "闌干詰曲臨官道，烟靄參差望城郭。", "打魚斫膾修故事，豪竹哀絲奉歡樂。", "樂莫樂於新相知，美人一笑回春姿。", "四方本是丈夫事，安用一生無别離。"]'),
('2475280c-c3ff-45ee-a469-696ac8d2b567','東山','陸游','宋','宋诗','song-poetry','','[]','今日之集何佳哉，入關劇飲始此回。',128,'全唐诗/poet.song.127000.json','["今日之集何佳哉，入關劇飲始此回。", "登山正可小天下，跨海何用尋蓬萊。", "青天肯爲陸子見，妍日似趣梅花開。", "有酒如涪緑可愛，一醉直欲空千罍。", "駞酥鵝黄出隴右，熊肪玉白黔南來。", "眼花耳熱不知夜，但見銀燭高花摧。", "京華故人死太半，歡極往往潛生哀。", "聊將豪縱壓憂患，鼓吹動地聲如雷。"]'),
('28187612-3d8c-4457-aba8-0eeb5cac949c','綿州録參廳觀姜楚公畫鷹少陵爲作詩者','陸游','宋','宋诗','song-poetry','','[]','我來訪古涪之濱，不辭百罔冀一真。',160,'全唐诗/poet.song.127000.json','["我來訪古涪之濱，不辭百罔冀一真。", "走馬朝尋海椶館，斫膾夜醉魴魚津。", "越王高樓亦已換，俯仰今古堪悲辛。", "督郵官舍最卑陋，棟撓楹腐知幾春。", "巋然此壁獨亡恙，老槎勁翮完如新。", "向來劫火何自免，叱呵守護疑有神。", "妖狐九尾穴中國，共置不問如越秦。", "天時此物合致用，下韝指呼端在人。", "會當原野灑毛血，坐令萬里清烟塵。", "老眼還憂不及見，詩成肝膽空輪囷。"]'),
('3bdc1071-b656-4b11-a0b1-6052779ca2fd','羅江驛翠望亭讀宋景文公詩','陸游','宋','宋诗','song-poetry','','[]','撲馬征塵拂不開，高亭欹帽一徘徊。',64,'全唐诗/poet.song.127000.json','["撲馬征塵拂不開，高亭欹帽一徘徊。", "蜀山地暖稀逢雪，閏歲春遲未見梅。", "陂水近人無鷺下，烟林藏寺有鐘來。", "宋公出牧曾題壁，錦段雖殘試剪裁。"]'),
('4bfcfae6-31bc-48d0-9900-0c975207ed86','鹿頭關過龐士元廟','陸游','宋','宋诗','song-poetry','','[]','士元死千載，凄惻過遺祠。',48,'全唐诗/poet.song.127000.json','["士元死千載，凄惻過遺祠。", "海內常難合，天心豈易知。", "英雄今古恨，父老歲時思。", "蒼蘚無情極，秋來滿斷碑。"]'),
('5827fddf-c37d-4ce4-97d0-3094608f726d','遊漢州西湖','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','房公一跌樷衆毁，八年漢州爲刺史。',128,'全唐诗/poet.song.127000.json','["房公一跌樷衆毁，八年漢州爲刺史。", "遶城鑿湖一百頃，島嶼曲折三四里。", "小庵靜院穿竹入，危榭飛樓壓城起。", "空濛烟雨媚松楠，顛倒風霜老葮葦。", "日月苦長身苦閑，萬事不理看湖水。", "向來愛琴雖一癖，觀過自足知夫子。", "畫船載酒凌湖光，想公樂飲千萬場。", "嘆息風流今未泯，兩川名醖避鵝黄。"]'),
('e6ea76ae-9704-41dd-9136-70a1d97c4dc7','嚴君平卜臺','陸游','宋','宋诗','song-poetry','','[]','先生久已蛻氛埃，道上猶傳舊卜臺。',32,'全唐诗/poet.song.127000.json','["先生久已蛻氛埃，道上猶傳舊卜臺。", "乞得寒泉濯肝肺，真成萬里不虚來。"]'),
('9539ef93-9ed7-48aa-bbeb-3e11525f2acf','梅花','陸游','宋','宋诗','song-poetry','','[]','家是江南友是蘭，水邊月底怯新寒。',64,'全唐诗/poet.song.127000.json','["家是江南友是蘭，水邊月底怯新寒。", "畫圖省識驚春早，玉笛孤吹怨夜殘。", "冷淡合教閑處著，清臞難遣俗人看。", "相逢剩作樽前恨，索笑情懷老漸闌。"]'),
('4a82d63b-d0dc-47d4-8bab-8050bff8e8dc','拜張忠定公祠二十韵','陸游','宋','宋诗','song-poetry','','[]','張公世外人，與蜀偶有緣。',240,'全唐诗/poet.song.127000.json','["張公世外人，與蜀偶有緣。", "天將靖蜀亂，生公在人間。", "厥初大盜興，樂禍迭相挻。", "天子輟玉食，貴臣擁戎旃。", "生殺出喜怒，死者常差肩。", "公曰此何哉，從之吾欺天。", "河流觸地軸，砥柱屹不遷。", "脅從盡縱捨，飛章交帝前。", "上意竟開悟，至仁勝兇殘。", "貴臣不極賞，追還黜其權。", "安危關社稷，豈惟蜀民全。", "後來有阿童，握兵事開邊。", "晚策睦州功，上公珥金蟬。", "勢張不可禦，北鄉挑幽燕。", "神京遂丘墟，迄今天步艱。", "時無忠定公，孰能折其姧。", "我來拜遺祠，喬木含蒼烟。", "死者不可作，愀然衰涕澘。", "憤切感虜禍，慷慨思公賢。", "春秋送迎神，誰爲歌此篇。"]'),
('490292cc-6b1d-4f44-b776-fb7f18f41bd4','成都歲暮始微寒小酌遣興','陸游','宋','宋诗','song-poetry','','[]','革带頻移紗帽寬，茶鐺欲熟篆香殘。',64,'全唐诗/poet.song.127000.json','["革带頻移紗帽寬，茶鐺欲熟篆香殘。", "疏梅已報先春信，小雨初成十月寒。", "身似野僧猶有髮，門如村舍強名官。", "鼠肝蟲臂元無擇，遇酒猶能罄一歡。"]'),
('2e9bdded-97f3-4cc2-84e7-0deb3c2dfe74','再賦梅花','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','老來愛酒賸狂顛，況復梅花到眼邊。',64,'全唐诗/poet.song.127000.json','["老來愛酒賸狂顛，況復梅花到眼邊。", "不怕幽香妨靜觀，正須疏影伴癯仙。", "松筠共嘆冰霜晚，桃李從教雨露偏。", "此去西湖八千里，破愁一笑得無緣。"]'),
('abdb10a2-8ced-4527-b9f8-d6489b68ba52','登塔','陸游','宋','宋诗','song-poetry','','[]','冷官無一事，日日得閑遊。',120,'全唐诗/poet.song.127000.json','["冷官無一事，日日得閑遊。", "壯哉千尺塔，攝衣上上頭。", "眼力老未減，足疾新有瘳。", "幸兹濟勝具，俯仰隘九州。", "雪山西北横，大江東南流。", "畫棟雲氣涌，鐵鐸風聲遒。", "旅懷忽惻愴，涕下不能收。", "十年辭象魏，萬里懷松楸。", "仰視去天咫，絕叫當聞不。", "帝閽守虎豹，此計終悠悠。"]'),
('cc3a30c5-a020-4553-915a-810f82d8742e','先主廟次唐貞元中張儼詩韵三首  其一','陸游','宋','宋诗','song-poetry','','[]','猾賊挾至尊，天命矜在已。',24,'全唐诗/poet.song.127000.json','["猾賊挾至尊，天命矜在已。", "豈知高帝業，煌煌漢中起。"]'),
('5be36ff9-2650-49d4-81ad-7b8ded76b51d','先主廟次唐貞元中張儼詩韵三首  其二','陸游','宋','宋诗','song-poetry','','[]','吳蜀本脣齒，悲哉乃連兵。',24,'全唐诗/poet.song.127000.json','["吳蜀本脣齒，悲哉乃連兵。", "盡銳下三峽，誰使復兩京。"]'),
('ea6b621f-2083-493f-8d27-6bad4fd4b751','先主廟次唐貞元中張儼詩韵三首  其三','陸游','宋','宋诗','song-poetry','','[]','洛陽化爲灰，棘生銅駞陌。',24,'全唐诗/poet.song.127000.json','["洛陽化爲灰，棘生銅駞陌。", "討賊志不成，父老泣陵柏。"]'),
('90b6e792-d871-4330-8036-8581ed012581','睡起書事','陸游','宋','宋诗','song-poetry','','[]','京華豪飲釂千鍾，濯錦江邊怯酒濃。',64,'全唐诗/poet.song.127000.json','["京華豪飲釂千鍾，濯錦江邊怯酒濃。", "烈士壯心雖未減，狂奴故態有誰容。", "折梅著句聊排悶，閉户焚香剩放慵。", "午枕如雷君莫怪，西風吹夢過吳松。"]'),
('b3cef789-4395-4569-81e2-56763ecf4d01','西郊尋梅','陸游','宋','宋诗','song-poetry','','[]','西郊梅花矜絕豔，走馬獨來看不厭。',160,'全唐诗/poet.song.127000.json','["西郊梅花矜絕豔，走馬獨來看不厭。", "似羞流落蒙市塵，寜墮荒寒傍茆店。", "翛然自是世外人，過去生中差一念。", "淺顰常鄙桃李學，獨立不容鶯蝶覘。", "山礬水仙晚角出，大是春秋吳楚僭。", "餘花豈無好顔色，病在一俗無由砭。", "朱欄玉砌渠有命，斷橋流水君何欠。", "嗟余相與頗同調，身客劍南家在剡。", "凄涼萬里歸無日，蕭颯二毛衰有漸。", "尚能作意晚相從，爛醉不辭杯瀲灩。"]'),
('434d2db9-8150-4c76-9d54-076fee793385','分韵作梅花詩得東字','陸游','宋','宋诗','song-poetry','','[]','淺寒籬落清霜後，疏影池塘淡月中。',64,'全唐诗/poet.song.127000.json','["淺寒籬落清霜後，疏影池塘淡月中。", "北客同春俱稅駕，南枝與我兩飄蓬。", "從來遇酒千鍾少，此外評花四海空。", "惟恨廣平風味減，坐看徐庾擅江東。"]'),
('24bb325c-52cc-4624-a75a-49b7222347c2','宇文子友聞予有西郊尋梅詩以詩借觀次其韵','陸游','宋','宋诗','song-poetry','','[]','拾遺遺跡付緇郎，槁葉凝塵欲滿堂。',64,'全唐诗/poet.song.127000.json','["拾遺遺跡付緇郎，槁葉凝塵欲滿堂。", "已恨罇罍孤勝餞，更堪風雨病幽芳。", "蘭蓀千古有同調，蜂蝶一春空自忙。", "馬上得詩歸絕嘆，故園三徑久成荒。"]'),
('50b5c66a-6ec8-4bc0-a4b0-705201bbbb35','海棠','陸游','宋','宋诗','song-poetry','','[]','誰道名花獨故宫，東城盛麗足爭雄。',64,'全唐诗/poet.song.127000.json','["誰道名花獨故宫，東城盛麗足爭雄。", "横陳錦障闌干外，盡吸紅雲酒醆中。", "貪看不辭持夜燭，倚狂直欲擅春風。", "拾遺舊詠悲零落，瘦損腰圍擬未工。"]'),
('a6c50c90-ac68-4381-b707-83d0152fb17c','簡南禪勤長老','陸游','宋','宋诗','song-poetry','','[]','宦遊處處是君恩，歸去無期莫更論。',64,'全唐诗/poet.song.127000.json','["宦遊處處是君恩，歸去無期莫更論。", "眼正修行新有力，心空憂患已無根。", "缽盂分我雲堂飯，拄杖敲君竹院門。", "屈宋向來堪一笑，故鄉何戀更招魂。"]'),
('bebe4278-c8af-41a0-928f-018342cfca67','和譚德稱送牡丹二首  其一','陸游','宋','宋诗','song-poetry','','[]','洛陽春色擅中州，檀暈鞓紅總勝流。',32,'全唐诗/poet.song.127000.json','["洛陽春色擅中州，檀暈鞓紅總勝流。", "憔悴劍南人不管，問渠情味似儂不。"]'),
('4bbb1b01-c61d-4d54-acff-f682f8849f63','和譚德稱送牡丹二首  其二','陸游','宋','宋诗','song-poetry','','[]','吾生何拙亦何工，憂患如山一笑空。',32,'全唐诗/poet.song.127000.json','["吾生何拙亦何工，憂患如山一笑空。", "猶有餘情被花惱，醉搔華髮倚屏風。"]'),
('814f14b7-4ec7-40fa-b83b-ee3d165e6771','初到蜀州寄成都諸友','陸游','宋','宋诗','song-poetry','','[]','流落天涯鬢欲絲，年來用短始能奇。',64,'全唐诗/poet.song.127000.json','["流落天涯鬢欲絲，年來用短始能奇。", "無材藉作長閑地，有懣留爲劇飲資。", "萬里不通京洛夢，一春最負牡丹時。", "襞牋報與諸公道，罨畫亭邊第一詩。"]'),
('ee2dc01b-04e6-4a0c-8b16-53ffc1f54f27','自蜀州暫還成都奉簡諸公','陸游','宋','宋诗','song-poetry','','[]','不染元規一點塵，行歌偶到錦江濵。',64,'全唐诗/poet.song.127000.json','["不染元規一點塵，行歌偶到錦江濵。", "淋漓詩酒無虚日，判斷鶯花又過春。", "客路柳陰初墮絮，還家梅子欲生仁。", "更須作意勤相過，要信年光屬散人。"]'),
('5980c66a-ed7c-4048-b782-0d3ea639f533','摩訶池','陸游','宋','宋诗','song-poetry','','[]','摩訶古池苑，一過一消魂。',48,'全唐诗/poet.song.127000.json','["摩訶古池苑，一過一消魂。", "春水生新漲，烟蕪没舊痕。", "年光走車轂，人事轉萍根。", "猶有宫梁燕，衘泥入水門。"]'),
('672f5607-88ce-4b9c-97e4-e977416643ed','三月十七日夜醉中作','陸游','宋','宋诗','song-poetry','','["\u58ee\u5fd7\u96be\u916c", "\u7231\u56fd"]','前年膾鯨東海上，白浪如山寄豪壯。',96,'全唐诗/poet.song.127000.json','["前年膾鯨東海上，白浪如山寄豪壯。", "去年射虎南山秋，夜歸急雪滿貂裘。", "今年摧頹最堪笑，華髮蒼顔羞自照。", "誰知得酒尚能狂，脫帽向人時大叫。", "逆胡未滅心未平，孤劍床頭鏗有聲。", "破驛夢回燈欲死，打窗風雨正三更。"]'),
('1c632724-3495-4fc1-ac80-216038a57c38','嘉祐院觀壁間文湖州墨竹','陸游','宋','宋诗','song-poetry','','[]','石室先生筆有神，我來拂拭一酸辛。',64,'全唐诗/poet.song.127000.json','["石室先生筆有神，我來拂拭一酸辛。", "敗牆慘澹欲無色，老氣森嚴猶逼人。", "慣閲冰霜元耐久，恥隨兒女更爭春。", "紛紛可笑空摹擬，爾輩毫端萬斛塵。"]'),
('ff5bac7d-3005-47a8-b00c-dbf083e74a61','春晚書懷三首  其一','陸游','宋','宋诗','song-poetry','','[]','吹盡郊原萬點紅，燕梁考室亦匆匆。',64,'全唐诗/poet.song.127000.json','["吹盡郊原萬點紅，燕梁考室亦匆匆。", "老來偏覺歲華速，客裏忽驚春事空。", "病有藥方傳肘後，懶無詩句付囊中。", "歸心日夜隨江水，只欲東門覓短篷。"]'),
('a76d6330-a1c8-4ce2-b49d-a1a45ec2b8a4','春晚書懷三首  其二','陸游','宋','宋诗','song-poetry','','[]','經春淹泊錦官城，作箇歸期苦未成。',64,'全唐诗/poet.song.127000.json','["經春淹泊錦官城，作箇歸期苦未成。", "老向軒裳增力量，病於風月減心情。", "官閑有味緣高臥，酒貴無憂爲細傾。", "憶探梅花如昨日，西齋榆莢與階平。"]'),
('eb38cf67-1ed4-4eec-87fc-d54b75fec574','春晚書懷三首  其三','陸游','宋','宋诗','song-poetry','','[]','老客天涯心尚孩，惜春直欲挽春回。',64,'全唐诗/poet.song.127000.json','["老客天涯心尚孩，惜春直欲挽春回。", "長繩縱繫斜陽住，右手難移故國來。", "暑近蚊雷先隠轔，雨前螘垤正崔嵬。", "茹芝却粒終無術，萬事惟須付一杯。"]'),
('c03b5217-81f9-4492-8095-d0e94342f2af','偶憶萬州戲作短歌','陸游','宋','宋诗','song-poetry','','[]','峽中天下最窮處，萬州蕭條誰肯顧。',96,'全唐诗/poet.song.127000.json','["峽中天下最窮處，萬州蕭條誰肯顧。", "去年正月偶過之，曾爲巴人三日住。", "南浦尋梅雪滿舟，西山載酒雲生屨。", "至今夢聽竹枝聲，燈火紛紛驛前路。", "殘春猶客蜀江邊，陳迹回思一愴然。", "漸老定知歡漸少，明年還復憶今年。"]'),
('eac54ad9-3258-4177-b571-56c039f71e0e','驛舍見故屏風畫海棠有感','陸游','宋','宋诗','song-poetry','','[]','厭煩只欲長面壁，此心安得頑如石。',128,'全唐诗/poet.song.127000.json','["厭煩只欲長面壁，此心安得頑如石。", "杜門復出嘆習氣，止酒還開慚定力。", "成都二月海棠開，錦繡裹城迷巷陌。", "燕宫最盛號花海，霸國雄豪有遺迹。", "猩紅鴨緑極天巧，疊蕚重跗眩朝日。", "繁華一夢忽吹散，閉眼細思猶歴歴。", "憂樂相尋豈易知，故人應記醉中詩。", "夜闌風雨嘉州驛，愁向屏風見折枝。"]'),
('3b00cac5-f615-40ae-9a64-46806c83fa0c','思政堂東軒偶題','陸游','宋','宋诗','song-poetry','','[]','羈愁酒病兩無聊，小篆吹香已半消。',32,'全唐诗/poet.song.127000.json','["羈愁酒病兩無聊，小篆吹香已半消。", "喚起十年閩嶺夢，赬桐花畔見紅蕉。"]'),
('3441d9f3-d2c1-4853-9903-41e3abcc5c7d','荔枝樓小酌二首  其一','陸游','宋','宋诗','song-poetry','','[]','碧瓦朱欄已半摧，強呼歌舞試樽罍。',32,'全唐诗/poet.song.127000.json','["碧瓦朱欄已半摧，強呼歌舞試樽罍。", "邦人莫訝心情懶，新出鶯花海裏來。"]'),
('a0eea4a3-3817-4ba1-bce4-06f352182c6b','荔枝樓小酌二首  其二','陸游','宋','宋诗','song-poetry','','[]','病與愁兼怯酒船，巴歌聞罷更悽然。',32,'全唐诗/poet.song.127000.json','["病與愁兼怯酒船，巴歌聞罷更悽然。", "此身未死長爲客，回首夔州又二年。"]'),
('dbc8c2a4-283e-4494-b8e9-0072d725c0b8','嘉陽官舍奇石甚富散棄無領略者予始取作假山因名西齋曰小山堂爲賦短歌','陸游','宋','宋诗','song-poetry','','[]','昔人何人愛巖壑，爲山未成儲犖确。',128,'全唐诗/poet.song.127000.json','["昔人何人愛巖壑，爲山未成儲犖确。", "散落支床壓酒槽，大或專車小拳握。", "幽人邂逅爲絕嘆，修綆趣取寒泉濯。", "峭峰幽竇相吐吞，翠嶺丹崖渺聨絡。", "石不能言意可解，問我胡爲憐寂寞。", "人間興廢自有數，昔棄何傷今豈樂。", "斯言妙矣予則陋，敢對石友辭罸爵。", "爲君寬作十日留，在眼便同真著脚。"]'),
('7b59b6ae-ad88-4689-a32b-0f27c2a97e95','望雲樓晚興','陸游','宋','宋诗','song-poetry','','[]','小閣東南獨詠詩，此生終與世差池。',64,'全唐诗/poet.song.127000.json','["小閣東南獨詠詩，此生終與世差池。", "夕陽明處蒼烟合，棲燕歸時畫角悲。", "人與江山均是夢，心非風月尚誰知。", "舊交幾歲音塵隔，三撫闌干有所思。"]'),
('5628b996-8d86-4121-b440-d9c8abac3a8d','護國天王院故神霄玉清萬壽宫也廢圯略盡而規模尚極壯麗過之有感','陸游','宋','宋诗','song-poetry','','[]','太霄帝君神霄府，一日璽書行海宇。',160,'全唐诗/poet.song.127000.json','["太霄帝君神霄府，一日璽書行海宇。", "築宫奔走誰敢後，萬牛挽材山作礎。", "步虚夜半落雲間，玉磬漻漻鸞鶴舞。", "帝師丞相領使君，侍晨校籍紛如雨。", "洛陽臨淮小睥睨，御史立奏投裔土。", "從來桑門喜嘲競，舉國冠巾噤無語。", "古傳東海會揚塵，君看此地亦荆榛。", "霓旌仙仗空遺堵，甃缺臺傾知幾春。", "牧兒驅牛齧庭草，誰記劍佩來朝真。", "斜陽却上筍輿去，溝水泠泠愁殺人。"]'),
('de0fe27c-e523-4298-9ddc-37b76739c9ef','登荔枝樓','陸游','宋','宋诗','song-poetry','','[]','平羌江水接天流，涼入簾櫳已似秋。',64,'全唐诗/poet.song.127000.json','["平羌江水接天流，涼入簾櫳已似秋。", "喚作主人元是客，知非吾土強登樓。", "閑憑曲檻常忘去，欲下危梯更小留。", "公事無多厨釀美，此身不負負嘉州。"]'),
('36f5a988-2169-4472-a292-bb9ae4aec1b9','再賦荔枝樓','陸游','宋','宋诗','song-poetry','','[]','只道文書撥不開，未妨高處獨徘徊。',64,'全唐诗/poet.song.127000.json','["只道文書撥不開，未妨高處獨徘徊。", "山横瓦屋披雲出，水自牂牁裂地來。", "暝入簾陰吹細雨，涼生樓角轉輕雷。", "癡頑也擬忘鄉國，不奈城頭暮角哀。"]'),
('238d59e4-a69b-471b-acd6-91068d4bb5c0','能仁院前有石像丈餘蓋作大像時様也','陸游','宋','宋诗','song-poetry','','[]','江閣欲開千尺像，雲龕先定此規模。',32,'全唐诗/poet.song.127000.json','["江閣欲開千尺像，雲龕先定此規模。", "斜陽徙倚空三嘆，嘗試成功自古無。"]'),
('c79bf425-0e43-407f-b482-6694e717b88b','謁凌雲大像','陸游','宋','宋诗','song-poetry','','[]','出郭幽尋一笑新，徑呼艇子截烟津。',64,'全唐诗/poet.song.127000.json','["出郭幽尋一笑新，徑呼艇子截烟津。", "不辭疾步登重閣，聊欲今生識偉人。", "泉鏡正涵螺髻緑，浪花不犯寶趺塵。", "始知神力無窮盡，丈六黄金果小身。"]'),
('30b0e8c9-3ab7-4103-8ff5-e7710a487a6f','凌雲醉歸作','陸游','宋','宋诗','song-poetry','','[]','峨嵋月入平羌水，嘆息吾行俄至此。',103,'全唐诗/poet.song.127000.json','["峨嵋月入平羌水，嘆息吾行俄至此。", "謫仙一去五百年，至今醉魂呼不起。", "玻瓈春滿琉璃鍾，宦情苦薄酒興濃。", "飲如長鯨渴赴海，詩成放筆千觴空。", "十年看盡人間事，更覺麴生偏有味。", "君不見蒲萄一斗換得西涼州，不如將軍告身供一醉。"]'),
('1e2269d3-0c66-4a47-bbd5-e4ebb9f72881','獨遊城西諸僧舍','陸游','宋','宋诗','song-poetry','','[]','我是天公度外人，看山看水自由身。',64,'全唐诗/poet.song.127000.json','["我是天公度外人，看山看水自由身。", "蘚崖直上飛雙屐，雲洞前頭岸幅巾。", "萬里欲呼牛渚月，一生不受庾公塵。", "非無好客堪招喚，獨往飄然覺更真。"]'),
('2ec2ccfe-d29d-4b75-bb56-d4fcca4f04ad','西林院','陸游','宋','宋诗','song-poetry','','[]','一邦盡對江邊像，試比西林總不如。',64,'全唐诗/poet.song.127000.json','["一邦盡對江邊像，試比西林總不如。", "群玉蕭森開士宅，五雲飛動相君書。", "磴危漸覺山爭出，屐響方驚閣半虚。", "安得棄官長住此，一杯香飯薦珍蔬。"]'),
('859ab83e-f164-4fd8-a524-48be41819321','聽事前紫薇花二本甚盛戲題絕句','陸游','宋','宋诗','song-poetry','','[]','紅藥紫薇西省春，從來惟慣對詞臣。',32,'全唐诗/poet.song.127000.json','["紅藥紫薇西省春，從來惟慣對詞臣。", "問囚自是粗官分，無奈名花解笑人。"]'),
('bf2870ce-f64a-48ce-8426-5346c966fa2c','同何元立蔡肩吾至東丁院汲泉煮茶二首  其一','陸游','宋','宋诗','song-poetry','','[]','一州佳處盡裴回，惟有東丁院未來。',32,'全唐诗/poet.song.127000.json','["一州佳處盡裴回，惟有東丁院未來。", "身是江南老桑苧，諸君小住共茶杯。"]'),
('b872fc43-f20a-4473-a890-66f2c13dcb40','同何元立蔡肩吾至東丁院汲泉煮茶二首  其二','陸游','宋','宋诗','song-poetry','','[]','雪芽近自峨嵋得，不減紅囊顧渚春。',32,'全唐诗/poet.song.127000.json','["雪芽近自峨嵋得，不減紅囊顧渚春。", "旋置風爐清樾下，他年奇事記三人。"]'),
('70a07e94-95a5-4c70-b0be-8f12253ed421','癸巳夏旁郡多苦旱惟漢嘉數得雨然未足也立秋夜三鼓雨至明日晡後未止高下霑足喜而有賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','畫簷鳴雨早秋天，不喜新涼喜有年。',32,'全唐诗/poet.song.127000.json','["畫簷鳴雨早秋天，不喜新涼喜有年。", "眼裏香秔三萬頃，寄聲父老共欣然。"]'),
('0891e0d9-ccf2-4648-8b4b-a31a6ec5e3f7','癸巳夏旁郡多苦旱惟漢嘉數得雨然未足也立秋夜三鼓雨至明日晡後未止高下霑足喜而有賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','五十衰翁髮半華，猶能把酒醉天涯。',32,'全唐诗/poet.song.127000.json','["五十衰翁髮半華，猶能把酒醉天涯。", "絲毫美政何曾有，惟把豐年贈漢嘉。"]'),
('fff468bd-ac92-4e1b-ab4e-eb0cf4e7a2c3','晚登望雲二首  其一','陸游','宋','宋诗','song-poetry','','[]','一出修門又十年，輩流多已珥金蟬。',64,'全唐诗/poet.song.127000.json','["一出修門又十年，輩流多已珥金蟬。", "衰如蠧葉秋先覺，愁似鰥魚夜不眠。", "輦路疏槐迎駕處，苑城殘日泛湖天。", "君恩未報身今老，徙倚危樓一泫然。"]'),
('4e856988-9399-4309-ad07-a191fa99e1b7','晚登望雲二首  其二','陸游','宋','宋诗','song-poetry','','[]','晚來烟雨暗江干，烽火遥傳畫角殘。',64,'全唐诗/poet.song.127000.json','["晚來烟雨暗江干，烽火遥傳畫角殘。", "看鏡功名空自許，上樓懷抱若爲寬。", "青楓揺落新秋令，白髮凄涼舊史官。", "飽見少年輕宿士，可憐隨處強追歡。"]'),
('dc9bf017-4b30-421b-a6e2-6c21607d4b21','立秋後十日風雨凄冷獨居有感','陸游','宋','宋诗','song-poetry','','[]','急雨鳴瓦溝，尖風入窗罅。',72,'全唐诗/poet.song.128000.json','["急雨鳴瓦溝，尖風入窗罅。", "紗籠耿青燈，寂寂新秋夜。", "誰言簿領中，乃復有此暇。", "稍繙書册讀，已念灰火跨。", "那知是羈客，恍若在家舍。", "睡晚且熟眠，洗沐官有假。"]'),
('2518eb5c-3657-47c3-ab77-42378b1d9a56','晦日西窗懷故山','陸游','宋','宋诗','song-poetry','','[]','今朝休日仍無客，茶罷西窗臥解衣。',64,'全唐诗/poet.song.128000.json','["今朝休日仍無客，茶罷西窗臥解衣。", "白髮已侵殘夢境，緑苔應滿舊漁磯。", "桃源雞犬塵凡隔，杜曲桑麻夢想歸。", "賴有小山聊慰眼，幽篁叢桂雨霏霏。"]'),
('dff63385-ca79-4494-bfa5-65578f86314d','秋日懷東湖二首  其一','陸游','宋','宋诗','song-poetry','','[]','小閣東頭罨畫池，秋來長是憶幽期。',64,'全唐诗/poet.song.128000.json','["小閣東頭罨畫池，秋來長是憶幽期。", "身如巢燕臨歸日，心似堂僧欲動時。", "病思羈懷惟付酒，西風落日更催詩。", "故知歲暮常多感，不獨當年宋玉悲。"]'),
('da7b0e7b-2c1b-4d37-8f9b-8adc6ef931de','秋日懷東湖二首  其二','陸游','宋','宋诗','song-poetry','','[]','罨畫池邊小釣磯，垂竿幾度到斜暉。',64,'全唐诗/poet.song.128000.json','["罨畫池邊小釣磯，垂竿幾度到斜暉。", "青蘋葉動知魚過，朱閣簾開看燕歸。", "歲晚官身空自閔，途窮世事巧相違。", "邊州客少巴歌陋，誰與愁城略解圍。"]'),
('2dc05749-76d2-48bf-a1c9-bcdb11f7e238','小山之南作曲欄石磴繚繞如棧道戲作二篇  其一','陸游','宋','宋诗','song-poetry','','[]','羈遊隨處得哦詩，掃溉軒窗每恨遲。',64,'全唐诗/poet.song.128000.json','["羈遊隨處得哦詩，掃溉軒窗每恨遲。", "已幻小山寬客恨，更添危磴作兒嬉。", "偶留塞上寜無數，徑返湖邊已有期。", "誰遣化工娛此老，幽花微拆緑苔滋。"]'),
('4f684f9e-67f2-42f5-9f01-c823c84abab0','小山之南作曲欄石磴繚繞如棧道戲作二篇  其二','陸游','宋','宋诗','song-poetry','','[]','吏退庭空剩得閑，一窗如在翠微間。',64,'全唐诗/poet.song.128000.json','["吏退庭空剩得閑，一窗如在翠微間。", "半崖縈棧遊秦路，疊嶂生雲入剡山。", "真有巖居臨絕壑，但無漁艇繫寒灣。", "躋攀自苦君休笑，寸步何曾不險艱。"]'),
('eadb8870-6d41-4597-b4b7-a5733e1f2574','得成都諸友書勸少留嘉陽戲作','陸游','宋','宋诗','song-poetry','','[]','一坐五十日，癡頑良可哀。',48,'全唐诗/poet.song.128000.json','["一坐五十日，癡頑良可哀。", "新涼爲醉地，少訟作慵媒。", "市柳風烟慘，汀蘋歲月催。", "遠官從漫浪，垂老懶低回。"]'),
('790b3f3d-3c49-47a0-8ab6-74013193abcf','道院','陸游','宋','宋诗','song-poetry','','[]','四壁長苔痕，經旬掩緑樽。',48,'全唐诗/poet.song.128000.json','["四壁長苔痕，經旬掩緑樽。", "雨聲清夢境，燈影伴吟魂。", "揺落悲徂歲，漂流憶故園。", "擬騷無傑語，千古愧湘沅。"]'),
('8cfb9e91-9030-4324-9ae3-3ff5a2fcb303','醉中感懷','陸游','宋','宋诗','song-poetry','','[]','早歲君王記姓名，只今憔悴客邊城。',64,'全唐诗/poet.song.128000.json','["早歲君王記姓名，只今憔悴客邊城。", "青衫猶是鵷行舊，白髮新從劍外生。", "古戍旌旗秋慘淡，高城刁斗夜分明。", "壯心未許全消盡，醉聽檀槽出塞聲。"]'),
('d3616d45-919a-4c25-8ad3-b4026e97f5bf','玻瓈江','陸游','宋','宋诗','song-poetry','','[]','玻瓈江水千尺深，不如江上離人心。',96,'全唐诗/poet.song.128000.json','["玻瓈江水千尺深，不如江上離人心。", "君行未過青衣縣，妾心先到峨嵋陰。", "金罇共釂不知曉，月落烟渚天横參。", "車輪無角那得住，馬蹄不方何處尋。", "空憑尺素寄幽恨，縱有緑綺誰知音。", "愁來只欲掩屏睡，無奈夢斷聞疏砧。"]'),
('d78f06bb-9422-47f6-bbce-556cc43a5d2f','夜思','陸游','宋','宋诗','song-poetry','','[]','蒼顔華鬢久低摧，嘆息何堪歲月催。',64,'全唐诗/poet.song.128000.json','["蒼顔華鬢久低摧，嘆息何堪歲月催。", "殘暑已隨團扇去，新涼還傍短檠來。", "月痕澹澹侵苔砌，雲葉蕭蕭覆水臺。", "簿領沈迷無日了，試憑詩思洗氛埃。"]'),
('d4044d56-3a1a-4b8f-b91f-5f174299cc0b','雨夜懷唐安','陸游','宋','宋诗','song-poetry','','[]','歸心日夜逆江流，官柳三千憶蜀州。',64,'全唐诗/poet.song.128000.json','["歸心日夜逆江流，官柳三千憶蜀州。", "小閣簾櫳頻夢蝶，平湖烟水已盟鷗。", "螢依溼草同爲旅，雨滴空階别是愁。", "堪笑邦人不解事，區區猶借陸君留。"]'),
('d3c991a3-f6e4-4cf7-8777-e7ca5666ec52','迎詔書','陸游','宋','宋诗','song-poetry','','[]','憶瞻鑾仗省門前，扇影鞭聲下九天。',32,'全唐诗/poet.song.128000.json','["憶瞻鑾仗省門前，扇影鞭聲下九天。", "寂寞嘉州迎詔處，忽聞鼓吹却悽然。"]'),
('f3a56e4f-43f3-4b8a-bbba-f4a0cf69423a','秋夜遣懷','陸游','宋','宋诗','song-poetry','','[]','江雲傍簷山雨細，羈客空堂臥荒翳。',96,'全唐诗/poet.song.128000.json','["江雲傍簷山雨細，羈客空堂臥荒翳。", "心如秋燕不安巢，迹似春萍本無柢。", "官身奔走何時定，病眼蒙籠惟欲閉。", "壯遊不復記墜鞭，夜語誰能懷擁髻。", "詩情已減但微吟，酒戒漸堅纔小嚌。", "從今更擬著幽禪，半世倀倀真誤計。"]'),
('3cc2e390-b5f5-4b18-86ab-a116a8ad26e1','送客至江上','陸游','宋','宋诗','song-poetry','','[]','多事經旬不出城，今朝送客此閑行。',64,'全唐诗/poet.song.128000.json','["多事經旬不出城，今朝送客此閑行。", "郊原遠带新晴色，人語中含樂歲聲。", "天際斂雲山盡出，江流收漲水初平。", "故園社友應惆悵，五歲無端棄耦耕。"]'),
('d95681f0-e39d-4464-827d-be2b2004f7f7','雨中至西林寺','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','胸中荆棘費鉏耘，正藉幽尋暫解紛。',64,'全唐诗/poet.song.128000.json','["胸中荆棘費鉏耘，正藉幽尋暫解紛。", "不盡長江來畫玉，半空飛閣對凌雲。", "昏昏横靄憑軒見，杳杳疏鐘隔岸聞。", "珍重山僧迎客意，螭奩一縷起微熏。"]'),
('966b11ba-bd4b-458b-a7ce-6d4bc44e47b9','休日登花將軍廟小樓','陸游','宋','宋诗','song-poetry','','[]','林間縹緲出層樓，欄角蒼茫萬頃秋。',32,'全唐诗/poet.song.128000.json','["林間縹緲出層樓，欄角蒼茫萬頃秋。", "曾是胸中著雲夢，不妨此地少遲留。"]'),
('078d6968-be4f-4f84-8325-5205319dc06b','深居','陸游','宋','宋诗','song-poetry','','[]','作吏難堪簿領迷，深居聊復學幽棲。',64,'全唐诗/poet.song.128000.json','["作吏難堪簿領迷，深居聊復學幽棲。", "病來酒户何妨小，老去詩名不厭低。", "零落野雲寒傍水，霏微山雨晚成泥。", "自憐甫里家風在，小摘殘蔬遶廢畦。"]'),
('d2a9aac4-bf1d-4a01-8369-1029e0859871','秋夜獨醉戲題','陸游','宋','宋诗','song-poetry','','[]','敝袍羸馬遍天涯，恰似伶優著處家。',64,'全唐诗/poet.song.128000.json','["敝袍羸馬遍天涯，恰似伶優著處家。", "社甕嫩醅初泛蟻，寒缸殘燼自成花。", "幽窗照影烏巾折，醉手題詩淡墨斜。", "莫恨久爲峨下客，江湖歸去得雄誇。"]'),
('06da784c-ab6c-4041-853e-c6efe94162ed','感事','陸游','宋','宋诗','song-poetry','','[]','清班曾見六龍飛，晚落天涯遠日畿。',64,'全唐诗/poet.song.128000.json','["清班曾見六龍飛，晚落天涯遠日畿。", "邊月空悲新雪鬢，京塵猶染舊朝衣。", "江山壯麗詩難敵，風物蕭條醉絕稀。", "賴有東湖堪吏隠，寄聲籬菊待吾歸。"]'),
('40e45e0f-e965-43f1-8111-d959287cd660','醉鄉','陸游','宋','宋诗','song-poetry','','[]','醉鄉卜築亦佳哉，但苦無情白髮催。',64,'全唐诗/poet.song.128000.json','["醉鄉卜築亦佳哉，但苦無情白髮催。", "癡欲煎膠黏日月，狂思入海訪蓬萊。", "辭巢歸燕先秋去，泣露幽花近社開。", "莫惜傾家供作樂，古人白骨有蒼苔。"]'),
('867845ff-a908-4509-893d-7b91efec1a46','夜讀岑嘉州詩集','陸游','宋','宋诗','song-poetry','','[]','漢嘉山水邦，岑公昔所寓。',120,'全唐诗/poet.song.128000.json','["漢嘉山水邦，岑公昔所寓。", "公詩信豪偉，筆力追李杜。", "常想從軍時，氣無玉關路。", "至今蠧簡傳，多昔横槊賦。", "零落財百篇，崔嵬多傑句。", "工夫刮造化，音節配韶頀。", "我後四百年，清夢奉巾屨。", "晚途有奇事，隨牒得補處。", "群胡自魚肉，明主方北顧。", "誦公天山篇，流涕思一遇。"]'),
('8d9a130a-7bfe-4e00-b496-2e58213ce592','次韵師伯渾見寄','陸游','宋','宋诗','song-poetry','','[]','眉山漢嘉東西州，估船日日到津頭。',64,'全唐诗/poet.song.128000.json','["眉山漢嘉東西州，估船日日到津頭。", "不得講書一行字，倚遍臨江百尺樓。", "黄鐘大吕忽復見，繡叚英瑶何足酬。", "願約青神王夫子，來醉萬景作中秋。"]'),
('83148c22-dee0-4374-b12f-62c5f0d165e6','社前一夕未昏輒寢中夜乃得寐','陸游','宋','宋诗','song-poetry','','[]','祠事當行懼不任，未昏強卧擁孤衾。',64,'全唐诗/poet.song.128000.json','["祠事當行懼不任，未昏強卧擁孤衾。", "三更自笑元無睡，萬事從來忌有心。", "簷角河傾秋耿耿，床頭蟲語夜愔愔。", "若耶溪上蘋花老，倦枕何人聽越吟。"]'),
('909ce5b5-fba1-4fbb-a2d8-aa28c108c302','晚雨','陸游','宋','宋诗','song-poetry','','[]','蕭瑟度横塘，霏微映繚牆。',48,'全唐诗/poet.song.128000.json','["蕭瑟度横塘，霏微映繚牆。", "壓低塵不動，灑急土生香。", "聲入楸梧碎，清分枕簟涼。", "回頭忽陳迹，簷角挂斜陽。"]'),
('dbd144ed-2b0b-4919-a15d-9dae055af1ae','社日','陸游','宋','宋诗','song-poetry','','[]','百穀登場酒滿巵，神林簫鼓晚清悲。',64,'全唐诗/poet.song.128000.json','["百穀登場酒滿巵，神林簫鼓晚清悲。", "蟬依疏柳長言處，燕委空巢大去時。", "幼學已忘那用忌，微聾自樂不須醫。", "傷心故里雞豚集，父老逢迎正見思。"]'),
('aab9a2aa-f446-4627-96c3-9e78de989925','夜雨感懷','陸游','宋','宋诗','song-poetry','','[]','老來每惜歲崢嶸，幾爲巴歌判宿酲。',64,'全唐诗/poet.song.128000.json','["老來每惜歲崢嶸，幾爲巴歌判宿酲。", "白帝草生時入夢，錦官花重更關情。", "簾疏夜雨侵燈暈，枕冷秋風逓角聲。", "定許何時理歸棹，酒狂猶解賦蕪城。"]'),
('64b948ec-0b23-4379-af57-c8e48a73afb6','八月二十二日嘉州大閲','陸游','宋','宋诗','song-poetry','','[]','陌上弓刀擁寓公，水邊旌斾卷秋風。',64,'全唐诗/poet.song.128000.json','["陌上弓刀擁寓公，水邊旌斾卷秋風。", "書生又試戎衣窄，山郡新添畫角雄。", "早事樞庭虚畫策，晚遊幕府愧無功。", "草間鼠輩何勞磔，要挽天河洗洛嵩。"]'),
('803289cc-60f8-40df-9cfb-61dad5fc8e0f','九月六夜夢中作笑詩覺而忘之明日戲追補一首','陸游','宋','宋诗','song-poetry','','[]','吾家笑疾自士龍，我才雖卑笑則同。',64,'全唐诗/poet.song.128000.json','["吾家笑疾自士龍，我才雖卑笑則同。", "紛紛世事何足計，盡付撫掌掀髯中。", "清樽可醉風月好，虚空萬象皆絕倒。", "問君此笑是喜不，道得老夫輸一籌。"]'),
('b8a1f942-e9c5-4be8-b9b9-943ace4205a0','重九會飲萬景樓','陸游','宋','宋诗','song-poetry','','[]','粲粲黄花手自持，登高聊答此佳時。',64,'全唐诗/poet.song.128000.json','["粲粲黄花手自持，登高聊答此佳時。", "纖雲不作看山祟，斗酒聊寬去國思。", "落日樓臺頻徙倚，西風鼓笛倍凄悲。", "彭城戲馬平生意，強爲巴歌一解頤。"]'),
('507c914c-7391-4294-8c9b-30bffc9b8106','久客書懷','陸游','宋','宋诗','song-poetry','','[]','行役飽看山，沉綿剩得閑。',72,'全唐诗/poet.song.128000.json','["行役飽看山，沉綿剩得閑。", "忘憂緣落魄，耐老爲癡頑。", "射虎臨秦塞，騎驢入蜀關。", "芳洲蘭可佩，幽磴桂堪攀。", "欸乃聲饒楚，陬隅句带蠻。", "悠然長自遣，故里幾時還。"]'),
('99a3eb13-efa1-4e72-ac66-a8f88d15d9ca','初報嘉陽除官還東湖有期喜而有作','陸游','宋','宋诗','song-poetry','','[]','塞上經秋幾醉醒，羈愁減盡鬢邊青。',64,'全唐诗/poet.song.128000.json','["塞上經秋幾醉醒，羈愁減盡鬢邊青。", "烽傳八詔登樓看，歌奏三巴忍泪聽。", "好語忽聞還印綬，歸心先已繞林坰。", "呼兒結束從今日，鵲語燈花故有靈。"]'),
('c5e367fb-178b-4f83-b6b6-7ac4b2f56ca9','聞勾龍司戸會客山亭送酒殽及橄欖并簡諸同僚','陸游','宋','宋诗','song-poetry','','[]','東山如高人，吾輩豈易見。',120,'全唐诗/poet.song.128000.json','["東山如高人，吾輩豈易見。", "君獨不出門，終日與相面。", "陰晴烟雨月，朝暮知幾變。", "聞君交不瀆，冠佩未嘗燕。", "弛張要有時，一笑山未譴。", "高秋得佳日，折簡喚諸彦。", "風流非俗飲，歌舞參筆硯。", "但恨五日尹，阻造三語掾。", "清樽遣分似，霜果亦可薦。", "爛醉君勿辭，光景真掣電。"]'),
('3d3e3eb2-e03e-4768-96a2-dd9446c55003','九月十六日夜夢駐軍河外遣使招降諸城覺而有作','陸游','宋','宋诗','song-poetry','','[]','殺氣昏昏横塞上，東並黄河開玉帳。',128,'全唐诗/poet.song.128000.json','["殺氣昏昏横塞上，東並黄河開玉帳。", "晝飛羽檄下列城，夜脱貂裘撫降將。", "將軍櫪上汗血馬，猛士腰間虎文韔。", "階前白刅明如霜，門外長戟森相向。", "朔風卷地吹急雪，轉盼玉花深一丈。", "誰言鐵衣冷徹骨，感義懷恩如挾纊。", "河外諸城一洗空，太行北嶽元無恙。", "更呼斗酒作長歌，要遣天山健兒唱。"]'),
('80a11ee5-43fb-418f-bcd1-afc96befa896','何元立示九日詩臥病累日乃能次韵','陸游','宋','宋诗','song-poetry','','[]','何郎戲寫菊花秋，落筆縱横豈易酬。',64,'全唐诗/poet.song.128000.json','["何郎戲寫菊花秋，落筆縱横豈易酬。", "豪士乃能爲老伴，寓公那得稱遨頭。", "早衰不耐危亭冷，獨臥空驚畫角愁。", "病起尚思尋宿約，一樽從子醉東樓。"]'),
('874dacf2-9429-4543-b68e-d0cb0c367b08','成都行','陸游','宋','宋诗','song-poetry','','[]','倚錦瑟，擊玉壺，吳中狂士遊成都。',144,'全唐诗/poet.song.128000.json','["倚錦瑟，擊玉壺，吳中狂士遊成都。", "成都海棠十萬株，繁華盛麗天下無。", "青絲金絡白雪駒，日斜馳遣迎名姝。", "燕脂褪盡見玉膚，緑鬟半脱嬌不梳。", "吳綾便面對客書，斜行小草密復疏。", "墨君秀潤瘦不枯，風枝雨葉筆筆殊。", "月浸羅韈清夜徂，滿身花影醉索扶。", "東來此歡墮空虚，坐悲新霜點鬢鬚。", "易求合浦千斛珠，難覓錦江雙鯉魚。"]'),
('fbea2427-ca82-4eaf-aa98-d8b6b7fa174f','聞虜亂有感','陸游','宋','宋诗','song-poetry','','[]','前年從軍南山南，夜出馳獵常半酣。',128,'全唐诗/poet.song.128000.json','["前年從軍南山南，夜出馳獵常半酣。", "玄熊蒼兕積如阜，赤手曵虎毛毿毿。", "有時登高望鄠社，悲歌仰天泪如雨。", "頭顱自揣已可知，一死猶思報明主。", "近聞索虜自相殘，秋風撫劍泪汍瀾。", "雒陽八陵那忍說，玉座塵昏松柏寒。", "儒冠忽忽垂五十，急裝何由穿袴褶。", "羞爲老驥伏櫪悲，寜作枯魚過河泣。"]'),
('d349a0d6-da7c-4a4b-8caf-d2316fa4839c','醉歌','陸游','宋','宋诗','song-poetry','','[]','我飲江樓上，闌干四面空。',84,'全唐诗/poet.song.128000.json','["我飲江樓上，闌干四面空。", "手把白玉船，身遊水精宫。", "方我吸酒時，江山入胸中。", "肺肝生崔嵬，吐出爲長虹。", "欲吐輒復吞，頗畏驚兒童。", "乾坤大如許，無處著此翁。", "何當呼青鸞，更駕萬里風。"]'),
('17ece5ec-d318-438a-8866-fcb19f1b2126','初寒','陸游','宋','宋诗','song-poetry','','[]','江路常逢雨，山城早得寒。',48,'全唐诗/poet.song.128000.json','["江路常逢雨，山城早得寒。", "蘭凋初解佩，菊老尚加餐。", "節物知何負，情懷自鮮歡。", "浮生看已熟，不必夢邯鄲。"]'),
('bd743f9b-7ab8-41fe-a339-ce37612b38e0','木山','陸游','宋','宋诗','song-poetry','','[]','枯楠千歲遭風雷，披枝折幹吁可哀。',128,'全唐诗/poet.song.128000.json','["枯楠千歲遭風雷，披枝折幹吁可哀。", "輪囷無用天所赦，秋水初落浮江來。", "嵌空宛轉若耳鼻，峭瘦拔起何崔嵬。", "珠宫貝闕留不得，忽出洲渚知誰推。", "書窗正對雲洞啟，樷菊初傍幽篁栽。", "是間著汝頗宜稱，摩挲朝暮真千回。", "天公解事雨十日，洗盡泥滓滋莓苔。", "一丘一壑吾所許，不須更慕明堂材。"]'),
('b9105fdd-61c2-426d-9100-7efd06c1038f','寒夜遣懷','陸游','宋','宋诗','song-poetry','','[]','臨觴本不飲，憂多自成醉。',96,'全唐诗/poet.song.128000.json','["臨觴本不飲，憂多自成醉。", "四方行萬里，不見埋憂地。", "憶昔入京都，寶馬揺香鬃。", "酣飲青樓夜，歌聲在半空。", "去日不可挽，華髮忽垂領。", "娟娟峨眉月，相對作凄冷。", "月落照空床，不寐聽寒螿。", "早知憂隨人，何用去故鄉。"]'),
('f947714a-bec1-4d4c-90ac-ed2202bf9a78','嘉陽絕無木犀偶得一枝戲作','陸游','宋','宋诗','song-poetry','','[]','久客紅塵不自憐，眼明初見廣寒仙。',64,'全唐诗/poet.song.128000.json','["久客紅塵不自憐，眼明初見廣寒仙。", "只饒籬菊同時出，尚占江梅一著先。", "重露溼香幽徑曉，斜陽烘蕊小窗妍。", "何人更與蒸況水，金鴨華燈惱醉眠。"]'),
('9cf31740-d316-449f-9e20-3306a40f559a','雨後登西樓獨酌','陸游','宋','宋诗','song-poetry','','[]','老覺人間無一欣，強尋高處看歸雲。',64,'全唐诗/poet.song.128000.json','["老覺人間無一欣，強尋高處看歸雲。", "天空列嶂開圖畫，水落寒江學篆文。", "四海道途行大半，百年光景近中分。", "交遊賴有麯生在，正向愁時能策勲。"]'),
('8e4d9257-9a8f-4bb3-93f0-97c98232c4fa','喜晴','陸游','宋','宋诗','song-poetry','','[]','西風吹雨冷凄凄，道上行人白晝迷。',64,'全唐诗/poet.song.128000.json','["西風吹雨冷凄凄，道上行人白晝迷。", "聊抉重雲取朝日，未容嘉穀臥秋泥。", "年豐郡府疏文檄，蠻遁邊亭息鼓鼙。", "寄語農家莫遊惰，冬閑正要飽鉏犁。"]'),
('390654a2-373b-4778-8f04-babe50accb9a','曉出城東','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','渺渺長江下估船，亭亭孤塔隠蒼烟。',64,'全唐诗/poet.song.128000.json','["渺渺長江下估船，亭亭孤塔隠蒼烟。", "不堪異縣蕭條地，更遇初寒慘澹天。", "巾褐已成歸有約，簞瓢未足去無緣。", "包羞強索侏儒米，豪舉何人記少年。"]'),
('f13cc67e-3736-4223-982d-61c1f38bc16b','寶劍吟','陸游','宋','宋诗','song-poetry','','[]','幽人枕寶劍，殷殷夜有聲。',72,'全唐诗/poet.song.128000.json','["幽人枕寶劍，殷殷夜有聲。", "人言劍化龍，直恐興風霆。", "不然憤狂虜，慨然思遐征。", "取酒起酹劍，至寶當潛形。", "豈無知君者，時來自施行。", "一匣有餘地，胡爲鳴不平。"]'),
('902aa655-b7e2-4982-8bc1-b5768efeb10d','十月一日浮橋成以故事宴客凌雲','陸游','宋','宋诗','song-poetry','','[]','陰風吹雨白晝昏，誰掃雲霧升朝暾。',160,'全唐诗/poet.song.128000.json','["陰風吹雨白晝昏，誰掃雲霧升朝暾。", "三江水縮獻洲渚，九頂秀色欲塞門。", "西山下竹十萬箇，江面便可馳車轅。", "巷無居人亦何怪，釋耒來看空山村。", "竹枝宛轉秋猿苦，桑落瀲灩春泉渾。", "衆賔共醉忘燭跋，一徑却下緣雲根。", "走沙人語若潮卷，爭橋炬火如星繁。", "肩輿睡兀到東郭，空有醉墨留衫痕。", "十年萬事俱變滅，點檢自覺惟身存。", "寒燈夜永照耿耿，臥賦長句招羈魂。"]'),
('718e25cb-908a-475c-92f3-bf27a2ec4e5e','聞王嘉叟訃報有作','陸游','宋','宋诗','song-poetry','','[]','嗚呼嘉叟今信死，哭君寢門泪如水。',176,'全唐诗/poet.song.128000.json','["嗚呼嘉叟今信死，哭君寢門泪如水。", "我初入都不妄交，傾倒如君數人耳。", "籠燈蹋雪夜相過，劇論懸河駭鄰里。", "地爐燔栗美芻豢，石鼎烹茶當醪醴。", "上書去國何勇决，作詩送君猶壯偉。", "十年偶復過都門，君方草制西垣裏。", "鬢鬚班白面骨生，心頗疑君遽如此。", "西來例不候達官，每欲寄聲中輒止。", "隻雞絮酒縱有時，雙魚素書長已矣。", "生前客屨紛滿户，身後人情薄於紙。", "懸知海內莆陽公，獨念遺孤爲經紀。"]'),
('596c7054-bacf-40f4-ab27-8575ad5268f1','出城至呂公亭按視修堤','陸游','宋','宋诗','song-poetry','','[]','翠靄横山澹日昇，孤亭聊借曲欄憑。',64,'全唐诗/poet.song.128000.json','["翠靄横山澹日昇，孤亭聊借曲欄憑。", "霜威漸重江初縮，農事方休役可興。", "重阜護城高歴歴，千夫在野築登登。", "寓公僅踵前人迹，伐石西山恨未能。"]'),
('0e468a65-a15e-4b19-b626-75725ceb93c2','登樓','陸游','宋','宋诗','song-poetry','','[]','從來好境遍人間，無奈勞生自欠閑。',64,'全唐诗/poet.song.128000.json','["從來好境遍人間，無奈勞生自欠閑。", "江近時時吹白雨，樓高面面看青山。", "歌聲哀怨傳三峽，行色凄涼带百蠻。", "流落愛君心未已，夢魂猶綴紫宸班。"]'),
('3706e369-c2c4-4e42-aa45-b22243571cde','醉中作四首  其一','陸游','宋','宋诗','song-poetry','','[]','晚途豪氣未低摧，一飲猶能三百杯。',32,'全唐诗/poet.song.128000.json','["晚途豪氣未低摧，一飲猶能三百杯。", "爛爛目光方似電，齁齁鼻息忽如雷。"]'),
('00c9d3a6-2e37-43e1-ae49-fb9e219a7620','醉中作四首  其二','陸游','宋','宋诗','song-poetry','','[]','駕鶴孤飛萬里風，偶然來憩大峨東。',32,'全唐诗/poet.song.128000.json','["駕鶴孤飛萬里風，偶然來憩大峨東。", "持杯露坐無人會，要看青天入酒中。"]'),
('1b801082-742f-478c-b99e-f2a0b77c4a04','醉中作四首  其三','陸游','宋','宋诗','song-poetry','','[]','曾賜琳腴白玉京，狂歌起舞蜀人驚。',32,'全唐诗/poet.song.128000.json','["曾賜琳腴白玉京，狂歌起舞蜀人驚。", "却騎黄鶴横空去，今夕垂虹醉月明。"]'),
('fe55e9ea-d3c0-49a8-b966-25e5dc723289','醉中作四首  其四','陸游','宋','宋诗','song-poetry','','[]','畫角三終夜未闌，醉憑飛閣喜天寬。',32,'全唐诗/poet.song.128000.json','["畫角三終夜未闌，醉憑飛閣喜天寬。", "月明滿地江風急，吹落幽人紫綺冠。"]'),
('565024d4-0030-44de-bc87-65fa0e5b0f88','觀大散關圖有感','陸游','宋','宋诗','song-poetry','','["\u6218\u4e89", "\u6292\u60c5", "\u7231\u56fd"]','上馬擊狂夫，下馬草軍書。',168,'全唐诗/poet.song.128000.json','["上馬擊狂夫，下馬草軍書。", "二十抱此志，五十猶癯儒。", "大散陳倉間，山川鬱盤紆。", "勁氣鍾義士，可與共壯圖。", "坡陀咸陽城，秦漢之故都。", "王氣浮夕靄，宫室生春蕪。", "安得從王師，汛掃迎皇輿。", "黄河與函谷，四海通舟車。", "士馬發燕趙，布帛來青徐。", "先當營七廟，次第畫九衢。", "偏師縛可汗，傾都觀受俘。", "上壽大安宫，復如正觀初。", "丈夫畢此願，死與螻螘殊。", "志大浩無期，醉膽空滿軀。"]'),
('9e5428a1-08c7-453b-a2dd-75a63d8996ba','嘉州守宅舊無後圃因農事之隙爲種花築亭觀甫成而歸戲作長句','陸游','宋','宋诗','song-poetry','','[]','吾州山水西州冠，正欠雄樓並傑觀。',160,'全唐诗/poet.song.128000.json','["吾州山水西州冠，正欠雄樓並傑觀。", "奇峰秀嶺待彈壓，明月清風須判斷。", "三峨舊不到郡齋，創爲詩人供几案。", "烟雲舒卷水墨圖，草木青紅錦繡段。", "一時冠盖共登臨，百年父老俱驚惋。", "縈回舞袖試弓彎，宛轉歌聲學珠貫。", "佳人蜂蝶爭遶鬢，上客龍蛇看揮翰。", "寓公雖作一月留，梅發東湖歸思亂。", "兒戲聊成此段奇，陳迹應留後人嘆。", "明朝艇子泝平羌，却伴謫仙遊汗漫。"]'),
('4a534419-b11c-45d8-836f-01885984c850','連日扶病領客殆不能支枕上懷故山偶成','陸游','宋','宋诗','song-poetry','','[]','已強迂疏假印章，更扶衰病主杯觴。',64,'全唐诗/poet.song.128000.json','["已強迂疏假印章，更扶衰病主杯觴。", "功名已判初心負，豪俠都無故態狂。", "靜覺此身猶外物，懶思與世永相忘。", "清泉白石生來事，曲几明窗味最長。"]'),
('e1fb6f04-a39c-435e-a3e4-34634fdd1afa','余往與宇文叔介同客山南今年叔介客死臨安十月十一日夜忽夢相從取架上書共讀如平生讀未竟忽辭去留之不可曰欲歸校藥方既覺泫然不能已因賦此詩','陸游','宋','宋诗','song-poetry','','[]','羈魂憔悴遠相尋，髭斷肩寒带苦吟。',32,'全唐诗/poet.song.128000.json','["羈魂憔悴遠相尋，髭斷肩寒带苦吟。", "歸校藥方緣底事，知君死抱濟時心。"]'),
('a6bb5c6e-1668-4079-857b-45080ea875ba','金錯刀行','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u58ee\u5fd7"]','黄金錯刀白玉裝，夜穿窗扉出光芒。',100,'全唐诗/poet.song.128000.json','["黄金錯刀白玉裝，夜穿窗扉出光芒。", "丈夫五十功未立，提刀獨立顧八荒。", "京華結交盡奇士，意氣相期共生死。", "千年史策恥無名，一片丹心報天子。", "爾來從軍天漢濵，南山曉雪玉嶙峋。", "嗚呼楚雖三戸能亡秦，豈有堂堂中國空無人。"]'),
('b0eb359c-84e7-48ae-8740-db2971e757d1','言懷','陸游','宋','宋诗','song-poetry','','[]','蘭碎作香塵，竹裂成直紋。',96,'全唐诗/poet.song.128000.json','["蘭碎作香塵，竹裂成直紋。", "炎火熾崐岡，美玉不受焚。", "孤生抱寸志，流離敢忘君。", "釀桂餐菊英，潔齋三沐熏。", "孰云九關遠，精意當徹聞。", "捐軀誠有地，賈勇先三軍。", "不然齎恨死，猶冀楊清芬。", "願乞一棺地，葬近要離墳。"]'),
('c6db4c81-210c-4873-9088-87604c9b28bb','十月九日與客飲忽記去年此時自錦屏歸山南道中小獵今又將去此矣','陸游','宋','宋诗','song-poetry','','[]','去年縱獵韓壇側，玉鞭自探南山雪。',96,'全唐诗/poet.song.128000.json','["去年縱獵韓壇側，玉鞭自探南山雪。", "今年痛飲蜀江邊，金杯却吸峨嵋月。", "竹枝歌舞新教成，凄怨傳得三巴聲。", "城頭築觀出雲雨，峨嵋正與闌干平。", "酒酣詩就擲杯去，醉蹋玻瓈江上路。", "懸知幽磵斷橋邊，已有梅花開半樹。"]'),
('74a2aa12-ebb9-4bb4-8cf2-c3f1e5845328','冬日','陸游','宋','宋诗','song-poetry','','[]','短景怱怱過，新寒亹亹來。',48,'全唐诗/poet.song.128000.json','["短景怱怱過，新寒亹亹來。", "客遊聊戲耳，世事亦悠哉。", "緑動連村麥，香吹到處梅。", "錦城花柳窟，歸去看春回。"]'),
('83db81cf-0fdb-49ef-b88d-3cad3a7ee6f7','十月十四夜月終夜如晝','陸游','宋','宋诗','song-poetry','','[]','月從海東來，徑尺鎔銀盤。',120,'全唐诗/poet.song.128000.json','["月從海東來，徑尺鎔銀盤。", "西行到峨嵋，玉宇萬里寛。", "幽人耿不寐，弄影清夜闌。", "五城十二樓，縹緲香霧間。", "不知何仙人，亭亭倚高寒。", "欲語不得往，悵望冰雪顔。", "叩頭儻見哀，容我躡素鸞。", "掬露以爲漿，屑玉以爲餐。", "泠泠潄齒頰，皓皓濯肺肝。", "逝將從君遊，人間苦無歡。"]'),
('a8c0cb8b-9808-4199-af65-19e44a6df3d9','下元日五更詣天慶觀寶林寺','陸游','宋','宋诗','song-poetry','','[]','朝罷琳宫謁寶坊，強扶衰疾具簪裳。',64,'全唐诗/poet.song.128000.json','["朝罷琳宫謁寶坊，強扶衰疾具簪裳。", "擁裘假寐籃輿穏，夾道吹烟樺炬香。", "樓外曉星猶磊落，山頭初日已蒼涼。", "鳴騶應有高人笑，五斗驅君早夜忙。"]'),
('164f1c70-20c4-4921-9421-ec7f7a730fb6','梅花四首  其一','陸游','宋','宋诗','song-poetry','','[]','老厭紛紛漸鮮歡，愛花聊復客江干。',64,'全唐诗/poet.song.128000.json','["老厭紛紛漸鮮歡，愛花聊復客江干。", "月中欲與人爭瘦，雪後偷憑笛訴寒。", "野艇幽尋驚歲晚，紗巾亂插醉更闌。", "尤憐心事凄涼甚，結子青青亦带酸。"]'),
('9a6f495b-fb3d-49a3-8e5f-bc28c04c4baf','梅花四首  其二','陸游','宋','宋诗','song-poetry','','[]','月地雲階暗斷腸，知心誰解賞孤芳。',64,'全唐诗/poet.song.128000.json','["月地雲階暗斷腸，知心誰解賞孤芳。", "相逢只怪影亦好，歸去始驚身染香。", "渡口耐寒窺淨緑，橋邊凝怨立昏黄。", "與卿俱是江南客，剩欲尊前說故鄉。"]'),
('10a5d0fd-8f71-49e4-a719-44aabc9057ce','梅花四首  其三','陸游','宋','宋诗','song-poetry','','[]','玄冥行令肅冰霜，牆角疏梅特地芳。',64,'全唐诗/poet.song.128000.json','["玄冥行令肅冰霜，牆角疏梅特地芳。", "屑玉定煩修月户，堆金難買破天荒。", "了知一氣環無盡，坐笑千林凍欲僵。", "力量世間誰得似，挽回歲律放春陽。"]'),
('f1f61e5d-efe0-4790-a45c-83ff8e989335','梅花四首  其四','陸游','宋','宋诗','song-poetry','','[]','折得名花伴此翁，詩情恰在醉魂中。',64,'全唐诗/poet.song.128000.json','["折得名花伴此翁，詩情恰在醉魂中。", "高標不合塵凡有，尤物真窮造化功。", "霧雨更知仙骨别，鉛丹那悟色塵空。", "前身姑射疑君是，問道端須順下風。"]'),
('fb4e05d0-9708-4b4e-9f94-aa9685c1259e','西園','陸游','宋','宋诗','song-poetry','','[]','半掩朱門蘚徑斜，翠屏繡谷忽谽谺。',64,'全唐诗/poet.song.128000.json','["半掩朱門蘚徑斜，翠屏繡谷忽谽谺。", "高高下下天成景，密密疏疏自在花。", "江近夕陽迎宿鷺，林昏殘角促歸鴉。", "吾舟已繫津南岸，喚客猶能一笑譁。"]'),
('62f611bc-a4b7-4114-9adf-4e9e7b38dd7c','胡無人','陸游','宋','宋诗','song-poetry','','[]','鬚如蝟毛磔，面如紫石稜。',124,'全唐诗/poet.song.128000.json','["鬚如蝟毛磔，面如紫石稜。", "丈夫出門無萬里，風雲之會立可乘。", "追奔露宿青海月，奪城夜蹋黄河冰。", "鐵衣度磧雨颯颯，戰鼓上隴雷憑憑。", "三更窮虜送降欵，天明積甲如丘陵。", "中華初識汗血馬，東夷再貢霜毛鷹。", "群陰伏，太陽昇，胡無人，宋中興。", "丈夫報主有如此，笑人白首篷窗燈。"]'),
('82e66310-2d13-4687-978f-10a998135b55','公無渡河','陸游','宋','宋诗','song-poetry','','[]','大莫大於死生，親莫親於骨肉。',74,'全唐诗/poet.song.128000.json','["大莫大於死生，親莫親於骨肉。", "河不可憑兮非有難知，言之不從兮繼以痛哭。", "望雲九井兮白浪嵯峨，刳肝瀝血兮不從奈何。", "秋風颯颯兮紙錢投波，從公於死兮下飽蛟鼉。"]'),
('d75bf483-32fd-45fa-aa77-597b2b857af6','長門怨','陸游','宋','宋诗','song-poetry','','[]','寒風號有聲，寒日慘無暉。',72,'全唐诗/poet.song.128000.json','["寒風號有聲，寒日慘無暉。", "空房不敢恨，但懷歲暮悲。", "今年選後宫，連娟千蛾眉。", "早知獲譴速，悔不承恩遲。", "聲當徹九天，泪當達九泉。", "死猶復見思，生當長棄捐。"]'),
('e3ad3bb4-6c71-4bb4-bbfa-389eec97b597','長信宫詞','陸游','宋','宋诗','song-poetry','','[]','憶年十七兮初入未央，獲侍步輦兮恭承寵光。',160,'全唐诗/poet.song.128000.json','["憶年十七兮初入未央，獲侍步輦兮恭承寵光。", "地寒祚薄兮自貽不祥，讒言乘之兮罪釁日彰。", "禍來嵯峨兮勢如壤牆，當伏重誅兮鼎耳劍鋩。", "長信雖遠兮匪棄路旁，歲給絮帛兮月賜稻粱。", "君舉玉食兮犀箸誰嘗，君御朝衣兮誰進熏香。", "婕妤才人兮儼其分行，千秋萬歲兮永奉君王。", "妾雖益衰兮尚供蠶桑，願置繭館兮組織玄黄。", "欲訴不得兮仰呼蒼蒼，佩服忠貞兮之死敢忘。"]'),
('da9b4381-3764-4703-bd23-ddef4593ce0f','銅雀妓','陸游','宋','宋诗','song-poetry','','[]','武王在時教歌舞，那知泪灑西陵土。',64,'全唐诗/poet.song.128000.json','["武王在時教歌舞，那知泪灑西陵土。", "君已去兮妾獨生，生何樂兮死何苦。", "亦知從死非君意，偷生自是慚天地。", "長夜昏昏死實難，孰知妾死心所安。"]'),
('07da3558-ca2b-47ed-8a0f-39e4a4c66ef3','得韓无咎書寄使虜時宴東都驛中所作小闋','陸游','宋','宋诗','song-poetry','','[]','大梁二月杏花開，錦衣公子乘傳來。',96,'全唐诗/poet.song.128000.json','["大梁二月杏花開，錦衣公子乘傳來。", "桐陰滿地掃不得，金轡玲瓏上源驛。", "上源驛中搥畫鼓，漢使作客誰作主。", "舞女不記宣和粧，廬兒盡能女真語。", "書來寄我宴時詩，歸鬢知添幾縷絲。", "有志未須深感慨，築城會據拂雲祠。"]'),
('48ac1d76-584d-4a2d-a666-7f35930f0d23','曉坐','陸游','宋','宋诗','song-poetry','','[]','低枕孤衾夜氣存，披衣起坐黙忘言。',64,'全唐诗/poet.song.128000.json','["低枕孤衾夜氣存，披衣起坐黙忘言。", "缾花力盡無風墮，爐火灰深到曉温。", "空槖時時聞鼠齧，小窗一一送鴉翻。", "悠然忽記幽居日，下榻先開水際門。"]'),
('8e2c5ce2-17d4-40c0-bbd5-2f89978a1cdd','斷碑嘆','陸游','宋','宋诗','song-poetry','','[]','二蕭同起南蘭陵，正如文叔與伯升。',96,'全唐诗/poet.song.128000.json','["二蕭同起南蘭陵，正如文叔與伯升。", "至今人悲大蕭死，齎恨不見梁家興。", "崇崇之陵久爲谷，豈惟群盜分珠玉。", "斷碑槎牙棄道邊，文字班班猶可讀。", "剝剜苔蘚一悽然，俯仰人間幾變遷。", "世人作碑君勿哂，千載園林須石筍。"]'),
('91834db8-240f-4111-9f10-4c550bd5edd3','夜行至平羌憩大悲院','陸游','宋','宋诗','song-poetry','','[]','憶昨遊天台，夜投石橋宿。',96,'全唐诗/poet.song.128000.json','["憶昨遊天台，夜投石橋宿。", "水聲亂人語，炬火散山谷。", "穿林有驚鶻，截道多奔鹿。", "今夕復何夕，此境忽在目。", "蒼茫陂十里，清淺溪數曲。", "微霜結裘茸，落葉拂帽屋。", "下馬憩村寺，頹然睡清熟。", "覺來窗已白，殘燈猶煜煜。"]'),
('dda8ad80-22c8-4079-b96c-10648a33f09e','迓益帥馬上作','陸游','宋','宋诗','song-poetry','','[]','馬上遥看江上山，白雲紅樹畫圖間。',32,'全唐诗/poet.song.128000.json','["馬上遥看江上山，白雲紅樹畫圖間。", "經年簿領無休日，却向忙中得少閑。"]'),
('baba4ad1-bee1-4a4c-b474-e95cc10dfac2','蜀酒歌','陸游','宋','宋诗','song-poetry','','[]','漢州鵝黄鸞鳯雛，不鷙不搏德有餘。',128,'全唐诗/poet.song.128000.json','["漢州鵝黄鸞鳯雛，不鷙不搏德有餘。", "眉州玻瓈天馬駒，出門已無萬里塗。", "病夫少年夢清都，曾賜虚皇碧琳腴。", "文德殿門晨奏書，歸局黄封羅百壺。", "十年流落狂不除，遍走人間尋酒壚。", "青絲玉瓶到處酤，鵝黄玻瓈一滴無。", "安得豪士致連車，倒瓶不用杯與盂。", "琵琶如雷聒坐隅，不愁渴死老相如。"]'),
('a58002f2-b16b-4562-a0e4-0a371b5965d3','十一月八日夜燈下對梅花獨酌累日勞甚頗自慰也','陸游','宋','宋诗','song-poetry','','[]','奔走人間無已時，夜窗喜對出塵姿。',64,'全唐诗/poet.song.128000.json','["奔走人間無已時，夜窗喜對出塵姿。", "移燈看影憐渠瘦，掩户留香笑我癡。", "冷豔照杯欺麯蘖，孤標逼硯結冰澌。", "本來難入繁華社，莫向春風怨不知。"]'),
('d41bd651-2a5b-4680-b93b-b1ff109da1b1','醉後草書歌詩戲作','陸游','宋','宋诗','song-poetry','','[]','朱樓矯首隘八荒，緑酒一舉累百觴。',164,'全唐诗/poet.song.128000.json','["朱樓矯首隘八荒，緑酒一舉累百觴。", "洗我堆阜崢嶸之胸次，寫爲淋漓放縱之詞章。", "墨翻初若鬼神怒，字瘦忽作蛟螭僵。", "寶刀出匣揮雪刅，大舸破浪馳風檣。", "紙窮擲筆霹靂響，婦女驚走兒童藏。", "往時草檄喻西域，颯颯聲動中書堂。", "一收朝迹忽十載，西掠三巴窮夜郎。", "山川荒絕風俗異，賴有酒美猶能狂。", "醉中自脱頭上幘，緑髮未許侵微霜。", "人生得喪良細事，孰謂老大多悲傷。"]'),
('8c81331c-7860-4ff5-b230-a2ed6e6c6555','古藤杖歌','陸游','宋','宋诗','song-poetry','','[]','我有古藤杖，夭矯蛟龍形。',94,'全唐诗/poet.song.128000.json','["我有古藤杖，夭矯蛟龍形。", "生於峭壁絕磵上，乃是會稽山陰之蘭亭。", "歴吳入楚上巴硤，北遊直看秦山青。", "夜飛或隨暴雨去，旦歸常带流漦腥。", "與子扶攜各老大，勿復狡獪誇神靈。", "愔愔從此常倚壁，聽我夜誦黄庭經。"]'),
('6badfca0-fe30-4f86-a9fb-a920293e6c6a','歲晚書懷','陸游','宋','宋诗','song-poetry','','[]','殘歲堂堂去，新春鼎鼎來。',48,'全唐诗/poet.song.128000.json','["殘歲堂堂去，新春鼎鼎來。", "夢移鄉國近，酒挽壯心回。", "暖律初催柳，晴光併上梅。", "東湖有歸日，衰抱得頻開。"]'),
('c376c3f2-9a76-44dc-86e8-c8469a410517','累日倦甚不能觴客睡起戲作','陸游','宋','宋诗','song-poetry','','[]','粉闇紅蔫罇爼薄，不如止酒得安眠。',64,'全唐诗/poet.song.128000.json','["粉闇紅蔫罇爼薄，不如止酒得安眠。", "無心已破浮生夢，有力聊輕造化權。", "脱髮滿梳真老矣，斷香縈几故翛然。", "晚知古佛中邊語，正合蒙莊內外篇。"]'),
('ca5802c5-4dfc-4eda-a62b-091e9ea76226','種花','陸游','宋','宋诗','song-poetry','','[]','西園作戲喚春回，桃李陰陰三萬栽。',32,'全唐诗/poet.song.128000.json','["西園作戲喚春回，桃李陰陰三萬栽。", "不是無心看開遍，錦江烟柳待歸來。"]'),
('730b0f96-aabc-424e-9b0a-eb919f629086','雨中登樓望大像','陸游','宋','宋诗','song-poetry','','[]','去年寒雨中，騎驢度劍閣。',96,'全唐诗/poet.song.128000.json','["去年寒雨中，騎驢度劍閣。", "今年當此時，臥聽邊城柝。", "巍巍千尺像，與我兩寂寞。", "交遊閲四海，此老差可託。", "但當頻自省，諸惡誓莫作。", "時時一憑高，相望要不怍。", "桑間戒三宿，堅坐豈渠樂。", "却應輸老夫，新春買芒屩。"]'),
('37438f0f-0752-414a-89b1-291f8091e8d8','迎赦呈王志夫李德孺師伯渾','陸游','宋','宋诗','song-poetry','','[]','平明置騎傳詔函，帝意欲與東皇參。',128,'全唐诗/poet.song.128000.json','["平明置騎傳詔函，帝意欲與東皇參。", "青城回仗國人喜，金雞銜赦天恩覃。", "吾君愛民靡不到，黄紙字密如吳蠶。", "紀元故事極用九，聖政盡美方登三。", "嗟余久已去魏闕，夢想豹尾猶毿毿。", "過郊一月方拜赦，始知身落天西南。", "歡呼已怪衰病愈，蹈舞更覺春風酣。", "何當與子歸共載，二月起柁江如藍。"]'),
('250f9404-3b40-4cb3-8492-d9db90064cb6','冬日','陸游','宋','宋诗','song-poetry','','[]','幸是元無了事癡，偷閑聊復學兒嬉。',64,'全唐诗/poet.song.128000.json','["幸是元無了事癡，偷閑聊復學兒嬉。", "午窗弄筆臨唐帖，夜几研朱勘楚詞。", "山暖已無梅可折，江清猶有蟹堪持。", "舊交乖隔音塵斷，安得歌呼共一卮。"]'),
('114a1bce-9341-43f8-97ae-e6121ddff9a0','雨中睡起','陸游','宋','宋诗','song-poetry','','[]','磔磔寒禽無定棲，纖纖小雨欲成泥。',64,'全唐诗/poet.song.128000.json','["磔磔寒禽無定棲，纖纖小雨欲成泥。", "松鳴湯鼎茶初熟，雪積爐灰火漸低。", "一氣推移均野馬，百年蒙覆等醯雞。", "青山黄葉蘭亭路，憶喚鄰翁共架犂。"]'),
('bfdd02c5-7b8d-4b49-ad71-ddbdf0259abc','十二月初一日得梅一枝絕奇戲作長句今年於是四賦此花矣','陸游','宋','宋诗','song-poetry','','[]','高標已壓萬花群，尚恐嬌春習氣存。',64,'全唐诗/poet.song.128000.json','["高標已壓萬花群，尚恐嬌春習氣存。", "月兔擣霜供換骨，湘娥鼓瑟爲招魂。", "孤城小驛初飛雪，斷角殘鐘半掩門。", "盡意端相終有恨，夜寒皴玉倩誰温。"]'),
('fc9f3e69-4119-418d-b345-92be7f9da111','無題','陸游','宋','宋诗','song-poetry','','[]','畫閣無人晝漏稀，離悰病思兩依依。',64,'全唐诗/poet.song.128000.json','["畫閣無人晝漏稀，離悰病思兩依依。", "釵梁雙燕春先到，箏柱羈鴻暖不歸。", "迎得紫姑占近信，裁成白紵寄征衣。", "晚來更就鄰姬問，夢到遼陽果是非。"]'),
('b4a24bb2-f260-40bf-8d0d-5275dc70425d','快晴','陸游','宋','宋诗','song-poetry','','[]','地闢天開斗柄回，今朝紅日遍池臺。',64,'全唐诗/poet.song.128000.json','["地闢天開斗柄回，今朝紅日遍池臺。", "新陽蘇醒春前柳，輕暖醫治雪後梅。", "瓦屋螺青披霧出，錦江鴨緑抱山來。", "衰翁也逐兒童喜，旋撥文書近酒杯。"]'),
('79257a02-0d51-4b7b-b552-7148b23c950d','獨坐','陸游','宋','宋诗','song-poetry','','[]','巾帽欹傾短髮稀，青燈照影夜相依。',64,'全唐诗/poet.song.128000.json','["巾帽欹傾短髮稀，青燈照影夜相依。", "窮邊草木春遲到，故國湖山夢自歸。", "茶鼎松風吹謖謖，香奩雲縷散馡馡。", "羸驂敢復和鑾望，只願連山苜蓿肥。"]'),
('dbcd40f4-658d-411c-a76b-7b4e7b7e4ff4','十二月十一日視築堤','陸游','宋','宋诗','song-poetry','','[]','江水來自蠻夷中，五月六月聲摩空。',144,'全唐诗/poet.song.128000.json','["江水來自蠻夷中，五月六月聲摩空。", "巨魚穹龜牙鬚雄，欲取闤市爲龍宫。", "横隄百丈臥霽虹，始誰築此東平公。", "今年樂哉適歲豐，吏不相倚勇赴功。", "西山大竹織萬籠，船舸載石來亡窮。", "横陳屹立相疊重，置力尤在水廟東。", "我登高原相其衝，一盾可愛百箭攻。", "蜿蜿其長高隆隆，截如長城限羌戎。", "安得椽筆記始終，插江石崖堅可礲。"]'),
('b38c328d-feb6-4b33-8c60-ae2477eaa9c0','題龍鶴菜帖','陸游','宋','宋诗','song-poetry','','[]','先生直玉堂，日羞太官羊。',72,'全唐诗/poet.song.128000.json','["先生直玉堂，日羞太官羊。", "如何夢故山，曉枕春蔬香。", "春蔬尚云爾，況我舊朋友。", "萬里一紙書，殷勤問安否。", "先生高世人，獨恨不早歸。", "坐令龍鶴菜，猶愧首陽薇。"]'),
('d9412a11-0386-46e4-9947-c0c5173b7c21','春愁曲','陸游','宋','宋诗','song-poetry','','[]','虙羲至今三十餘萬歲，春秋歲歲常相似。',98,'全唐诗/poet.song.128000.json','["虙羲至今三十餘萬歲，春秋歲歲常相似。", "外大瀛海環九洲，無有一洲無此愁。", "我願無愁但歡樂，朱顔緑鬢常如昨。", "金丹九轉徒可聞，玉兔千年空擣藥。", "蜀姬雙鬟婭姹嬌，醉看恐是海棠妖。", "世間無處無愁到，底事難過萬里橋。"]'),
('09a3d4a3-b746-4179-a912-9a6545d51f6a','荀秀才送蠟梅十枝奇甚爲賦此詩','陸游','宋','宋诗','song-poetry','','[]','與梅同譜又同時，我爲評香似更奇。',64,'全唐诗/poet.song.128000.json','["與梅同譜又同時，我爲評香似更奇。", "痛飲便判千日醉，清狂頓減十年衰。", "色疑初割蜂脾蜜，影欲平欺鶴膝枝。", "插向寶壺猶未稱，合將金屋貯幽姿。"]'),
('e5b7f158-943b-422f-bf5c-b358324609ff','離嘉州宿平羌','陸游','宋','宋诗','song-poetry','','[]','初挈囊衣宿水村，蕭然一掃舊巢痕。',64,'全唐诗/poet.song.128000.json','["初挈囊衣宿水村，蕭然一掃舊巢痕。", "本來信手忘工拙，却爲無心少怨恩。", "自笑遠遊諳馬上，已營小築老雲根。", "淡烟疏雨平羌路，便恐從今入夢魂。"]'),
('eb088ef1-0062-4148-9365-a12cebdc0c5f','瑞草橋道中作','陸游','宋','宋诗','song-poetry','','[]','經年簿書無少暇，欵段今朝欣一跨。',160,'全唐诗/poet.song.128000.json','["經年簿書無少暇，欵段今朝欣一跨。", "瑞草橋邊水亂流，青衣渡口山如畫。", "老翁醉著看龍鍾，小婦出窺聞婭奼。", "荒陂吹笛晚呼牛，古路倚梯晨采柘。", "殘花零落不禁折，香草芉茸如可藉。", "郵亭慈竹筍穿籬，野店蒲萄枝上架。", "功名垂世端有數，利欲昏心喜乘罅。", "羈窮自笑豈人謀，閑放每欲從天借。", "草根蟲語秪自悲，風裏篷征安稅駕。", "祖師補處浣花村，會傍清江結茆舍。"]'),
('4b507d2f-5798-419a-a230-9ef9ebfe01c6','遊修覺寺','陸游','宋','宋诗','song-poetry','','[]','上盡蒼崖百級梯，詩囊香椀手親攜。',64,'全唐诗/poet.song.128000.json','["上盡蒼崖百級梯，詩囊香椀手親攜。", "山從飛鳥行邊出，天向平蕪盡處低。", "花落忽驚春事晚，樓高剩覺客魂迷。", "興闌掃榻禪房臥，清夢還應到剡溪。"]'),
('950fb522-54ff-4044-a0bb-abc6fe0a581e','晚步湖上','陸游','宋','宋诗','song-poetry','','[]','雲薄漏春暉，湖空弄夕霏。',48,'全唐诗/poet.song.128000.json','["雲薄漏春暉，湖空弄夕霏。", "沾泥花半落，掠水燕交飛。", "小倦聊扶策，新晴旋減衣。", "幽尋殊未已，畫角喚人歸。"]'),
('d2a269c8-e32b-49ce-832e-dc8c92ead309','暮春','陸游','宋','宋诗','song-poetry','','[]','忙裏偷閑慰晚途，春來日日在東湖。',64,'全唐诗/poet.song.128000.json','["忙裏偷閑慰晚途，春來日日在東湖。", "凭欄投飯看魚隊，挾彈驚鴉護雀雛。", "俗態似看花爛漫，病身能鬭竹清癯。", "一樽是處成幽賞，風月隨人不用呼。"]'),
('a8f0b13d-2dc2-48d4-a2f7-8759fc2a8d54','池上醉歌','陸游','宋','宋诗','song-poetry','','[]','我欲築化人中天之臺，下視四海皆飛埃。',132,'全唐诗/poet.song.128000.json','["我欲築化人中天之臺，下視四海皆飛埃。", "又欲造方士入海之舟，破浪萬里求蓬萊。", "取日挂向扶桑枝，留春挽回北斗魁。", "横笛三尺作龍吟，腰鼓百面聲轉雷。", "飲如長鯨海可竭，玉山不倒高崔嵬。", "半酣脱幘髮尚緑，壯心未肻成低摧。", "我妓今朝如花月，古人白骨生蒼苔。", "後當視今如視古，對酒惜醉何爲哉。"]'),
('863a2383-8e2c-4121-8585-38666557a060','四月五夜見螢','陸游','宋','宋诗','song-poetry','','[]','蜀州官居富水竹，四月螢火遶梁飛。',32,'全唐诗/poet.song.128000.json','["蜀州官居富水竹，四月螢火遶梁飛。", "流年迫人不相貸，客子倦遊何日歸。"]'),
('dec491a4-4b12-4e2d-a3d5-d42590c6770f','塞上曲','陸游','宋','宋诗','song-poetry','','[]','三尺鐵如意，一枝玉馬鞭。',96,'全唐诗/poet.song.128000.json','["三尺鐵如意，一枝玉馬鞭。", "笑把出門去，萬里行無前。", "當道何崔嵬，云是玉門關。", "方當置屯守，征人何時還。", "馬色如雜花，鎧光若流水。", "肅肅不敢譁，遥望但塵起。", "日落戍火青，烟重塞垣紫。", "回首五湖秋，西風開芡觜。"]'),
('c9fdf006-537f-4a41-93fc-c30d254fae93','夜聞塔鈴及泉聲','陸游','宋','宋诗','song-poetry','','[]','山泉瀉幽竇，塔鈴揺天風。',72,'全唐诗/poet.song.128000.json','["山泉瀉幽竇，塔鈴揺天風。", "清音無時盡，靜夜尤璁瓏。", "嗟我走紅塵，市聲聒欲聾。", "多生耳根業，賴此一洗空。", "夢騎白鳯凰，佩玉朝珠宫。", "覺來撫枕嘆，月滿草堂中。"]'),
('abb239f7-0257-4749-b940-e98893455bac','曉嘆','陸游','宋','宋诗','song-poetry','','[]','一鴉飛鳴窗已白，推枕欲起先嘆息。',160,'全唐诗/poet.song.128000.json','["一鴉飛鳴窗已白，推枕欲起先嘆息。", "翠華東巡五十年，赤縣神州滿戎狄。", "主憂臣辱古所云，世間有粟吾得食。", "少年論兵實狂妄，諫官劾奏當竄殛。", "不爲孤囚死嶺海，君恩如天豈終極。", "容身有禄愧滿顔，滅賊無期泪横臆。", "未聞含桃薦宗廟，至今銅駞没荆棘。", "幽并從古多烈士，悒悒可令長失職。", "王師入秦駐一月，傳檄足定河南北。", "安得揚鞭出散關，下令一變旌旗色。"]'),
('1b49d4cc-854b-4e0c-853a-e18669dd09a3','苦筍','陸游','宋','宋诗','song-poetry','','[]','藜藿盤中忽眼明，駢頭脱襁白玉嬰。',64,'全唐诗/poet.song.128000.json','["藜藿盤中忽眼明，駢頭脱襁白玉嬰。", "極知耿介種性别，苦節乃與生俱生。", "我見魏徴殊媚嫵，約束兒童勿多取。", "人才自古要養成，放使干霄戰風雨。"]'),
('25bde8ca-d8f6-48c0-8468-833881580848','月下作二首  其一','陸游','宋','宋诗','song-poetry','','[]','池上迎微風，柏間蹋涼月。',120,'全唐诗/poet.song.128000.json','["池上迎微風，柏間蹋涼月。", "冷然醉夢醒，一洗煩惱熱。", "嗟予世外人，火食常嘔噎。", "易求雲表露，難覓大古雪。", "況欲試秘方，瓊漿和玉屑。", "俛首居俗間，愁若鷹在紲。", "惟兹服月芒，比歲稍得訣。", "但令天無雲，豈復計圜缺。", "玉鈎定誰挂，冰輪了無轍。", "詩成獨高詠，靈府炯澄澈。"]'),
('1f96be0a-49fb-413f-8993-903cf12cd738','月下作二首  其二','陸游','宋','宋诗','song-poetry','','[]','畏暑不巾襪，步月搘短笻。',120,'全唐诗/poet.song.128000.json','["畏暑不巾襪，步月搘短笻。", "瘦身髮鬅鬙，顧影如孤松。", "徑幽螢開闔，池漲魚噞喁。", "飛泉穿北垣，珠玉相撞舂。", "東湖更奇絕，百畆銀初鎔。", "但能抱琴往，絕恨欠鶴從。", "重露傾荷盤，微風墮芙蓉。", "歡言美清夜，縹渺吹疏鐘。", "空中飛僊人，粲然冰雪容。", "笑我老塵世，不記瑶臺逢。"]'),
('1a9ef8b0-4787-4610-ac11-f08cf81ac5e5','小宴','陸游','宋','宋诗','song-poetry','','[]','洗君鸚鵡杯，酌我蒲萄醅。',48,'全唐诗/poet.song.128000.json','["洗君鸚鵡杯，酌我蒲萄醅。", "冒雨鶯不去，過春花續開。", "英雄漫青史，富貴亦黄埃。", "今夕湖邊醉，還須秉燭回。"]'),
('814eeb25-2199-481b-8a55-70b8905b6a30','小閣納涼','陸游','宋','宋诗','song-poetry','','[]','侵床月白病全蘇，掠面風清酒欲無。',64,'全唐诗/poet.song.128000.json','["侵床月白病全蘇，掠面風清酒欲無。", "渺渺塘陰下鷗鷺，蕭蕭秋意滿菰蒲。", "縱輸烟渡横孤艇，也勝京塵暗九衢。", "莫遣良工更摹寫，此詩端是臥遊圖。"]'),
('e95cc1c2-a900-45e7-96dd-c18f34378067','晨雨','陸游','宋','宋诗','song-poetry','','[]','揮汗驅蚊廢夜眠，清晨一雨便翛然。',64,'全唐诗/poet.song.128000.json','["揮汗驅蚊廢夜眠，清晨一雨便翛然。", "涼生池閣衣巾爽，潤入園林草木鮮。", "青蒻雲腴開鬭茗，翠甖玉液取寒泉。", "飯餘一枕華胥夢，不怪門生笑腹便。"]'),
('2c7142f2-fe95-4f38-9c96-d29619cdd02b','湖上筍盛出戲作長句','陸游','宋','宋诗','song-poetry','','[]','𧥄𧥄穿苔瑇瑁簪，按行日夜待成林。',64,'全唐诗/poet.song.128000.json','["𧥄𧥄穿苔瑇瑁簪，按行日夜待成林。", "養渠百尺干霄氣，見我平生及物心。", "剩插藩籬憂玉折，豫期風雨聽龍吟。", "明年又徙囊衣去，誰與平安報好音。"]'),
('9101938b-4fea-4d43-9e51-b1762cb96964','雨後集湖上','陸游','宋','宋诗','song-poetry','','[]','野水交流自滿畦，芳池新漲恰平堤。',64,'全唐诗/poet.song.128000.json','["野水交流自滿畦，芳池新漲恰平堤。", "花藏密葉多時在，鶯占高枝盡日啼。", "繡袂寶裙催結束，金尊翠杓共提攜。", "白頭自喜能狂在，笑襞蠻牋落醉題。"]'),
('bf8b55e1-f594-4bd6-8c5c-33b984e1f500','過大蓬嶺度繩橋至杜秀才山莊','陸游','宋','宋诗','song-poetry','','[]','度筰臨千仞，梯山躡半空。',72,'全唐诗/poet.song.128000.json','["度筰臨千仞，梯山躡半空。", "濕雲朝莫雨，陰壑古今風。", "亭觀參差見，闌干詰曲通。", "柳空叢篠出，松偃翠蘿蒙。", "負籠銀釵女，鉏畬鶴髮翁。", "何由有餘俸，小築此山中。"]'),
('2834b152-0894-4c22-83e3-5fdd649ea07f','宿杜氏莊晨起遇雨','陸游','宋','宋诗','song-poetry','','[]','怪藤十圍蔽白日，老木千尺干青霄。',64,'全唐诗/poet.song.128000.json','["怪藤十圍蔽白日，老木千尺干青霄。", "水泛戞灘竹作舫，陸行跨空繩繫橋。", "陰陰古屋精靈語，慘慘江雲蛟鰐驕。", "吾道非耶行至此，諸公正散紫宸朝。"]'),
('ccc82594-58c8-458b-8ed4-9e7d71329469','翠圍院','陸游','宋','宋诗','song-poetry','','[]','曉入翠圍寺，擁門千萬峰。',48,'全唐诗/poet.song.128000.json','["曉入翠圍寺，擁門千萬峰。", "山空鳥自命，林茂鹿相從。", "嫋嫋風中筰，昏昏雲外鐘。", "將歸興未盡，清嘯倚長松。"]'),
('7cf1b303-4cdd-4b9c-b57d-7cf1f13d3098','野飯','陸游','宋','宋诗','song-poetry','','[]','薏實炊明珠，苦筍饌白玉。',120,'全唐诗/poet.song.128000.json','["薏實炊明珠，苦筍饌白玉。", "輪囷斸區芋，芳辛采山蔌。", "山深少鹽酪，淡薄至味足。", "往往八十翁，登山逐奔鹿。", "可憐城南社，零落依澗曲。", "面餘作詩瘦，趨拜尚不俗。", "病夫益倦遊，頗願老窮谷。", "是家吾所慕，食菜如食肉。", "時能喚鄰里，小甕酒新漉。", "何必懷故鄉，下箸厭雁鶩。"]'),
('f549141d-af97-4e23-964d-43ff74a59390','化成院','陸游','宋','宋诗','song-poetry','','[]','翠圍至化成，七里幾千盤。',144,'全唐诗/poet.song.128000.json','["翠圍至化成，七里幾千盤。", "肩輿掀濘淖，嘆息行路難。", "緣坡忽入谷，蜒蜿蒼龍蟠。", "孤塔插空起，雙柟當夏寒。", "飛屐到上方，漸覺所見寬。", "前山横一几，稻陂白漫漫。", "肥僧大腰腹，呀喘趨迎官。", "走疾不得語，坐定汗未乾。", "高人遺世事，跏趺穴蒲團。", "作此望塵態，豈如返巾冠。", "日落聞鹿鳴，感我平生歡。", "客遊殊未已，芳歲行當闌。"]'),
('952dad54-25a6-491b-9f4d-17c11d3a05f3','慈雲院東閣小憩','陸游','宋','宋诗','song-poetry','','[]','横閣院東偏，翛然拂榻眠。',48,'全唐诗/poet.song.128000.json','["横閣院東偏，翛然拂榻眠。", "香濃烟穗直，茶嫰乳花圓。", "巖倚團團桂，筒分細細泉。", "憑誰爲題版，牓作小壺天。"]'),
('8c74ad3b-6cec-4094-a250-1323eb628af5','遊靈鷲寺堂中僧闐然獨作禮開山定心尊者尊者唐人有問法者輒點胸示之時號點點和尚','陸游','宋','宋诗','song-poetry','','[]','半世吳松理釣絲，蜀山著脚豈前知。',64,'全唐诗/poet.song.128000.json','["半世吳松理釣絲，蜀山著脚豈前知。", "雲堂已散三三衆，卵塔空尋點點師。", "戴雪數峰臨峭絕，浮花一水舞淪漪。", "勞生未盡能重到，應掃流塵讀此詩。"]'),
('1e868e4f-0394-4ddc-a09f-6cf323b0b690','桃源','陸游','宋','宋诗','song-poetry','','[]','木缺橋横一徑微，斷烟殘靄晚霏霏。',64,'全唐诗/poet.song.128000.json','["木缺橋横一徑微，斷烟殘靄晚霏霏。", "十年勌客明雙眼，五月遊人換夾衣。", "翠峽束成寒練靜，蒼崖濺落素鮫飛。", "爾來自笑癡頑甚，著處吟哦不記歸。"]'),
('ecde9f0d-0a46-4f20-9342-41a1f7c87703','白塔院','陸游','宋','宋诗','song-poetry','','[]','冷翠千竿玉，浮嵐萬幅屏。',48,'全唐诗/poet.song.128000.json','["冷翠千竿玉，浮嵐萬幅屏。", "凭欄避微雨，挈笠遇歸僧。", "殘日明樓角，屯雲擁塔層。", "溪山屬閑客，隨意倚枯藤。"]'),
('5bb75726-9ccb-4f7d-adb2-56be3129b036','急雨','陸游','宋','宋诗','song-poetry','','[]','炎炎赤日當空燒，簿書圍坐如居窰。',96,'全唐诗/poet.song.128000.json','["炎炎赤日當空燒，簿書圍坐如居窰。", "黑雲壓簷忽岧嶤，急雨鼎來風駕潮。", "彈壓旱氣蘇枯焦，祝融退聽不敢驕。", "父老歌舞看稻苗，殺雞買酒更相邀。", "我亦巾褐涼蕭蕭，酒醒點滴聞梧蕉。", "珍簟不御扇罷揺，安用萬里登凌歊。"]'),
('1f29b5a2-4060-495a-a1b4-8c8510e1e19a','東湖新竹','陸游','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u7af9\u5b50", "\u548f\u7269"]','插棘編籬謹護持，養成寒碧映淪漪。',64,'全唐诗/poet.song.128000.json','["插棘編籬謹護持，養成寒碧映淪漪。", "清風掠地秋先到，赤日行天午不知。", "解籜時聞聲簌簌，放梢初見葉離離。", "官閑我欲頻來此，枕簟仍教到處隨。"]'),
('dd427525-df34-4041-9e15-e329608704f5','睡起試茶','陸游','宋','宋诗','song-poetry','','[]','笛材細織含風漪，蟬翼新裁雲碧帷。',66,'全唐诗/poet.song.128000.json','["笛材細織含風漪，蟬翼新裁雲碧帷。", "端谿硯璞斵作枕，素屏畫出月墮空江時。", "朱欄碧甃玉色井，自候銀缾試蒙頂。", "門前剝啄不嫌渠，但恨此味無人領。"]'),
('e4229c14-b0f3-43e9-87ba-2288d55fe0fa','五月五日蜀州放解牓第一人楊鑑具慶下孤生愴然有感','陸游','宋','宋诗','song-poetry','','[]','甲午五月之庚寅，淵魚躍起三江津。',144,'全唐诗/poet.song.128000.json','["甲午五月之庚寅，淵魚躍起三江津。", "震雷霔雨夜達晨，我知决定非凡鱗。", "人生富貴不逮親，萬鍾五鼎空酸辛。", "少年得禄羞常珍，調節滋味躬爨薪。", "徹食奉盥授帨巾，此樂豈復論賤貧。", "嗟我不孝負鬼神，俯仰二紀悲如新。", "仕宦空飽息與嬪，左右供養無復辰。", "子行射策對楓宸，綵衣楚楚映華紳。", "泝江亟歸娛老人，切勿著意長安春。"]'),
('57b5c776-a3ce-4415-86e2-6c92c112b55b','病酒新愈獨臥蘋風閣戲書','陸游','宋','宋诗','song-poetry','','[]','用酒驅愁如伐國，敵雖摧破吾亦病。',96,'全唐诗/poet.song.128000.json','["用酒驅愁如伐國，敵雖摧破吾亦病。", "狂呼起舞先自困，閉户垂帷真廟勝。", "今朝屏事臥湖邊，不但心空兼耳靜。", "自燒沉水瀹紫筍，聊遣森嚴配堅正。", "追思昨日乃可笑，倚醉題詩恣豪横。", "逝從屈子學獨醒，免使曹公怪中聖。"]'),
('4e435bcd-5c9c-4b88-a076-9ce44379dcca','神君歌','陸游','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰山可爲礪，東海可揚塵。',178,'全唐诗/poet.song.128000.json','["泰山可爲礪，東海可揚塵。", "惟有壯士志，死生要一伸。", "我夢神君自天下，威儀奕奕難具陳。", "飛龍駕車不用馬，訶前殿後皆鬼神。", "奇形詭狀密如魚鱗，𧥄𧥄齾齾爭扶車輪。", "黑纛白旄其來無垠，黄霧紫氛合散輪囷。", "考録魑魅號呼吟呻，約束蛟螭夭矯服馴。", "後車百兩載美人，巾褠鮮麗工笑顰。", "金尊翠杓溢芳醇，琵琶箜篌飾怪珍。", "世間局促常悲辛，神君歡樂千萬春。", "嗚呼生不封侯死廟食，丈夫豈得抱志長黙黙。"]'),
('c53af92e-bdd2-4abb-8b5b-452973cf8794','讀胡基仲舊詩有感','陸游','宋','宋诗','song-poetry','','[]','少日飛騰翰墨塲，暮年相見尚昻藏。',64,'全唐诗/poet.song.128000.json','["少日飛騰翰墨塲，暮年相見尚昻藏。", "沈沙舟畔千帆過，剪翮籠邊百鳥翔。", "訪古毎思春並轡，說詩仍記夜連床。", "匆匆去日多於髮，不獨悲君亦自傷。"]'),
('52a5caa1-01f8-4b85-9c67-5aebb2161fde','夏日湖上','陸游','宋','宋诗','song-poetry','','[]','烏帽笻枝散客愁，不妨胥史雜沙鷗。',64,'全唐诗/poet.song.128000.json','["烏帽笻枝散客愁，不妨胥史雜沙鷗。", "迎風枕簟平欺暑，近水簾櫳探借秋。", "茶竈遠從林下見，釣筒常向月中收。", "江湖四十餘年夢，豈信人間有蜀州。"]'),
('29d3a2ef-7933-4b1c-9306-461e7702d436','對酒嘆','陸游','宋','宋诗','song-poetry','','[]','鏡雖明不能使醜者妍，酒雖美不能使悲者樂。',176,'全唐诗/poet.song.128000.json','["鏡雖明不能使醜者妍，酒雖美不能使悲者樂。", "男子之生桑弧蓬矢射四方，古人所懷何磊落。", "我欲北臨黄河觀禹功，干戈不息塵漠漠。", "又欲南適蒼梧吊虞舜，九疑難尋眇聨絡。", "惟有一片心，可受生死託。", "千金輕擲重意氣，百舍孤征赴然諾。", "或攜短劍隠紅塵，亦入名山燒大藥。", "兒女何足顧，歲月不貸人。", "黑貂十年弊，白髮一朝新。", "半酣耿耿不自得，清嘯長歌裂金石。", "曲終四座慘悲風，人人掩泪無人色。"]'),
('b6f14989-b153-41dd-b3f6-3207f306f713','病後暑雨書懷','陸游','宋','宋诗','song-poetry','','[]','髮毛蕭颯疾初平，雲物輪囷氣未清。',64,'全唐诗/poet.song.128000.json','["髮毛蕭颯疾初平，雲物輪囷氣未清。", "水漲小亭無路到，雨多幽草上牆生。", "窗昏頓減讐書課，屋老時聞墮瓦聲。", "止酒無聊還自笑，少年豪飲似長鯨。"]'),
('5a3f97ba-8a7e-49bc-afe3-c353014b4ae9','雨聲','陸游','宋','宋诗','song-poetry','','[]','暑氣滿天地，薄暮加煩促。',56,'全唐诗/poet.song.128000.json','["暑氣滿天地，薄暮加煩促。", "清風吹急雨，集我北窗竹。", "竹聲蕭蕭固自奇，況得雨聲相發揮。", "令人忽憶雲門寺，半夜長松墮雪時。"]'),
('f3db800b-3fe7-482a-8d54-1bce5dc5c157','同何元立賞荷花追懷鏡湖舊遊','陸游','宋','宋诗','song-poetry','','[]','少狂欺酒氣吐虹，一笑未了千觴空。',128,'全唐诗/poet.song.128000.json','["少狂欺酒氣吐虹，一笑未了千觴空。", "涼堂下簾人似玉，月色泠泠透湘竹。", "三更畫船穿藕花，花爲四壁船爲家。", "不須更踏花底藕，但嗅花香已無酒。", "花深不見畫船行，天風空吹白紵聲。", "雙槳歸來弄湖水，往往湖邊人已起。", "即今憔悴不堪論，賴有何郎共此尊。", "紅緑疏疏君勿嘆，漢嘉去歲無荷看。"]'),
('5e0d7c44-d7fb-4e5d-bd9b-6468134b5632','小樓','陸游','宋','宋诗','song-poetry','','[]','吾州近在西山麓，雪山萬仞臨冰谷。',96,'全唐诗/poet.song.128000.json','["吾州近在西山麓，雪山萬仞臨冰谷。", "小樓森森閲三伏，清簟疏簾對棋局。", "肌膚凄凜起芒粟，肝肺崢嶸疊瓊玉。", "香泉向夕初罷浴，桐竹生風吹細縠。", "九衢憧憧車擊轂，黄塵赤日汗可掬。", "還家欲休客陸續，借與此詩令一讀。"]'),
('e309652f-cd0d-4b0b-93af-4dcde76bb11e','怡齋','陸游','宋','宋诗','song-poetry','','[]','東湖仲夏草樹荒，屋古無人亭午涼。',128,'全唐诗/poet.song.128000.json','["東湖仲夏草樹荒，屋古無人亭午涼。", "萱房微呀不見日，筍籜自解時吹香。", "野藤蟠屈入窗罅，溼菌扶疏生屋梁。", "跨溝數椽最幽翳，漲水及檻雨敗牆。", "靜涵青蘋舞藻荇，閑立白鷺浮鴛鴦。", "芙蕖雖瘦亦瀰漫，照眼翠蓋遮紅粧。", "水紋珍簟欲卷却，團團素扇懶復將。", "天風忽送塔鈴語，喚覺清夢遊瀟湘。"]'),
('262f8075-4fdb-4da4-bd9f-4bdc1ba951cc','龍湫歌','陸游','宋','宋诗','song-poetry','','[]','環湫巨木老不花，奫淪千尺龍所家。',128,'全唐诗/poet.song.128000.json','["環湫巨木老不花，奫淪千尺龍所家。", "爪痕入木欲數寸，觀者心掉不敢譁。", "去年大旱綿千里，禾不立苗麥垂死。", "林神社鬼無奈何，老龍欠伸徐一起。", "隆隆之雷浩浩風，倒卷江水傾虚空。", "鱗間出火作飛電，金蛇夜掣層雲中。", "明朝父老來賽雨，大巫吹簫小巫舞。", "祠門人散月姢姢，龍歸抱珠湫底眠。"]'),
('c772f4ee-0455-4e00-ba9a-c17bbad6a4cb','月夕','陸游','宋','宋诗','song-poetry','','[]','我昔隠天台，夜半遊句曲。',124,'全唐诗/poet.song.128000.json','["我昔隠天台，夜半遊句曲。", "弄月過垂虹，萬頃一片玉。", "烟艇起菱唱，水風吹釣絲。", "更欲小徙倚，恐失初平期。", "今年遊青城，三十六峰巒。", "白雲反在下，使我毛骨寒。", "天如玻璃鍾，倒覆溼銀海。", "素璧行其間，草木盡光彩。", "姮娥顧我笑，手撫玉兔兒。", "莫怪世人生白髮，秋風桂老欲無枝。"]'),
('4698aa5f-57a0-4cda-b7fc-b0182184f656','蒸暑思梁州述懷','陸游','宋','宋诗','song-poetry','','[]','宣和之末予始生，遭亂不及遊司并。',192,'全唐诗/poet.song.128000.json','["宣和之末予始生，遭亂不及遊司并。", "從軍梁州亦少慰，土脉深厚泉流清。", "季秋嶺谷浩積雪，二月草木初抽萌。", "夏中高涼最可喜，不省舉手驅蟁蝱。", "藏冰一出賣滿市，玉璞堆積寒崢嶸。", "柳陰夜臥千駟馬，沙上露宿連營兵。", "胡笳吹墮漾水月，烽燧傳到山南城。", "最思出甲戍秦隴，戈戟徹夜相摩聲。", "兩年劍南走塵土，肺熱煩促無時平。", "荒池昏夜蛙閤閤，食案白日蠅營營。", "何時王師自天下，雷雨澒洞收攙搶。", "老生衰病畏暑濕，思卜鄠杜開柴荆。"]'),
('ffd54bd7-5d3c-4468-85e9-26a97bea67cf','湖上晚歸','陸游','宋','宋诗','song-poetry','','[]','地僻多幽事，官閑慰古心。',48,'全唐诗/poet.song.128000.json','["地僻多幽事，官閑慰古心。", "晚花藏密葉，新筍補疏林。", "碩果畦丁獻，芳醪稚子斟。", "碧雲遮日盡，歸路更蕭森。"]'),
('5e7b32bb-563b-4c3d-baf1-62f964bbfcc8','秋聲','陸游','宋','宋诗','song-poetry','','[]','人言悲秋難爲情，我喜枕上聞秋聲。',96,'全唐诗/poet.song.128000.json','["人言悲秋難爲情，我喜枕上聞秋聲。", "快鷹下韝爪觜健，壯士撫劍精神生。", "我亦奮迅起衰病，唾手便有擒戎興。", "弦開雁落詩亦成，筆力未饒弓力勁。", "五原草枯苜蓿空，青海蕭蕭風卷蓬。", "草罷捷書重上馬，却從鑾駕下遼東。"]'),
('49c0bc55-2a35-464f-b801-f84ac80193a4','觀小孤山圖','陸游','宋','宋诗','song-poetry','','[]','江平風不生，鏡面渺千里。',80,'全唐诗/poet.song.128000.json','["江平風不生，鏡面渺千里。", "軻峨萬斛舟，遠望一點耳。", "大孤江中央，四面峭插水。", "小孤特奇麗，丹翠凌雲起。", "重樓邃殿神之家，帳中美人粲如花。", "遊人徙倚欄干處，俊鶻横江東北去。"]'),
('883e31ba-204c-4c67-a185-337b4159a5de','飲酒','陸游','宋','宋诗','song-poetry','','[]','陸生學道欠力量，胸次未能和盎盎。',130,'全唐诗/poet.song.128000.json','["陸生學道欠力量，胸次未能和盎盎。", "百年自笑足悲歡，萬事聊須付酣暢。", "有時堆阜起崢嶸，大呼索酒澆使平。", "世間豈無道師與禪老，不如閉門參麴生。", "朋舊年來散如水，惟有鐺杓同生死。", "一日不見令人愁，晝夜共處終無尤。", "世言有毒在麴糵，腐脇穿腸凝血脉。", "人生適意即爲之，醉死愁生君自擇。"]'),
('f84e7e10-d2e6-40a9-a71b-796f455433c8','北窗梧葉坐間落四五有感','陸游','宋','宋诗','song-poetry','','[]','高梧一葉脱，便覺秋不遠。',96,'全唐诗/poet.song.128000.json','["高梧一葉脱，便覺秋不遠。", "晨起髮滿梳，吾衰孰云晚。", "古來追電足，歴塊或小踠。", "金鼓噪陳間，此任豈駑蹇。", "女子則多怨，丈夫當自反。", "黙觀憂患機，推見生死本。", "山林嫌獨往，臺省亦衮衮。", "會稽歸去來，皋橋住差穏。"]'),
('17ea7ff4-108f-4243-83ea-ae23b8f858e7','神山歌','陸游','宋','宋诗','song-poetry','','[]','吾聞海中五神山，其根戴以十五鼇。',160,'全唐诗/poet.song.128000.json','["吾聞海中五神山，其根戴以十五鼇。", "一朝六鼇被釣去，岱輿貟嶠沉洪濤。", "尚餘三山巋然在，當時不沒爭秋毫。", "如何蓬萊又已淺，忽見平地生藜蒿。", "伏羲迨今幾萬歲，世事如火煎油膏。", "娶妻不敢待翁命，治水無暇憐兒號。", "避讒奔楚僅得免，歴聘返魯終不遭。", "老聃關尹亦又死，人實危脆無堅牢。", "有口惟可飲醇醪，有手惟可持霜螯。", "勿令他人復笑汝，後有萬世來滔滔。"]'),
('bb80da64-7834-46c9-93f4-d308a7b03f08','久雨','陸游','宋','宋诗','song-poetry','','[]','昏昏風雨暗東湖，恰似梅黄四月初。',64,'全唐诗/poet.song.128000.json','["昏昏風雨暗東湖，恰似梅黄四月初。", "高樹送聲驚客枕，小池分溜入清渠。", "飛蚊屏迹知何在，團扇生塵已暗疏。", "須信西遊有奇事，今年三伏夜觀書。"]'),
('66804273-c917-4fe6-8281-ab62b9d99c60','古意','陸游','宋','宋诗','song-poetry','','[]','紲足飼饑鷹，鷹飽意未平。',72,'全唐诗/poet.song.128000.json','["紲足飼饑鷹，鷹飽意未平。", "伏櫪豈不安，老驥終悲鳴。", "士生固欲達，又懼徒富貴。", "素願有未伸，五鼎淡無味。", "茅屋秋雨漏，稻陂春水深。", "長歌傾濁酒，舉世不知心。"]'),
('e7010427-aaba-4b1a-b44e-17db46d696ae','自唐安之成都','陸游','宋','宋诗','song-poetry','','[]','出門猶苦雨，度塹喜新晴。',48,'全唐诗/poet.song.128000.json','["出門猶苦雨，度塹喜新晴。", "日正車無影，風高蓋有聲。", "疏疏稚苗立，鬱鬱晚桑生。", "宿醉行猶倦，無人爲解酲。"]'),
('0b6db754-cc65-4dbb-9407-d7ef1f70330a','度筰','陸游','宋','宋诗','song-poetry','','[]','翩翩翻翻筰受風，行人疾走緣虚空。',96,'全唐诗/poet.song.128000.json','["翩翩翻翻筰受風，行人疾走緣虚空。", "回觀目眩浪花上，小跌身裹蛟涎中。", "汗沾兩握色如菜，數乘此險私自怪。", "九折元非叱馭行，千金空犯垂堂戒。", "此身老大足悲傷，歲歲天涯憶故鄉。", "安得畫船明月夜，滿川歌吹入盤閶。"]'),
('9126158d-e35e-4cec-80d4-723113f116fb','故袍','陸游','宋','宋诗','song-poetry','','[]','青衫猶是國工裁，破篋塵侵手自開。',32,'全唐诗/poet.song.128000.json','["青衫猶是國工裁，破篋塵侵手自開。", "莫笑渾如霜葉闇，兩朝曾見聖君來。"]'),
('412d4233-a57e-443d-8121-0e4f322cd228','寓寶相有作','陸游','宋','宋诗','song-poetry','','[]','掃地鏡面清，燒香雲氣潤。',96,'全唐诗/poet.song.128000.json','["掃地鏡面清，燒香雲氣潤。", "道人敬愛客，危坐目不瞬。", "童子髠兩髦，經禪亦精進。", "我來願同龕，歡喜無少吝。", "臨堂坐夜分，佛燈看墮燼。", "清晨爽如秋，攝衣相問訊。", "道在氛埃表，此語其殆信。", "永愧小阮高，超然棄鬚鬢。"]'),
('647356ab-74a4-4573-a40e-4b9c0f2acb78','寓驛舍','陸游','宋','宋诗','song-poetry','','[]','閑坊古驛掩朱扉，又憩空堂綻客衣。',64,'全唐诗/poet.song.128000.json','["閑坊古驛掩朱扉，又憩空堂綻客衣。", "九萬里中鯤自化，一千年外鶴仍歸。", "遶庭數竹饒新筍，解带量松長舊圍。", "惟有壁間詩句在，暗塵殘墨兩依依。"]'),
('4e50f988-b8c5-4058-9bf6-ee93592e2398','題宇文子友所藏薛公鶴','陸游','宋','宋诗','song-poetry','','[]','仙人騏驥絕世稀，卵生凡禽似而非。',64,'全唐诗/poet.song.128000.json','["仙人騏驥絕世稀，卵生凡禽似而非。", "宫保妙筆窮化機，縞衣玄裳真令威。", "千年華表聊一歸，回首幸脱乘軒譏。", "喙吞不恨菰米微，從吾曹遊安得肥。"]'),
('0cfca6f6-20f8-4859-aebe-9e6452e37e07','宴西樓','陸游','宋','宋诗','song-poetry','','[]','西樓遺跡尚豪雄，錦繡笙簫在半空。',64,'全唐诗/poet.song.128000.json','["西樓遺跡尚豪雄，錦繡笙簫在半空。", "萬里因循成久客，一年容易又秋風。", "燭光低映珠簾麗，酒暈徐添玉頰紅。", "歸路迎涼更堪愛，摩訶池上月方中。"]'),
('19720d7f-325a-4c1c-aa68-22887f992b4a','月中歸驛舍','陸游','宋','宋诗','song-poetry','','[]','歲歲常爲錦水行，驛前雙堠慣逢迎。',64,'全唐诗/poet.song.128000.json','["歲歲常爲錦水行，驛前雙堠慣逢迎。", "草深閑院蟲相語，人靜空廊月自明。", "病起酒徒嘲小戸，才衰詩律愧長城。", "何時却泛耶溪路，臥聽菱歌四面聲。"]'),
('3cc949e4-8d75-4418-81e8-abf8781f656a','江瀆池醉歸馬上作','陸游','宋','宋诗','song-poetry','','[]','久住西州似宿緣，笙歌叢裏著華顛。',64,'全唐诗/poet.song.128000.json','["久住西州似宿緣，笙歌叢裏著華顛。", "每嗟相見多生客，却憶初來尚少年。", "迎馬緑楊爭拂帽，滿街丹荔不論錢。", "浮生何處非羈旅，休問東吳萬里船。"]'),
('54b41103-87c8-4b30-b9d9-9e4786983721','離成都後却寄公壽子友德稱','陸游','宋','宋诗','song-poetry','','[]','蕭條常閉爵羅門，點檢朋儕幾箇存。',64,'全唐诗/poet.song.128000.json','["蕭條常閉爵羅門，點檢朋儕幾箇存。", "吾道將爲天下裂，此心難與俗人言。", "逢時尚可還三代，掩卷何由作九原。", "寄語龜城舊交道，新涼殊憶共清尊。"]'),
('33df3765-522b-47f1-aff7-f4819f87c4c1','晨至湖上二首  其一','陸游','宋','宋诗','song-poetry','','[]','劍南無劇暑，長夏更宜人。',48,'全唐诗/poet.song.128000.json','["劍南無劇暑，長夏更宜人。", "啼鳥常終日，幽花不减春。", "荷香浮緑酒，藤露落烏巾。", "莫作天涯想，翛然夢裏身。"]'),
('5f0f5812-c07e-4941-a597-fbe9c3d482a8','晨至湖上二首  其二','陸游','宋','宋诗','song-poetry','','[]','園古逢秋好，身閑與懶宜。',48,'全唐诗/poet.song.128000.json','["園古逢秋好，身閑與懶宜。", "空堂賞疏豁，重閣望參差。", "竹粉有新意，松風含古姿。", "低回慚禄米，官事少於詩。"]'),
('7de627b9-3a85-4c60-ae36-61cf008110c3','池上見魚躍有懷姑孰舊遊','陸游','宋','宋诗','song-poetry','','[]','雨過回塘漲碧漪，幽人閑照角巾欹。',32,'全唐诗/poet.song.128000.json','["雨過回塘漲碧漪，幽人閑照角巾欹。", "銀刀忽裂圓波出，宛似姑溪晚泊時。"]'),
('cff97d7a-d5a2-4111-8bf5-747a79f05623','六月二十五日曉出郊','陸游','宋','宋诗','song-poetry','','[]','劍南作客歲再淹，正如病翼遭𥻿黏。',96,'全唐诗/poet.song.128000.json','["劍南作客歲再淹，正如病翼遭𥻿黏。", "短衣射虎性所樂，不耐齷齪垂車幨。", "今晨偶出得一快，欣然意若脱楚鉗。", "曉星已疏更磊磊，殘月欲盡猶纖纖。", "雞鳴已與夜漏斷，鴉起似逐朝陽暹。", "揚鞭走馬忘老憊，自笑狂疾何由砭。"]'),
('32e966a0-1fde-427c-8e02-d43e0ee7887b','作雨不成終夜極涼時去立秋五日也','陸游','宋','宋诗','song-poetry','','[]','雲映星芒澹，風闌雨脚回。',48,'全唐诗/poet.song.128000.json','["雲映星芒澹，風闌雨脚回。", "體輕知病去，氣爽喜秋來。", "疏放抛烏帢，歌呼覆緑杯。", "東歸定何日，灩澦欲崔嵬。"]'),
('efa0db09-b14e-43e8-9271-ee8f10677f09','池上晚雨','陸游','宋','宋诗','song-poetry','','[]','烏紗白葛一枝笻，罨畫池邊遡晚風。',64,'全唐诗/poet.song.128000.json','["烏紗白葛一枝笻，罨畫池邊遡晚風。", "雲葉初生高樹外，雨聲已到亂荷中。", "憑闌頓覺氛埃遠，回首方知暑毒空。", "閲世萬端惟小忍，何人更事似衰翁。"]'),
('0cb2c5ed-c0ff-4500-a87c-b5d89d7a49d9','五十','陸游','宋','宋诗','song-poetry','','[]','五十未名老，無如衰疾何。',48,'全唐诗/poet.song.128000.json','["五十未名老，無如衰疾何。", "肺肝空激烈，顔鬢已蹉跎。", "夜宴看長劍，秋風舞短蓑。", "此身如砥柱，猶足閲頺波。"]'),
('27f8962b-33ca-4778-8f52-60bf5b1b498f','記夢','陸游','宋','宋诗','song-poetry','','[]','夢泛扁舟禹廟前，中流拂面風泠然。',160,'全唐诗/poet.song.128000.json','["夢泛扁舟禹廟前，中流拂面風泠然。", "樓臺縹緲知幾疊，雲物點綴多餘妍。", "蓮房芡觜采無主，漁歌菱唱聲滿川。", "夢中了了知是夢，却恐燕語來驚眠。", "弄橈顧謂共載客，乖離不記經幾年。", "即今相逢兩幻質，轉盼變滅如飛烟。", "斯言未竟客大笑，人生寓世豈獨堅。", "元章嘉叟君所見，一别丹旐俱翩翩。", "君知夢覺本無異，勿爲畫餅流饞涎。", "我慚俛首夢亦斷，尚覺細浪鳴船舷。"]'),
('01355fde-cea3-499a-8c45-b75d8ac9da50','憑欄','陸游','宋','宋诗','song-poetry','','[]','蟬嘒晚尤壯，鴉栖久未安。',48,'全唐诗/poet.song.128000.json','["蟬嘒晚尤壯，鴉栖久未安。", "不成浮舴艋，故作凭闌干。", "露重傾荷蓋，風尖蹙芡盤。", "新秋動歸思，更覺五湖寬。"]'),
('381b1fc9-1d18-46fd-9c63-55844cbfc5f9','聽琴','陸游','宋','宋诗','song-poetry','','[]','疏簾曲檻蘋風涼，細腰美人藕絲裳。',96,'全唐诗/poet.song.128000.json','["疏簾曲檻蘋風涼，細腰美人藕絲裳。", "緑藤水文穿矮床，玉指纖纖彈履霜。", "高林鶯囀日正長，幽澗泉鳴夜未央。", "哀思不怨和而莊，有齊淑女禮自防。", "世人但惑青樓倡，琵琶箜篌雜胡羌。", "試聽一曲醒汝狂，文姬指法傳中郎。"]'),
('e9ed40f0-5e75-4858-8472-7ac387063cc7','秋思','陸游','宋','宋诗','song-poetry','','[]','烈日炎天欲不禁，喜逢秋色到園林。',64,'全唐诗/poet.song.128000.json','["烈日炎天欲不禁，喜逢秋色到園林。", "雲陰映日初蕭瑟，露氣侵簾已峭深。", "衰髮凋零隨槁葉，苦吟凄斷雜疏碪。", "鴈來不得中原信，撫劍何人識壯心。"]'),
('93fb3212-45ea-41dd-a80b-5bdf8da74632','醉書','陸游','宋','宋诗','song-poetry','','[]','似閑有俸錢，似仕無簿書。',120,'全唐诗/poet.song.128000.json','["似閑有俸錢，似仕無簿書。", "似長免事任，似屬非走趨。", "病能加餐飯，老與酒不疏。", "婆娑東湖上，幽曠足自娱。", "時時喚客醉，小閣臨紅蕖。", "釣魚斫銀絲，擘荔見玉膚。", "檀槽列四十，遺聲傳故都。", "豈惟豪兩川，自足誇東吳。", "但恨詩不進，榛荒失耘鋤。", "何當掃纖豔，傑作追黄初。"]'),
('6ce9960c-4dd2-459b-80ec-a1c766e11782','楚氏莊龜泉','陸游','宋','宋诗','song-poetry','','[]','曵尾穹龜不負圖，一泓寒碧照庭除。',32,'全唐诗/poet.song.128000.json','["曵尾穹龜不負圖，一泓寒碧照庭除。", "醉中只合長來此，臥聽蠻童放轆轤。"]'),
('3a909aff-d55a-4f2d-8bd8-03def179727b','書懷二首  其一','陸游','宋','宋诗','song-poetry','','[]','楚澤巴江兩鬢殘，夕陽又是倚闌干。',64,'全唐诗/poet.song.128000.json','["楚澤巴江兩鬢殘，夕陽又是倚闌干。", "敢言日與長安遠，惟恨天如蜀道難。", "客枕五更歸夢短，新詩千首後人看。", "青簾白舫何時發，醉聽琵琶興已闌。"]'),
('df89ba12-dabc-4ea7-a53f-67a7b2492286','書懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','西風蕭瑟晚吹衣，又見亭皋木葉飛。',64,'全唐诗/poet.song.128000.json','["西風蕭瑟晚吹衣，又見亭皋木葉飛。", "已是中年頻作惡，更堪秋日送將歸。", "黄塵顔鬢無人識，青史功名與願違。", "彊把一杯還徑醉，羈懷何必不依依。"]'),
('cdd2534d-20e5-4d16-b326-0d649c0b1460','秋思三首  其一','陸游','宋','宋诗','song-poetry','','[]','大面山前秋笛清，細腰宫畔莫灘平。',64,'全唐诗/poet.song.128000.json','["大面山前秋笛清，細腰宫畔莫灘平。", "吳檣楚柁動歸思，隴月巴雲空復情。", "萬里風塵舊朝士，百年鉛槧老書生。", "水村漁市從今始，安用區區海內名。"]'),
('854aa481-7903-46da-be2e-1d275ee3ef0f','秋思三首  其二','陸游','宋','宋诗','song-poetry','','[]','巢燕成歸秋景奇，頗容老子醉哦詩。',64,'全唐诗/poet.song.128000.json','["巢燕成歸秋景奇，頗容老子醉哦詩。", "山晴更覺雲含態，風定閑看水弄姿。", "痛飲何由從次道，並遊空復憶安期。", "天涯又作經年客，莫對青銅恨鬢絲。"]'),
('68d42392-4953-4f72-b280-09b58c5a99a0','秋思三首  其三','陸游','宋','宋诗','song-poetry','','[]','西風吹葉滿湖邊，初換秋衣獨慨然。',64,'全唐诗/poet.song.128000.json','["西風吹葉滿湖邊，初換秋衣獨慨然。", "白首有詩悲蜀道，清宵無夢到鈞天。", "迂疏早不營三窟，流落今寜直一錢。", "把酒未妨餘興在，試憑絲管餞流年。"]'),
('7e1d2354-66fe-43d5-a32a-93ff06a76ddc','東園晚步','陸游','宋','宋诗','song-poetry','','[]','久客天涯憶故園，彊名官寺只衡門。',64,'全唐诗/poet.song.128000.json','["久客天涯憶故園，彊名官寺只衡門。", "秋桐蠧遍無全葉，古柳吹斜出半根。", "痛飲每思尊酒窄，微官空羨布衣尊。", "何時定下三巴去，思臥孤舟聽斷猿。"]'),
('ef4df02b-176f-4b2c-af68-2ec9a333b5f7','秋夜讀書戲作','陸游','宋','宋诗','song-poetry','','[]','别駕生涯似蠧魚，簡編垂老未相疏。',32,'全唐诗/poet.song.128000.json','["别駕生涯似蠧魚，簡編垂老未相疏。", "也知賦得寒儒分，五十燈前見細書。"]'),
('0cd990fa-6fb7-4ee8-be5f-1969c3dbca1a','太平花','陸游','宋','宋诗','song-poetry','','[]','扶床踉蹡出京華，頭白車書未一家。',32,'全唐诗/poet.song.128000.json','["扶床踉蹡出京華，頭白車書未一家。", "宵旰至今勞聖主，泪痕空對太平花。"]'),
('8a098b3f-958d-48a5-9e69-08bec3c1eb43','日暮至湖上','陸游','宋','宋诗','song-poetry','','[]','籃輿晚繞湖，樂此新秋涼。',120,'全唐诗/poet.song.128000.json','["籃輿晚繞湖，樂此新秋涼。", "粉落竹方老，紅凋荷更香。", "天宇無纖雲，仰視鴻鵠翔。", "小樓久不登，撫檻悲慨慷。", "浮生寄一夢，共盡無彭殤。", "況我數月客，轉眼促去裝。", "顧作兒女態，裵徊惜流光。", "簷角迎夜月，林間送斜陽。", "四年已五遷，終歲常遑遑。", "安得一茆屋，歸老樵風旁。"]'),
('c5a502c8-e0ff-475a-8694-8f107ae2919e','秋興','陸游','宋','宋诗','song-poetry','','[]','無處逢秋不黯然，驛前斜日渡頭烟。',64,'全唐诗/poet.song.128000.json','["無處逢秋不黯然，驛前斜日渡頭烟。", "吟肩雅與寒驢稱，歸夢頻爭社燕先。", "百歲猶穿幾兩屐，千詩不及一囊錢。", "故應身世如團扇，已向人間耐棄捐。"]'),
('36192289-e1ac-4630-8d2d-1b95476052df','秋色','陸游','宋','宋诗','song-poetry','','[]','一段凄涼傍酒杯，中年剩作楚囚哀。',64,'全唐诗/poet.song.128000.json','["一段凄涼傍酒杯，中年剩作楚囚哀。", "迢迢似伴明河出，慘慘如隨落照來。", "客路半生常泪眼，鄉關萬里更危臺。", "蓼汀荻浦江南岸，自入秋來夢幾回。"]'),
('57426923-96aa-45e2-95cf-1a8f7094091c','秋聲','陸游','宋','宋诗','song-poetry','','[]','蕭騷拂樹過中庭，何處人間有此聲。',64,'全唐诗/poet.song.128000.json','["蕭騷拂樹過中庭，何處人間有此聲。", "漲水雨餘晨放閘，騎兵戰罷夜還營。", "閑憑曲几聽雖久，彊撫哀弦寫不成。", "暑退涼生君勿喜，一年光景又崢嶸。"]'),
('7e4570a7-c1b6-47a9-bf18-9cd1f85e7a23','觀長安城圖','陸游','宋','宋诗','song-poetry','','[]','許國雖堅鬢已斑，山南經歲望南山。',64,'全唐诗/poet.song.128000.json','["許國雖堅鬢已斑，山南經歲望南山。", "横戈上馬嗟心在，穿塹環城笑虜孱。", "日暮風烟傳隴上，秋高刁斗落雲間。", "三秦父老應惆悵，不見王師出散關。"]'),
('a8480434-86f0-437e-a230-b22a49e9aeb0','雨中作','陸游','宋','宋诗','song-poetry','','[]','方驚歲更端，不覺秋已孟。',72,'全唐诗/poet.song.128000.json','["方驚歲更端，不覺秋已孟。", "雖云暑毒竢，無奈風雨横。", "荷空湖面濶，葉脱樹枝勁。", "百卉亦已衰，非復昔華盛。", "遊子老忘歸，一榻臥衰病。", "欲談無客來，向壁弄麈柄。"]'),
('009a7312-94f7-432b-af70-7d5628b39bf2','夜讀了翁遺文有感','陸游','宋','宋诗','song-poetry','','[]','秋雨蕭蕭夜不眠，挑燈開卷意凄然。',64,'全唐诗/poet.song.128000.json','["秋雨蕭蕭夜不眠，挑燈開卷意凄然。", "吾曹自欲期千載，世論何曾待百年。", "當日公卿笑迂濶，即今河洛污腥膻。", "陰陽消長從來事，玩易深知屢絕編。"]'),
('0b225375-767d-478c-81a1-48b0735dd4de','雷','陸游','宋','宋诗','song-poetry','','[]','君不見冬月雷，深藏九地底，寂黙如寒灰。',147,'全唐诗/poet.song.128000.json','["君不見冬月雷，深藏九地底，寂黙如寒灰。", "紛紛槁葉木盡脱，蠢蠢蟄户蟲爭坯。", "堅冰積雪一朝盡，風揺天邊斗柄回。", "雷聲却擘九地出，殷殷似挾春俱來。", "魚龍振鰭熟睡醒，桃李一笑韶顔開。", "候耕老農喜欲舞，掀泥百草知誰催。", "惟嗟婦女不解事，深屋揜耳藏嬰孩。", "吾聞陰陽有常數，非時動靜皆爲菑。", "無人爲報阿香道，時來何至勞卿推。"]'),
('e663b5ce-9343-491e-9c9b-d3b284a9cdfb','龍眠畫馬','陸游','宋','宋诗','song-poetry','','[]','國家一從失西陲，年年買馬西南夷。',132,'全唐诗/poet.song.128000.json','["國家一從失西陲，年年買馬西南夷。", "瘴鄉所産非權奇，邊頭歲入幾番皮。", "崔嵬瘦骨带火印，離立欲不禁風吹。", "圉人太僕空列位，龍媒汗血來何時。", "李公太平官京師，立仗慣見渥洼姿。", "斷縑歲久墨色暗，逸氣尚若不可羈。", "賞奇好古自一癖，感事憂國空餘悲。", "嗚呼安得毛骨若此三千疋，衘枚夜度桑乾磧。"]'),
('24bc090a-a49d-45f1-869c-b4c03853abf8','秋夜池上作','陸游','宋','宋诗','song-poetry','','[]','短髮颼颼病骨輕，臨池閑看露荷傾。',32,'全唐诗/poet.song.128000.json','["短髮颼颼病骨輕，臨池閑看露荷傾。", "月明何與浮雲事，正向圓時故故生。"]'),
('48522e50-3abf-4226-bf56-88e8e4de769a','秋雨','陸游','宋','宋诗','song-poetry','','[]','西山雲千重，東園泥一尺。',72,'全唐诗/poet.song.128000.json','["西山雲千重，東園泥一尺。", "可憐牆下路，十日無履迹。", "空庭桐葉盡，古甃土花碧。", "坐懷江湖間，病鴈濕羽翮。", "寒窗向人青，衰髮垂領白。", "孤吟更不寐，聊伴候蟲嘖。"]'),
('37ee6005-321a-4403-bd68-2f4dd8d4db37','臥病','陸游','宋','宋诗','song-poetry','','[]','人生寓一氣，血脉日夜流。',108,'全唐诗/poet.song.128000.json','["人生寓一氣，血脉日夜流。", "秋毫或壅隔，百體若相仇。", "嗟予少多艱，衣食拙自謀。", "方寸叢百慮，如箭集射侯。", "奔走連數歲，呻吟劇兹秋。", "生死亦何有，成壞同一漚。", "胡爲不自愛，森然起戈矛。", "一笑衆妄滅，霜天鷹睨鞲。", "呼兒屏藥囊，吾疾今其瘳。"]'),
('4bdca7d3-d200-4ae0-8fc2-3ce3b15eb505','夢入禪林有老宿方陞座或云通悟禪師也','陸游','宋','宋诗','song-poetry','','[]','塵埃車馬何憧憧，麞頭鼠目厭妄庸。',64,'全唐诗/poet.song.128000.json','["塵埃車馬何憧憧，麞頭鼠目厭妄庸。", "樂哉夢見德人容，巍巍堂堂人中龍。", "舉頭仰望太華峰，攝衣欲往路無從。", "忽然夢斷難再逢，空記說法聲如鐘。"]'),
('46021111-8d58-4e0c-b97a-2ee8516c100d','蜀州大閲','陸游','宋','宋诗','song-poetry','','[]','曉束戎衣一悵然，五年奔走遍窮邊。',64,'全唐诗/poet.song.128000.json','["曉束戎衣一悵然，五年奔走遍窮邊。", "平生亭障休兵日，慘澹風雲閲武天。", "戍隴舊遊真一夢，渡遼奇事付他年。", "劉琨晚抱聞雞恨，安得英雄共著鞭。"]'),
('99b31869-2876-4c1d-af61-3b84b329a538','放懷亭獨立有感','陸游','宋','宋诗','song-poetry','','[]','葦叢枯倒蓼花紅，小立東湖更向東。',64,'全唐诗/poet.song.128000.json','["葦叢枯倒蓼花紅，小立東湖更向東。", "委肉本知居几上，翦翎何恨蓍籠中。", "一笻信脚乾坤迮，百榼澆愁寵辱空。", "誰道窮途知舊少，此心念念與天通。"]'),
('2276ea1a-4594-4ff7-b5b0-34efd2d0844f','九月三日同吕周輔教授遊大邑諸山','陸游','宋','宋诗','song-poetry','','[]','大邑知名杜叟詩，山中仍值菊花時。',64,'全唐诗/poet.song.128000.json','["大邑知名杜叟詩，山中仍值菊花時。", "節旄落盡羈臣老，髀肉生來壯士悲。", "豪舉每嫌杯緑淺，癡頑頗怪鬢絲遲。", "廣文别乘官俱冷，相伴寬爲五日期。"]'),
('4e4c3605-e239-4c4a-bd6a-0a363dd78a7a','次韵周輔道中二首  其一','陸游','宋','宋诗','song-poetry','','[]','山靈喜我馬蹄聲，正用此時秋雨晴。',32,'全唐诗/poet.song.128000.json','["山靈喜我馬蹄聲，正用此時秋雨晴。", "日淡風斜江上路，蘆花也似柳花輕。"]'),
('c9de66d4-5bf6-44c6-8600-5f56e294c05c','次韵周輔道中二首  其二','陸游','宋','宋诗','song-poetry','','[]','從來重九如寒食，天氣微陰正自佳。',32,'全唐诗/poet.song.128000.json','["從來重九如寒食，天氣微陰正自佳。", "莫問茱茰賜朝士，一尊隨處有黄花。"]'),
('19c76e34-549b-46f0-90e1-d049a7d01897','憩黄秀才書堂','陸游','宋','宋诗','song-poetry','','[]','吾生如虚舟，萬里常泛泛。',72,'全唐诗/poet.song.128000.json','["吾生如虚舟，萬里常泛泛。", "終年厭作客，著處思繫纜。", "道邊何人居，花竹頗閑淡。", "門庭淨如拭，窗几光可鑑。", "堂上滿架書，朱黄方點勘。", "把茅容卜鄰，老死更誰憾。"]'),
('5262ee2d-ecff-4ea7-a111-27e71748786b','夜宿鵠鳴山','陸游','宋','宋诗','song-poetry','','[]','西遊萬里已關天，采藥名山亦宿緣。',64,'全唐诗/poet.song.128000.json','["西遊萬里已關天，采藥名山亦宿緣。", "老柏干霄如許壽，幽花泣露爲誰妍。", "苔黏石磴捫蘿上，燈耿雲房掃榻眠。", "安得仙翁索米術，一生留此弄寒泉。"]'),
('ce6182d3-f09f-4c0f-93cf-2d0c950115a6','次韵周輔霧中作','陸游','宋','宋诗','song-poetry','','["\u534e\u5c71"]','一日籃輿十過溪，丹茰黄菊及佳時。',64,'全唐诗/poet.song.128000.json','["一日籃輿十過溪，丹茰黄菊及佳時。", "端居恐作他年恨，聨轡聊成此段奇。", "側磴下臨重澗黑，亂雲高出一峰危。", "何時關輔烟塵靜，太華山頭更卜期。"]'),
('1f1e7992-b408-4475-9f73-9a215fbe97a9','山中得長句戲呈周輔并簡朱縣丞山','陸游','宋','宋诗','song-poetry','','[]','鶴鳴山空無鶴來，青霞嶂深天壁開。',224,'全唐诗/poet.song.128000.json','["鶴鳴山空無鶴來，青霞嶂深天壁開。", "千巖角逐互吞吐，一峰拔起矜崔嵬。", "日光微漏潭見底，水氣上薄雲成堆。", "幽禽飛鳴報客至，奇樹璀璨知誰栽。", "花藤怪蔓白晝暗，奔猿落狖無時哀。", "路窮尚躡一千級，忽見密竹藏樓臺。", "共言神僧昔住此，至今光景如天台。", "搘笻負笠出復沒，喜動婦人驚提孩。", "高人何至作狡獪，無乃翫世聊相詼。", "不然學道窮實際，詎捨正大崇奇瓌。", "儒林丈人學擅世，餘事尚壓蔡與崔。", "名山未死可再到，此士一失難重陪。", "贊府摘山事如織，擺撥領客何奇哉。", "境幽神愴不可住，歸倩玉手傳金杯。"]'),
('de5ef82f-00ee-407c-9a8f-afcd0c09cee4','擣藥鳥','陸游','宋','宋诗','song-poetry','','[]','白髮無情日日生，散愁聊復作山行。',32,'全唐诗/poet.song.128000.json','["白髮無情日日生，散愁聊復作山行。", "幽禽似欲嘲衰病，故學禪房杵藥聲。"]'),
('561548e0-49d8-4519-ba5e-9b43e6295994','出山','陸游','宋','宋诗','song-poetry','','[]','出山似與高人别，回首時時一悵然。',32,'全唐诗/poet.song.128000.json','["出山似與高人别，回首時時一悵然。", "它日再來緣要熟，遍題名姓緑巖邊。"]'),
('7e71252a-2e07-4897-9be0-be5601e4d50e','平雲亭','陸游','宋','宋诗','song-poetry','','[]','滿榼芳醪何處傾，金鼇背上得同行。',64,'全唐诗/poet.song.128000.json','["滿榼芳醪何處傾，金鼇背上得同行。", "天垂緑野三邊盡，雲與朱闌一様平。", "烟樹微茫疑誤墨，風松蕭瑟有新聲。", "黄花未吐無多恨，也勝湘纍拾落英。"]'),
('a7b445c8-ba97-4ba3-90d7-bbf590b52154','高秋亭','陸游','宋','宋诗','song-poetry','','[]','三日山中醉復醒，徑歸回首愧山靈。',32,'全唐诗/poet.song.128000.json','["三日山中醉復醒，徑歸回首愧山靈。", "從今惜取觀書眼，長看天西萬疊青。"]'),
('77172e46-65d1-43dc-b9c9-8f4040320505','九日小疾不出','陸游','宋','宋诗','song-poetry','','[]','病厭追遊懶舉觴，今年閉戸作重陽。',64,'全唐诗/poet.song.128000.json','["病厭追遊懶舉觴，今年閉戸作重陽。", "香烟裊裊閑縈几，書卷紛紛靜滿床。", "斜日更增秋慘淡，黄花應怪客凄涼。", "長安光景還如昨，誰醉城南杜曲旁。"]'),
('9168b4dc-7363-40a0-8bb8-e6cbbb5f24ac','九日試霧中僧所贈茶','陸游','宋','宋诗','song-poetry','','[]','少逢重九事豪華，南陌雕鞍擁鈿車。',32,'全唐诗/poet.song.128000.json','["少逢重九事豪華，南陌雕鞍擁鈿車。", "今日蜀州生白髮，瓦爐獨試霧中茶。"]'),
('81d9308e-d64d-4131-b4da-e8a95803d293','我有美酒歌','陸游','宋','宋诗','song-poetry','','[]','我有美酒起自斟，勸君一巵爲君吟。',96,'全唐诗/poet.song.128000.json','["我有美酒起自斟，勸君一巵爲君吟。", "素衣未遂京塵化，緑鬢已受吳霜侵。", "三巴塗路何嶔崟，五溪霧潦多毒淫。", "虎豹夜嘯裂崖谷，魑魅晝出矜山林。", "身如槁葉墮幽穽，窅窅何啻千尺深。", "無因剖胸出此心，一寸孤忠天實臨。"]'),
('efc6634a-f737-4f04-9b4d-2376af7fa7f2','次韵師伯渾見寄','陸游','宋','宋诗','song-poetry','','[]','窮鄉久客易消魂，短髮秋來白幾分。',64,'全唐诗/poet.song.128000.json','["窮鄉久客易消魂，短髮秋來白幾分。", "夢泛扁舟鏡湖月，身騎瘦馬劍關雲。", "萬釘寶带知何用，九轉金丹幸有聞。", "欲與先生同此計，會營茅舍近江濱。"]'),
('4f38de8c-cfa1-4d8d-85ab-6dda2dc135d6','自江源過雙流不宿徑行之成都','陸游','宋','宋诗','song-poetry','','[]','斷笮飄飄挂渡頭，臨江立馬喚漁舟。',64,'全唐诗/poet.song.128000.json','["斷笮飄飄挂渡頭，臨江立馬喚漁舟。", "少城已破繁華夢，老境聊尋汗漫遊。", "斜日驛門雙堠立，早霜風葉一林秋。", "詩材滿路無人取，凖擬歸驂到處留。"]'),
('ec4580e5-ba2b-4f08-8e1d-4ca3000b396a','過緑楊橋','陸游','宋','宋诗','song-poetry','','[]','過縣東馳十里遥，行吟不覺度谿橋。',64,'全唐诗/poet.song.128000.json','["過縣東馳十里遥，行吟不覺度谿橋。", "磑輪激水無時息，酒斾迎風盡日揺。", "半掩店門燈煜煜，横穿村市馬蕭蕭。", "秦吳萬里行幾遍，莫恨尊前緑鬢凋。"]'),
('cb93cb5b-604c-44e9-b71a-331d12994dd5','五鼓自簇橋入府','陸游','宋','宋诗','song-poetry','','[]','曉月有餘光，秋樹無濃影。',72,'全唐诗/poet.song.128000.json','["曉月有餘光，秋樹無濃影。", "野烟浩無際，陂路行愈永。", "堰聲何澎湃，露氣正凄冷。", "忽然客愁破，更覺詩律整。", "昔人千載意，忙裏一笑領。", "山林豈難歸，吾計自不猛。"]'),
('90442ce4-822b-45d1-a65c-7c5082774d0a','客多福院晨起','陸游','宋','宋诗','song-poetry','','[]','萬鯨傳響徹修廊，喚起衰翁曉夢長。',64,'全唐诗/poet.song.128000.json','["萬鯨傳響徹修廊，喚起衰翁曉夢長。", "萬事可憐隨日出，一生常是伴人忙。", "馳驅深厭交飛盖，息偃何時靜炷香。", "四到錦城身愈老，更堪重入少年場。"]'),
('fbfe9829-7708-4102-816c-4d72132b0d6e','雨中出謁歸晝臥','陸游','宋','宋诗','song-poetry','','[]','宿雨盈車轍，秋風漲帽裙。',48,'全唐诗/poet.song.128000.json','["宿雨盈車轍，秋風漲帽裙。", "愛閑惟兀兀，應俗苦紛紛。", "病眼添花暈，酡顔散纈紋。", "歸來炷香臥，窗底看微雲。"]'),
('136307ce-d262-4595-8167-1ca73f15b877','長歌行','陸游','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u7406\u60f3", "\u62b1\u8d1f"]','人生不作安期生，醉入東海騎長鯨。',160,'全唐诗/poet.song.128000.json','["人生不作安期生，醉入東海騎長鯨。", "猶當出作李西平，手杖旄鉞清舊京。", "金印煌煌未入手，白髮種種來無情。", "成都古寺臥秋晚，落日偏傍僧窗明。", "豈其馬上破賊手，哦詩長作寒螿鳴。", "興來買盡市橋酒，大車磊落堆長缾。", "哀絲豪竹助劇飲，如鉅野受黄河傾。", "平時一滴不入口，意氣頓使千人驚。", "國讎未報壯士老，匣中寶劍夜有聲。", "何當凱還宴將士，三更雪壓飛狐城。"]'),
('94b94d82-ef51-446f-8e1d-f818cd0ae985','夜食炒栗有感','陸游','宋','宋诗','song-poetry','','[]','齒根浮動嘆吾衰，山栗炮燔療夜饑。',32,'全唐诗/poet.song.128000.json','["齒根浮動嘆吾衰，山栗炮燔療夜饑。", "喚起少年京輦夢，和寜門外早朝來。"]'),
('9ea987a8-422e-438e-90ec-8090d96157b9','秋夜懷吳中','陸游','宋','宋诗','song-poetry','','[]','秋夜挑燈讀楚辭，昔人句句不吾欺。',64,'全唐诗/poet.song.128000.json','["秋夜挑燈讀楚辭，昔人句句不吾欺。", "更堪臨水登山處，正是浮家泛宅時。", "巴酒不能消客恨，蜀巫空解報歸期。", "灞橋烟柳知何限，誰念行人寄一枝。"]'),
('52c1a88e-3d65-4009-825d-70dd953e2f38','遊三井觀','陸游','宋','宋诗','song-poetry','','[]','三井久知名，暇日偶一訪。',168,'全唐诗/poet.song.128000.json','["三井久知名，暇日偶一訪。", "棟宇壞欲盡，基址尚閎壯。", "畫牆皆國工，烟雲儼天仗。", "旌旄亞戈戟，佩玉雜弓䩨。", "太古實傑作，筆落九天上。", "吳生名擅世，睥睨未肻讓。", "規模遠有考，意象豪不放。", "最奇老癯仙，骨立神愈王。", "石恪雖少怪，用筆亦跌宕。", "兩姝淡蛾眉，非復火食狀。", "塵埃久侵蝕，風雨無蓋障。", "好事未易逢，寜能久亡恙。", "雍洛劫火餘，妙迹盡凋喪。", "斯遊恐難繼，佇立增悄愴。"]'),
('5201e246-2585-437a-9c1b-e98e650c126c','僊遊閣','陸游','宋','宋诗','song-poetry','','[]','張公一去二百載，傑閣依然横靄中。',32,'全唐诗/poet.song.128000.json','["張公一去二百載，傑閣依然横靄中。", "徙倚看碑仍看畫，時聞柏子落秋風。"]'),
('105e9b19-e15b-4dcb-b426-54d6849d2376','寓居小庵纔袤丈戲作','陸游','宋','宋诗','song-poetry','','[]','早衰甚畏寒，颼颼壓空館。',120,'全唐诗/poet.song.128000.json','["早衰甚畏寒，颼颼壓空館。", "登閣望東庵，亭亭長一繖。", "欣然願暫寓，竹底門可欵。", "外看磔蝟毛，仰視覆鵠卵。", "席纔置錐地，牖若窺天管。", "瓦爐香不去，菅寢衾易暖。", "頗疑漁庵結，又類土室窽。", "家具止囊衣，弛擔著亦滿。", "客來勿嗤陋，老我善用短。", "猶能設胡床，相喚共茗椀。"]'),
('5d81e881-1398-4762-a36d-ef4b81094fc9','送華師從劍州張秘書之招','陸游','宋','宋诗','song-poetry','','[]','三年相伴錦江頭，一日翩然不可留。',64,'全唐诗/poet.song.128000.json','["三年相伴錦江頭，一日翩然不可留。", "官冷蓬門無客戀，時清劍閣有僧遊。", "關山黙數來時路，風月懸知别後愁。", "禪版經龕有餘暇，頻登高處望西州。"]'),
('b3d09fd9-6593-46de-af8d-c0aff5d91e54','江上對酒作','陸游','宋','宋诗','song-poetry','','[]','把酒不能飲，苦泪滴酒觴。',96,'全唐诗/poet.song.128000.json','["把酒不能飲，苦泪滴酒觴。", "醉酒蜀江中，和涙下荆揚。", "樓櫓壓湓口，山川蟠武昌。", "石頭與鍾阜，南望鬱蒼蒼。", "戈船破浪飛，鐡騎射日光。", "冦來即送死，詎能犯金湯。", "汴洛我舊都，燕趙我舊疆。", "請書一尺檄，爲國平氐羌。"]'),
('c55d62cc-b97c-48f8-9260-a6a1ac3a5485','自嘲','陸游','宋','宋诗','song-poetry','','[]','華子中年百事忘，嵇生仍坐懶爲妨。',64,'全唐诗/poet.song.128000.json','["華子中年百事忘，嵇生仍坐懶爲妨。", "病於榮宦冥心久，老向端閑得味長。", "對客欲談還憒憒，讀書纔過已茫茫。", "青縑帳暖黄紬稳，聊借東庵作睡鄉。"]'),
('3b6f7a09-8bd4-47ee-bbda-025d1aad29ec','暮歸馬上作','陸游','宋','宋诗','song-poetry','','[]','石筍街頭日落時，銅壺閣上角聲悲。',64,'全唐诗/poet.song.128000.json','["石筍街頭日落時，銅壺閣上角聲悲。", "不辭與世終難合，惟恨無人麤見知。", "寶馬俊逰春浩蕩，江樓豪飲夜淋漓。", "醉來剩欲吟梁父，千古隆中可與期。"]'),
('06cae4de-b4aa-4e96-85fe-7d37be67040e','臨别成都帳飲萬里橋贈譚德稱','陸游','宋','宋诗','song-poetry','','[]','成都城南萬里橋，蘆根蘋末風蕭蕭。',224,'全唐诗/poet.song.128000.json','["成都城南萬里橋，蘆根蘋末風蕭蕭。", "映花碾草鈿車小，駐坡驀澗青驄驕。", "入門翠徑絕窈窕，臨水飛觀何岧嶤。", "判無功名著不朽，惟仗詩酒寬亡聊。", "迎霜早已足雉兔，微冷便欲思狐貂。", "喜看縷膾映盤箸，恨欠斫蟹加橙椒。", "坐中譚侯天下士，龍馬毛骨矜超遥。", "烏犀白紵謫仙様，但可邂逅不可招。", "今年一戰馘餘子，風送六翮凌青霄。", "美人再拜乞利市，醉墨飛落生蛟綃。", "我衰於世百無用，十年不趁含元朝。", "華纓肻傍蕭颯鬢，寶带那束龍鍾腰。", "祝君好去事明主，日望分喜來漁樵。", "逰談引類亦細事，寄酒且解相如消。"]'),
('e53a24c5-885f-4b49-82f7-01d6b0dd0134','夜宿二江驛','陸游','宋','宋诗','song-poetry','','[]','鷄鳴原前風折樹，夜到雙流雨如注。',96,'全唐诗/poet.song.128000.json','["鷄鳴原前風折樹，夜到雙流雨如注。", "樺皮濕透點不明，旋設篝爐燎衣袴。", "重城回首一夢散，錦障氊車渺無處。", "新聲猶傍耳邊來，殘酒半隨風力去。", "飛觴縱飲亦何樂，憒憒不堪長閉户。", "丈夫要爲國平戎，俗子豈識吾所寓。"]'),
('474a5159-f2e4-4a67-8028-15af4497c7ba','涉白馬渡慨然有懷','陸游','宋','宋诗','song-poetry','','[]','我馬顧影嘶，忽涉白馬津。',56,'全唐诗/poet.song.128000.json','["我馬顧影嘶，忽涉白馬津。", "雖非黄河上，撫事猶悲辛。", "太行之下吹戰塵，燕南趙北空無人。", "袁曹百戰相持處，犬羊堂堂自來去。"]'),
('02bc3249-93e4-4415-8805-864cfe33f098','瑞草橋','陸游','宋','宋诗','song-poetry','','[]','柘葉颼颼雪意驕，檐頭雙兔遇歸樵。',32,'全唐诗/poet.song.128000.json','["柘葉颼颼雪意驕，檐頭雙兔遇歸樵。", "宿酲未觧題詩懶，虚過風流瑞草橋。"]'),
('b443040c-0cb7-4934-b648-a5c2950507c3','將之榮州取道青城','陸游','宋','宋诗','song-poetry','','[]','倚天山作海濤傾，看遍人間兩赤城。',64,'全唐诗/poet.song.128000.json','["倚天山作海濤傾，看遍人間兩赤城。", "自笑年年隨宦牒，不如處處得閑行。", "草痕沙際猶餘緑，楓葉霜餘已带頳。", "歸去還堪咤兒輩，錦囊三十六峥嶸。"]'),
('5c5c3381-5d16-4774-a020-9acde67c15df','丈人觀','陸游','宋','宋诗','song-poetry','','[]','黄金篆書扁朱門，夾道巨竹屯蒼雲。',176,'全唐诗/poet.song.128000.json','["黄金篆書扁朱門，夾道巨竹屯蒼雲。", "崖嶺劃若天地分，千柱耽耽壓其垠。", "纓冠肅謁丈人君，廣殿空庭吹寶熏。", "摩挲畫牆手爲皸，異哉山巙與土羵。", "物怪齾齾冠丘墳，仙人佩玉雜帨帉。", "手整貂冠最不群，欲去不忍恨日曛。", "道翁採藥晝夜勤，松根茯苓獲兼斤。", "人芝植立彊骨觔，狗杞群吠聲狺狺。", "山爐小甑吹幽芬，朱顔不飲常自醺。", "我亦宿誦五千文，一念之差墮世紛。", "逝将從翁走如麋，隐書秘訣何由聞。"]'),
('ca1cc168-5bd0-40ea-a6af-fbc3ed504244','題丈人觀道院壁','陸游','宋','宋诗','song-poetry','','[]','斷香浮月磬聲殘，木影如龍布石壇。',64,'全唐诗/poet.song.128000.json','["斷香浮月磬聲殘，木影如龍布石壇。", "偶駕青鸞塵世窄，閑吹玉笛洞天寒。", "奇香滿院晨炊藥，異氣穿巖夜浴丹。", "却笑飛仙未忘俗，金貂猶著侍中冠。"]'),
('1cd9d9e6-d0c0-48be-8438-086b0620e429','宿上清宫','陸游','宋','宋诗','song-poetry','','[]','九萬天衢浩浩風，此身真是一枯蓬。',64,'全唐诗/poet.song.128000.json','["九萬天衢浩浩風，此身真是一枯蓬。", "盤蔬采掇多靈藥，閣道攀隮出半空。", "累盡神仙端可致，心虚造化欲無功。", "金丹定觧幽人意，散作山椒百炬紅。"]'),
('dd31dd34-7432-4777-a8a8-2373fe8efa78','自上清延慶歸過丈人觀少留','陸游','宋','宋诗','song-poetry','','[]','再到蓬萊路欲平，却吹長笛過青城。',64,'全唐诗/poet.song.128000.json','["再到蓬萊路欲平，却吹長笛過青城。", "空山霜葉無行迹，半嶺天風有嘯聲。", "細棧跨雲縈峭絕，危橋飛柱插澄清。", "玉華更控青鸞住，要倚欄干待月明。"]'),
('04c07558-1f7b-41e1-9169-6e019b6deaea','長生觀觀月','陸游','宋','宋诗','song-poetry','','[]','碧天萬里月正中，清夜弭節長生宫。',98,'全唐诗/poet.song.128000.json','["碧天萬里月正中，清夜弭節長生宫。", "廣寒忽墮人間世，但怪步虚聲散瑶臺空。", "四山沉沉萬籟寂，夭矯髯龍舞娱客。", "弭貂老仙期不來，獨倚欄干吹玉笛。", "道人不怕九霄寒，銀闕冰壺處處看。", "天台四萬八千丈，明年照我扶藜杖。"]'),
('21e2bb19-371a-4e62-bafd-b17d1970d4a3','儲福觀','陸游','宋','宋诗','song-poetry','','[]','路轉屏風疊，雲藏帝子家。',48,'全唐诗/poet.song.128000.json','["路轉屏風疊，雲藏帝子家。", "窮幽行犖确，息倦倚槎牙。", "緑蘚封茶樹，清霜折藥花。", "世無勾漏令，誰此養丹砂。"]'),
('b49df2be-280c-4529-a8f7-b580b5a69a87','龍門洞','陸游','宋','宋诗','song-poetry','','[]','我來香積寺，清晨歴龍門。',96,'全唐诗/poet.song.128000.json','["我來香積寺，清晨歴龍門。", "孤峰撐蒼昊，大壑裂厚坤。", "古穴吹腥風，峭壁挂爪痕。", "水浮石楠花，崖絡菖蒲根。", "横策意未饜，褰裳探其源。", "絕境豈可名，恨我詩語煩。", "須臾蒼雲合，便恐白雨翻。", "東走得平野，萬里扶桑暾。"]'),
('f3cd0b4c-263d-4b73-89bf-e9e5a32d4c8b','布金院','陸游','宋','宋诗','song-poetry','','[]','萬里西來了宿緣，憑鞭欹帽過年年。',64,'全唐诗/poet.song.128000.json','["萬里西來了宿緣，憑鞭欹帽過年年。", "山寒院落開爐月，霜重郊原斸芋天。", "淺碧鱗鱗人度彴，長空杳杳鳥衝烟。", "夜投蕭寺清無寐，楼角三更月滿川。"]'),
('4008aba5-9eac-4a22-93c4-0f30fc1d0242','離堆伏龍祠觀孫太古畫英惠王像','陸游','宋','宋诗','song-poetry','','[]','岷山導江書禹貢，江流蹴山山爲動。',160,'全唐诗/poet.song.128000.json','["岷山導江書禹貢，江流蹴山山爲動。", "嗚呼秦守信豪傑，千年遺迹人猶誦。", "决江一支溉數州，至今禾黍連雲種。", "孫翁下筆開生面，岌嶪高冠摩屋棟。", "徙木遺風雖峭刻，取材尚足當世用。", "寥寥後世豈乏人，尺寸未施讒已衆。", "要官無責空賦禄，軒盖傳呼真一閧。", "奇勲偉績曠世無，仁人志士臨風慟。", "我遊故祠九頓首，夜遇神君了非夢。", "披雲激電從天來，赤手騎鯨不施鞚。"]'),
('30e7d8d9-0f68-4149-a7c1-38bccd219a22','登灌口廟東大楼觀崏江雪山','陸游','宋','宋诗','song-poetry','','[]','我生不識柏梁建章之宫殿，安得峨冠侍遊宴。',135,'全唐诗/poet.song.128000.json','["我生不識柏梁建章之宫殿，安得峨冠侍遊宴。", "又不及身在滎陽京索間，擐甲横戈夜酣戰。", "胸中迫隘思遠遊，泝江來倚岷山楼。", "千年雪嶺闌邊出，萬里雲濤坐上浮。", "禹迹茫茫始江漢，疏鑿功當九州半。", "丈夫生世要如此，齎志空死能無嘆。", "白髮蕭條吹北風，手把巵酒酹江中。", "姓名未死終磊磊，要與此江東注海。"]'),
('23c06999-38be-4a3a-8187-5b17e992fc3b','郫縣道中思故里','陸游','宋','宋诗','song-poetry','','[]','衰髮不勝簮，馳驅豈復堪。',48,'全唐诗/poet.song.128000.json','["衰髮不勝簮，馳驅豈復堪。", "客魂迷劍外，歸思滿天南。", "江路灘聲壮，雲停雪意酣。", "空懷小叢碧，細酌破吴柑。"]'),
('f6d63269-10bd-4f05-a4dd-4bfabc2395cd','宿江原縣東十里張氏亭子未明而起','陸游','宋','宋诗','song-poetry','','[]','寸廩驅人卒歲勞，一官坐失布衣高。',64,'全唐诗/poet.song.128000.json','["寸廩驅人卒歲勞，一官坐失布衣高。", "劍南十月霜猶薄，江上五更鷄亂號。", "孤枕擁衾尋短夢，青燈照影著征袍。", "客愁相續無時斷，那得并州快剪刀。"]'),
('0f9fdd49-b823-4178-b845-3716f45744b1','戲詠西州風土','陸游','宋','宋诗','song-poetry','','[]','衍沃綿千里，融和被四時。',48,'全唐诗/poet.song.128000.json','["衍沃綿千里，融和被四時。", "蠶叢角歌吹，石室盛書詩。", "緑樹藏漁市，清江遶佛祠。", "吾行更堪樂，載酒上蟆頤。"]'),
('190af6ea-83aa-4e03-80d3-ba23ee000a97','宿彭山縣通津驛大風鄰園多喬木終夜有聲','陸游','宋','宋诗','song-poetry','','[]','木欲静，風不止。',136,'全唐诗/poet.song.128000.json','["木欲静，風不止。", "子欲養，親不留。", "夜誦此語涕莫收。", "吾親之没今幾秋，尚疑捨我而遠遊。", "心冀乘雲反故丘，再拜奉觴陳膳羞。", "陶盎治米聲叟叟，木甑炊餅香浮浮。", "芼薑屑桂調甘柔，稚鼈煮𦞦長魚䐹。", "夜敷枕席視衾裯，晨起熏籠進衣裘。", "哀樂此志終莫酬，有言不聞九泉幽。", "北風歲晚號松楸，哀哉萬里爲食謀。"]'),
('0706f5ff-c589-4982-9d7d-3b874d538b52','眉州郡燕大醉中間道馳出城宿石佛院','陸游','宋','宋诗','song-poetry','','[]','玻瓈春作江水清，紫玉簫如雛鳯鳴。',128,'全唐诗/poet.song.128000.json','["玻瓈春作江水清，紫玉簫如雛鳯鳴。", "漏聲不聞看炧燭，俠氣未減欺飛觥。", "單車萬里信有数，二年三過寧忘情。", "釵頭玉茗妙天下，瓊花一樹真虚名。", "酒酣忽作檀公策，間道絕出東關城。", "清歌未斷去已遠，回首楼堞空峥嶸。", "貂裘狐帽醉走馬，陌上應有行人驚。", "徑投野寺睡正美，魚鼓忽報江天明。"]'),
('0d6f660f-50e8-45b0-ac6c-2b6977a568c0','雙柏','陸游','宋','宋诗','song-poetry','','[]','雙柏屹相向，剛嚴如巨人。',48,'全唐诗/poet.song.128000.json','["雙柏屹相向，剛嚴如巨人。", "龍吟風雨夕，山立雪霜晨。", "閲世易成古，刳心不復春。", "扶顛要力量，歲晚莫全身。"]'),
('3eb967de-57fb-47d9-8a76-d083e51a858c','戍卒說沉黎事有感','陸游','宋','宋诗','song-poetry','','[]','亭障曾無閲歲寕，頻聞夷落犯王靈。',64,'全唐诗/poet.song.128000.json','["亭障曾無閲歲寕，頻聞夷落犯王靈。", "孤城月落寃魂哭，百里風吹戰血腥。", "瘴重厭看茅葉赤，春殘不放柳條青。", "焦頭爛額知何補，弭患從來貴未形。"]'),
('b0d41833-b6f5-4666-a559-7e89ddf34585','平羌道中望峨眉山慨然有作','陸游','宋','宋诗','song-poetry','','[]','白雲如玉城，翠嶺出其上。',72,'全唐诗/poet.song.128000.json','["白雲如玉城，翠嶺出其上。", "異境忽墮前，心目久蕩漾。", "别來二百日，突兀喜亡恙。", "飛仙遥舉手，喚我一税鞅。", "此行豈或使，屏迹事幽曠。", "何必故山歸，更破萬里浪。"]'),
('3bb6c264-1a21-437d-8686-b8dddcd994d1','次韵何元立都曹贈行','陸游','宋','宋诗','song-poetry','','[]','嘉榮東西川，此别不爲遠。',72,'全唐诗/poet.song.128000.json','["嘉榮東西川，此别不爲遠。", "徘徊凌雲寺，决去未遽忍。", "登高望故人，烟樹参差見。", "懸知今日夢，不隔重城鍵。", "平生相從意，百年有未滿。", "結巢青城雲，期子在歲晚。"]'),
('8be169ad-a3c1-45c5-aa9b-d6790899f626','次韵楊嘉父先輩贈行','陸游','宋','宋诗','song-poetry','','[]','貞元舊朝士，太學老諸生。',84,'全唐诗/poet.song.128000.json','["貞元舊朝士，太學老諸生。", "半世不偶諧，殘年正飄零。", "危坐但愁悲，一笑黄河清。", "佳客如晨星，俗子如春萍。", "奇哉今日事，諸賢送東征。", "吸酒杯當空，綴詩筆勿停。", "明發復百憂，君聽馬蹄聲。"]'),
('6456cc23-c15d-4c08-8b47-3b87b31832f7','入榮州境','陸游','宋','宋诗','song-poetry','','[]','一起一伏黄茅岡，崔嵬破丘狐兔藏。',128,'全唐诗/poet.song.128000.json','["一起一伏黄茅岡，崔嵬破丘狐兔藏。", "炯炯寒日清無光，單單終日行羊腸。", "村落聚看如驚麞，亦有銀釵伏短牆。", "黄旗翻翻鼓其鏜，畫角鳴咽吹斜陽。", "長筒汲井熬雪霜，轆轤咿啞官道傍。", "渺然孤城天一方，傳者或云古夜郎。", "其民簡朴士甚良，千里鬱爲詩書鄉。", "閉閤掃地焚清香，老人處處是道場。"]'),
('9022e3c7-ba75-49e1-a14e-806683a54376','井研道中','陸游','宋','宋诗','song-poetry','','[]','窮冬景方促，下嶺路微平。',48,'全唐诗/poet.song.128000.json','["窮冬景方促，下嶺路微平。", "地瘦竹無葉，風乾茅有聲。", "客逰空自嘆，歸計與誰評。", "尚喜長亭下，雲穿夕照明。"]'),
('9e7897ed-c4e8-4bfe-9633-ee00b71d8b3c','頼牟鎮早行','陸游','宋','宋诗','song-poetry','','[]','孤燈照影聽初鷄，攬轡情懷倍慘悽。',64,'全唐诗/poet.song.128000.json','["孤燈照影聽初鷄，攬轡情懷倍慘悽。", "雪作未成雲意閙，茅荒無際客魂迷。", "觸寒手指藏猶裂，畏嶮圖書棄不擕。", "老去有文無賣處，等閑題遍蜀東西。"]'),
('68777e91-b8e7-425a-8282-a0d121d216a7','初到榮州','陸游','宋','宋诗','song-poetry','','[]','亂山缺處城楼呀，雙旗蕭蕭晚吹笳。',160,'全唐诗/poet.song.128000.json','["亂山缺處城楼呀，雙旗蕭蕭晚吹笳。", "烟深緑桂臨絕壑，霜落殘瀬鳴寒沙。", "廢臺已無隐士嘯，遺宅上有高人家。", "鈴齋下榻約僧話，松陰枕石放吏衙。", "杯羹最珍慈竹筍，缾水自養山薑花。", "地爐堆獸熾石炭，瓦鼎號蚓煎秋茶。", "少年遠逰無百里，一饑能使行天涯。", "豈惟慣見蓬婆雪，直恐遂泛星河槎。", "故巢肻作兒女戀，異境會向鄉閭誇。", "一杯徑醉幘自墜，燈下髮影看鬖髿。"]'),
('6ac4bacd-5e38-4236-9631-0439fb8442a4','城上二首  其一','陸游','宋','宋诗','song-poetry','','[]','雙雙黄犢臥斜陽，葉葉丹楓著早霜。',64,'全唐诗/poet.song.128000.json','["雙雙黄犢臥斜陽，葉葉丹楓著早霜。", "沙水自鳴如有恨，野花無主爲誰芳。", "郫筒味釅愁濡甲，巴曲聲悲怯斷腸。", "賴有生平管城子，不妨驅使荅風光。"]'),
('cb2d3207-d51c-451f-88be-fce009d44c1a','城上二首  其二','陸游','宋','宋诗','song-poetry','','[]','濯錦豪華夢不通，巋然孤疊亂山中。',64,'全唐诗/poet.song.128000.json','["濯錦豪華夢不通，巋然孤疊亂山中。", "行歌滿道知人樂，露積連村見歲豐。", "萬瓦新霜掃殘瘴，一林丹葉換青楓。", "鵝黄名醖何由得，且醉杯中琥珀紅。"]'),
('b2d6e767-7c3a-4e7e-ae93-910ca34c2be4','西楼夕望','陸游','宋','宋诗','song-poetry','','[]','夜郎城裏嘆途窮，賴有西楼著此翁。',64,'全唐诗/poet.song.128000.json','["夜郎城裏嘆途窮，賴有西楼著此翁。", "溪鳥孤飛寒靄外，野人參語夕陽中。", "蒼天可恃何曾老，白髮緣愁却未公。", "俗態十年看爛熟，不如留眼送歸鴻。"]'),
('27c0bf34-38d9-48e1-a50d-04216d52de17','醉中懷眉山舊逰','陸游','宋','宋诗','song-poetry','','[]','勁酒少和氣，哀歌無歡情。',80,'全唐诗/poet.song.128000.json','["勁酒少和氣，哀歌無歡情。", "故鄉不敢思，登高望錦城。", "錦城那得去，彷彿蟆頤路。", "遙知尊前人，指我題詩處。", "我雖流落夜郎天，遇酒能狂似少年。", "想見東郊携手日，海棠如雪柳飛綿。"]'),
('6a9e4a36-a609-481a-82e4-10d1368c754e','登城望西崦','陸游','宋','宋诗','song-poetry','','[]','登城望西崦，数家斜照中。',72,'全唐诗/poet.song.128000.json','["登城望西崦，数家斜照中。", "柴荆晝亦閉，乃有太古風。", "慘淡起炊烟，寂歴下釣筒。", "土瘦麥苗短，霜重桑枝空。", "恐是種桃人，或有采芝翁。", "何當宿楼上，月明照夜舂。"]'),
('72e8b4f0-25e5-45b5-b8ea-5e17526d2173','甲午十一月十三夜夢右臂踊出一小劍長八九寸有光既覺猶微痛也','陸游','宋','宋诗','song-poetry','','[]','少年學劍白猿翁，曾破浮生十歲功。',64,'全唐诗/poet.song.128000.json','["少年學劍白猿翁，曾破浮生十歲功。", "玉具拄頤誰復許，蒯緱彈鋏老猶窮。", "床頭忽覺蛟龍吼，天上方驚牛斗空。", "此夢怪奇君記取，佩刀猶得世三公。"]'),
('ed8ed78f-6c01-4b85-a9e9-2398efb4e7d2','漢齋中夜坐有感','陸游','宋','宋诗','song-poetry','','[]','荒山爲城溪作壕，風鼓巨木聲翻濤。',128,'全唐诗/poet.song.128000.json','["荒山爲城溪作壕，風鼓巨木聲翻濤。", "鴟梟乘屋彈不去，狐狸欺人怒竪毛。", "雨來紅鶴更可惡，争巢一似嬰兒號。", "城孤屋老草木茂，正坐人少此輩豪。", "急呼五百具畚鍤，欲掀窟穴窮腥臊。", "忽然語罷却自笑，殘年何至與汝鏖。", "浣花江色緑如黛，春波灔灔浮輕舠。", "行當繫纜柳陰下，仰聽鶯語傾香醪。"]'),
('8e76c242-b242-464f-a5aa-3afed138cf5e','晚登横溪閣二首  其一','陸游','宋','宋诗','song-poetry','','[]','楼鼓聲中日又斜，憑高愈覺在天涯。',64,'全唐诗/poet.song.128000.json','["楼鼓聲中日又斜，憑高愈覺在天涯。", "空桑客土生秋草，野渡虚舟集晚鴉。", "瘴霧不開連六詔，俚歌相荅带三巴。", "故鄉可望應添泪，莫恨雲山萬疊遮。"]'),
('c08cf794-4bb6-4f51-b162-59d7e3b7e603','晚登横溪閣二首  其二','陸游','宋','宋诗','song-poetry','','[]','犖确坡頭笻竹枝，西臨村路立多時。',64,'全唐诗/poet.song.128000.json','["犖确坡頭笻竹枝，西臨村路立多時。", "賣蔬市近還家早，煮井人忙下麥遲。", "病客情懷常怯酒，山城光景盡供詩。", "晚來試問愁多少，只許高楼横笛吹。"]'),
('068ee7d4-3d53-47ab-b583-4569b236b9f1','昭德堂晚步','陸游','宋','宋诗','song-poetry','','[]','笑喚枯笻蹋夕陽，探春聊作静中忙。',64,'全唐诗/poet.song.128000.json','["笑喚枯笻蹋夕陽，探春聊作静中忙。", "高枝鵲語如相命，幽徑梅開秪自香。", "苔蝕斷碑驚世換，鐘來廢寺覺城荒。", "謫仙未必無遺恨，老欠題詩到夜郎。"]'),
('da15c8c2-618c-49fb-ba64-5f91bcd24377','龍洞','陸游','宋','宋诗','song-poetry','','[]','峭崖磨天如立壁，柟根横走松倒植。',128,'全唐诗/poet.song.128000.json','["峭崖磨天如立壁，柟根横走松倒植。", "呀然一岫驚倒人，空洞坡陁三百尺。", "幽陰宜爲異物託，角爪痕存猶可識。", "想當蟠蟄未奮時，腥風逼人雲觸石。", "一朝偶爲旱歲起，卷海作雨飛霹靂。", "向來伊吕正如此，莘渭千年有遺迹。", "我欲酌酒招蜿蜒，安用辛苦常行天。", "太平海內多豐年，歸來故祠聽管弦。"]'),
('7295a25c-b1c9-4913-909e-15212b327734','客中夜寒戲作長謠','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','孤翁癡鈍如寒蠅，霜夕不暝愁嚴凝。',112,'全唐诗/poet.song.128000.json','["孤翁癡鈍如寒蠅，霜夕不暝愁嚴凝。", "寝衣觸體起芒粟，鼻息嘘潤成冰凌。", "鼕鼕黙數嚴譙鼓，耿耿獨看幽窗燈。", "支床龜老共夜永，號月鷄冷同晨興。", "白狐紫貂了不暖，何况蜀錦并吳綾。", "静思忽得安樂法，人生所欠絮與繒。", "十年一衲尚可過，不信請視匡山僧。"]'),
('53149044-1a77-42b1-b10c-c3a1a7da203b','高齋小飲戲作','陸游','宋','宋诗','song-poetry','','[]','梅花又發鬼門關，坐覺春風萬里寛。',64,'全唐诗/poet.song.128000.json','["梅花又發鬼門關，坐覺春風萬里寛。", "荔子陰中時縱酒，竹枝聲裏彊追歡。", "丁年漢使殊方老，子夜吴歌昨夢殘。", "白帝夜郎俱不惡，兩公補處得憑欄。"]'),
('62be4fe5-682d-4e82-a181-6b4166b05a2f','太液黄鵠歌','陸游','宋','宋诗','song-poetry','','[]','建章宫裏春風寒，太液水生池面寛。',96,'全唐诗/poet.song.128000.json','["建章宫裏春風寒，太液水生池面寛。", "中人馳奏黄鵠下，龍旗豹尾臨池看。", "芹香藻暖鵠得意，左右從官呼萬歲。", "須臾傳詔宴公卿，歡聲如雷動天地。", "時平宮省逰樂多，黄鵠刷羽涵恩波。", "小臣珥筆龍墀下，願繼前朝天馬歌。"]'),
('8c8c9a8c-6136-4eee-85c4-6de6ed7a0288','自唐安徙家來和義出城迎之馬上作','陸游','宋','宋诗','song-poetry','','[]','身如林下僧，處處常寄包。',96,'全唐诗/poet.song.128000.json','["身如林下僧，處處常寄包。", "家如梁上鷰，歲歲旋作巢。", "豈惟人所憐，顧影每自嘲。", "眼看佳山水，不得結把茅。", "造物困豪傑，如視餓虎哮。", "要令出精神，感激使叫呶。", "頗思投筆去，走馬盤雲旓。", "三更冒急雪，大戰梁楚郊。"]'),
('2d5a8fc9-60d2-4fff-831c-6e1a60e21e66','乙未元日','陸游','宋','宋诗','song-poetry','','[]','五十人間老大身，更堪從此数新春。',64,'全唐诗/poet.song.128000.json','["五十人間老大身，更堪從此数新春。", "鼕鼕漏鼓催窗色，急急文書動驛塵。", "病後光陰常自惜，客中節物爲誰新。", "壯心只向郵亭盡，自揣頭顱莫問人。"]'),
('fd46fa15-e88f-43ce-b2e0-e1e650d294e2','别榮州','陸游','宋','宋诗','song-poetry','','[]','浮生歲歲俱如夢，一枕輕安亦可人。',64,'全唐诗/poet.song.128000.json','["浮生歲歲俱如夢，一枕輕安亦可人。", "偶落山城無事處，暫還老子自由身。", "嘯臺載酒雲生履，仙穴尋梅雨墊巾。", "便恐清遊從此少，錦城車馬漲紅塵。"]'),
('8c41113b-4cab-4739-81bf-bbb15ac896de','聞仲高從兄訃','陸游','宋','宋诗','song-poetry','','[]','去國萬里逰，發書三日哭。',96,'全唐诗/poet.song.128000.json','["去國萬里逰，發書三日哭。", "久矣吾已衰，哀哉公不淑。", "寄書墨未乾，玉立在我目。", "天高鬼神惡，生世露電速。", "丹心抱忠貞，白首悲放逐。", "九閽不可叫，百身何由贖。", "文章果何罪，一斥獨不復。", "上壽阿母前，悔不早碌碌。"]'),
('c2938062-dece-41fe-8ed9-782f0ccb1036','夏日過摩訶池','陸游','宋','宋诗','song-poetry','','[]','烏帽翩翩白紵輕，摩訶池上試閑行。',64,'全唐诗/poet.song.128000.json','["烏帽翩翩白紵輕，摩訶池上試閑行。", "淙潺野水鳴空苑，寂歴斜陽下廢城。", "縱轡迎涼看馬影，袖鞭尋句聽蟬聲。", "白頭散吏元無事，却爲興亡一愴情。"]'),
('8ec13a35-2270-45e5-9bf1-b8fa7020d473','早行','陸游','宋','宋诗','song-poetry','','[]','筰馬踐槐影，紗籠吹蠟香。',48,'全唐诗/poet.song.128000.json','["筰馬踐槐影，紗籠吹蠟香。", "憑鞭尋斷夢，側帽受微涼。", "病骨更疏放，衰懷罷激昻。", "道邉雙石筍，笑我伴人忙。"]'),
('4aca4c21-4dd4-4865-a3ae-d2f4dff67df7','天申節前三日大聖慈寺華嚴閣燃燈甚盛逰人過於元夕','陸游','宋','宋诗','song-poetry','','[]','萬瓦如鱗百尺梯，遥看突兀與雲齊。',64,'全唐诗/poet.song.128000.json','["萬瓦如鱗百尺梯，遥看突兀與雲齊。", "寶簾風定燈相射，綺陌塵香馬不嘶。", "星隕半空天宇静，蓮生陸地客心迷。", "歸途細踏槐陰月，家在花行更向西。"]'),
('68dfca17-6081-4773-bda1-8286c7daffe6','喜雨','陸游','宋','宋诗','song-poetry','','[]','黄塵赤日欲忘生，一夜新涼滿錦城。',64,'全唐诗/poet.song.128000.json','["黄塵赤日欲忘生，一夜新涼滿錦城。", "雨急驟增車轍水，泥深漸壯馬蹄聲。", "蚊蠅斂迹知無地，燈火於人頓有情。", "市遠鷄豚不須問，小畦蔬甲已堪烹。"]'),
('bb8bf161-14c4-411d-80b4-8c3d1a2f063f','夜聞浣花江聲甚壯','陸游','宋','宋诗','song-poetry','','[]','浣花之東當筰橋，奔流齧橋橋爲搖。',96,'全唐诗/poet.song.128000.json','["浣花之東當筰橋，奔流齧橋橋爲搖。", "分洪初疑兩蛟舞，觸石散作千珠跳。", "壯聲每挾雷雨横，巨勢濳借黿鼉驕。", "夢回聞之坐太息，鐡衣何日東征遼。", "銜枚度磧沙颯颯，盤槊斷隴風蕭蕭。", "不然投檄徑歸去，短篷臥聽錢塘潮。"]'),
('70aa7716-e7cf-49e0-a200-975510db4f02','暑行憩新都驛','陸游','宋','宋诗','song-poetry','','[]','細細黄花落古槐，江皋不雨轉輕雷。',64,'全唐诗/poet.song.128000.json','["細細黄花落古槐，江皋不雨轉輕雷。", "長空鳥破蒼烟去，落日人從緑野來。", "散策意行尋水石，脱巾高臥避氛埃。", "羈逰未羡端居樂，看月房湖又一回。"]'),
('e276f743-a38e-4d00-b0c1-3da267b77cfa','早發新都驛','陸游','宋','宋诗','song-poetry','','[]','喔喔江村鷄，迢迢縣門漏。',96,'全唐诗/poet.song.128000.json','["喔喔江村鷄，迢迢縣門漏。", "河漢縱復横，繁星明如晝。", "爱涼趣上馬，未曉閲兩堠。", "高林起宿鳥，絕澗落驚狖。", "寺楼插蒼烟，沙泉瀉幽竇。", "我行忽萬里，坐嘆關河溜。", "官如廣文冷，面作拾遺瘦。", "今年盍歸哉，勿落春雁後。"]'),
('bdfdca19-8108-47bd-b600-efe3d0c17a3a','謁諸葛丞相廟','陸游','宋','宋诗','song-poetry','','[]','漢終四百天所命，老賊方持太阿柄。',96,'全唐诗/poet.song.128000.json','["漢終四百天所命，老賊方持太阿柄。", "區區梁益豈足支，不忍安坐觀異姓。", "遺民亦知王室在，閏位那干天統正。", "公雖已没有神靈，猶假賊手誅鍾鄧。", "前年我過沔陽祠，再拜奠爼衰泪迸。", "潔齋請作送迎詩，精忠大義神其聽。"]'),
('804e0473-9d07-4b0c-af5d-00b818eaf973','自漢州之金堂過沈氏竹園小憩坐間微雨','陸游','宋','宋诗','song-poetry','','[]','修修萬竹壓康莊，碧玉掾圍一尺彊。',64,'全唐诗/poet.song.128000.json','["修修萬竹壓康莊，碧玉掾圍一尺彊。", "雪節烟梢誰暇賞，馬蹄車轍可憐忙。", "帽邉忽墮吹香句，肘後舊傳醫俗方。", "更覺清逰天所惜，坐來飛雨度横塘。"]'),
('3c38ff74-501a-4a8f-9594-97fecfd0a4d6','自小雲頂上雲頂寺','陸游','宋','宋诗','song-poetry','','[]','素衣雖成緇，不爲京路塵。',96,'全唐诗/poet.song.128000.json','["素衣雖成緇，不爲京路塵。", "躍馬上雲頂，欲呼飛仙人。", "飛仙不可呼，野僧意甚真。", "煎茶清樾下，童子拾墮薪。", "我少本疏放，一出但坐貧。", "縛袴屬櫜鞬，哀哉水雲身。", "此地雖暫寓，失喜忘吟呻。", "故溪歸去來，歲晚思鱸蓴。"]'),
('5c7f18e0-8f9e-43aa-a14d-ac4b604f65ee','馬上微雨','陸游','宋','宋诗','song-poetry','','[]','三日觸毒暑，衣垢背汗浹。',72,'全唐诗/poet.song.128000.json','["三日觸毒暑，衣垢背汗浹。", "今旦殊蕭然，涼雨吹醉頰。", "瘦松無横枝，蠧竹少全葉。", "渚蓮乃可念，泫泣如放妾。", "豈惟人意適，我馬亦振鬛。", "遠村有歸人，清溪争晚涉。"]'),
('9570219e-7bc0-4703-ba28-ad73ede4c405','彌牟鎮驛舍小酌','陸游','宋','宋诗','song-poetry','','[]','郵亭草草置盤盂，買果煎蔬便有餘。',64,'全唐诗/poet.song.128000.json','["郵亭草草置盤盂，買果煎蔬便有餘。", "自許白雲終醉死，不論黄紙有除書。", "角巾墊雨蟬聲外，細葛含風日落初。", "行遍天涯身尚健，却嫌陶令爱吾廬。"]'),
('642310ec-b1ab-41e9-8cc5-20539db34dc1','遊彌牟菩提院庭下有凌霄藤附古楠其高数丈花已零落滿地','陸游','宋','宋诗','song-poetry','','[]','絳英翠蔓亦佳哉，零亂空庭碼瑙杯。',32,'全唐诗/poet.song.128000.json','["絳英翠蔓亦佳哉，零亂空庭碼瑙杯。", "遍雨新花天有意，定知閑客欲閑來。"]'),
('7845d340-424e-41d3-85b5-8a8c9544ac31','楼上醉歌','陸游','宋','宋诗','song-poetry','','[]','我遊四方不得意，陽狂施藥成都市。',96,'全唐诗/poet.song.128000.json','["我遊四方不得意，陽狂施藥成都市。", "大瓢滿貯隨所求，聊爲疲民起憔悴。", "瓢空夜静上高楼，買酒捲簾邀月醉。", "醉中拂劍光射月，往往悲歌獨流涕。", "剗却君山湘水平，斫却桂樹月更明。", "丈夫有志苦難成，修名未立華髮生。"]'),
('7d7b9012-7a9d-4e93-b8e8-9dea4f6ddfa8','伏日獨逰城西','陸游','宋','宋诗','song-poetry','','[]','幕府重來老令威，山川良是昔人非。',64,'全唐诗/poet.song.128000.json','["幕府重來老令威，山川良是昔人非。", "癡兒已遣了官事，伏日元知當早歸。", "避熱幽花房自斂，迎秋高樹葉先飛。", "論詩敢補先師處，僭拂江頭舊釣磯。"]'),
('69711172-d195-4343-927e-62ae4838340f','五鼓送客出城馬上作','陸游','宋','宋诗','song-poetry','','[]','夜漏餘十刻，涼颸如九秋。',48,'全唐诗/poet.song.128000.json','["夜漏餘十刻，涼颸如九秋。", "灘聲聒酒醒，月色照人愁。", "落魄悲孤宦，龍鍾怯遠遊。", "此生那可料，六歲劍南州。"]'),
('4479be8b-b462-4b89-b5c1-c71d422a4dac','寓舍書懷','陸游','宋','宋诗','song-poetry','','[]','借得茅齋近筰橋，羈懷病思兩無聊。',64,'全唐诗/poet.song.128000.json','["借得茅齋近筰橋，羈懷病思兩無聊。", "春從豆蔲梢頭老，日向樗蒱齒上消。", "叢竹曉兼風力横，高梧夜挾雨聲驕。", "書生莫倚身常健，未畫凌烟鬢已凋。"]'),
('e96d72fd-3a5f-4c71-a4ac-9a591c619e47','夜登城楼','陸游','宋','宋诗','song-poetry','','[]','上天何蒼蒼，四序浩旋斡。',120,'全唐诗/poet.song.128000.json','["上天何蒼蒼，四序浩旋斡。", "異哉今年熱，炊鬻不可活。", "夜分睡復起，揺箑腕欲脱。", "彊登城西楼，月露渺空濶。", "憑欄弄清影，涼颸入蕉葛。", "濕螢沾草根，驚鶻起木末。", "亦知難久留，襟抱資一豁。", "人事迭廢興，天理交予奪。", "羲和不停馭，去若弦上筈。", "此熱會當衰，歲晚備裘褐。"]'),
('3092795b-5b94-4b67-ab74-46d380959b77','試茶','陸游','宋','宋诗','song-poetry','','[]','蒼爪初驚鷹脱韝，得湯已見玉花浮。',64,'全唐诗/poet.song.128000.json','["蒼爪初驚鷹脱韝，得湯已見玉花浮。", "睡魔何止避三舍，歡伯直知輸一籌。", "日鑄焙香懷舊隐，谷簾試水憶西逰。", "銀缾銅碾俱官様，恨欠纖纖爲捧甌。"]'),
('77e6c955-c697-4edb-a230-ee001bd753ac','成都大閲','陸游','宋','宋诗','song-poetry','','[]','千步毬場爽氣新，西山遥見碧嶙峋。',64,'全唐诗/poet.song.128000.json','["千步毬場爽氣新，西山遥見碧嶙峋。", "令傳雪嶺蓬婆外，聲震秦川渭水濵。", "旗脚倚風時弄影，馬蹄經雨不霑塵。", "屬櫜縛袴毋多恨，久矣儒冠誤此身。"]'),
('5fc1ab6d-8e08-450e-a667-b16c498332f1','書懷','陸游','宋','宋诗','song-poetry','','[]','萬里馳驅坐一饑，自憐無計脱塵鞿。',64,'全唐诗/poet.song.128000.json','["萬里馳驅坐一饑，自憐無計脱塵鞿。", "身留幕府還家少，眼亂文書把酒稀。", "客路更逢秋色晚，故山空有夢魂歸。", "芋羮豆飯元堪飽，錯用人言恨子威。"]'),
('6852ebe4-f902-4bd6-945c-341d33b2fa6a','逰大智寺','陸游','宋','宋诗','song-poetry','','[]','脱髮紛滿梳，衰顔不堪照。',168,'全唐诗/poet.song.128000.json','["脱髮紛滿梳，衰顔不堪照。", "百年忽已半，去日如過燒。", "平生功名心，上馬無燕趙。", "爾來閲世故，萬事驚錯料。", "豈無舊朋儔，聮翩半廊廟。", "誰能伴此老，泝峽聽猿叫。", "錦城得数公，意氣如再少。", "偷閑訪野寺，繫馬追一笑。", "新糟厭玉貍，畏酒亦復釂。", "古殿鼪鼯豪，壊壁冠佩肖。", "摩挲宋公詩，句法嘆高妙。", "正如霓裳曲，零落得遺調。", "歸途繚長堤，掠面霜氣峭。", "佳逰不可忘，落筆君勿誚。"]'),
('5d4625ab-1622-4528-b859-4a4939170b45','看月睡晚戲作','陸游','宋','宋诗','song-poetry','','[]','香火課夙興，風月留晚睡。',72,'全唐诗/poet.song.128000.json','["香火課夙興，風月留晚睡。", "直言散吏閑，亦未盡無事。", "舊聞雲臺翁，高枕閲塵世。", "至今青嶂間，鼻息亂松吹。", "平生寡嗜好，所願究此味。", "千年一欠伸，笑看巖花墜。"]'),
('8bb18248-b05e-4522-b022-7c6a146e6c1f','成都書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','劍南山水盡清暉，濯錦江邉天下稀。',64,'全唐诗/poet.song.128000.json','["劍南山水盡清暉，濯錦江邉天下稀。", "烟柳不遮楼角斷，風花時傍馬頭飛。", "芼羮筍似稽山美，斫膾魚如笠澤肥。", "客報城西有園賣，老夫白首欲忘歸。"]'),
('d5443958-d8cb-4171-85f9-5b1c02ed6af0','成都書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','大城少城柳已青，東臺西臺雪正晴。',64,'全唐诗/poet.song.128000.json','["大城少城柳已青，東臺西臺雪正晴。", "鶯花又作新年夢，絲竹常聞静夜聲。", "廢苑烟蕪迎馬動，清江春漲拍堤平。", "尊中酒滿身彊健，未恨飄零過此生。"]'),
('01f2e7b5-f26a-4e0e-952b-a66eb16d529f','雙溪道中','陸游','宋','宋诗','song-poetry','','[]','曉出筰橋門，天低日未暾。',48,'全唐诗/poet.song.128000.json','["曉出筰橋門，天低日未暾。", "緑陂寒淡淡，白霧遠昏昏。", "古路亂車轍，行人驚雁群。", "征塗不須厭，蓬轉本無根。"]'),
('75e7e32b-f974-479e-9173-2620698498c7','牛飲市中小飲呈坐客','陸游','宋','宋诗','song-poetry','','[]','牛飲橋頭小市東，店門繫馬一尊同。',64,'全唐诗/poet.song.128000.json','["牛飲橋頭小市東，店門繫馬一尊同。", "已能自置功名外，尚欲相期意氣中。", "褐擁紫茸迎曉日，酒翻紅浪醉春風。", "從今共約無疏索，竹外梅花欲惱公。"]'),
('d350698f-e9bb-4e91-9cb6-88ea549594ea','自警','陸游','宋','宋诗','song-poetry','','[]','乳烹佛粥遽如許，菜簇春盤行及時。',64,'全唐诗/poet.song.128000.json','["乳烹佛粥遽如許，菜簇春盤行及時。", "草木欣欣渠得意，乾坤浩浩我何私。", "懷材所忌多輕用，學道當從不自欺。", "旦莫置規君勿怪，修身三省自先師。"]'),
('0437362b-43d2-4f99-ad54-81e10a7205a1','午寢','陸游','宋','宋诗','song-poetry','','[]','眼澀朦朧不自支，欠伸常恨到床遲。',64,'全唐诗/poet.song.128000.json','["眼澀朦朧不自支，欠伸常恨到床遲。", "庭花著雨晴方見，野客敲門去始知。", "灰冷香烟無復在，湯成茶椀徑須持。", "頽然却自嫌疏放，旋了生涯一首詩。"]'),
('ee20d271-b62f-455e-8d74-4178abc191dd','白髮','陸游','宋','宋诗','song-poetry','','[]','我生實多邅，九折行晚途。',96,'全唐诗/poet.song.128000.json','["我生實多邅，九折行晚途。", "憂傷日熏心，驚見頰與顱。", "稍生秋風時，競出寒雨餘。", "星星初尚稀，𧥄𧥄不可除。", "昔如春柳妍，今作霜蓬枯。", "蓬枯有再緑，念我豈得如。", "平昔樂方外，固與功名疏。", "投鑷三嘆息，金丹豈無書。"]'),
('e805169b-f417-4162-9655-bd1d0be4d23c','明日午睡至暮復次前韵','陸游','宋','宋诗','song-poetry','','[]','酒力醺然入四支，華胥税駕不應遲。',64,'全唐诗/poet.song.128000.json','["酒力醺然入四支，華胥税駕不應遲。", "殘年已覺衰難彊，萬事無如睡不知。", "幸有琴書供枕籍，安能冠带更支持。", "紅爐過盡灰如雪，獨守青燈坐畫詩。"]'),
('435b1b5b-33b6-4b79-8396-a49930c5b8b1','醉中長歌','陸游','宋','宋诗','song-poetry','','[]','闌干斗柄搖天東，人間一夜回春風。',128,'全唐诗/poet.song.128000.json','["闌干斗柄搖天東，人間一夜回春風。", "注桃染柳歲相似，惟我衰顔非昔紅。", "可憐逢春不自感，更欲使氣驚兒童。", "烟郊射雉錦臆碎，水亭供鱠金盤空。", "歸穿南市萬人看，流星突過連錢驄。", "高樓作歌醉自寫，墨光燭焰交長虹。", "人生未死貴適意，萬里作客元非窮。", "故人夜直金鑾殿，僵臥獨聽宫門鐘。"]'),
('23a201eb-12d5-4cef-b486-1ce3d8e49470','對酒','陸游','宋','宋诗','song-poetry','','[]','扇邉生怕庾公塵，索笑來逰錦水濵。',64,'全唐诗/poet.song.128000.json','["扇邉生怕庾公塵，索笑來逰錦水濵。", "四野雲齊初釀雪，一枝梅動已催春。", "緑尊有味能消日，白髮無情不貸人。", "商略此生何所恨，太平時得自由身。"]'),
('fb208c82-9107-46b5-b5fd-c7ec49c9a30d','人日飲昭覺','陸游','宋','宋诗','song-poetry','','[]','天涯羈旅逄人日，病起消搖集寶坊。',64,'全唐诗/poet.song.128000.json','["天涯羈旅逄人日，病起消搖集寶坊。", "雪水初融錦江漲，梅花半落緑苔香。", "家山松桂年年長，幕府文書日日忙。", "自笑餘生有幾許，一庵僣與得深藏。"]'),
('5c8b51e6-c1df-4261-ba70-055e75f84f03','上元前一日','陸游','宋','宋诗','song-poetry','','[]','異縣客逰久，今年春事遲。',48,'全唐诗/poet.song.128000.json','["異縣客逰久，今年春事遲。", "峭寒增酒價，微雨惱燈期。", "老態人未覺，孤愁心自知。", "停車呼病婦，彊出伴諸兒。"]'),
('35b6308b-3251-4e16-8ee8-bcd6a0a444d4','上元二首  其一','陸游','宋','宋诗','song-poetry','','[]','細細香塵暗六街，魚鱗淺碧暮雲開。',64,'全唐诗/poet.song.128000.json','["細細香塵暗六街，魚鱗淺碧暮雲開。", "新粧褰幕全身見，誤馬隨車一笑回。", "酒釅頓忘風力峭，夜長猶恨漏聲催。", "京華舊侶彫零盡，短鬢成絲心未灰。"]'),
('e428669b-5cea-4db2-bca2-41246598fb47','上元二首  其二','陸游','宋','宋诗','song-poetry','','[]','病起衰顔非昔紅，偷閑聊與少年同。',64,'全唐诗/poet.song.128000.json','["病起衰顔非昔紅，偷閑聊與少年同。", "一規寒玉挂楼角，千點華星來坐中。", "久戍遺民雖困弊，承平舊鎮尚繁雄。", "歸時瘦馬崔嵬影，定有遊人笑此翁。"]'),
('975016b7-4a94-4939-8a8f-dca010e2ba6f','喜譚德稱歸','陸游','宋','宋诗','song-poetry','','[]','少鄙章句學，所慕在經世。',120,'全唐诗/poet.song.128000.json','["少鄙章句學，所慕在經世。", "諸公薦文章，頗恨非素志。", "一朝落江湖，爛漫得自恣。", "討論極王霸，事業窺莘渭。", "孔明景略間，却立頗眦睨。", "從人無一欣，對食有三喟。", "譚侯信豪雋，可共不朽事。", "天涯再相見，握手更抆泪。", "欲尋西郊路，斗酒傾意氣。", "浩歌君和我，勿作尋常醉。"]'),
('da293e10-65a4-4f76-a10d-69a7b8602ead','春感','陸游','宋','宋诗','song-poetry','','[]','少時狂走西復東，銀鞍駿馬馳如風。',192,'全唐诗/poet.song.128000.json','["少時狂走西復東，銀鞍駿馬馳如風。", "眼看春去不復惜，只道歲月來無窮。", "初逰漢中亦未覺，一飲尚可傾千鍾。", "义魚狼藉漾水濁，獵虎蹴蹋南山空。", "射堋命中萬人看，毬門對植雙旗紅。", "華堂却來弄筆硯，新詩醉草誇坐中。", "劍關南山纔幾日，壯氣摧縮成衰翁。", "雪霜蕭颯已滿鬢，蛟龍鬱屈空蟠胸。", "鄰園杏花忽爛漫，推枕彊起隨逰蜂。", "遶看百匝幾嘆息，吹紅洗緑行匆匆。", "莫年逢春尚有幾，常恐春去尋無踪。", "青錢三百幸可辦，且判爛醉酤郫筒。"]'),
('b5c5d259-6837-42fb-8167-31c35138105d','春晴暄甚逰西市施家園','陸游','宋','宋诗','song-poetry','','[]','税駕名園半日留，逰絲飛蝶晚悠悠。',64,'全唐诗/poet.song.128000.json','["税駕名園半日留，逰絲飛蝶晚悠悠。", "驟暄不爲海棠計，長晝只添鸚鵡愁。", "老去自驚詩酒減，客中偏覺歲時遒。", "東風好爲吹歸夢，著我松江弄釣舟。"]'),
('7ab09f0f-d4c4-4716-9d62-a64975579a27','花時遍逰諸家園十首  其一','陸游','宋','宋诗','song-poetry','','[]','看花南陌復東阡，曉露初乾日正妍。',32,'全唐诗/poet.song.128000.json','["看花南陌復東阡，曉露初乾日正妍。", "走馬碧鷄坊裏去，市人喚作海棠顛。"]'),
('750e75a2-f1de-443f-8b7d-5deabe9bd3d6','花時遍逰諸家園十首  其二','陸游','宋','宋诗','song-poetry','','[]','爲爱名花抵死狂，只愁風日損紅芳。',32,'全唐诗/poet.song.128000.json','["爲爱名花抵死狂，只愁風日損紅芳。", "緑章夜奏通明殿，乞借春陰護海棠。"]'),
('eb3aa8b8-e579-47a6-b8d9-0e6c5636e156','花時遍逰諸家園十首  其三','陸游','宋','宋诗','song-poetry','','[]','翩翩馬上帽簷斜，盡日尋春不到家。',32,'全唐诗/poet.song.128000.json','["翩翩馬上帽簷斜，盡日尋春不到家。", "偏爱張園好風景，半天高柳臥溪花。"]'),
('b00ed837-bf1a-4787-af5e-fcc5a77ca60b','花時遍逰諸家園十首  其四','陸游','宋','宋诗','song-poetry','','[]','花陰掃地置清尊，爛醉歸時夜已分。',32,'全唐诗/poet.song.128000.json','["花陰掃地置清尊，爛醉歸時夜已分。", "欲睡未成欹倦枕，輪囷帳底見紅雲。"]'),
('41141e59-b4d1-43e6-b230-6a715c9ba263','花時遍逰諸家園十首  其五','陸游','宋','宋诗','song-poetry','','[]','宣華無樹著啼鶯，惟有摩訶春水生。',32,'全唐诗/poet.song.128000.json','["宣華無樹著啼鶯，惟有摩訶春水生。", "故老能言當日事，直將宫錦裹宫城。"]'),
('f05b9e69-b8df-4f97-9748-d96c6bc27f2c','花時遍逰諸家園十首  其六','陸游','宋','宋诗','song-poetry','','[]','枝上猩猩血未晞，尊前紅袖醉成圍。',32,'全唐诗/poet.song.128000.json','["枝上猩猩血未晞，尊前紅袖醉成圍。", "應須直到三更看，畫燭如椽爲發輝。"]'),
('5b9a1594-acbd-4cb2-970d-13c995aa9f39','花時遍逰諸家園十首  其七','陸游','宋','宋诗','song-poetry','','[]','重蕚丹砂品最高，可憐寂寞棄蓬蒿。',32,'全唐诗/poet.song.128000.json','["重蕚丹砂品最高，可憐寂寞棄蓬蒿。", "會當車載金錢去，買取春歸亦足豪。"]'),
('4ece7c51-2f39-4f73-8cf6-415ea95749e9','花時遍逰諸家園十首  其八','陸游','宋','宋诗','song-poetry','','[]','絲絲紅蕚弄春柔，不似疏梅只慣愁。',32,'全唐诗/poet.song.128000.json','["絲絲紅蕚弄春柔，不似疏梅只慣愁。", "常恐夜寒花索寞，錦茵銀燭按涼州。"]'),
('1b9b6de9-e33d-47ab-9c44-eb37f83f594f','花時遍逰諸家園十首  其九','陸游','宋','宋诗','song-poetry','','[]','飛花盡逐五更風，不照先生社酒中。',32,'全唐诗/poet.song.128000.json','["飛花盡逐五更風，不照先生社酒中。", "輸與新來雙燕子，啣泥猶得带殘紅。"]'),
('05be61a5-14ea-4fa5-b10b-40f8b7212505','花時遍逰諸家園十首  其一○','陸游','宋','宋诗','song-poetry','','[]','海棠已過不成春，絲竹凄涼鎖暗塵。',32,'全唐诗/poet.song.128000.json','["海棠已過不成春，絲竹凄涼鎖暗塵。", "眼看燕脂吹作雪，不須零落始愁人。"]'),
('e38d1add-7e72-4b61-a7fd-db544eb068ff','曉過萬里橋','陸游','宋','宋诗','song-poetry','','[]','曉出錦江邉，長橋柳带烟。',48,'全唐诗/poet.song.128000.json','["曉出錦江邉，長橋柳带烟。", "豪華行樂地，芳潤養花天。", "擁路看欹帽，窺門笑墜鞭。", "京華歸未得，聊此送流年。"]'),
('0ba02de6-c866-4cb2-a12d-6e275adc6f7c','自合江亭涉江至趙園','陸游','宋','宋诗','song-poetry','','[]','政爲梅花憶兩京，海棠又滿錦官城。',64,'全唐诗/poet.song.128000.json','["政爲梅花憶兩京，海棠又滿錦官城。", "鴉藏高柳陰初宻，馬涉清江水未生。", "風掠春衫驚小冷，酒潮玉頰見微頳。", "殘年飄泊無時了，腸斷樓頭畫角聲。"]'),
('2b8d717f-e295-4023-b460-6c688e11f41c','春晴','陸游','宋','宋诗','song-poetry','','[]','一庭舞絮鬭身輕，百尺遊絲弄午晴。',64,'全唐诗/poet.song.128000.json','["一庭舞絮鬭身輕，百尺遊絲弄午晴。", "静喜香烟縈曲几，臥驚玉子落紋枰。", "新春易失遽如許，薄宦忘歸何似生。", "安得一船東下峽，江南江北聽鶯聲。"]'),
('a49c951a-51d6-42d6-b2fe-936a82ef874f','題明皇幸蜀圖','陸游','宋','宋诗','song-poetry','','[]','天寶政事何披猖，使典相國胡奴王。',160,'全唐诗/poet.song.128000.json','["天寶政事何披猖，使典相國胡奴王。", "弄權楊李不足怪，阿瞞手自裂紀綱。", "八姨富貴尚有理，何至詔書褒五郎。", "盧龍賊騎已洶洶，丹鳯神語猶琅琅。", "人知大勢危絫卵，天稔奇禍如崩牆。", "臺省諸公獨耐事，歌詠功德卑虞唐。", "一朝殺氣横天末，疋馬西奔幾不脱。", "向來諂子知幾人，賊前稱臣草間活。", "劍南萬里望秦天，行殿春寒聞杜鶻。", "老臣九齡不可作，魚蠧蛛絲金鑑篇。"]'),
('80d1e44b-085e-40c6-9204-6b7562fe410b','春寒連日不出','陸游','宋','宋诗','song-poetry','','[]','海棠花入燕泥乾，梅子枝頭已带酸。',64,'全唐诗/poet.song.128000.json','["海棠花入燕泥乾，梅子枝頭已带酸。", "老去懶尋年少夢，舂分不減社前寒。", "著書敢望垂千載，嗜酒猶須隐一官。", "正是閑時無客過，小庭斜日倚闌干。"]'),
('793ac840-6e54-4cc5-b799-1d0413082edd','馬上偶成','陸游','宋','宋诗','song-poetry','','[]','城南城北紫遊韁，盡日閑行看似忙。',64,'全唐诗/poet.song.128000.json','["城南城北紫遊韁，盡日閑行看似忙。", "刺水離離葛葉短，連村漠漠豆花香。", "夕陽有信催殘角，春草無情上繚牆。", "我亦人間倦逰者，長吟聊復愴興亡。"]'),
('fcda61e5-c227-4d4e-bb42-70d6f5c685ab','夜宴','陸游','宋','宋诗','song-poetry','','[]','酒浪搖春不受寒，燭花垂燼忽堆盤。',64,'全唐诗/poet.song.128000.json','["酒浪搖春不受寒，燭花垂燼忽堆盤。", "山川路邈人将老，絲管聲遒夜向闌。", "四海交朋更聚散，百年光景雜悲歡。", "自憐病眼猶明在，更把名花半醉看。"]'),
('bb2939c3-b619-4152-87dd-eeb914cfc5ac','觀音院讀壁間蘓在廷少卿兩小詩次韵二首  其一','陸游','宋','宋诗','song-poetry','','[]','揚鞭暮出錦官城，小院無僧有月明。',32,'全唐诗/poet.song.128000.json','["揚鞭暮出錦官城，小院無僧有月明。", "不信道人心似鐡，隔城猶送擣衣聲。"]'),
('b456059a-3999-42f9-8f61-d9e253c64dee','觀音院讀壁間蘓在廷少卿兩小詩次韵二首  其二','陸游','宋','宋诗','song-poetry','','[]','老去癡頑不受鐫，姓名身後更須傳。',32,'全唐诗/poet.song.128000.json','["老去癡頑不受鐫，姓名身後更須傳。", "世間商略無歸處，只合長齋繡佛前。"]'),
('9b4504d6-9006-4bb8-be70-d0b9688b8dc9','錦亭','陸游','宋','宋诗','song-poetry','','[]','天公爲我齒頬計，遣飫黄甘與丹荔。',162,'全唐诗/poet.song.128000.json','["天公爲我齒頬計，遣飫黄甘與丹荔。", "又憐狂眼老更狂，令看廣陵芍藥蜀海棠。", "周行萬里逐所樂，天公於我元不薄。", "貴人不出長安城，寶带華纓真汝縳。", "樂哉今從石湖公，大度不計聾承聾。", "夜宴新亭海棠底，紅雲倒吸玻璃鍾。", "琵琶絃繁腰鼓急，盤鳯舞衫香霧濕。", "春醪凸盞燭光搖，素月中天花影立。", "逰人如雲環玉帳，詩未落紙先傳唱。", "此邦句律方一新，鳯閣舍人今有様。"]'),
('46da883c-d18a-4ac1-9f6c-6dc94c2cfa7b','晚起','陸游','宋','宋诗','song-poetry','','[]','新晴窗日弄春妍，幌小屏深意自便。',64,'全唐诗/poet.song.128000.json','["新晴窗日弄春妍，幌小屏深意自便。", "長恨病多妨痛飲，却緣客少得安眠。", "雛鶯故故啼簷角，飛絮翩翩墮枕前。", "欲著衣裳還孏起，重尋殘夢一悠然。"]'),
('a99d839c-a041-4526-b509-465bd4c0149b','雨','陸游','宋','宋诗','song-poetry','','[]','映空初作繭絲微，掠地俄成箭鏃飛。',64,'全唐诗/poet.song.128000.json','["映空初作繭絲微，掠地俄成箭鏃飛。", "紙帳光遲饒曉夢，銅鑪香潤覆春衣。", "池魚鱍鱍隨溝出，梁燕翩翩接翅歸。", "惟有落花吹不去，数枝紅濕自相依。"]'),
('39bd2c81-bf81-465f-b85b-25413c3def00','春晚書懷','陸游','宋','宋诗','song-poetry','','[]','萬里西逰爲覔詩，錦城更付一官癡。',64,'全唐诗/poet.song.128000.json','["萬里西逰爲覔詩，錦城更付一官癡。", "脱巾漉酒從人笑，拄笏看山頗自奇。", "疏雨池塘魚避釣，曉鶯窗户客争棋。", "老來怕與春爲别，醉過殘紅滿地時。"]'),
('3eddb4c0-91c9-4e0c-bade-c665d796abd9','出朝天門繚長堤至劉侍郎廟由小西門歸','陸游','宋','宋诗','song-poetry','','[]','曉從北郭過西城，十里沙堤似席平。',64,'全唐诗/poet.song.128000.json','["曉從北郭過西城，十里沙堤似席平。", "澹日向人供帽影，微風傍馬助鞭聲。", "歡情寂寂隨年減，俗事紛紛逐日生。", "到處每求佳水竹，晚途牢落念歸耕。"]'),
('dd6466c0-5798-4701-b8dc-87cc2f5b5aa1','夜分讀書有感','陸游','宋','宋诗','song-poetry','','[]','光陰百歲已中分，擬結茅茨老白雲。',64,'全唐诗/poet.song.128000.json','["光陰百歲已中分，擬結茅茨老白雲。", "萬里誰憐新臥疾，九重猶記舊能文。", "枕邉得句題屏疊，馬上看山隔帽裙。", "終恨無勞縻廩粟，夜窗聊策讀書勲。"]'),
('b2e0c1c1-2fad-4e23-909b-f29c994c2757','中夜聞大雷雨','陸游','宋','宋诗','song-poetry','','[]','雷車駕雨龍盡起，電行半空如狂矢。',128,'全唐诗/poet.song.128000.json','["雷車駕雨龍盡起，電行半空如狂矢。", "中原戰爭五十年，上帝震怒初一洗。", "黄頭女真褫魂魄，面縳軍門争請死。", "已聞三箭定天山，何啻積甲齊熊耳。", "捷書馳騎奏行宫，近臣上壽天顔喜。", "閤門明日催賀班，雲集千官摩劍履。", "長安父老請移蹕，願見六龍臨渭水。", "從今身是太平人，敢憚安西九千里。"]'),
('e5a1048a-dafc-4c2d-a668-2733febac27a','春殘','陸游','宋','宋诗','song-poetry','','[]','石鏡山前送落暉，春殘回首倍依依。',64,'全唐诗/poet.song.128000.json','["石鏡山前送落暉，春殘回首倍依依。", "時平壯士無功老，鄉遠征人有夢歸。", "苜蓿苗侵官道合，蕪菁花入麥畦稀。", "倦逰自笑摧頺甚，誰記飛鷹醉打圍。"]'),
('86dcda59-f2e9-4f2e-b2fd-c33674277168','武擔東臺晚望','陸游','宋','宋诗','song-poetry','','[]','憔悴西窗已一翁，登高意氣尚豪雄。',64,'全唐诗/poet.song.128000.json','["憔悴西窗已一翁，登高意氣尚豪雄。", "關河覇國興亡後，風月詩人醉醒中。", "病起頓驚雙鬢改，春歸一掃萬花空。", "欄邉徙倚君知否，直到吳天目未窮。"]'),
('41071a6c-e01b-4c4d-81a6-7997c893df49','行武擔西南村落有感','陸游','宋','宋诗','song-poetry','','[]','騎馬悠然欲斷魂，春愁滿眼與誰論。',64,'全唐诗/poet.song.128000.json','["騎馬悠然欲斷魂，春愁滿眼與誰論。", "市朝遷變歸蕪没，磵谷谺谺互吐吞。", "一徑松楠遙見寺，数家鷄犬自成村。", "最憐高冢臨官道，細細烟莎遍焼痕。"]'),
('1f3c839f-4f41-4993-9699-23f4629b8dd2','小飲房園','陸游','宋','宋诗','song-poetry','','[]','宦逰到處即忘家，况得閑身管物華。',64,'全唐诗/poet.song.128000.json','["宦逰到處即忘家，况得閑身管物華。", "疏索故人緣病酒，折除厚禄爲看花。", "泥新高棟初巢燕，萍匝荒池已集蛙。", "斟酌人生要行樂，燈前起舞落烏紗。"]'),
('6db6f867-24fe-43f0-8f0c-c937b7b7d892','飯昭覺寺抵暮乃歸','陸游','宋','宋诗','song-poetry','','[]','身墮黄塵每慨然，攜兒蕭散亦前緣。',64,'全唐诗/poet.song.128000.json','["身墮黄塵每慨然，攜兒蕭散亦前緣。", "聊憑方外巾盂净，一洗人間匕箸羶。", "静院春風傳浴鼓，畫廊晚雨濕茶烟。", "濳光寮裏明窗下，借我消搖過十年。"]'),
('759c31eb-6369-4228-962f-4892b9a2e199','自芳華楼過瑤林莊','陸游','宋','宋诗','song-poetry','','[]','春晚江邉草過腰，雨餘楼下水平橋。',64,'全唐诗/poet.song.128000.json','["春晚江邉草過腰，雨餘楼下水平橋。", "名花未落如相待，佳客能來不費招。", "欄角峭風羅袖薄，柳陰斜日玉驄驕。", "此身醉死元關命，敢笑聞鷄趁早朝。"]'),
('a92b296e-c2bf-4305-a2e2-1248764c6d92','書懷','陸游','宋','宋诗','song-poetry','','[]','詩不能工浪得窮，幾年衮衮看諸公。',64,'全唐诗/poet.song.128000.json','["詩不能工浪得窮，幾年衮衮看諸公。", "摧頺已作驥伏櫪，留滯敢嫌船逆風。", "消日劇棋疏竹下，送春爛醉亂花中。", "倚楼看鏡俱癡絕，贏取烟蓑伴釣翁。"]'),
('b98a3072-9f7f-4342-937d-eed8fe6376fc','逰東郭趙氏園','陸游','宋','宋诗','song-poetry','','[]','清晨呼馬出，馭吏請所之。',96,'全唐诗/poet.song.128000.json','["清晨呼馬出，馭吏請所之。", "錦城浩如海，我亦無與期。", "有花即入門，莫問主人誰。", "下馬據胡床，傲睨忘訶譏。", "人言白頭翁，胡爲尚兒癡。", "老翁故不癡，借花發吾詩。", "詩句带花香，東風不敢吹。", "徘徊雙蛺蝶，許汝鼻端知。"]'),
('409621f4-6170-4d97-951b-efcb2ee0c2e8','卜居二首  其一','陸游','宋','宋诗','song-poetry','','[]','歴盡人間行路難，老來要覔数年閑。',64,'全唐诗/poet.song.128000.json','["歴盡人間行路難，老來要覔数年閑。", "供家米少因添鶴，買宅錢多爲見山。", "池靣紋生風細細，花根土潤雨斑斑。", "借舂乞火依鄰里，剩釀村醪約往還。"]'),
('451e338b-921a-468e-8795-22dfcb5350f3','卜居二首  其二','陸游','宋','宋诗','song-poetry','','[]','南浮七澤吊沉湘，西泝三巴掠夜郎。',64,'全唐诗/poet.song.128000.json','["南浮七澤吊沉湘，西泝三巴掠夜郎。", "自信前緣與人薄，每求寛地寄吾狂。", "雪山水作中泠味，蒙頂茶如正焙香。", "儻有把茅端可老，不須辛苦念還鄉。"]'),
('b7a06df4-b171-4599-ba48-74ed19b0ada7','馬上','陸游','宋','宋诗','song-poetry','','[]','春殘馬上意倀倀，縱轡微吟過数坊。',64,'全唐诗/poet.song.128000.json','["春殘馬上意倀倀，縱轡微吟過数坊。", "緑樹成帷連藥市，清流如带繞毬場。", "城荒鼓角增悲壯，苑廢雲烟尚莽蒼。", "堪笑年來向詩懶，還家古錦只空囊。"]'),
('ee6a4e22-9bae-43bc-a400-ca2f8fea2658','夜登江楼','陸游','宋','宋诗','song-poetry','','[]','平生胸中無滯留，曠然獨與造物逰。',96,'全唐诗/poet.song.128000.json','["平生胸中無滯留，曠然獨與造物逰。", "天風駕我周宇縣，夜半忽過江邉楼。", "楼前茫茫天地濶，萬頃月浸空江秋。", "雲階無塵鸞鶴舞，玉笛裂石魚龍愁。", "肺肝澄澈納灝氣，毛髮慘慄臨寒流。", "世間回首真一夢，誰能更念酬恩讎。"]'),
('cceb82b9-7e6e-4b63-8fee-6d35fe84cdc7','書嘆','陸游','宋','宋诗','song-poetry','','[]','早得虚名翰墨林，謝歸忽已歲時侵。',64,'全唐诗/poet.song.128000.json','["早得虚名翰墨林，謝歸忽已歲時侵。", "春郊射雉朝盤馬，秋院焚香夜弄琴。", "病酒閉門常兀兀，哦詩袖手久愔愔。", "浮沉不是忘經世，後有仁人識此心。"]'),
('e083a4f7-a529-4257-86b6-79cbdddca0c6','三月一日府宴學射山','陸游','宋','宋诗','song-poetry','','[]','北出昇仙路少東，據鞍自笑老從戎。',64,'全唐诗/poet.song.128000.json','["北出昇仙路少東，據鞍自笑老從戎。", "百年身世酣歌裏，千古功名感慨中。", "天遠僅分山髣髴，霧收初見日曈曨。", "横空我欲江湖去，誰借泠然禦寇風。"]'),
('b364ee86-d6f6-47fa-b541-12ec1491cdde','對酒','陸游','宋','宋诗','song-poetry','','[]','閑愁如飛雪，入酒即消融。',72,'全唐诗/poet.song.128000.json','["閑愁如飛雪，入酒即消融。", "好花如故人，一笑杯自空。", "流鶯有情亦念我，柳邉盡日啼春風。", "長安不到十四載，酒徒往往成衰翁。", "九環寶带光照地，不如留君雙頰紅。"]'),
('58feb9f3-858b-41d9-937c-5af70ba9c380','題直舍壁','陸游','宋','宋诗','song-poetry','','[]','文書那得廢哦詩，羞作群兒了事癡。',32,'全唐诗/poet.song.128000.json','["文書那得廢哦詩，羞作群兒了事癡。", "付與後人評此老，一丘一壑過元規。"]'),
('bcd4f832-8eba-4243-8150-43cea8365bc6','逰圜覺乾明祥符三院至暮','陸游','宋','宋诗','song-poetry','','[]','成都再見春事殘，雖名閑官實不閑。',160,'全唐诗/poet.song.128000.json','["成都再見春事殘，雖名閑官實不閑。", "門前車馬閙如市，案上文檄高於山。", "有時投罅輙徑出，略似齊客偷秦關。", "日斜僕夫已整駕，顧景欲駐愁嘲訕。", "豈知今朝有此樂，放浪一笑開衰顔。", "抽身黄塵烏帽底，得意翠木清泉間。", "褰裳危磴窮犖确，洗耳古澗聽淙潺。", "豈惟頓覺宇宙廣，政爾一散腰脚頑。", "似聞青城縹緲處，待我歸綴仙官班。", "俊鷹解絛即萬里，豈比倦翼方知還。"]'),
('36967a80-6fac-4ec6-8a92-afc242dddc44','逰合江園戲題','陸游','宋','宋诗','song-poetry','','[]','朱朱白白池臺間，好風妍日開未殘。',128,'全唐诗/poet.song.128000.json','["朱朱白白池臺間，好風妍日開未殘。", "我來覔醉苦草草，常恨不如花意閑。", "山鷄飛起亂花落，下上青林穿翠壑。", "世間動步即有拘，常恨不如禽意樂。", "人言功名恐不免，我願徜徉娱歲晚。", "熟計滛書理白魚，何如縱獵牽黄犬。", "成都四郊如砥平，安得雙鞬馳出城。", "鞚飛塵起望不見，從騎尋我鳴鶻聲。"]'),
('d15d7372-8835-4460-b149-f0e1193e9c0b','三月十六日作','陸游','宋','宋诗','song-poetry','','[]','石筍街西風景幽，醉眠萬事付悠悠。',64,'全唐诗/poet.song.128000.json','["石筍街西風景幽，醉眠萬事付悠悠。", "倦逰我已七年客，促駕春無三日留。", "枝上蝶稀紅藥老，舍中蠶起緑桑柔。", "功名墮甑誰能問，羞作饑鷹夜掣韝。"]'),
('cd4994fd-bc5f-4ee8-a5e2-be3033dca48e','食薺三首  其一','陸游','宋','宋诗','song-poetry','','[]','日日思歸飽蕨薇，春來薺美忽忘歸。',32,'全唐诗/poet.song.128000.json','["日日思歸飽蕨薇，春來薺美忽忘歸。", "傳誇真欲嫌荼苦，自笑何時得瓠肥。"]'),
('582a8cf0-f2b9-4e9f-bd22-5071c00dfd67','食薺三首  其二','陸游','宋','宋诗','song-poetry','','[]','采采珍蔬不待畦，中原正味壓蓴絲。',32,'全唐诗/poet.song.128000.json','["采采珍蔬不待畦，中原正味壓蓴絲。", "桃根擇葉無虚日，直到開花如雪時。"]'),
('8440a1ee-1924-4548-be01-e1428c90834c','食薺三首  其三','陸游','宋','宋诗','song-poetry','','[]','小著鹽醯助滋味，微加薑桂發精神。',32,'全唐诗/poet.song.128000.json','["小著鹽醯助滋味，微加薑桂發精神。", "風爐歙鉢窮家活，妙訣何曾肻授人。"]'),
('d670b125-6c21-4f28-9fb1-00c25ec6a57b','次韵范文淵','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','簞瓢氣已壓膏梁，不傍朱門味更長。',64,'全唐诗/poet.song.128000.json','["簞瓢氣已壓膏梁，不傍朱門味更長。", "細看高人忘寵辱，始知吾輩可憐傷。", "巖扃勾漏新丹竈，香火匡廬古道場。", "剩欲與君堅此約，它年八十鬢眉蒼。"]'),
('514aedce-716e-4c69-92de-0f01f3d084b7','題醉中所作草書卷後','陸游','宋','宋诗','song-poetry','','["\u6218\u4e89", "\u8c6a\u8fc8", "\u4e66\u6cd5", "\u5fd7\u5411", "\u6292\u6000"]','胸中磊落藏五兵，欲試無路空峥嶸。',96,'全唐诗/poet.song.128000.json','["胸中磊落藏五兵，欲試無路空峥嶸。", "酒爲旗鼓筆刀槊，勢從天落銀河傾。", "端溪石池濃作墨，燭光相射飛縱横。", "須臾收卷復把酒，如見萬里烟塵清。", "丈夫身在要有立，逆虜運盡行當平。", "何時夜出五原塞，不聞人語聞鞭聲。"]'),
('2be56162-13ed-4570-9f79-0c7c9efae840','登子城新楼遍至西園池亭','陸游','宋','宋诗','song-poetry','','[]','狂夫無計奈狂何，何况登臨逸興多。',64,'全唐诗/poet.song.128000.json','["狂夫無計奈狂何，何况登臨逸興多。", "千疊雪山連滴博，一支春水入摩訶。", "吟餘騎省霜侵鬢，釣罷玄真雨滿蓑。", "逐冦榆關期尚遠，不妨隨處得婆娑。"]'),
('d792b23c-d298-4d46-88f5-03e53dd164b8','小疾謝客','陸游','宋','宋诗','song-poetry','','[]','小疾深居不喚醫，消搖更覺勝平時。',64,'全唐诗/poet.song.128000.json','["小疾深居不喚醫，消搖更覺勝平時。", "癡人未害看周易，名士真須讀楚辭。", "緑徑風斜花片片，畫廊人静雨絲絲。", "晚來頓覺清羸甚，自置篝爐煮粟糜。"]'),
('0c0c7d6e-b3d6-492f-a284-a889fcb540e4','歸耕','陸游','宋','宋诗','song-poetry','','[]','隨牒人間鬢欲疏，歸耕且復補東隅。',64,'全唐诗/poet.song.128000.json','["隨牒人間鬢欲疏，歸耕且復補東隅。", "甑炊地碓新舂米，衣拆天吳舊繡圖。", "有圃免煩官送菜，叩門翻喜吏徴租。", "不愁問字無來客，惟欠揚雄宅一區。"]'),
('bcfddb25-0435-44d1-8347-e1a470f9141c','聞孫巖老挂冠嘆仰之餘輙賦長句','陸游','宋','宋诗','song-poetry','','[]','聖賢在世龍行天，出處何至爲物牽。',128,'全唐诗/poet.song.128000.json','["聖賢在世龍行天，出處何至爲物牽。", "後人競作駒伏轅，未死奄奄如九泉。", "郫孫公者山澤僊，巉巖玉骨寒入肩。", "哦詩調苦亂嘒蟬，燥墨瘦字醜不妍。", "諸公好之挽使前，六丁力盡山嶷然。", "奏書告老不待年，脱手徑上岷山巔。", "吾儕一官自糾纒，俛首鞭箠不自憐。", "强欲作詩誦公賢，事偉辭卑難竝傳。"]'),
('a6ad5b33-44b8-4591-bec2-e31f29a04bcf','松驥行','陸游','宋','宋诗','song-poetry','','[]','驥行千里亦何得，垂首伏櫪終自傷。',96,'全唐诗/poet.song.128000.json','["驥行千里亦何得，垂首伏櫪終自傷。", "松閲千年棄澗壑，不如殺身扶明堂。", "士生抱材願少試，誓取燕趙歸君王。", "閉門高臥身欲老，聞鷄相蹴涕数行。", "正令吚嚶死床簀，豈若横身當戰場。", "半酣浩歌聲激烈，車輪百轉盤愁腸。"]'),
('48a20719-22d4-4047-bea7-9470176b0642','遣興','陸游','宋','宋诗','song-poetry','','[]','鶴料無多又掃空，今年真是浣花翁。',64,'全唐诗/poet.song.128000.json','["鶴料無多又掃空，今年真是浣花翁。", "放敎緑酒關身事，留得朱顔在鏡中。", "挾彈園林芳徑雨，投竿窗檻小溪風。", "癡頑自笑歸何日，家在東吳更向東。"]'),
('fe8a2289-3a9f-40ea-a957-dd2255fba509','野意','陸游','宋','宋诗','song-poetry','','[]','小東門外曵笻枝，白葛烏紗自一奇。',64,'全唐诗/poet.song.128000.json','["小東門外曵笻枝，白葛烏紗自一奇。", "閑客逍遥無吏責，茂陰清潤勝花時。", "茶經每向僧窗讀，菰米仍於野艇炊。", "便覺眼邉歸路近，鏡湖禹廟見參差。"]'),
('c88372f4-7862-451d-8bd6-b51650e7ff8c','雨中登安福寺塔','陸游','宋','宋诗','song-poetry','','[]','平生喜登高，醉眼無疆界。',120,'全唐诗/poet.song.128000.json','["平生喜登高，醉眼無疆界。", "北顧極幽并，東望誇海岱。", "喟然撫手嘆，從古幾成敗。", "英雄如過鳥，城郭但遺塊。", "今朝上黑塔，千里曠無礙。", "忽驚風霆掣，坐覺天地晦。", "急雨挾龍腥，溽暑爲摧壊。", "皇天念蟠鬱，令我寄一快。", "那知書生狂，自倚心眼大。", "更思駐潼關，黄河看如带。"]'),
('fd926259-2e88-4da4-9b5d-138dd573be38','過野人家有感','陸游','宋','宋诗','song-poetry','','[]','縱轡江皋送夕暉，誰家井臼映荆扉。',64,'全唐诗/poet.song.128000.json','["縱轡江皋送夕暉，誰家井臼映荆扉。", "隔籬犬吠窺人過，滿箔蠶饑待葉歸。", "世態十年看爛熟，家山萬里夢依稀。", "躬耕本是英雄事，老死南陽未必非。"]'),
('0371053c-c2b2-424e-859f-c7d2f70f95dd','幽居晚興','陸游','宋','宋诗','song-poetry','','[]','借鉏劚藥喜微香，汲井澆花趁晚涼。',64,'全唐诗/poet.song.128000.json','["借鉏劚藥喜微香，汲井澆花趁晚涼。", "胸次何曾横一物，尊前尚欲笑千場。", "錦江秋雨芙蓉老，笠澤春風杜若芳。", "歸去自佳留亦樂，夢中何處是吾鄉。"]'),
('29c95daf-1e01-4bc8-ae11-b1bb15c9aacd','飯保福','陸游','宋','宋诗','song-poetry','','[]','簁雨雲低未放晴，閉門作病憶閑行。',64,'全唐诗/poet.song.128000.json','["簁雨雲低未放晴，閉門作病憶閑行。", "攝衣丈室參耆宿，曵杖長廊喚弟兄。", "飽飯即知吾事了，免官初覺此身輕。", "歸來更欲誇妻子，學煮雲堂芋糝羮。"]'),
('2f4eb066-a653-4b28-bf53-145fc864cd14','觀華嚴閣僧齋','陸游','宋','宋诗','song-poetry','','[]','拂劍當年氣吐虹，喑嗚坐覺朔庭空。',32,'全唐诗/poet.song.128000.json','["拂劍當年氣吐虹，喑嗚坐覺朔庭空。", "早知壮志成癡絕，悔不藏名萬衲中。"]'),
('08b69d7a-681b-4d47-96dc-aaec34b3af38','閑中偶題二首  其一','陸游','宋','宋诗','song-poetry','','[]','楚澤巴山歲歲忙，今年睡足向禪房。',64,'全唐诗/poet.song.128000.json','["楚澤巴山歲歲忙，今年睡足向禪房。", "只知閑味如茶永，不放羈愁似草長。", "架上漢書那復看，床頭周易亦相忘。", "客來拈起清談麈，且破西窗半篆香。"]'),
('966d7b56-1271-4a58-b35d-5fb0b0552281','閑中偶題二首  其二','陸游','宋','宋诗','song-poetry','','[]','久矣雲衢斂羽翰，退飛更覺一枝安。',64,'全唐诗/poet.song.128000.json','["久矣雲衢斂羽翰，退飛更覺一枝安。", "七千里外新閑客，十五年前舊史官。", "花底清歌春載酒，江邉明月夜投竿。", "癡頑直爲多更事，莫怪胸懷扺死寛。"]'),
('2da31f7a-2516-4145-9167-9d22611cdcde','病中戲書三首  其一','陸游','宋','宋诗','song-poetry','','[]','五十忽過二，流年消壯心。',48,'全唐诗/poet.song.128000.json','["五十忽過二，流年消壯心。", "避人便小疾，移竹喜微陰。", "洗甕閑篘酒，焚香静斵琴。", "鏡中青鬢在，切莫遣愁侵。"]'),
('9f592cac-2bb0-480a-833a-880c7a38ad2e','病中戲書三首  其二','陸游','宋','宋诗','song-poetry','','[]','微疾餞餘災，時須藥裹開。',48,'全唐诗/poet.song.128000.json','["微疾餞餘災，時須藥裹開。", "禽驚杵聲去，蜂認蜜香來。", "閉户知長日，全生幸散材。", "晚涼幽興動，彊到竹邊回。"]'),
('568ba713-256e-4f86-8851-93a54874785d','病中戲書三首  其三','陸游','宋','宋诗','song-poetry','','[]','食筍動衰疾，清羸逾兩旬。',48,'全唐诗/poet.song.128000.json','["食筍動衰疾，清羸逾兩旬。", "藥囊隨臥起，詩句雜吟呻。", "架足書籖蠧，窗凝酒榼塵。", "免從官乞假，且喜是閑身。"]'),
('0442ddf3-6470-474a-acae-a2ba4ea8b10a','病起書懷二首  其一','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u52b1\u5fd7", "\u5fe7\u56fd\u5fe7\u6c11", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u58ee\u5fd7\u96be\u916c", "\u5b8b\u8bd7"]','病骨支離紗帽寛，孤臣萬里客江干。',64,'全唐诗/poet.song.128000.json','["病骨支離紗帽寛，孤臣萬里客江干。", "位卑未敢忘憂國，事定猶須待闔棺。", "天地神靈扶廟社，京華父老望和鑾。", "出師一表通今古，夜半挑燈更細看。"]'),
('0f13dd6b-ca9b-4687-9c36-ed2c65c479c9','病起書懷二首  其二','陸游','宋','宋诗','song-poetry','','[]','酒酣看劍凛生風，身是天涯一秃翁。',64,'全唐诗/poet.song.128000.json','["酒酣看劍凛生風，身是天涯一秃翁。", "捫蝨劇談空自許，聞鷄浩嘆與誰同。", "玉關歲晚無來使，沙苑春生有去鴻。", "人壽定非金石永，可令虚死蜀山中。"]'),
('a2634841-b2c5-4e78-87ce-80b22dff439d','寺楼月夜醉中戲作三首  其一','陸游','宋','宋诗','song-poetry','','[]','素璧徐升天宇閑，連峰積雪蒼茫間。',32,'全唐诗/poet.song.128000.json','["素璧徐升天宇閑，連峰積雪蒼茫間。", "楼臺是處可見月，無此巉巉群玉山。"]'),
('439cd7d6-3a5a-436c-b87a-fa5dd6b5d6e9','寺楼月夜醉中戲作三首  其二','陸游','宋','宋诗','song-poetry','','[]','水精盞映碧琳腴，月下泠泠看似無。',32,'全唐诗/poet.song.128000.json','["水精盞映碧琳腴，月下泠泠看似無。", "此酒定從何處得，判知不是文君壚。"]'),
('3fb0e7cb-d545-448c-9714-7cda1eeffb5f','寺楼月夜醉中戲作三首  其三','陸游','宋','宋诗','song-poetry','','[]','海山縹緲玉真妃，貪看冰輪不肻歸。',32,'全唐诗/poet.song.128000.json','["海山縹緲玉真妃，貪看冰輪不肻歸。", "楼上三更風露冷，旋圍步障換羅衣。"]'),
('57c56ed1-a862-4b5a-9aa8-d8ee808ca8b0','晚過五門','陸游','宋','宋诗','song-poetry','','[]','五門路，四月乳鴉啼緑樹。',60,'全唐诗/poet.song.128000.json','["五門路，四月乳鴉啼緑樹。", "閑逰但喜日初長，薄暑始知春已去。", "楼頭風高舞雙旗，畫角聲中日還暮。", "馬蹄特特無斷時，老盡行人路如故。"]'),
('4a3287ff-d6b1-4569-ac7b-c53ef59d0115','躬耕','陸游','宋','宋诗','song-poetry','','[]','莫笑躬耕老蜀山，也勝菜把仰園官。',64,'全唐诗/poet.song.128000.json','["莫笑躬耕老蜀山，也勝菜把仰園官。", "喚回癡夢塵機息，空盡閑愁酒地寛。", "無復短衣隨李廣，但思微雨過蘓端。", "十年世事茫如海，輸與閑人静處看。"]'),
('92e3dc9b-b8e0-4e26-a47f-464e00b8adff','晚興','陸游','宋','宋诗','song-poetry','','[]','老病愁趨畫戟門，天教高臥浣花村。',64,'全唐诗/poet.song.128000.json','["老病愁趨畫戟門，天教高臥浣花村。", "山林獨往雜屠釣，世界皆空誰怨恩。", "千卷蠧書忘歲月，一尊濁酒信乾坤。", "興來倚杖清江上，斷角踈鐘正斂昏。"]'),
('36b1edda-460f-4246-b7b3-cdaac8375d71','夏夜大醉醒後有感','陸游','宋','宋诗','song-poetry','','[]','少時酒隐東海濵，結交盡是英豪人。',128,'全唐诗/poet.song.128000.json','["少時酒隐東海濵，結交盡是英豪人。", "龍泉三尺動牛斗，陰符一編役鬼神。", "客逰山南夜望氣，頗謂王師當入秦。", "欲傾天上河漢水，盡洗關中戰士塵。", "那知一旦事大繆，騎驢劍閣霜毛新。", "却將覆氊草檄手，小詩點綴西州春。", "素心雖願老巖壑，大義未敢忘君臣。", "鷄鳴酒解不成寐，起坐肝膽空輪囷。"]'),
('92f7e0bd-cef1-473f-a8d8-d3c2a9847ba2','合江夜宴歸馬上作','陸游','宋','宋诗','song-poetry','','[]','零露中宵濕緑苔，江郊縱飲亦荒哉。',64,'全唐诗/poet.song.128000.json','["零露中宵濕緑苔，江郊縱飲亦荒哉。", "引杯快似黄河瀉，落筆聲如白雨來。", "纎指醉聽筝柱促，長檠時看燭花摧。", "頭顱自揣應虚死，馬上長歌寄此哀。"]'),
('26f0f24b-fdb4-42ac-8c29-eeaffdb921ce','齋居書事','陸游','宋','宋诗','song-poetry','','[]','慵養金丹換鬢鬚，微霜正要稱清癯。',64,'全唐诗/poet.song.128000.json','["慵養金丹換鬢鬚，微霜正要稱清癯。", "平生風露充蟬腹，到處雲山寄鶴軀。", "道室焚香勤守白，虚窗點易静研朱。", "自知世事難諧偶，不待幽人夜見呼。"]'),
('61283e36-3fdc-4e4e-b605-b39da54911b2','午夢','陸游','宋','宋诗','song-poetry','','[]','苦爱幽窗午夢長，此中與世暫相忘。',32,'全唐诗/poet.song.128000.json','["苦爱幽窗午夢長，此中與世暫相忘。", "華山處士如容見，不覔仙方覓睡方。"]'),
('f679ef7f-72fc-42f2-ad1f-2f275e57273c','江瀆池納涼','陸游','宋','宋诗','song-poetry','','[]','雨過荒池藻荇香，月明如水浸胡床。',32,'全唐诗/poet.song.128000.json','["雨過荒池藻荇香，月明如水浸胡床。", "天公作意憐羈客，乞與今年一夏涼。"]'),
('14bf827a-6303-4116-b307-5cb54cf08e73','晚步','陸游','宋','宋诗','song-poetry','','[]','屏居無俗事，薄暮行溪園。',72,'全唐诗/poet.song.128000.json','["屏居無俗事，薄暮行溪園。", "斷續風蟬噪，俯仰露葉翻。", "月出照西壁，參差見簷痕。", "新沐懶不櫛，清冷入髮根。", "臨流揮羽扇，對月傾芳尊。", "寄謝南昌尉，何必隐市門。"]'),
('3ea6b0b4-ad49-4b12-adfa-91eec829e9a4','姚將軍靖康初以戰敗亡命建炎中下詔求之不可得後五十年乃從吕洞賔劉高尚往來名山有見之者予感其事作詩寄題青城山上清宫壁間將軍儻見之乎','陸游','宋','宋诗','song-poetry','','[]','造物困豪傑，意將使有爲。',120,'全唐诗/poet.song.128000.json','["造物困豪傑，意將使有爲。", "功名未足言，或作出世資。", "姚公勇冠軍，百戰起西陲。", "天方覆中原，殆非一木支。", "脱身五十年，世人識公誰。", "但驚山澤間，有此熊豹姿。", "我亦志方外，白頭未逢師。", "年來幸廢放，儻遂與世辭。", "從公逰五嶽，稽首餐靈芝。", "金骨換緑髓，欻然松杪飛。"]'),
('75b6f913-021a-4b93-8995-033cc7b6b444','客自鳯州來言岐雍間事悵然有感','陸游','宋','宋诗','song-poetry','','[]','表裏山河古帝京，一時力盡固當平。',64,'全唐诗/poet.song.128000.json','["表裏山河古帝京，一時力盡固當平。", "千門未報甘泉火，萬耦方觀渭上耕。", "前日已傳天狗墮，今年寕許佛貍生。", "會須一洗儒酸態，獵罷南山夜下營。"]'),
('2ae6fa2e-24e3-45e4-aa30-8af339ca09f7','席上作','陸游','宋','宋诗','song-poetry','','[]','緑波畫槳浣花船，清簟疏簾角黍筵。',64,'全唐诗/poet.song.128000.json','["緑波畫槳浣花船，清簟疏簾角黍筵。", "一幅葛巾林下客，百壺春酒飲中仙。", "散懷絲管繁華地，寄傲江湖浩蕩天。", "浮世升沉何足計，丹成碧落珥貂蟬。"]'),
('500a20ce-caf0-4b4d-9c90-57b694294bdf','水亭偶題','陸游','宋','宋诗','song-poetry','','[]','涼榭閑拈玉笛吹，十年疏放負明時。',64,'全唐诗/poet.song.128000.json','["涼榭閑拈玉笛吹，十年疏放負明時。", "溝中木斷誰曾問，空裏蓬征自不知。", "金井梧桐生晝寂，緑池蘋藻弄風漪。", "人生行樂從來事，此理何須更細推。"]'),
('f8e81a43-4317-4c13-92ff-a36872827e64','避暑江上','陸游','宋','宋诗','song-poetry','','[]','苦熱厭城市，初夜臨江湍。',72,'全唐诗/poet.song.128000.json','["苦熱厭城市，初夜臨江湍。", "風從西山來，頗带積雪寒。", "堰聲静尤壯，噴薄如急灘。", "頓遠車馬喧，更覺衣裳單。", "斷岸吐缺月，恨不三更看。", "且隨螢火歸，城扉欲横關。"]'),
('2036a673-95d1-4ee2-af3b-ad38baba1e2d','夏白紵  其一','陸游','宋','宋诗','song-poetry','','[]','雲母屏薄望如空，水精簾疏不礙風。',64,'全唐诗/poet.song.128000.json','["雲母屏薄望如空，水精簾疏不礙風。", "美人獨立何所似，白玉芙蕖秋水中。", "素綃細織冰蠶縷，清寒不受人間暑。", "晚來浴罷緑窗閑，自把新詩教鸚鵡。"]'),
('40cfaebd-409b-4aa4-9c82-b3185bd57065','夏白紵  其二','陸游','宋','宋诗','song-poetry','','[]','翔鸞矯矯離風塵，眼明見此絕代人。',64,'全唐诗/poet.song.128000.json','["翔鸞矯矯離風塵，眼明見此絕代人。", "紗窗弄筆消永日，臨得黄庭新逼真。", "飛楼縹緲今何夕，月與玉人同一色。", "下簾不爲九霄寒，自要玲瓏看團璧。"]'),
('9542edd6-b505-4730-aaf7-59bb0fdae107','久旱忽大雨涼甚小飲醉眠覺而有作','陸游','宋','宋诗','song-poetry','','[]','暑雨蕭蕭滴夜長，曉窗探借九秋涼。',64,'全唐诗/poet.song.128000.json','["暑雨蕭蕭滴夜長，曉窗探借九秋涼。", "金荷淺酌閑傳酒，銀葉無烟静炷香。", "舒雁且爲賖死計，鳴鳩便欲策勲忙。", "散人亦未全無事，枕籍琴書滿一床。"]'),
('8d6711c1-f376-4797-af4e-492d4b31a9f5','明日開霽益涼復得長句','陸游','宋','宋诗','song-poetry','','[]','睡起東窗照眼明，朝陽爛漫作新晴。',64,'全唐诗/poet.song.128000.json','["睡起東窗照眼明，朝陽爛漫作新晴。", "已聞雨斷空階滴，更覺風從細葛生。", "蛺蝶飛來停酒榼，石榴飄落糝棋枰。", "四時好處閑方覺，不枉今年住錦城。"]'),
('40657450-28ac-4e4a-8680-68cdca17f6be','夜讀東京記','陸游','宋','宋诗','song-poetry','','[]','海東小冦辜覆冒，敢據神州竊名號。',128,'全唐诗/poet.song.128000.json','["海東小冦辜覆冒，敢據神州竊名號。", "幅員萬里宋乾坤，五十一年讎未報。", "煌煌藝祖中天業，東都實宅神明隩。", "即今犬豕穴宫殿，安得旄頭下除掃。", "寶玉大弓久不獲，臣子義敢忘巨盗。", "景靈太廟威神在，北鄉慟哭猶可告。", "壯士方當棄軀命，書生詎忍開和好。", "孤臣白首困西南，有志不伸空自悼。"]'),
('e687a3dd-5ac5-4955-95eb-e345e5655c59','感事','陸游','宋','宋诗','song-poetry','','[]','青鬢當時映緑衣，堯功曾預記巍巍。',64,'全唐诗/poet.song.128000.json','["青鬢當時映緑衣，堯功曾預記巍巍。", "玄都春老人何在，華表天高鶴未歸。", "流輩凋疏情話少，年光遲暮壯心違。", "倚楼不用悲身世，倦鷁無風亦退飛。"]'),
('1195552f-feb9-4c01-9df5-afe10185f619','書嘆','陸游','宋','宋诗','song-poetry','','[]','三代藏寶器，世守參河圖。',156,'全唐诗/poet.song.128000.json','["三代藏寶器，世守參河圖。", "埋湮則已矣，可使列市區。", "文章有廢興，盖與治亂符。", "慶歴嘉祐間，和氣扇大鑪。", "数公實主盟，渾灝配典謨。", "開闢始歐王，菑畬逮曾蘓。", "大駕初渡江，中原皆荒蕪。", "吾猶及故老，清夜陪坐隅。", "論文有脉絡，千古著不誣。", "俯仰四十年，緑髮霜蓬枯。", "孤生尊所聞，秉節不敢渝。", "久幽士固有，速售理則無。", "世方亂珉玉，吾其老江湖。"]'),
('4527c635-1340-4153-bacb-43cee572651f','睡起','陸游','宋','宋诗','song-poetry','','[]','睡味清酣鼻息輕，碧幮文簟喜涼生。',64,'全唐诗/poet.song.128000.json','["睡味清酣鼻息輕，碧幮文簟喜涼生。", "片雲過處失簾影，急雨來時聞瓦聲。", "索虜尚憑三輔險，散關未下九天兵。", "白頭漫倚詩豪在，手掣鯨魚意未平。"]'),
('1c308f53-844c-4ee8-9b7f-e7f481adfa9b','飯罷碾茶戲書','陸游','宋','宋诗','song-poetry','','[]','江風吹雨暗衡門，手碾新茶破睡昏。',32,'全唐诗/poet.song.128000.json','["江風吹雨暗衡門，手碾新茶破睡昏。", "小餅戲龍供玉食，今年也到浣花村。"]'),
('638a679a-ccfe-4bdf-80a6-e4c1699d458f','夢逰山水奇麗處有古宫觀云雲臺觀也','陸游','宋','宋诗','song-poetry','','[]','神逰忽到雲臺宫，太華彩翠明秋空。',128,'全唐诗/poet.song.128000.json','["神逰忽到雲臺宫，太華彩翠明秋空。", "曲廊下闞白蓮沼，小閣正對青蘿峰。", "林間突兀見古碣，雲外縹緲聞疏鐘。", "褐衣紗帽瘦如削，遺像恐是希夷翁。", "窮搜未遍忽驚覺，半窗朝日初曈曨。", "却思巉然五千仞，可使常墮戰塵中。", "小臣昧死露肝鬲，願扈鑾駕臨崤潼。", "何當真過此山下，百尺嫋嫋龍旗風。"]'),
('30dc0fb4-8529-45a7-907c-aa11d5b614a9','月下醉題','陸游','宋','宋诗','song-poetry','','[]','黄鵠飛鳴未免饑，此身自笑欲何之。',64,'全唐诗/poet.song.128000.json','["黄鵠飛鳴未免饑，此身自笑欲何之。", "閉門種菜英雄老，彈鋏思魚富貴遲。", "生擬入山隨李廣，死當穿冢近要離。", "一樽彊醉南楼月，感慨長吟恐過悲。"]'),
('122ddb75-9c2e-4239-a514-545750f45e42','野外劇飲示坐中','陸游','宋','宋诗','song-poetry','','[]','悲歌流涕遣誰聽，酒隐人間已半生。',64,'全唐诗/poet.song.128000.json','["悲歌流涕遣誰聽，酒隐人間已半生。", "但恨見疑非節俠，豈忘小忍就功名。", "江湖舟楫行安在，燕趙風塵久未平。", "飲罷别君擕劍起，試横雲海剪長鯨。"]'),
('c7bd13bb-fc60-48c0-950a-22a7a1c414df','與青城道人飲酒作','陸游','宋','宋诗','song-poetry','','[]','君不見太傅晚歲具海舟，歸欲極意東山逰。',119,'全唐诗/poet.song.128000.json','["君不見太傅晚歲具海舟，歸欲極意東山逰。", "翰林偶脱夜郎讁，大醉賦詩黄鶴楼。", "兩公窮達何足道，同是逸氣横清秋。", "我無一事行萬里，青山白雲聊散愁。", "有酒不換西涼州，無酒不典鷫鸘裘。", "不作王猛傲晲坐捫蝨，不作甯戚悲歌起飯牛。", "五雲覆鼎金丹熟，笙鶴飄然戲十洲。"]'),
('39bc2f20-68ef-4c2e-bc16-1bc7c3094495','銅壺閣望月','陸游','宋','宋诗','song-poetry','','[]','銅壺閣上看明月，身在千尋白銀闕。',64,'全唐诗/poet.song.128000.json','["銅壺閣上看明月，身在千尋白銀闕。", "十年肺渇今夕平，皓然胸次堆冰雪。", "恨無僊掌出雲表，更取墜露和玉屑。", "夜闌三嘆下危梯，明日人間火雲熱。"]'),
('0765c55f-e729-4132-83cc-9217fdcbcd33','連日得雨涼甚有作','陸游','宋','宋诗','song-poetry','','[]','九淵龍起跨蒼茫，聊爲西州洗亢陽。',64,'全唐诗/poet.song.128000.json','["九淵龍起跨蒼茫，聊爲西州洗亢陽。", "曉看空濛知歲稔，夜聞點滴覺心涼。", "紗幮不下蚊蠅静，焙火微温書畫香。", "睡足何須雲夢澤，如雷鼻息撼鄰墻。"]'),
('38150a57-83b5-4cfc-a4e0-c0c65d90abd7','待青城道人不至','陸游','宋','宋诗','song-poetry','','[]','我亦從來薄世緣，偶然采藥到西川。',64,'全唐诗/poet.song.128000.json','["我亦從來薄世緣，偶然采藥到西川。", "慵追萬里騎鯨客，且伴千年化鶴僊。", "金鼎養丹暾海日，玉壺取酒醉江天。", "朝來坐待方平久，讀盡黄庭內外篇。"]'),
('15002504-2f56-41e3-836d-7ec4a993b586','劍客行','陸游','宋','宋诗','song-poetry','','[]','我友劍俠非常人，袖中青蛇生細鱗。',64,'全唐诗/poet.song.128000.json','["我友劍俠非常人，袖中青蛇生細鱗。", "騰空頃刻已千里，手决風雲驚鬼神。", "荆軻專諸何足数，中夜入燕特起舞。", "一身獨報萬國讎，歸告昌陵泪如雨。"]'),
('e52e6de2-e02f-4aa4-950d-0cb18fe59fe1','夜宴即席作','陸游','宋','宋诗','song-poetry','','[]','宣華輦路牧牛羊，摩訶龍池草茫茫。',96,'全唐诗/poet.song.128000.json','["宣華輦路牧牛羊，摩訶龍池草茫茫。", "宫殿犂盡餘繚牆，南風遠吹禾黍香。", "草間白骨横秋霜，何由喚起釂一觴。", "癡人走死聲利場，我獨感此惜流光。", "蘋花開時風榭涼，美人縹緲如鸞翔。", "堯年舜日樂未央，非子之故爲誰狂。"]'),
('d5c73d2c-3467-4886-8d09-57ad10f7d80c','宿沱江彌勒院','陸游','宋','宋诗','song-poetry','','[]','雨足陂塘溢，庭空草樹荒。',48,'全唐诗/poet.song.128000.json','["雨足陂塘溢，庭空草樹荒。", "衰年愁客路，野寺憩衣囊。", "蛙吹喧孤枕，蚊雷動四廊。", "青燈照無寐，寂寞数更長。"]'),
('c30aee25-dfc9-4a36-9ea0-0439503fc2ca','學射道中感事','陸游','宋','宋诗','song-poetry','','[]','學射山前宿雨收，籃輿咿軋自生愁。',64,'全唐诗/poet.song.128000.json','["學射山前宿雨收，籃輿咿軋自生愁。", "得閑何惜傾家醸，漸老真須秉燭逰。", "道廢尚書猶乞米，時來校尉亦封侯。", "自憐白首能豪在，車轍何因遍九州。"]'),
('ce9798ac-133d-40a3-8512-0fec3e5cd83a','逰學射觀次壁間詩韵','陸游','宋','宋诗','song-poetry','','[]','走遍人間鬢尚青，爾來樂事滿餘齡。',64,'全唐诗/poet.song.128000.json','["走遍人間鬢尚青，爾來樂事滿餘齡。", "傍潭秋爽鉏甘菊，登嶽春暄采茯苓。", "閑倚松蘿論劍術，静臨窗几勘丹經。", "嚴光本是逃名者，安用天文動客星。"]'),
('dcfc8a73-d53a-4356-bd16-54d8106d10a7','昇僊橋遇風雨大至憩小店','陸游','宋','宋诗','song-poetry','','[]','觸熱真疑墮火灰，雨如飛鏃亦佳哉。',64,'全唐诗/poet.song.128000.json','["觸熱真疑墮火灰，雨如飛鏃亦佳哉。", "空江魚鼈從龍起，平野雷霆擁馬來。", "正怪横吹屋茅盡，俄聞下擊澗松摧。", "晚來日漏風猶急，臥看柴扉闔復開。"]'),
('3d0fdd27-5bf0-4b41-95a5-89a429245109','龍挂','陸游','宋','宋诗','song-poetry','','[]','成都六月天大風，發屋動地聲勢雄。',96,'全唐诗/poet.song.128000.json','["成都六月天大風，發屋動地聲勢雄。", "黑雲崔嵬行風中，凛如鬼神寒虚空。", "霹靂迸火射地紅，上帝有命起伏龍。", "龍尾不卷曵天東，壯哉雨點車軸同。", "山摧江溢路不通，連根拔出千尺松。", "未言爲人作年豐，偉觀一洗芥蒂胸。"]'),
('227a21d8-1c06-4683-9c2b-f227b8d33135','芳華楼夜宴','陸游','宋','宋诗','song-poetry','','[]','射虎將軍老不侯，尚能豪縱醉江楼。',64,'全唐诗/poet.song.128000.json','["射虎將軍老不侯，尚能豪縱醉江楼。", "笙歌雜沓娱清夜，風露高寒接素秋。", "少日壯心輕玉塞，暮年幽夢墮滄洲。", "人間清絕沅湘路，常笑靈均作許愁。"]'),
('75c1f624-445a-40a9-996c-6fa91c83f47f','遣興','陸游','宋','宋诗','song-poetry','','[]','老子從來薄宦情，不辭落魄錦官城。',64,'全唐诗/poet.song.128000.json','["老子從來薄宦情，不辭落魄錦官城。", "生前猶著幾兩屐，身後更須千載名。", "楼外雪山森曉色，井邉風葉戰秋聲。", "一尊尚有臨卭酒，却爲無憂得細傾。"]'),
('5ee47747-dae7-4e09-a73e-874c1e654779','六月九日夜步月至朝真觀','陸游','宋','宋诗','song-poetry','','[]','朝斗真人有舊祠，追涼老子曳笻枝。',64,'全唐诗/poet.song.128000.json','["朝斗真人有舊祠，追涼老子曳笻枝。", "從來步月難爲客，此夕聽琴合有詩。", "竹院沉沉聞漏永，玉繩耿耿看星移。", "慇懃更作重來約，迨及冰輪未缺時。"]'),
('28494d05-651f-4615-921e-91abc23d981e','十日夜月中馬上作','陸游','宋','宋诗','song-poetry','','[]','身逰碧海跨鯨魚，心似寒冰貯玉壺。',64,'全唐诗/poet.song.128000.json','["身逰碧海跨鯨魚，心似寒冰貯玉壺。", "衣濕三更清露墜，眼明萬里片雲無。", "横空孤鶴曾相識，散髮飛仙定可呼。", "老向人間無復意，逝將從此謁清都。"]'),
('b312e116-2de0-4fa0-8c68-7988839aaceb','百歲','陸游','宋','宋诗','song-poetry','','[]','百歲紛紛易白頭，一年鼎鼎又清秋。',64,'全唐诗/poet.song.128000.json','["百歲紛紛易白頭，一年鼎鼎又清秋。", "壯心空似驥伏櫪，病骨敢懷狐首丘。", "屠釣論交成酒隐，山林高臥得天逰。", "莫悲晚節功名誤，即死猶堪贈醉侯。"]'),
('1b38629e-1834-47f2-aa9f-b6123dc488df','獨飲醉臥比覺已夜半矣戲作此詩','陸游','宋','宋诗','song-poetry','','[]','澤畔元非慕獨醒，散人一飲費經營。',64,'全唐诗/poet.song.128000.json','["澤畔元非慕獨醒，散人一飲費經營。", "也知世少蘓司業，安得官如阮步兵。", "醉著面顔驚少壯，澆餘胸次失峥嶸。", "更闌莫厭殘燈火，臥聽空廊絡緯聲。"]'),
('63a79a33-dd91-4854-9cf0-c9f594aae1ff','蒙恩奉祠桐柏','陸游','宋','宋诗','song-poetry','','[]','少年曾綴紫宸班，晚落危途九折艱。',64,'全唐诗/poet.song.128000.json','["少年曾綴紫宸班，晚落危途九折艱。", "罪大初聞收郡印，恩寛俄許領家山。", "羈鴻但自思烟渚，病驥寕容著帝關。", "回首觚稜渺何處，從今常寄夢魂間。"]'),
('257e0df9-3a63-418d-8591-c7c8bdce6457','和范待制月夜有感','陸游','宋','宋诗','song-poetry','','[]','榆枋正復異鵬飛，等是垂頭受馽鞿。',64,'全唐诗/poet.song.128000.json','["榆枋正復異鵬飛，等是垂頭受馽鞿。", "坐客笑談嘲遠志，故人書札寄當歸。", "醉思蓴菜黏篙滑，饞憶鱸魚墜釣肥。", "誰遣貴人同此感，夜來風月夢苔磯。"]'),
('a85f9c24-afa6-4fb8-98f7-8da92743699b','和范待制秋興三首  其一','陸游','宋','宋诗','song-poetry','','[]','策策桐飄已半空，啼螿漸覺近房櫳。',64,'全唐诗/poet.song.128000.json','["策策桐飄已半空，啼螿漸覺近房櫳。", "一生不作牛衣泣，萬事從渠馬耳風。", "名姓已甘黄紙外，光陰全付緑尊中。", "門前剥啄誰相覔，賀我今年號放翁。"]'),
('3a493077-73fb-4611-a1b3-7abddcc5a6be','和范待制秋興三首  其二','陸游','宋','宋诗','song-poetry','','[]','睡臉餘痕印枕紋，秋衾微潤覆爐熏。',64,'全唐诗/poet.song.128000.json','["睡臉餘痕印枕紋，秋衾微潤覆爐熏。", "井桐搖落先霜盡，衣杵凄涼带月聞。", "佛屋紗燈明小像，經奩魚蠧蝕真文。", "身如病驥惟思臥，誰許能空萬馬群。"]'),
('3f9a22a1-f192-4a57-aae0-4592dac6669d','和范待制秋興三首  其三','陸游','宋','宋诗','song-poetry','','[]','山澤沉冥氣尚豪，鬢絲未遽嘆蕭騷。',64,'全唐诗/poet.song.128000.json','["山澤沉冥氣尚豪，鬢絲未遽嘆蕭騷。", "已忘海運鯤鵬化，那計風微燕雀高。", "萬里客魂迷楚峽，五更歸夢隔胥濤。", "故知有酒當勤醉，自古寕聞死可逃。"]'),
('b203aeb3-7686-4a02-a612-687fda1df060','和范待制秋日書懷二首游自七月病起蔬食止酒故詩中及之  其一','陸游','宋','宋诗','song-poetry','','[]','閑窗貝葉對旁行，不覺城笳報夕陽。',64,'全唐诗/poet.song.128000.json','["閑窗貝葉對旁行，不覺城笳報夕陽。", "嗜酒步兵猶未達，拂衣司諌亦成忙。", "室無摩詰持花女，囊有婆娑等價香。", "欲與衆生共安隐，秋來夢不到鱸鄉。"]'),
('c2cf0653-3e8b-4040-9d1e-840ebd195c12','和范待制秋日書懷二首游自七月病起蔬食止酒故詩中及之  其二','陸游','宋','宋诗','song-poetry','','[]','故人無字寄相思，敢向窮途怨不知。',64,'全唐诗/poet.song.128000.json','["故人無字寄相思，敢向窮途怨不知。", "老病已全惟欠死，貪嗔雖斷尚餘癡。", "数莖雪鬢江湖遠，九轉金丹日月遲。", "畬粟山苗俱可飽，明年東去隐峨眉。"]'),
('6112cbf2-2150-4cba-aac1-dfbfe6a614bc','逰學射山遇景道人','陸游','宋','宋诗','song-poetry','','[]','肩輿適青郊，飛屐登翠麓。',168,'全唐诗/poet.song.128000.json','["肩輿適青郊，飛屐登翠麓。", "餘霜未泫瓦，晨日初挂木。", "推門覔黄冠，避客似奔鹿。", "雖無與晤言，清坐意亦足。", "豈知逢此士，曠度超世俗。", "欣然同一笑，齒頬粲冰玉。", "探囊贈奇草，甘香勝芎菊。", "試臨清鏡照，衰顔森已緑。", "出門恣幽討，老仙有遺躅。", "丹竈雖已空，藥丸遍山谷。", "嗟予迫遲暮，冠盖厭追逐。", "結茅遠人境，此計亦已熟。", "若人真我友，玉字當共讀。", "客來不知處，鷄犬望雲屋。"]'),
('3beaa535-f1eb-4e64-8b3e-62f165a2ad89','城東醉歸深夜復呼酒作此詩','陸游','宋','宋诗','song-poetry','','[]','冬夜走馬城東回，追風逐電何雄哉。',96,'全唐诗/poet.song.128000.json','["冬夜走馬城東回，追風逐電何雄哉。", "五門鼓動燈火閙，意氣忽覺如章臺。", "歸來脱靴靴滿霜，月明如水浸野堂。", "梅花滿手不可負，催熾獸炭傳清觴。", "書生所懷未易料，會與君王掃燕趙。", "只愁漸老不禁寒，臥載輜車君勿笑。"]'),
('e408593e-7764-46be-aebc-c54bcf454344','融州寄松紋劍','陸游','宋','宋诗','song-poetry','','[]','十年學劍勇成癖，騰身一上三千尺。',96,'全唐诗/poet.song.128000.json','["十年學劍勇成癖，騰身一上三千尺。", "術成欲試酒半酣，直躡丹梯削青壁。", "青壁一削平無蹤，浩歌却過蓮花峰。", "世人仰視那得測，但怪雪刃飛秋空。", "老胡畏誅奉約束，假息漁陽連上谷。", "願聞下詔遣材官，恥作腐儒長碌碌。"]'),
('2dcee1da-37cf-4897-8f6f-1fd2ad52a0ab','歲晚','陸游','宋','宋诗','song-poetry','','[]','歲晚城隅車馬稀，偷閑聊得掩荆扉。',64,'全唐诗/poet.song.128000.json','["歲晚城隅車馬稀，偷閑聊得掩荆扉。", "征蓬滿野風霜苦，多稼連雲雁鶩肥。", "報國有心空自信，結茅無地竟安歸。", "浣花道上人誰識，華表千年老令威。"]'),
('401333cb-3e71-42f8-9771-4a2af242126f','玉京行','陸游','宋','宋诗','song-poetry','','[]','玉京清都奉紫皇，赤明開皇刧茫茫。',128,'全唐诗/poet.song.128000.json','["玉京清都奉紫皇，赤明開皇刧茫茫。", "有路坦如馳康莊，惜哉背之趨死鄉。", "絳陵朱兒朝吐光，森然箭鏃攅玉床。", "潔齋山棲祓不祥，朝餐夕食芝术香。", "縹囊蘂笈出秘方，日精月華鍊陰陽。", "爐開沐浴時日良，清夜玉杵聞琳房。", "服之刀圭換肝腸，三十六帝參翺翔。", "下視一笑争奪塲，纍纍枯冢壓北邙。"]'),
('39e0b470-a9a4-4672-94d3-7c8aa1d78b03','步出萬里橋門至江上','陸游','宋','宋诗','song-poetry','','[]','久坐意不懌，掩卷聊出逰。',144,'全唐诗/poet.song.128000.json','["久坐意不懌，掩卷聊出逰。", "一笻吾事足，安用車與騶。", "浮生了無根，両踵蹋百州。", "常憶航巨海，銀山卷濤頭。", "一日新雨霽，微茫見流求。", "西行亦足快，縱獵南山秋。", "騰身刺猛虎，至今血濺裘。", "命薄每自笑，校尉略已侯。", "短劍隐市塵，浩歌醉江楼。", "頗疑屠博中，可與共奇謀。", "丈夫等一死，滅賊報國讎。", "徙倚萬里橋，寒日墮前洲。"]'),
('11f5ecec-9065-40b6-8db6-c6b615746684','晚步','陸游','宋','宋诗','song-poetry','','[]','院荒有古意，僧少無人聲。',96,'全唐诗/poet.song.128000.json','["院荒有古意，僧少無人聲。", "徘徊楠陰下，賞此落日明。", "著書亦何急，寂寞身後名。", "今年復止酒，歌舞陳空觥。", "不如且消搖，出門隨意行。", "看竹入廢園，望江上高城。", "纎纎素月出，靄靄蒼烟横。", "此夕當復奇，緱山吹玉笙。"]'),
('b3231576-5b54-4fab-b90d-706b74208c67','数日寒頓減頗有春意感懷賦短歌','陸游','宋','宋诗','song-poetry','','[]','微陰寒不力，破臘春暗動。',96,'全唐诗/poet.song.128000.json','["微陰寒不力，破臘春暗動。", "林梢報梅白，水際聞鳥哢。", "羈鴻漸整翮，一一勞目送。", "應憐飛蓬客，猶作浣花夢。", "平生江淮間，裘馬事豪縱。", "豈知老畏死，齋鉢受蔬供。", "忍饞每自笑，小飲未敢痛。", "何以慰寂寥，臥聽壓春甕。"]'),
('f773efe8-ab84-495f-b82d-f7e8a9860d43','春愁','陸游','宋','宋诗','song-poetry','','[]','春愁茫茫塞天地，我行未到愁先至。',64,'全唐诗/poet.song.128000.json','["春愁茫茫塞天地，我行未到愁先至。", "滿眼如雲忽復生，尋人似瘧何由避。", "客來勸我飛觥籌，我笑謂客君罷休。", "醉自醉倒愁自愁，愁與酒如風馬牛。"]'),
('5d14d4d3-bc8f-4fd8-a013-2bfbd3287575','歲暮感懷','陸游','宋','宋诗','song-poetry','','[]','征塵十載暗戎衣，虚負名山采藥期。',64,'全唐诗/poet.song.128000.json','["征塵十載暗戎衣，虚負名山采藥期。", "少日覆氊曾草檄，即今横槊尚能詩。", "昏昏殺氣秋登隴，颯颯飛霜夜出師。", "會有英豪能共此，鏡中未用嘆吾衰。"]'),
('c4dfe6f8-845f-482e-be11-8851d6a8460c','梅花','陸游','宋','宋诗','song-poetry','','[]','冰崖雪谷木未芽，造物破荒開此花。',96,'全唐诗/poet.song.128000.json','["冰崖雪谷木未芽，造物破荒開此花。", "神全形枯近有道，意莊色正知無衺。", "高堅政要飽憂患，放棄何遽愁荒遐。", "移根上苑亦過計，竹籬茅屋真吾家。", "平生自嫌亦自許，妙處可識不可誇。", "金樽翠杓未免俗，篝火爲試江南茶。"]'),
('7087df68-fa99-4e0b-a037-6cafeaf72569','寺居夙興','陸游','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','閑居無一事，睡少自夙興。',72,'全唐诗/poet.song.128000.json','["閑居無一事，睡少自夙興。", "空庭翠霧合，高樹紅日昇。", "曳杖遶四廊，悄然不逢僧。", "厨烟俄漠漠，魚鼓亦登登。", "晨粥香滿堂，粱肉坐可憎。", "匡山在何許，吾将買行縢。"]'),
('17ce9d27-3baa-4706-b1d1-cb216cdfb01b','萬里橋江上習射','陸游','宋','宋诗','song-poetry','','[]','坡隴如濤東北傾，胡床看射及春晴。',64,'全唐诗/poet.song.128000.json','["坡隴如濤東北傾，胡床看射及春晴。", "風和漸減雕弓力，野逈遙聞羽箭聲。", "天上攙搶端可落，草間狐兔不須驚。", "丈夫未死誰能料，一笴他年下百城。"]'),
('c67858d2-134c-41bc-a3ec-60dd5e4623ff','關山月','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u60b2\u6124", "\u58ee\u5fd7\u672a\u916c"]','和戎詔下十五年，將軍不戰空臨邉。',96,'全唐诗/poet.song.128000.json','["和戎詔下十五年，將軍不戰空臨邉。", "朱門沉沉按歌舞，廐馬肥死弓斷弦。", "戍楼刁斗催落月，三十從軍今白髮。", "笛裏誰知壯士心，沙頭空照征人骨。", "中原干戈古亦聞，豈有逆冦傳子孫。", "遺民忍死望恢復，幾處今宵垂泪痕。"]'),
('64e809d4-2025-4fb0-88a4-1bea9ce8e763','出塞曲','陸游','宋','宋诗','song-poetry','','[]','佩刀一刺山爲開，壯士大呼城爲摧。',96,'全唐诗/poet.song.128000.json','["佩刀一刺山爲開，壯士大呼城爲摧。", "三軍甲馬不知数，但見動地銀山來。", "長戈逐虎祁連北，馬前曵來血丹臆。", "却回射雁鴨緑江，箭飛雁起連雲黑。", "清泉茂草下程時，野帳牛酒争淋漓。", "不學京都貴公子，唾壺麈尾事兒嬉。"]'),
('40047070-7be5-40c3-9a7f-1af7b1d26ff5','戰城南','陸游','宋','宋诗','song-poetry','','[]','王師出城南，塵頭暗城北。',92,'全唐诗/poet.song.128000.json','["王師出城南，塵頭暗城北。", "五軍戰馬如錯繡，出入變化不可測。", "逆胡欺天負中國，虎狼雖猛那勝德。", "馬前嗢咿爭氣降，滿地縱橫熱劍戟。", "將軍駐坡擁黄旗，遣騎得令勿自疑。", "詔書許汝以不死，股栗何爲汗如洗。"]'),
('c44b1adc-48f3-42f4-a70a-ab7960bb912c','讀書二首  其一','陸游','宋','宋诗','song-poetry','','[]','面骨峥嶸鬢欲疏，退藏只合臥蝸廬。',32,'全唐诗/poet.song.128000.json','["面骨峥嶸鬢欲疏，退藏只合臥蝸廬。", "自嫌尚有人間意，射雉歸來夜讀書。"]'),
('10423758-afd5-4d67-855e-fc7866f0cfef','讀書二首  其二','陸游','宋','宋诗','song-poetry','','["\u5fe7\u56fd\u5fe7\u6c11", "\u8bfb\u4e66"]','歸老寕無五畆園，讀書本意在元元。',32,'全唐诗/poet.song.128000.json','["歸老寕無五畆園，讀書本意在元元。", "燈前目力雖非昔，猶課蠅頭二萬言。"]'),
('5caaf57c-5e53-4e56-8cfc-7f05ccd4effd','晚過保福','陸游','宋','宋诗','song-poetry','','[]','堂静僧閑普請疏，爐紅氊暖放參餘。',64,'全唐诗/poet.song.128000.json','["堂静僧閑普請疏，爐紅氊暖放參餘。", "蓮花池上容投社，椰子身中悔著書。", "茶試趙坡如潑乳，芋來犀浦可專車。", "放翁一飽真無事，擬伴園頭日把鉏。"]'),
('b8be3753-9246-440d-b0e5-adca8d0b298d','偶過浣花感舊逰戲作','陸游','宋','宋诗','song-poetry','','[]','憶昔初爲錦城客，醉騎駿馬桃花色。',112,'全唐诗/poet.song.128000.json','["憶昔初爲錦城客，醉騎駿馬桃花色。", "玉人擕手上江楼，一笑鈎簾賞微雪。", "寶釵換酒忽徑去，三日楼中香未滅。", "市人不識呼酒仙，異事驚傳一城說。", "至今西壁餘小草，過眼年光如電掣。", "正月錦江春水生，花枝缺處小舟横。", "閑倚胡床吹玉笛，東風十里斷腸聲。"]'),
('95002b3f-eaee-4d2f-b0c0-65b32e7d4f1c','夜讀唐諸人詩多賦烽火者因記在山南時登城觀塞上傳烽追賦一首','陸游','宋','宋诗','song-poetry','','[]','我昔逰梁州，軍中方罷戰。',96,'全唐诗/poet.song.128000.json','["我昔逰梁州，軍中方罷戰。", "登城看烽火，川迥風裂面。", "青熒竝駱谷，隐翳連鄠縣。", "月黑望愈明，雨急滅復見。", "初疑雲罅星，又似山際電。", "豈無酒滿尊，對此不能嚥。", "低頭愧虎韔，零落白羽箭。", "何時復關中，却照甘泉殿。"]'),
('f817c51a-64be-44ff-be5a-2d4aa040bde6','平明出小東門觀梅','陸游','宋','宋诗','song-poetry','','[]','知心多别離，慰眼易零落。',100,'全唐诗/poet.song.128000.json','["知心多别離，慰眼易零落。", "東風吹梅花，爛漫照城郭。", "晴日千堆雪，偏宜馬上看。", "逢迎無幾日，不惜犯春寒。", "明年花發時，我在両京道。", "花香固無盡，我亦未遽老。", "脱帽髮如漆，看花心未灰。", "平戎那得妨持酒，會有詩傳劍外來。"]'),
('61e056eb-9aad-424d-a31c-e7d46b8139aa','寺居睡覺二首  其一','陸游','宋','宋诗','song-poetry','','[]','虚窗寂寂夜三更，燈斂殘光避月明。',32,'全唐诗/poet.song.128000.json','["虚窗寂寂夜三更，燈斂殘光避月明。", "老懶只貪春睡美，愧聞童子誦經聲。"]'),
('1b8db19e-5add-47d0-90cb-c63cda1de133','寺居睡覺二首  其二','陸游','宋','宋诗','song-poetry','','[]','心地安平曉夢長，忽聞魚鼓動修廊。',32,'全唐诗/poet.song.128000.json','["心地安平曉夢長，忽聞魚鼓動修廊。", "披衣起意清羸甚，想像雲堂缹粥香。"]'),
('828fc095-60bb-423b-857d-d6c86711db37','楼上醉書','陸游','宋','宋诗','song-poetry','','[]','丈夫不虚生世間，本意滅虜收河山。',128,'全唐诗/poet.song.128000.json','["丈夫不虚生世間，本意滅虜收河山。", "豈知蹭蹬不稱意，八年梁益凋朱顔。", "三更撫枕忽大叫，夢中奪得松亭關。", "中原機會嘆屡失，明日茵席留餘澘。", "益州官楼酒如海，我來解旗論日買。", "酒酣博簺爲歡娱，信手梟盧喝成采。", "牛背爛爛電目光，狂殺自謂元非狂。", "故都九廟臣敢忘，祖宗神靈在帝旁。"]'),
('f00bb8d2-cca0-4906-ac9a-9a8091ad7426','醉題','陸游','宋','宋诗','song-poetry','','[]','裘馬清狂錦水濵，最繁華地作閑人。',64,'全唐诗/poet.song.128000.json','["裘馬清狂錦水濵，最繁華地作閑人。", "金壺投箭消長日，翠袖傳杯領好春。", "幽鳥語隨歌處拍，落花鋪作舞時茵。", "悠然自適君知否，身與浮名若箇親。"]'),
('9db8b986-9df5-4ac8-a752-3868ea93e376','初春出逰','陸游','宋','宋诗','song-poetry','','[]','春風初來滿刀州，江水照人如潑油。',128,'全唐诗/poet.song.128000.json','["春風初來滿刀州，江水照人如潑油。", "犢車芳草南陌頭，家家傾貲事遨逰。", "萬里橋西繫黄騮，爲君一登散花楼。", "半年長齋廢觥籌，興來忽典千金裘。", "小桃婀娜弄芳柔，紅蘭茁芽滿春洲。", "壚邉女兒不解愁，鬭草纔罷還藏鈎。", "可憐世人自拘囚，盎中乾坤舞蜉蝣。", "百年苦短去日遒，問君安用萬户侯。"]'),
('a13e5fcd-ce9c-483c-9b86-f8a1370fe7e9','芳華楼夜飲二首  其一','陸游','宋','宋诗','song-poetry','','[]','春風射雉苑城旁，走馬還來入醉鄉。',64,'全唐诗/poet.song.128000.json','["春風射雉苑城旁，走馬還來入醉鄉。", "夜暖酒波揺燭焰，舞回粧粉鑠花光。", "浮生一笑常難必，此樂它年未易忘。", "莫作五陵豪俠看，奚奴歸路有詩囊。"]'),
('5282fcb5-6c82-4565-800e-27b62bd8fe74','芳華楼夜飲二首  其二','陸游','宋','宋诗','song-poetry','','[]','結客追逰亦樂哉，城南城北古池臺。',64,'全唐诗/poet.song.128000.json','["結客追逰亦樂哉，城南城北古池臺。", "香生赭汗連錢馬，光溢金舩撥雪醅。", "難覓長繩縻日住，且憑羯鼓喚花開。", "一春政使渾無事，醉到清明得幾回。"]'),
('80545201-1082-4480-b017-0aab83526a1b','東門外遍歴諸園及僧院觀逰人之盛','陸游','宋','宋诗','song-poetry','','[]','馬上哦詩畫醉鞭，東城南陌去翩翩。',64,'全唐诗/poet.song.128000.json','["馬上哦詩畫醉鞭，東城南陌去翩翩。", "微風蹙水魚鱗浪，薄日烘雲卵色天。", "隔屋鳩鳴閑院落，争門花簇小輜軿。", "病來久已疏杯酌，春物撩人又破禪。"]'),
('0e6c2ec9-8668-4fc1-9dc5-f8c4d6f291c5','城東馬上作二首  其一','陸游','宋','宋诗','song-poetry','','[]','古寺名園處處行，翩然南陌復東城。',64,'全唐诗/poet.song.128000.json','["古寺名園處處行，翩然南陌復東城。", "手柔弓燥獵徒喜，耳熱酒酣詩興生。", "月似有情迎馬見，鶯如相識向人鳴。", "摩挲病眼還三嘆，猶擬中原看太平。"]'),
('f50d8bba-d73e-4955-b940-e7069af45fbd','城東馬上作二首  其二','陸游','宋','宋诗','song-poetry','','[]','割鮮藉草醉春醪，仰看鳴髇百尺高。',64,'全唐诗/poet.song.128000.json','["割鮮藉草醉春醪，仰看鳴髇百尺高。", "杜老何妨希稷禹，孔明本自陋袁曹。", "邉頭插羽無傳檄，篋裏盤鵰有舊袍。", "寄語長安衆年少，妓圍不似獵圍豪。"]'),
('e198eef9-22d8-4c37-893e-8431d56abc5c','丁酉上元三首  其一','陸游','宋','宋诗','song-poetry','','[]','突兀毬場錦繡峰，逰人士女擁千重。',64,'全唐诗/poet.song.128000.json','["突兀毬場錦繡峰，逰人士女擁千重。", "月離雲海飛金鏡，燈射冰簾掣火龍。", "信馬隨車紛醉俠，賣薪買酒到耕農。", "今年自笑真衰矣，但覺憑鞍睡思濃。"]'),
('7a9d30be-4ef2-4dd2-a929-a9dea0aa0b3e','丁酉上元三首  其二','陸游','宋','宋诗','song-poetry','','[]','鼓吹連天沸五門，燈山萬炬動黄昏。',64,'全唐诗/poet.song.128000.json','["鼓吹連天沸五門，燈山萬炬動黄昏。", "美人與月正同色，客子折梅空斷魂。", "寶馬暗塵思輦路，釣舩孤火夢江村。", "古來漫道新知樂，此意何由可共論。"]'),
('743a5a73-b9e5-4f65-8e94-9f1292b48f48','丁酉上元三首  其三','陸游','宋','宋诗','song-poetry','','[]','放翁也入少年場，一笑燈前未歇狂。',64,'全唐诗/poet.song.128000.json','["放翁也入少年場，一笑燈前未歇狂。", "翠袖成圍欺月冷，氊車争道覺塵香。", "蠻酥點綴春風早，楚餌留連夜漏長。", "結騎莫辭侵曉色，昔人萬里看西涼。"]'),
('e2eb2377-c241-481a-9c35-7b1ed675aa5b','後陵永慶院在大西門外不及一里盖王建墓也有二石幢猶當時物又有太后墓琢石爲人馬甚偉','陸游','宋','宋诗','song-poetry','','[]','陵闕凄涼俯舊邦，恨流衮衮似江長。',64,'全唐诗/poet.song.128000.json','["陵闕凄涼俯舊邦，恨流衮衮似江長。", "穿殘已嘆金鳬盡，缺落空餘石馬雙。", "攫飯饑烏占寺鼓，避人飛鼠上經幢。", "阿和乳臭崇韜耄，堪笑昏童束手降。"]'),
('0038508a-509b-4459-92b7-85aaa23ac344','小飲趙園','陸游','宋','宋诗','song-poetry','','[]','少年結騎厭追歡，漸老方知一笑難。',64,'全唐诗/poet.song.128000.json','["少年結騎厭追歡，漸老方知一笑難。", "邂逅偶能成午醉，登臨末覺怕春寒。", "高林横靄丹青幅，亂蝶争花錦繡團。", "滿眼風光索彈壓，酒杯須似蜀江寛。"]'),
('16aa1a59-8f83-42a3-b942-44466ff94cca','和范舍人書懷','陸游','宋','宋诗','song-poetry','','[]','歲月如奔不可遮，即今楊柳已藏鴉。',64,'全唐诗/poet.song.128000.json','["歲月如奔不可遮，即今楊柳已藏鴉。", "客中常欠尊中酒，馬上時看檐上花。", "末路凄涼老巴蜀，少年豪舉動京華。", "天魔久矣先成佛，多病維摩尚在家。"]'),
('135db7e3-95dc-43b2-9fe8-f5876f2ba7b6','和范舍人病後二詩末章兼呈張正字  其一','陸游','宋','宋诗','song-poetry','','[]','放衙元不爲春酲，澹蕩江天氣未清。',64,'全唐诗/poet.song.128000.json','["放衙元不爲春酲，澹蕩江天氣未清。", "欲賞園花先夢到，忽聞簷雨定心驚。", "香雲不動熏籠暖，蠟泪成堆斗帳明。", "關隴宿兵邊末靖，祝公垂意在尊生。"]'),
('a8b77579-6a82-493b-a6df-4de8a9617969','和范舍人病後二詩末章兼呈張正字  其二','陸游','宋','宋诗','song-poetry','','[]','士生不及慶歴初，下方元祐當勿疏。',64,'全唐诗/poet.song.128000.json','["士生不及慶歴初，下方元祐當勿疏。", "請看蛟龍得雲雨，豈比鳥雀馴階除。", "舍人起視北門草，學士歸著東觀書。", "劍外老農亦吐氣，醸酒畦花常晏如。"]'),
('044d314f-84ca-4dc7-99d7-539ad16d12d9','江路見杏花','陸游','宋','宋诗','song-poetry','','[]','我行浣花村，紅杏紅於染。',72,'全唐诗/poet.song.128000.json','["我行浣花村，紅杏紅於染。", "数樹照南坡，一林藏北崦。", "雖慚嶺梅高，繁麗豈易貶。", "雨絲飛復止，雲葉低未斂。", "似嫌風日緊，護此燕脂點。", "身閑得縱觀，無語吾所歉。"]'),
('31bbcb4d-2bc5-48cf-b8e7-fb19c25d6f43','夜聞雨聲','陸游','宋','宋诗','song-poetry','','[]','高簷夜雨瀉淋浪，起擁寒衾旋炷香。',64,'全唐诗/poet.song.128000.json','["高簷夜雨瀉淋浪，起擁寒衾旋炷香。", "春事豈堪頻破壊，客愁不可復禁當。", "長缾磊落輸郫醸，輕騎聮翩報海棠。", "著意物華君莫笑，世間得喪更茫茫。"]'),
('3c9feba9-fb45-4621-904f-6f1aa494506f','海棠二首  其一','陸游','宋','宋诗','song-poetry','','[]','十里迢迢望碧鷄，一城晴雨不曾齊。',32,'全唐诗/poet.song.128000.json','["十里迢迢望碧鷄，一城晴雨不曾齊。", "今朝未得平安報，便恐飛紅已作泥。"]'),
('211240ed-f802-413d-9bdf-d268a7a177b5','海棠二首  其二','陸游','宋','宋诗','song-poetry','','[]','蜀地名花擅古今，一枝氣可壓千林。',32,'全唐诗/poet.song.128000.json','["蜀地名花擅古今，一枝氣可壓千林。", "譏彈更到無香處，常恨人言太刻深。"]'),
('bd0a448c-ab73-4808-8862-c2a27ef570ce','張園海棠','陸游','宋','宋诗','song-poetry','','[]','洛陽春信久不通，姚魏開落戰塵中。',128,'全唐诗/poet.song.128000.json','["洛陽春信久不通，姚魏開落戰塵中。", "揚州千葉昔曾見，已嘆造化無餘功。", "西來始見海棠盛，成都第一推燕宮。", "池臺掃除凡木盡，天地眩轉花光紅。", "慶雲墮空不飛去，時有絳雪縈微風。", "蜂蝶成團出無路，我亦狂走迷西東。", "此園低樹猶三丈，錦繡却在青天上。", "不須更著刀尺裁，乞與齊奴開步障。"]'),
('491c921f-5a96-470a-a1fc-62ea0fd67e0d','登劍南西川門感懷','陸游','宋','宋诗','song-poetry','','[]','自古高楼傷客情，更堪萬里望吳京。',64,'全唐诗/poet.song.128000.json','["自古高楼傷客情，更堪萬里望吳京。", "故人不見暮雲合，客子欲歸春水生。", "瘴癘連年須藥石，退藏無地著柴荆。", "諸公勉畫平戎策，投老深思看太平。"]'),
('14fd5624-e7d7-4b36-9d58-e749ff5bbb9f','和范舍人永康青城道中作','陸游','宋','宋诗','song-poetry','','[]','風驅雨壓無浮埃，驂驔千騎東方來。',130,'全唐诗/poet.song.128000.json','["風驅雨壓無浮埃，驂驔千騎東方來。", "勝逰公自輩王謝，浄社我亦追宗雷。", "岷山楼上一徙倚，如地始闢天初開。", "廓然眼界三萬里，山一螘垤水一杯。", "世間幻妄幾變滅，正自不滿吾曹咍。", "丈夫本願布衣老，達士詎畏蒼顔催。", "君看神君歲食羊四萬，處處棄骨高成堆。", "西山老翁飽松麨，造物賦予何遼哉。"]'),
('926b580c-fa0e-492c-aa31-beed714db2a1','宿上清宫  其一','陸游','宋','宋诗','song-poetry','','[]','永夜寥寥憩上清，下聽萬壑度松聲。',32,'全唐诗/poet.song.128000.json','["永夜寥寥憩上清，下聽萬壑度松聲。", "星辰頓覺去人近，風雨何曾敗月明。"]'),
('3128f42c-2940-4bb1-94f2-bb8ae449025e','宿上清宫  其二','陸游','宋','宋诗','song-poetry','','[]','早歲文辭妨至道，中年憂患博虚名。',32,'全唐诗/poet.song.128000.json','["早歲文辭妨至道，中年憂患博虚名。", "一庵倘許西峰住，常就巢仙問養生。"]'),
('777ac46d-d705-432c-8fa1-63d9f3192b72','登上清小閣','陸游','宋','宋诗','song-poetry','','[]','楼觀參差倚晚晴，偶然信脚得閑行。',64,'全唐诗/poet.song.128000.json','["楼觀參差倚晚晴，偶然信脚得閑行。", "欲求靈藥換凡骨，先挽天河洗俗情。", "雲作玉峰時特起，山如翠浪盡東傾。", "何因從此横空去，笙鶴飄然過洛城。"]'),
('829fa733-69a2-44b9-a289-4ee74f293edc','小憩長生觀飯已遂行','陸游','宋','宋诗','song-poetry','','[]','清絕長生觀，再逰疑後身。',48,'全唐诗/poet.song.128000.json','["清絕長生觀，再逰疑後身。", "人間空石劫，物外自壺春。", "道士青精飯，先生烏角巾。", "回頭增悵望，倦馬撲征塵。"]'),
('2b288d8a-1a81-49c1-97cc-508e07313eff','新津小宴之明日欲逰修覺寺以雨不果呈范舍人二首  其一','陸游','宋','宋诗','song-poetry','','[]','風雨長亭話别離，忍看清涙濕燕脂。',32,'全唐诗/poet.song.128000.json','["風雨長亭話别離，忍看清涙濕燕脂。", "酒光搖蕩歌雲暖，不似西楼夜宴時。"]'),
('05957420-24eb-4c4a-a025-f8563958f9df','新津小宴之明日欲逰修覺寺以雨不果呈范舍人二首  其二','陸游','宋','宋诗','song-poetry','','[]','新津渡頭舩欲開，山亭凖擬把離杯。',32,'全唐诗/poet.song.128000.json','["新津渡頭舩欲開，山亭凖擬把離杯。", "不如意事十八九，正用此時風雨來。"]'),
('de6ce35c-e6c2-49af-89ae-aa16e246c5f3','眉州驛舍睡起','陸游','宋','宋诗','song-poetry','','[]','平生百無能，一懶每自喜。',120,'全唐诗/poet.song.128000.json','["平生百無能，一懶每自喜。", "胡爲八年間，逐食走萬里。", "身如盤永轉，心似爐丹死。", "事君未免愧，富貴不如已。", "雨餘古驛涼，晝寐無錯履。", "澹然得高臥，睡思極清美。", "心平了無夢，驚魘何自起。", "尚嫌漆園蝶，肻作南柯螘。", "斜陽生木影，龍蛇滿窗紙。", "煎茶倘已熟，一笑問童子。"]'),
('83377855-302c-4785-b624-0a6f8e5a65d6','送范舍人還朝','陸游','宋','宋诗','song-poetry','','[]','平生嗜酒不爲味，聊欲醉中遺萬事。',160,'全唐诗/poet.song.128000.json','["平生嗜酒不爲味，聊欲醉中遺萬事。", "酒醒客散獨悽然，枕上屡揮憂國涙。", "君如高光那可負，東都兒童作羌語。", "常時念此氣生癭，况送公歸覲明主。", "皇天震怒賊得長，三年昴星失光芒。", "旄頭下掃在旦暮，嗟此大議知誰當。", "公歸上前勉畫策，先取關中次河北。", "堯舜尚不有百蠻，此時何能擾中國。", "黄扉甘泉多故人，定知不作白頭新。", "因公併寄千萬意，早爲神州清戰塵。"]'),
('f58e297d-5366-4dbe-a859-9bd4e0e1e2f4','過魚蛇市小寺','陸游','宋','宋诗','song-poetry','','[]','六月苦多雨，肩輿走江村。',120,'全唐诗/poet.song.128000.json','["六月苦多雨，肩輿走江村。", "過市居人集，陟險兵子喧。", "日昳休野寺，汛掃開北軒。", "霧氣如蒼虬，夭矯出洞門。", "溪清見白石，糾結菖蒲根。", "逰魚去甚健，投餌棄不吞。", "嗟予獨何爲，貪禄忘故園。", "馳驅不自恤，面有風沙痕。", "俯仰二十年，竟孤明主恩。", "寄謝衆君子，努力蘓元元。"]'),
('3051e7db-6be8-48e7-b8f3-9fcbce3c585f','眉州作','陸游','宋','宋诗','song-poetry','','[]','扁舟久不泛蟆津，常恐黄塵觧污人。',64,'全唐诗/poet.song.128000.json','["扁舟久不泛蟆津，常恐黄塵觧污人。", "爛醉破除千日懣，狂吟判斷四州春。", "汀洲漸嘆蘋花老，風露初嘗荔子新。", "便欲騎鯨東海去，勝逰未忍别峨岷。"]'),
('d69fb51b-b32c-4263-b226-98339835dd51','過修覺山不果登覽','陸游','宋','宋诗','song-poetry','','[]','前日泛江時，雨昏失南山。',96,'全唐诗/poet.song.128000.json','["前日泛江時，雨昏失南山。", "今日迎我馬，䰀鬌擁髻鬟。", "白塔映朱閣，間見青林間。", "問我豈忘之，掦鞭亟西還。", "西還亦聊爾，行矣來憑欄。", "擾擾紅塵中，豈無一日閑。", "會復賡此詩，大書榜其顔。", "但恐厄風雨，清逰天所慳。"]'),
('1a8675d9-21a1-498f-b12d-811fec1a1e97','青城縣會飲何氏池亭贈譚德稱','陸游','宋','宋诗','song-poetry','','[]','赤日黄塵行路難，青城縣裏得偷閑。',64,'全唐诗/poet.song.128000.json','["赤日黄塵行路難，青城縣裏得偷閑。", "十年去國悲霜鬢，六月登楼望雪山。", "醉客千言猶落筆，美人斗酒未酡顔。", "憑誰喚住譚夫子，更與徘徊水石間。"]'),
('7158b33e-eb07-4ac1-b13d-13070d06a38a','題庵壁','陸游','宋','宋诗','song-poetry','','[]','偶向城南卜草廬，二年浪迹寄樵漁。',64,'全唐诗/poet.song.128000.json','["偶向城南卜草廬，二年浪迹寄樵漁。", "大床獨臥豪猶在，萬衆横行策竟疏。", "清濁戲分春甕酒，朱黄閑勘夜窗書。", "衰顔安用頻看鏡，日日元知有不如。"]'),
('a6d73f4b-4a47-4831-ae99-cfb4d41e4ece','幽居二首  其一','陸游','宋','宋诗','song-poetry','','[]','殊方飄泊向誰論，小住僧廬亦所欣。',64,'全唐诗/poet.song.128000.json','["殊方飄泊向誰論，小住僧廬亦所欣。", "得飽罷揮求米帖，爱眠新著毁茶文。", "摘蔬籃小霑清露，斸藥鉏輕带濕雲。", "從此生涯足幽事，宦逰虚用半生勤。"]'),
('b9a22dd8-466c-4d58-a438-245ffb46f85b','幽居二首  其二','陸游','宋','宋诗','song-poetry','','[]','剡曲故廬歸未得，蹔從地主借茅茨。',64,'全唐诗/poet.song.128000.json','["剡曲故廬歸未得，蹔從地主借茅茨。", "桃花春水夢不到，菰菜秋風心自知。", "彊健猶穿幾兩屐，榮華正似一絇絲。", "此心炯炯無人會，烟雨蒼茫獨立時。"]'),
('d6c19e98-c6cb-4063-bb6d-2d0608f6eb96','浣花女','陸游','宋','宋诗','song-poetry','','[]','江頭女兒雙髻丫，常隨阿母供桑麻。',99,'全唐诗/poet.song.128000.json','["江頭女兒雙髻丫，常隨阿母供桑麻。", "當户夜織聲咿啞，地爐豆{艹點}煎土茶。", "長成嫁與東西家，柴門相對不上車。", "青裙竹笥何所嗟，插髻燦燦牽牛花。", "城中妖姝臉如霞，争嫁官人慕高華。", "青驪一出天之涯，年年傷春抱琵琶。"]'),
('3cd02466-a4a1-4fdc-b9a4-3a614955385f','七月八日馬上作','陸游','宋','宋诗','song-poetry','','[]','溝水浸新月，街槐生碧烟。',48,'全唐诗/poet.song.128000.json','["溝水浸新月，街槐生碧烟。", "明河七夕後，倦馬五門前。", "小市燈初閙，高楼鼓已傳。", "賦詩寛客恨，哦罷却凄然。"]'),
('1794eb93-cfee-4705-ac9f-f8ccaf132c53','江楼','陸游','宋','宋诗','song-poetry','','[]','急雨洗殘瘴，江邉閑倚楼。',48,'全唐诗/poet.song.128000.json','["急雨洗殘瘴，江邉閑倚楼。", "日依平野没，水带斷槎流。", "擣紙荒村晚，呼牛古巷秋。", "腐儒憂國意，此際入搔頭。"]'),
('ca5c5631-c002-44d2-8bd4-8bfd334b4df6','夜登小南門城上','陸游','宋','宋诗','song-poetry','','[]','曵杖上江城，清宵破二更。',48,'全唐诗/poet.song.128000.json','["曵杖上江城，清宵破二更。", "月回高樹影，風壯急灘聲。", "野艇魚罾舉，優場炬火明。", "湖塘正如此，回首憶柴荆。"]'),
('f1fee712-1223-4b8f-850b-10797b30fcf2','野步至青羊宫偶懷前年嘗劇飲于此','陸游','宋','宋诗','song-poetry','','[]','錦官門外曵枯笻，此地天教著放翁。',64,'全唐诗/poet.song.128000.json','["錦官門外曵枯笻，此地天教著放翁。", "萬事元無工拙處，一官已付有無中。", "拏雲柏樹瘦蛟立，繞郭江流清鏡空。", "欲把酒杯終覺懶，緩歌曾醉落花風。"]'),
('678e8cde-6059-4992-923e-7270f54736c8','月夜江瀆池納涼','陸游','宋','宋诗','song-poetry','','[]','微逕荒城曲，叢祠野水邉。',48,'全唐诗/poet.song.128000.json','["微逕荒城曲，叢祠野水邉。", "月能從我醉，風欲駕人僊。", "静看黏螢草，遥聞采芡舩。", "熱官那有此，留滯莫尤天。"]'),
('015be2f1-5d3f-4d5a-a4f3-4100267c4f79','華亭院僧房二首  其一','陸游','宋','宋诗','song-poetry','','[]','半闔朱門見緑苔，幽花仍傍小山開。',32,'全唐诗/poet.song.128000.json','["半闔朱門見緑苔，幽花仍傍小山開。", "劍南七月暑未退，明日更擕棋簟來。"]'),
('1b8076fc-8d1f-49ae-b57e-2f50340b73ff','華亭院僧房二首  其二','陸游','宋','宋诗','song-poetry','','[]','悠悠馬上困思茶，休歇僧房到日斜。',32,'全唐诗/poet.song.128000.json','["悠悠馬上困思茶，休歇僧房到日斜。", "殿背無人緑錢滿，小盆零落珊瑚花。"]'),
('c474b124-3d6f-4ea0-9fe4-8df177872ec5','乾明院觀畫','陸游','宋','宋诗','song-poetry','','[]','唐年蘭若占閑坊，名畫蕭條半在亡。',64,'全唐诗/poet.song.128000.json','["唐年蘭若占閑坊，名畫蕭條半在亡。", "簌簌踈篁常似雨，陰陰古屋自生涼。", "入門疊鼓初催講，喚馬斜陽欲滿廊。", "顯晦熟思真有数，萬金奇跡棄頺牆。"]'),
('7f2288f2-e277-4bcb-82a9-49f1d13241d2','登城','陸游','宋','宋诗','song-poetry','','[]','我登少城門，四顧天地接。',192,'全唐诗/poet.song.128000.json','["我登少城門，四顧天地接。", "大風正北起，號怒撼危堞。", "九衢百萬家，楼觀争岌嶪。", "臥病氣壅塞，放目意頗愜。", "永懷河洛間，煌煌祖宗業。", "上天祐仁聖，萬邦盡臣妾。", "横流始靖康，趙魏血可蹀。", "小胡寕遠略，爲國恃剽劫。", "自量勢難久，外很中已懾。", "籍民備勝廣，陛戟畏荆聶。", "誰能提萬騎，大呼擁馬鬛。", "奇兵四面出，快若霜掃葉。", "植旗朝受降，馳驛夜奏捷。", "豺狼一朝空，狐兔何足獵。", "遺民世忠義，泣血受汗脅。", "繫箭射我詩，往檄五陵俠。"]'),
('9274bd28-c364-4ce0-be6e-a759acfad91a','秋日登僊逰閣','陸游','宋','宋诗','song-poetry','','[]','馬蹄連早暮，車塵細如霧。',96,'全唐诗/poet.song.128000.json','["馬蹄連早暮，車塵細如霧。", "誰知此路邉，高閣下風馭。", "頗傳秋月夕，語笑聮杖履。", "始知僊與人，混迹無異處。", "我來想鸞鶴，稽首祈一顧。", "飛僊不可見，惟與白雲遇。", "白雲如有情，傍我欄角住。", "借問何山來，雲驚却飛去。"]'),
('d2f5f1cf-c3a6-48ad-a174-49858471f383','自詠','陸游','宋','宋诗','song-poetry','','[]','華髮蕭蕭居士身，江頭風雨折烏巾。',64,'全唐诗/poet.song.128000.json','["華髮蕭蕭居士身，江頭風雨折烏巾。", "無人問字尤宜懶，有吏徴租未是貧。", "薄宦倘來難倚仗，舊交漸少每酸辛。", "敲門且復尋僧話，要結他生物外因。"]'),
('6fb34605-1ee0-4fb5-843c-244939006b0d','雜詠四首  其一','陸游','宋','宋诗','song-poetry','','[]','青羊宫中竹暗天，白馬廟畔柏如山。',32,'全唐诗/poet.song.128000.json','["青羊宫中竹暗天，白馬廟畔柏如山。", "琴尊處處可消日，車馬紛紛自欠閑。"]'),
('c62d161d-0282-4067-a880-90cb1e251c35','雜詠四首  其二','陸游','宋','宋诗','song-poetry','','[]','石犀廟壖江已回，陵谷一變吁可哀。',32,'全唐诗/poet.song.128000.json','["石犀廟壖江已回，陵谷一變吁可哀。", "即今禾黍連雲處，當日帆檣隐映來。"]'),
('6169f7ff-1df1-49c3-b262-bca60842eb8d','雜詠四首  其三','陸游','宋','宋诗','song-poetry','','[]','微風翻翻芋葉白，落日漠漠稻花香。',32,'全唐诗/poet.song.128000.json','["微風翻翻芋葉白，落日漠漠稻花香。", "出門縱轡何所詣，萬里橋南追晚涼。"]'),
('a16673d5-533d-40ed-af9b-ff981b0dd0e8','雜詠四首  其四','陸游','宋','宋诗','song-poetry','','[]','世事盛衰誰得知，惠陵烟草掩柴扉。',32,'全唐诗/poet.song.128000.json','["世事盛衰誰得知，惠陵烟草掩柴扉。", "陵邉人家叢竹裏，燈火喧呼迎婦歸。"]'),
('440c81c9-e803-44d3-bb94-72f4b0d07266','大醉歸南禪弄影月下有作','陸游','宋','宋诗','song-poetry','','[]','昔我變姓名，釣魚散花洲。',96,'全唐诗/poet.song.128000.json','["昔我變姓名，釣魚散花洲。", "有舩不用檝，江急聽自流。", "即今客錦城，醉過百花楼。", "天風吹筍輿，快若凌空逰。", "月露浩無際，指點隘九州。", "君看塵土中，頗有此樂不。", "題詩碧玉簡，飛僊相答酬。", "酒醒墮何處，楼臺海山秋。"]'),
('7ffe4f31-edaf-4370-894f-b92efdf10ebc','訪楊先輩不遇因至石室','陸游','宋','宋诗','song-poetry','','[]','訪客客已去，追涼成獨行。',48,'全唐诗/poet.song.128000.json','["訪客客已去，追涼成獨行。", "衣冠嚴漢殿，草木拱秦城。", "古甃蒼苔滑，空庭落日明。", "出門還儻恍，列屋打碑聲。"]'),
('5999d116-ea2e-4a7e-afa3-517b49c6e31d','病酒戲作','陸游','宋','宋诗','song-poetry','','[]','新秋風月佳，数夕破酒戒。',72,'全唐诗/poet.song.128000.json','["新秋風月佳，数夕破酒戒。", "飲少輙醉眠，衰早頗自怪。", "高舂未離枕，眩轉疑屋壊。", "家人具鷄豚，熟視不能嘬。", "尚無千里蓴，敢覓鏡湖蟹。", "一杯苦蕒齏，價直娑婆界。"]'),
('f4ec2316-7b3d-4616-9677-bf86efb459dc','訪昭覺老','陸游','宋','宋诗','song-poetry','','[]','久矣耆年罷送迎，喜聞革履下堂聲。',64,'全唐诗/poet.song.128000.json','["久矣耆年罷送迎，喜聞革履下堂聲。", "逰山笑我驀直去，過憂憐君太瘦生。", "庭際楠陰凝晝寂，牆頭鵲語報秋晴。", "功名已付諸賢了，長作閑人樂太平。"]'),
('3a82da69-2b65-49e5-8cd5-ae8a06945618','晝臥','陸游','宋','宋诗','song-poetry','','[]','秋暑侵人氣力微，焼香高枕掩齋扉。',64,'全唐诗/poet.song.128000.json','["秋暑侵人氣力微，焼香高枕掩齋扉。", "弄姿野蘤晴猶斂，作態江雲晚未歸。", "身外極知皆夢事，世間隨處有危機。", "故山松菊今何似，晚矣淵明悟昨非。"]'),
('fa0e0664-910a-45ed-b350-628e8d3a5a24','晚步江上','陸游','宋','宋诗','song-poetry','','[]','萬里橋邉带夕陽，隔江漁市似清湘。',64,'全唐诗/poet.song.128000.json','["萬里橋邉带夕陽，隔江漁市似清湘。", "山林獨往吾何恨，車馬交流渠自忙。", "高柳陰中扶拄杖，平沙稳處據胡床。", "故人京國無消息，安得相擕共此涼。"]'),
('0fb06ae7-a255-4d7a-9f8f-f9eb7df9b9ee','夜坐','陸游','宋','宋诗','song-poetry','','[]','大風横吹斗柄折，迅雷下擊山壁裂。',32,'全唐诗/poet.song.128000.json','["大風横吹斗柄折，迅雷下擊山壁裂。", "放翁閉户寂不聞，楞嚴卷盡燈花結。"]'),
('7e140748-b2c4-40d0-9168-d5f199984e16','夜行','陸游','宋','宋诗','song-poetry','','[]','紅藤拄杖扶衰病，村北村南破夜行。',64,'全唐诗/poet.song.128000.json','["紅藤拄杖扶衰病，村北村南破夜行。", "閑繞長堤逐螢火，戲臨荒沼問鼃聲。", "倦逰但有笭箵興，久客真諳褦襶情。", "安得故人同一醉，三更城上看河傾。"]'),
('a292e566-e4df-4e35-88e9-4af0d76c4526','悲秋','陸游','宋','宋诗','song-poetry','','[]','一抛蓑笠雪溪舟，八載梁州復益州。',64,'全唐诗/poet.song.128000.json','["一抛蓑笠雪溪舟，八載梁州復益州。", "纔破繁華海棠夢，又驚揺落井梧秋。", "曉班無復趋行殿，晚境惟思老寢丘。", "病肺經旬疏酒盞，愁來惟是上南楼。"]'),
('1b1140a5-560c-4386-9364-af166ae2d104','城北青蓮院方丈壁間有畫鷰子者過客多題詩予亦戲作二絕句  其一','陸游','宋','宋诗','song-poetry','','[]','一雙掠水鷰來初，萬點飛花社雨餘。',32,'全唐诗/poet.song.128000.json','["一雙掠水鷰來初，萬點飛花社雨餘。", "辛苦成巢君勿笑，從來吾亦爱吾廬。"]'),
('9c4358b2-96b6-4536-a422-9b517dd043ac','城北青蓮院方丈壁間有畫鷰子者過客多題詩予亦戲作二絕句  其二','陸游','宋','宋诗','song-poetry','','[]','明窗短壁拂蛛絲，常是江邉送客時。',32,'全唐诗/poet.song.128000.json','["明窗短壁拂蛛絲，常是江邉送客時。", "留滯錦城生白髮，不如巢燕有歸期。"]'),
('070a21cc-6110-4150-9a85-c75fb9b8c618','睡起','陸游','宋','宋诗','song-poetry','','[]','閑身喜午睡，睡起日猶早。',48,'全唐诗/poet.song.128000.json','["閑身喜午睡，睡起日猶早。", "茂竹青入簷，幽花紅出草。", "苔錢亦滿砌，護惜不忍掃。", "宦情本自踈，此地可忘老。"]'),
('8cdbe355-211b-468c-94c2-677830ce8c2e','天涯','陸游','宋','宋诗','song-poetry','','[]','天涯到處自生愁，逰子征塵暗弊裘。',64,'全唐诗/poet.song.128000.json','["天涯到處自生愁，逰子征塵暗弊裘。", "燈火青熒五門夜，風烟索莫二江秋。", "帝城漫誦新詩句，客路難逢舊輩流。", "送老把茅須早决，此生何止四宜休。"]'),
('c3b0033d-aa7f-4e60-adf1-64a72e74ff07','暇日行城上同行追不能及','陸游','宋','宋诗','song-poetry','','[]','疾步登城殊未衰，欣然一笑擲笻枝。',64,'全唐诗/poet.song.128000.json','["疾步登城殊未衰，欣然一笑擲笻枝。", "正當閑似白鷗處，不減健如黄犢時。", "秋野烟雲横慘淡，暮天楼閣倚參差。", "高吟醉舞忘歸去，乞與丹青畫怪奇。"]'),
('6a74dc33-ec64-4305-b43f-dd99f2a3aad5','感秋','陸游','宋','宋诗','song-poetry','','[]','西風繁杵擣征衣，客子關情正此時。',64,'全唐诗/poet.song.128000.json','["西風繁杵擣征衣，客子關情正此時。", "萬事從初聊復爾，百年彊半欲何之。", "畫堂蟋蟀怨清夜，金井梧桐辭故枝。", "一枕凄涼眠不得，呼燈起作感秋詩。"]'),
('a99ef1c8-1a43-40dc-bbff-a6912135f17c','雙流旅舍三首  其一','陸游','宋','宋诗','song-poetry','','[]','孤市人稀冷欲冰，昏昏一盞店家燈。',32,'全唐诗/poet.song.128000.json','["孤市人稀冷欲冰，昏昏一盞店家燈。", "開門拂榻便酣寢，我是江南行脚僧。"]'),
('da5df60c-2c87-4571-8cad-74e35a6da971','雙流旅舍三首  其二','陸游','宋','宋诗','song-poetry','','[]','西風黄葉滿江村，瘦馬來穿渡口雲。',32,'全唐诗/poet.song.128000.json','["西風黄葉滿江村，瘦馬來穿渡口雲。", "動地傳呼逢醉尉，誰何禁殺故將軍。"]'),
('4971d534-1c90-420d-87db-96e27e5079e2','雙流旅舍三首  其三','陸游','宋','宋诗','song-poetry','','[]','每因髀肉嘆身閑，聊欲勤勞鞍馬間。',32,'全唐诗/poet.song.128000.json','["每因髀肉嘆身閑，聊欲勤勞鞍馬間。", "黑矟黄旗端未免，會衝風雪出榆關。"]'),
('a26bac25-fcb4-449f-a86f-b0ecc407d19b','早行至江原','陸游','宋','宋诗','song-poetry','','[]','喔喔鳴鷄促起程，翻翻飛鷺導孤征。',64,'全唐诗/poet.song.128000.json','["喔喔鳴鷄促起程，翻翻飛鷺導孤征。", "節旄盡落歸猶遠，带眼頻移瘦自驚。", "小市蕭條黄葉滿，斷橋零落緑苔生。", "居人猶復多愁思，何况天涯倦客情。"]'),
('fe32bec5-dce1-4a35-95e8-6923e5ffe266','安仁道中二首  其一','陸游','宋','宋诗','song-poetry','','[]','千古臨卭路，飄然偶獨逰。',48,'全唐诗/poet.song.128000.json','["千古臨卭路，飄然偶獨逰。", "病身那迫老，遠客更禁秋。", "水退橋未葺，渡閑舩自流。", "飛騰付年少，回首思悠悠。"]'),
('11d6beca-95b8-4768-93c3-da6b2e0d088a','安仁道中二首  其二','陸游','宋','宋诗','song-poetry','','[]','三驛未爲遠，衰翁愁出門。',48,'全唐诗/poet.song.128000.json','["三驛未爲遠，衰翁愁出門。", "貪程多卒卒，失睡每昏昏。", "天大圍平野，江回隔近村。", "何時有餘俸，小築占雲根。"]'),
('e8497d11-9d0f-431e-a552-b890368037c6','八月十四夜三叉市對月','陸游','宋','宋诗','song-poetry','','[]','去年看月籌邉楼，雲罅微光如玉鈎。',128,'全唐诗/poet.song.128000.json','["去年看月籌邉楼，雲罅微光如玉鈎。", "主人不樂客嘆息，清歌空送黄金舟。", "今年看月三义市，纎雲不作良霄祟。", "素娥命駕洗客愁，我亦傾杯邀共醉。", "風露萬里方渺然，冰輪無轍行碧天。", "盈盈耿耿意無盡，月不忍落人忘眠。", "一言欲報廣寒殿，茅簷華屋均相見。", "明年萬事不足論，但願月滿人常健。"]'),
('89d48b47-f65f-42ae-a364-3c3722a24abd','豐橋旅舍作','陸游','宋','宋诗','song-poetry','','[]','我本山林人，心期在塵表。',80,'全唐诗/poet.song.128000.json','["我本山林人，心期在塵表。", "出門消底物，兩屩萬事了。", "群兒何足愠，爲爾常悄悄。", "今朝山中路，更喜相識少。", "三叉市人醉争席，豐橋逆旅留饋食。", "小婦梳髻高一尺，梭聲札札當户織。"]'),
('1f3812b3-af1c-4432-8f9f-f7355185d0b1','文君井','陸游','宋','宋诗','song-poetry','','[]','落魄西州泥酒杯，酒酣幾度上琴臺。',32,'全唐诗/poet.song.128000.json','["落魄西州泥酒杯，酒酣幾度上琴臺。", "青鞋自笑無羈束，又向文君酒畔來。"]'),
('9588a60b-1773-47c4-8543-2fc1014e420d','白鶴館夜坐','陸游','宋','宋诗','song-poetry','','[]','竹聲風雨交，松聲波濤翻。',120,'全唐诗/poet.song.128000.json','["竹聲風雨交，松聲波濤翻。", "我坐白鶴館，燈青無晤言。", "廓然心境寂，一洗吏卒喧。", "袖手哦新詩，清寒愧雄渾。", "屈宋死千載，誰能起九原。", "中間李與杜，獨招湘水魂。", "自此競摹寫，幾人望其藩。", "蘭苕看翡翠，烟雨啼青猿。", "豈知雲海中，九萬擊鵬鵾。", "更闌燈欲死，此意與誰論。"]'),
('59dd6c73-696d-4b95-97bf-7f25f74e5142','南津勝因院亭子','陸游','宋','宋诗','song-poetry','','[]','南江平無風，如鏡新拂拭。',96,'全唐诗/poet.song.128000.json','["南江平無風，如鏡新拂拭。", "漁舟不點破，瀲瀲千頃碧。", "闌干西北角，雲散山争出。", "坡陁競南走，翠入窗戸窄。", "江山不世情，作意娱此客。", "豈無尊中酒，豪飲非宿昔。", "明當還成都，塵土埋馬跡。", "後巖在眼中，飛去無羽翼。"]'),
('ce1c4d59-5896-4d2a-90db-812cba1bfce0','登卭州譙門門三重其西偏有神仙張四郎畫像張盖隐白鶴山中','陸游','宋','宋诗','song-poetry','','[]','浮雲在脚底，千里在眼邉。',96,'全唐诗/poet.song.128000.json','["浮雲在脚底，千里在眼邉。", "攀躋忽至此，倚柱眩欲顛。", "車馬細如螘，紛紛衢路間。", "嗟汝何爲者，馳驅窮歲年。", "我本澹蕩人，此心實爱閑。", "向來出處際，不愧咫尺天。", "風吹哦詩聲，十里搖西山。", "懸知老僊翁，爲我一粲然。"]'),
('3e710a02-7b5e-4afa-9fda-f2d5fa2ce429','書寓舍壁二首  其一','陸游','宋','宋诗','song-poetry','','["\u8861\u5c71"]','天與癡頑不解愁，未埋病骨且閑逰。',64,'全唐诗/poet.song.128000.json','["天與癡頑不解愁，未埋病骨且閑逰。", "山於拄杖横時看，路到芒鞵破處休。", "初擬焼丹住南嶽，却因學劍客西州。", "秋風巾褐添蕭爽，又作臨卭十日留。"]'),
('19757d04-2fa2-40f7-b546-863b1a1f90e5','書寓舍壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','落佩頹冠慣放慵，經旬寓館古臨卭。',64,'全唐诗/poet.song.128000.json','["落佩頹冠慣放慵，經旬寓館古臨卭。", "西偏取路横穿竹，北向開門倒看松。", "醉後蹇驢歸薄暮，閑來支枕睡高舂。", "鵠鳴山谷曾逰處，剩欲扶犂學老農。"]'),
('3404db6c-0351-4cd0-a87f-1211561eeb79','次韵使君吏部見贈時欲逰鶴山以雨止','陸游','宋','宋诗','song-poetry','','[]','蟆頤江上約同行，白鶴峰前辱寄聲。',64,'全唐诗/poet.song.128000.json','["蟆頤江上約同行，白鶴峰前辱寄聲。", "青史功名男子事，後堂歌舞故人情。", "午甌誰致葉家白，春甕旋撥郎官清。", "登覽不嫌鳩喚雨，十年芒屩慣山程。"]'),
('ddc4b029-b864-4016-b6cc-d0f003253e17','西巖翠屏閣','陸游','宋','宋诗','song-poetry','','[]','把酒孤亭半日留，西巖獨擅鶴山秋。',64,'全唐诗/poet.song.128000.json','["把酒孤亭半日留，西巖獨擅鶴山秋。", "也知絕境終難賦，且喜閑身得縱逰。", "鶻起危巢時磔磔，鹿鳴深澗暮呦呦。", "人生適意方爲樂，甲第朱門秖自囚。"]'),
('d8230df8-2915-4596-8dcc-1610ddf0bb77','幽居院','陸游','宋','宋诗','song-poetry','','[]','久墮塵沙裏，幽尋始此行。',72,'全唐诗/poet.song.128000.json','["久墮塵沙裏，幽尋始此行。", "侵雲千嶂合，披草一僧迎。", "蘚潤泉時滴，崖傾竹倒生。", "登高忽平曠，回首失峥嶸。", "老矣猶孤客，歸哉念耦耕。", "結廬殊未定，此地頗關情。"]'),
('f50b9bd4-4256-44b5-ab68-a7d478dfbd6a','中溪','陸游','宋','宋诗','song-poetry','','[]','散人無俗事，日日山中行。',96,'全唐诗/poet.song.128000.json','["散人無俗事，日日山中行。", "今朝中溪寺，妙絕不可名。", "幽處萬木合，忽然千頃平。", "緑黛染晴嶂，白雲如玉城。", "巖花勸小酌，天風吹獨醒。", "雖無九皋鶴，奇哉此松聲。", "我如折翼鵬，回盡九萬程。", "脱履擲拄杖，於此餞餘生。"]'),
('64a9159b-c40f-4105-a886-055af72ed1a9','天台院有小閣下臨官道予爲名曰玉霄','陸游','宋','宋诗','song-poetry','','[]','竹輿衝雨到天台，緑樹陰中小閣開。',32,'全唐诗/poet.song.128000.json','["竹輿衝雨到天台，緑樹陰中小閣開。", "牓作玉霄君會否，要知散吏按行來。"]'),
('d5ad283c-36cb-42d4-98b2-65e3ed8c8d4c','山中小雨得宇文使君簡問嘗見張僊翁乎戲作一絕','陸游','宋','宋诗','song-poetry','','[]','張僊挾彈知何往，清嘯穿林但可聞。',32,'全唐诗/poet.song.128000.json','["張僊挾彈知何往，清嘯穿林但可聞。", "拾得鐡丸無處用，爲君打散四山雲。"]'),
('94a2e2e0-6b74-472c-bc51-6a19903fe614','雨中山行至松風亭忽澄霽','陸游','宋','宋诗','song-poetry','','[]','烟雨千峰擁髻鬟，忽看青嶂白雲間。',32,'全唐诗/poet.song.128000.json','["烟雨千峰擁髻鬟，忽看青嶂白雲間。", "卷藏破墨營丘筆，却展將軍著色山。"]'),
('d5ce4a72-3d55-419d-880e-41fd2f08eedd','贈宋道人','陸游','宋','宋诗','song-poetry','','[]','我不如昔人騎鶴上九天，玉簡奏事虚皇前。',131,'全唐诗/poet.song.128000.json','["我不如昔人騎鶴上九天，玉簡奏事虚皇前。", "平生嗇養氣麤全，兩脚馳走輕如烟。", "鳥道懸崖忽飛鶱，戲擲短劍聲鏗然。", "轉盼跳下千仞淵，已復取劍升層巔。", "騰猿俊鶻争後先，饑食松花掬飛泉。", "金骨緑髓漸凝堅，口哦七字黄庭篇。", "西來欲訪挾彈僊，丹經劍訣更精研。", "嗟哉一失五百年，作詩付子勿妄傳。"]'),
('e75a1170-be10-41c6-8bb3-d8be3d695f5a','自山中泛舟歸郡城','陸游','宋','宋诗','song-poetry','','[]','我呼小艇浮南津，落日亂山衘半輪。',160,'全唐诗/poet.song.128000.json','["我呼小艇浮南津，落日亂山衘半輪。", "背舩雙鷺低掠水，下灘峭風冷逼人。", "中流回望始太息，烟中白塔高嶙峋。", "適從彼來忽在此，老夫拄杕捷有神。", "尉曹堆盤笠澤膾，秀才瀉榼中山春。", "豈惟外物不挂眼，醉後兀爾忘吾身。", "朝冠行即挂神武，買犢遂欲耕峨岷。", "金丹自喜日日長，白髮未許年年新。", "擁橋炬火遠已閙，歸舍睡息清而勻。", "明朝笑謂同載客，有脚莫踏東華塵。"]'),
('349d1377-a7b9-4fd3-9284-1c511dbc99af','次韵宇文使君山行','陸游','宋','宋诗','song-poetry','','[]','城中望西山，爽氣固可致。',144,'全唐诗/poet.song.128000.json','["城中望西山，爽氣固可致。", "不如山中行，衣屦染濃翠。", "使若資高逸，鐡馬奏横吹。", "平郊何曠蕩，修竹亦清閟。", "既聞蘓門嘯，遂挹浮丘袂。", "似嫌太清絕，開宴盡主意。", "戲留楚臺雲，寶靨鬭姿媚。", "珠貫按歌聲，泉湧發詩思。", "歸來殊不倦，吏牘閲千紙。", "却笑江左人，把酒輙遺事。", "下客亦未衰，尚可提萬騎。", "安能學胡公，危苦寄鶴翅。"]'),
('4384f08e-c39b-4444-bc58-53cb4f247c86','同王無玷羅用之訪臨卭道士墓','陸游','宋','宋诗','song-poetry','','[]','樂天詩句本嘲詼，那有人從碧海來。',32,'全唐诗/poet.song.128000.json','["樂天詩句本嘲詼，那有人從碧海來。", "五百年間逢好事，披榛來訪此崔嵬。"]'),
('e04e3934-0a86-4e6e-a59e-860a619ed2af','登太平塔','陸游','宋','宋诗','song-poetry','','[]','我從平地來，忽寄百尺巔。',72,'全唐诗/poet.song.128000.json','["我從平地來，忽寄百尺巔。", "眼力與脚力，初不減少年。", "漸高山愈出，杳杳浮雲烟。", "舉手捫參旗，日月磨螘旋。", "天風忽吹衣，便欲從此僊。", "且復下梯去，著書未終篇。"]'),
('0144b3bd-cee5-4882-a2f2-aae62281b22c','中夜投宿修覺寺','陸游','宋','宋诗','song-poetry','','[]','陸走崔嵬水下瀧，客中更復客它邦。',64,'全唐诗/poet.song.128000.json','["陸走崔嵬水下瀧，客中更復客它邦。", "晚離方井雲藏市，夜渡新津火照江。", "人語紛紛投野市，床敷草草寄僧窗。", "五更風雨妨歸夢，臥看殘燈吐半缸。"]'),
('ec7e7c1d-0094-46a9-ae03-305fb8e3ea10','絕勝亭','陸游','宋','宋诗','song-poetry','','[]','蜀漢羈逰歲月侵，京華乖隔少來音。',64,'全唐诗/poet.song.128000.json','["蜀漢羈逰歲月侵，京華乖隔少來音。", "登臨忽據三江會，飛動從來萬里心。", "地勝頓驚詩力壯，氣增不怕酒杯深。", "一琴一劍白雲外，揮手下山何處尋。"]'),
('520df196-80fe-487d-b272-c396884b684d','雲谿觀竹戲書二絕句  其一','陸游','宋','宋诗','song-poetry','','[]','氣盖冰霜勁有餘，江邉見此列僊癯。',32,'全唐诗/poet.song.128000.json','["氣盖冰霜勁有餘，江邉見此列僊癯。", "清寒直入人肌骨，一點塵埃住得無。"]'),
('71898daf-4161-4df7-9be5-b62ac10d9efc','雲谿觀竹戲書二絕句  其二','陸游','宋','宋诗','song-poetry','','[]','溪光竹色兩相宜，行到溪橋竹更奇。',32,'全唐诗/poet.song.128000.json','["溪光竹色兩相宜，行到溪橋竹更奇。", "對此莫論無肉瘦，閉門可忍十年饑。"]'),
('6ced3b68-3375-41d1-9d70-71251034d1a5','九月十日如漢州小獵於新都彌牟之間投宿民家','陸游','宋','宋诗','song-poetry','','[]','適從卭州歸，又作漢州去。',168,'全唐诗/poet.song.128000.json','["適從卭州歸，又作漢州去。", "天低慘欲雪，逰子悲歲暮。", "十年辭京國，疋馬厭道路。", "野火炎高岡，江雲暗空戍。", "角弓寒始勁，霜鶻饑更怒。", "邂逅成小獵，尺箠聊指呼。", "北連武侯祠，南竝稚子墓。", "合圍蹙窮鹿，設仗截狡兔。", "壯哉带箭雉，耿介死不顧。", "吾寧暴天物，戰法因得寓。", "黄昏過民家，休馬燎裘袴。", "割鮮盛燔炙，毛血灑庭戸。", "老姥亦復奇，汛掃邀我駐。", "丈夫儻未死，千金酬此遇。"]'),
('68f974ce-ae54-4fe3-aee7-e1ea9d118ee5','獵罷夜飲示獨孤生三首  其一','陸游','宋','宋诗','song-poetry','','[]','客途孤憤只君知，不作兒曹怨别離。',64,'全唐诗/poet.song.128000.json','["客途孤憤只君知，不作兒曹怨别離。", "報國雖思包馬革，爱身未忍價羊皮。", "呼鷹小獵新霜後，彈劍長歌夜雨時。", "感慨却愁傷壯志，倒瓶濁酒洗餘悲。"]'),
('4c2d162d-c71b-4dc7-9b85-6442b431d6c7','獵罷夜飲示獨孤生三首  其二','陸游','宋','宋诗','song-poetry','','[]','關輔何時一戰收，蜀郊且復獵清秋。',64,'全唐诗/poet.song.128000.json','["關輔何時一戰收，蜀郊且復獵清秋。", "洗空狡穴銀頭鶻，突過重城玉腕騮。", "賊勢已衰真大慶，士心未振尚私憂。", "一樽共講平戎策，勿爲飛鳶念少游。"]'),
('7edd4e29-c95f-4cd1-a3e7-1be43d54a763','獵罷夜飲示獨孤生三首  其三','陸游','宋','宋诗','song-poetry','','[]','白袍如雪寶刀横，醉上銀鞍身更輕。',64,'全唐诗/poet.song.128000.json','["白袍如雪寶刀横，醉上銀鞍身更輕。", "帖草角鷹掀兔窟，憑風羽箭作鴟鳴。", "關河可使成南北，豪傑誰堪共死生。", "欲疏萬言投魏闕，燈前攬筆涕先傾。"]'),
('d38d9772-7ebe-4ee4-b050-a71d9ad7e16c','自廣漢歸宿十八里草市','陸游','宋','宋诗','song-poetry','','[]','月黑叩店門，燈青坐床簀。',72,'全唐诗/poet.song.128000.json','["月黑叩店門，燈青坐床簀。", "飯麤雜沙土，菜瘦等草棘。", "泰然均一飽，未覺異玉食。", "我豈兒女哉，口腹爲怨德。", "古人恥懷禄，不仕當力穯。", "從今扶犂手，終老謝翰墨。"]'),
('90b06119-3367-4492-b499-343526370812','東郊飲村酒大醉後作','陸游','宋','宋诗','song-poetry','','[]','丈夫無苟求，君子有素守。',72,'全唐诗/poet.song.128000.json','["丈夫無苟求，君子有素守。", "不能垂竹帛，正可死隴畆。", "邯鄲枕中夢，要是念所有。", "持枕與農夫，亦作此夢否。", "今朝櫟林下，取醉村市酒。", "未敢羞空囊，爛漫詩千首。"]'),
('a13687f3-a08f-4fed-b2cb-1dc9cf894d91','九月十八夜夢避雨叩一僧院有老宿年八十許邀留甚勤若舊相識者夢中爲賦此詩','陸游','宋','宋诗','song-poetry','','[]','畫簷急雨傾高秋，夜投丈室燈幽幽。',64,'全唐诗/poet.song.128000.json','["畫簷急雨傾高秋，夜投丈室燈幽幽。", "耆年擁毳雪滿頭，拂拭床敷邀我留。", "雛猊戲擲香出喉，蓬蓬結成蒼玉毬。", "蠻童掲簾侍者憂，觸散香烟當罰油。"]'),
('e7b0b196-8875-4db5-8c0b-9a76d7127a81','秋晚登城北門','陸游','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u79cb\u5929", "\u767b\u697c", "\u6292\u6000", "\u58ee\u5fd7"]','幅巾藜杖北城頭，卷地西風滿眼愁。',64,'全唐诗/poet.song.128000.json','["幅巾藜杖北城頭，卷地西風滿眼愁。", "一點烽傳散關信，兩行雁带杜陵秋。", "山河興廢供搔首，身世安危入倚樓。", "橫槊賦詩非復昔，夢魂猶繞古梁州。"]'),
('6934864f-f782-4d55-aaa2-843f17241815','秋興','陸游','宋','宋诗','song-poetry','','[]','成都城中秋夜長，燈籠蠟紙明空堂。',128,'全唐诗/poet.song.128000.json','["成都城中秋夜長，燈籠蠟紙明空堂。", "高梧月白繞飛鵲，衰草露濕啼寒螀。", "堂上書生讀書罷，欲眠未眠偏斷腸。", "起行百匝幾嘆息，一夕緑髮成秋霜。", "中原本是關情地，幽州寧謂非吾鄉。", "滎河溫洛底處所，可使長作爭戰塲。", "百金戎衣鵰鶻盤，三尺劍鋒霜雪寒。", "一朝出塞君試看，旦發寶雞暮長安。"]'),
('7fa11582-de00-47f2-ab24-caae8a286b02','夜飲','陸游','宋','宋诗','song-poetry','','[]','引劍酣歌亦壯哉，要君共覆手中杯。',64,'全唐诗/poet.song.128000.json','["引劍酣歌亦壯哉，要君共覆手中杯。", "秋鴻陣密横江去，暮角聲酣戰雨來。", "莫恨皇天無老眼，請看白骨有青苔。", "中年倍覺流光速，行矣西郊又見梅。"]'),
('a17fedf1-67d5-4049-b844-2d16ef95d328','暮秋二首  其一','陸游','宋','宋诗','song-poetry','','[]','時序中年速，風霜客路長。',48,'全唐诗/poet.song.128000.json','["時序中年速，風霜客路長。", "孤愁巴月白，清夢楚山蒼。", "燈暗秋銜壁，鐘踈夜殷床。", "端居有微禄，不敢恨殊方。"]'),
('ee8295d7-3d66-4b3d-9a4a-8e724cb2c416','暮秋二首  其二','陸游','宋','宋诗','song-poetry','','[]','萬里歸無策，八年淹此留。',48,'全唐诗/poet.song.128000.json','["萬里歸無策，八年淹此留。", "羞蒙子公力，寜倦長卿遊。", "聽雨瀟湘夜，飛鷹鄠杜秋。", "更須論富貴，此計亦悠悠。"]'),
('6fcc07fe-6189-4972-8007-2228a59e1700','夜雨有感','陸游','宋','宋诗','song-poetry','','[]','北風吹雨暗江郊，十月僧廬旋補茆。',64,'全唐诗/poet.song.128000.json','["北風吹雨暗江郊，十月僧廬旋補茆。", "病馬敢希三品料，驚禽聊借一枝巢。", "少時諸老爭求識，晚歲殊方罕定交。", "閉户不妨新得趣，丹經盈篋手親抄。"]'),
('cda3da49-d939-45c2-a3f7-2e6f8dee6dd5','道室','陸游','宋','宋诗','song-poetry','','[]','一室冷如冰，人疑在定僧。',48,'全唐诗/poet.song.128000.json','["一室冷如冰，人疑在定僧。", "手稱丹竈火，紗護佛龕燈。", "食減形雖槁，心虛氣自凝。", "平生坐忘論，字字欲銘膺。"]'),
('5522c111-954c-44e9-8f98-951cf867ff98','飯罷戲作','陸游','宋','宋诗','song-poetry','','[]','南市沽濁醪，浮螘甘不壊。',101,'全唐诗/poet.song.128000.json','["南市沽濁醪，浮螘甘不壊。", "東門買彘骨，醯醤點橙薤。", "蒸雞最知名，美不數魚蟹。", "輪囷犀浦芋，磊落新都菜。", "欲賡老饕賦，畏破頭陀戒。", "況予齒日疏，大臠敢屢嘬。", "杜老死牛{炙火=肉}，千古懲禍敗。", "閉門餌朝霞，無病亦無債。"]'),
('8092cb01-6ae4-4ae6-a730-9d22fbc3991c','初冬夜宴','陸游','宋','宋诗','song-poetry','','[]','絲管紛紛燭滿堂，梟盧擲罷夜飛觴。',64,'全唐诗/poet.song.128000.json','["絲管紛紛燭滿堂，梟盧擲罷夜飛觴。", "帷犀風定歌雲暖，香獸烟濃漏箭長。", "泛菊已成前日夢，探梅又續去年狂。", "醉歸自笑摧頽甚，冷逼貂裘怯曉霜。"]'),
('42f69db4-6383-47ed-895a-4de29b728ba3','冬夜醉歸復小飲','陸游','宋','宋诗','song-poetry','','[]','野外歸來晚，空庭露氣新。',48,'全唐诗/poet.song.128000.json','["野外歸來晚，空庭露氣新。", "乍晴雲妬月，多病酒欺人。", "倚杖行吟久，投杯起舞頻。", "早梅消息動，春事漸關身。"]'),
('d03e2cea-c2f1-4db2-bfc0-21c63c26ba93','病酒述懷','陸游','宋','宋诗','song-poetry','','[]','閑處天教著放翁，草廬高卧筰橋東。',64,'全唐诗/poet.song.128000.json','["閑處天教著放翁，草廬高卧筰橋東。", "數莖白髮悲秋後，一醆青燈病酒中。", "李廣射歸關月墮，劉琨嘯罷塞雲空。", "古人意氣憑君看，不待功成固已雄。"]'),
('301bab97-1083-458e-bf20-8e3287644e41','數日暄妍頗有春意予閑居無日不出遊戲作','陸游','宋','宋诗','song-poetry','','[]','小春花蕾索春饒，已有暄風入紫貂。',64,'全唐诗/poet.song.128000.json','["小春花蕾索春饒，已有暄風入紫貂。", "村路雨晴鳩婦喜，射塲草緑雉媒驕。", "花邊結客飛金勒，樓上誰家弄玉簫。", "莫怪夕陽歸獨後，早梅喚我度谿橋。"]'),
('e81e2c2a-91f8-4556-89de-370a48763ceb','遣興','陸游','宋','宋诗','song-poetry','','[]','耆舊日凋謝，将如此老何。',48,'全唐诗/poet.song.128000.json','["耆舊日凋謝，将如此老何。", "懣拈如意舞，狂叩唾壺歌。", "郡縣輕民力，封疆恃虜和。", "功名莫看鏡，吾意已蹉跎。"]'),
('d24b3ae9-112e-41f4-92ba-c0de6e1414ae','趙將軍','陸游','宋','宋诗','song-poetry','','[]','我夢遊太華，雲開千仞青。',96,'全唐诗/poet.song.128000.json','["我夢遊太華，雲開千仞青。", "擘山瀉黄河，萬古仰巨靈。", "往者禍亂初，氛祲干太寜。", "豈無卧雲龍，一起奔風霆。", "時事方錯繆，三秦盡飄零。", "山河銷王氣，原野失大刑。", "将軍散髮去，短劍斸茯苓。", "定知三峰上，爛醉今未醒。"]'),
('8192f672-49d4-4a73-96e1-a85f9430f650','江樓醉中作','陸游','宋','宋诗','song-poetry','','[]','淋漓百榼宴江樓，秉燭揮毫氣尚遒。',64,'全唐诗/poet.song.128000.json','["淋漓百榼宴江樓，秉燭揮毫氣尚遒。", "天上但聞星主酒，人間寜有地埋憂。", "生希李廣名飛将，死慕劉伶贈醉侯。", "戲語佳人頻一笑，錦城已是六年留。"]'),
('32578fa8-744d-4ed3-8d27-45d126534f7f','曵策','陸游','宋','宋诗','song-poetry','','[]','慈竹蕭森拱廢臺，醉歸曵策一徘徊。',64,'全唐诗/poet.song.128000.json','["慈竹蕭森拱廢臺，醉歸曵策一徘徊。", "紛紛落日牛羊下，黯黯長空霰雪來。", "三峽猿催清泪落，兩京梅傍戰塵開。", "客懷已是凄凉甚，更聽城頭畫角哀。"]'),
('90395b27-f6d9-45b8-aa77-1aaa01f1231a','謁漢昭烈惠陵及諸葛公祠宇','陸游','宋','宋诗','song-poetry','','[]','雨止風益豪，雪作雲不動。',168,'全唐诗/poet.song.128000.json','["雨止風益豪，雪作雲不動。", "凄凉漢陵廟，衰草卧翁仲。", "畫妓空笙竽，土馬闕羈鞚。", "壤沃黄犢耕，柏密幽鳥哢。", "尚想忠武公，身任社稷重。", "整整渭上營，氣已無岐雍。", "少須天意定，破賊寜患衆。", "興亡信有數，星隕事可痛。", "陵邊四五家，茆竹居接棟。", "手皸紙上箔，醅熟酒鳴甕。", "雖嗟生理微，亦足逭饑凍。", "劉葛固雄傑，閲世均一夢。", "論高常近迂，才大本難用。", "九原不可作，再拜臨風慟。"]'),
('a43e81fa-1136-4dad-a194-64b90ebc9937','遥夜','陸游','宋','宋诗','song-poetry','','[]','遥夜雨聲急，愔愔窗户幽。',48,'全唐诗/poet.song.128000.json','["遥夜雨聲急，愔愔窗户幽。", "開編堯舜在，得句鬼神愁。", "同俗愚儒辠，容身壯士羞。", "燈殘不成睡，曉角動南樓。"]'),
('45069c38-91b5-4238-97bb-4f0fdf8cf117','遠遊','陸游','宋','宋诗','song-poetry','','[]','遠遊行復歲華新，懶學劉郎問大鈞。',64,'全唐诗/poet.song.128000.json','["遠遊行復歲華新，懶學劉郎問大鈞。", "一點不蒙稽古力，十分合作卧雲身。", "苦寒與酒漸增價，小雨爲梅先辟塵。", "擬佩一壺江路去，花邊醉墮白綸巾。"]'),
('67ae94b0-fb1b-400b-bf49-2d24921acdbd','大雪歌','陸游','宋','宋诗','song-poetry','','[]','長安城中三日雪，潼關道上行人絕。',128,'全唐诗/poet.song.128000.json','["長安城中三日雪，潼關道上行人絕。", "黄河鐵牛僵不動，承露金盤凍将折。", "虬鬚豪客狐白裘，夜來醉眠寶釵樓。", "五更未醒已上馬，衝雪却作南山遊。", "千年老虎獵不得，一箭横穿雪皆赤。", "拏空爭死作雷吼，震動山林裂崖石。", "曳歸擁路千人觀，髑髏作枕皮蒙鞍。", "人間壮士有如此，胡不來歸漢天子。"]'),
('70bed861-ca5f-42c2-a9af-cf80876baaa1','簡譚德稱','陸游','宋','宋诗','song-poetry','','[]','幼輿骨相稱山巖，自要閑遊不避讒。',64,'全唐诗/poet.song.128000.json','["幼輿骨相稱山巖，自要閑遊不避讒。", "錦里先生爲老伴，玉霄散吏是頭銜。", "探春苑路花篸帽，看月江樓酒滿衫。", "惟恨題詩無逸氣，愧君陣馬與風颿。"]'),
('0600a1cc-9660-4259-b6a9-192c3448bbcc','排悶','陸游','宋','宋诗','song-poetry','','[]','世事何知與願違，十年高卧看群飛。',64,'全唐诗/poet.song.128000.json','["世事何知與願違，十年高卧看群飛。", "獵圍花市無人問，漁艇烟村有夢歸。", "銀燭焰長揺酒浪，寶刀佩穩壓戎衣。", "君看白首寒窗客，俠氣縱横亦未非。"]'),
('4810e3ee-0c2d-4d6e-872d-d75faf79e5e5','夜意三首  其一','陸游','宋','宋诗','song-poetry','','[]','名姓人誰記，形骸老漸侵。',48,'全唐诗/poet.song.128000.json','["名姓人誰記，形骸老漸侵。", "酒慳停劇飲，詩退負高吟。", "雨隔踈更斷，雲藏古院深。", "衰遲常兀兀，惆悵少年心。"]'),
('f0a9ee01-ad2c-468a-9b05-7cedcd51564b','夜意三首  其二','陸游','宋','宋诗','song-poetry','','[]','心清知睡少，氣定覺神凝。',48,'全唐诗/poet.song.128000.json','["心清知睡少，氣定覺神凝。", "但有一無愧，何妨百不能。", "燈昏如隔霧，研冷欲生冰。", "兀爾遺身世，東窗待日升。"]'),
('d4e396c6-bc3e-4df5-bac9-8a2d26240c3b','夜意三首  其三','陸游','宋','宋诗','song-poetry','','[]','瘴地晨霜薄，郊墟暮雨昏。',48,'全唐诗/poet.song.128000.json','["瘴地晨霜薄，郊墟暮雨昏。", "啼螀如有恨，微火解相温。", "末路真無策，孤忠敢自言。", "輪囷肝膽在，白首倚乾坤。"]'),
('66ef772c-0193-4de1-9c0d-d67abdc68cb7','玉局觀拜東坡先生海外畫像','陸游','宋','宋诗','song-poetry','','[]','商周去不還，盛哉漢唐宋。',168,'全唐诗/poet.song.128000.json','["商周去不還，盛哉漢唐宋。", "蘇公本天人，謫墮爲世用。", "太平極嘉祐，珠玉始包貢。", "公車三千牘，字字岌飛動。", "氣力倒犀象，律呂諧鸞鳯。", "天驥西極來，矯矯不受鞚。", "飛騰上臺閣，廢放落雲夢。", "至寶不侵蝕，終亦老侍從。", "晚途遷海表，萬里天宇空。", "豈惟騎鯨魚，遂欲跨螮蝀。", "心空物莫撓，氣老筆愈縱。", "粃糠郊祀歌，遠友清廟頌。", "我生雖後公，妙句得吟諷。", "整衣拜遺像，千古尊正統。"]'),
('57a6a56f-867b-4acf-9f5b-53791bb1445d','心太平庵','陸游','宋','宋诗','song-poetry','','[]','天下本無事，庸人擾之耳。',72,'全唐诗/poet.song.128000.json','["天下本無事，庸人擾之耳。", "胸中故湛然，忿欲定誰使。", "本心倘不失，外物真一螘。", "困窮何足道，持此端可死。", "空齋夜方中，窗月淡如水。", "忽有清磬鳴，老夫從定起。"]'),
('f0a45edf-cc0b-49d3-aba5-e584d4a1e189','訪客至西郊','陸游','宋','宋诗','song-poetry','','[]','摵摵敗葉飛，黯黯寒雲低。',120,'全唐诗/poet.song.128000.json','["摵摵敗葉飛，黯黯寒雲低。", "村墟與市里，觸目一慘悽。", "今日病體輕，駕言適城西。", "丹柿滿野店，青帘出江隄。", "獵騎載雉兔，樵擔懸鶉雞。", "居人各自得，使我念故谿。", "故谿不敢說，况復朝金閨。", "傷哉齧雪翁，歲晚猶牧羝。", "下愚不自還，大惑終身迷。", "君恩何由報，力耕愧黔黎。"]'),
('f4dbcae9-c894-4d57-80d8-a67623b25236','得都下八月書報蒙恩牧敘州','陸游','宋','宋诗','song-poetry','','[]','鳯城書到錦江邊，故里歸期愈渺然。',64,'全唐诗/poet.song.128000.json','["鳯城書到錦江邊，故里歸期愈渺然。", "掌上山川初入夢，壺中日月尚經年。", "方輪落落難推轂，倦馬駸駸怕著鞭。", "未佩魚符無吏責，看花且作拾遺顛。"]'),
('4c4ddfe3-007d-45b5-a501-1d3805080b52','晚起二首  其一','陸游','宋','宋诗','song-poetry','','[]','賣劍捐書絕世緣，掩關高枕送流年。',64,'全唐诗/poet.song.128000.json','["賣劍捐書絕世緣，掩關高枕送流年。", "久從道士學踵息，誰管門生嘲腹便。", "化蝶飛時嗟昨夢，睡蛇去後喜安眠。", "欠伸看起東窗日，也似金鑾過八磚。"]'),
('30bd109b-3fa7-4f19-8a51-a2b6bfa92f8a','晚起二首  其二','陸游','宋','宋诗','song-poetry','','[]','學道逍遥心太平，幽窗鼻息撼床聲。',64,'全唐诗/poet.song.128000.json','["學道逍遥心太平，幽窗鼻息撼床聲。", "柳花無蒂蠻氊暖，龜甲有紋繒帳明。", "候起兒童陳盥櫛，笑衰人客闖柴荆。", "此生睡足無餘念，安用元戎報五更。"]');
